window.MINNA_LESSONS = [{"l":1,"t":"N₁ といえば、N₂","de":"Apropos N₁ — typischerweise denkt man an N₂","slots":[{"text":"N₁","role":"obj","label":"Stichwort"},{"text":"といえば、","role":"actor","label":"apropos"},{"text":"N₂","role":"subj","label":"Assoziation"},{"text":"だ/です","role":"plain"}],"gloss":"»Wenn man N₁ sagt, denkt man an N₂.« — nennt das, was einem zu einem Thema sofort einfällt (allgemein bekannt). Auch: というと / といったら.","ex":{"jp":"<ruby>京都<rt>きょうと</rt></ruby><b>といえば</b>、お<ruby>寺<rt>てら</rt></ruby>ですね。","de":"Apropos Kyoto — Tempel, oder?"},"simpel":"Greift ein Stichwort auf und nennt die typische Assoziation dazu — einfach <b>といえば</b> ans Nomen hängen.<br><span class=\"jp\"><ruby>京都<rt>きょうと</rt></ruby>といえば、お<ruby>寺<rt>てら</rt></ruby></span> = „Apropos Kyoto — Tempel“","rule":"Drückt eine typische, geteilte Assoziation aus. Sprecher A nennt N₁ als Stichwort, und N₂ ist das, was den meisten Menschen dazu sofort einfällt. Sehr häufige Konversationseröffnung — »wenn von X die Rede ist, dann …«."},{"l":1,"t":"<ruby>数量<rt>すうりょう</rt></ruby> + も (überraschende Menge)","de":"sogar / ganze … (Menge ist erstaunlich groß)","slots":[{"text":"Subjekt は/が","role":"subj"},{"text":"<ruby>数量<rt>すうりょう</rt></ruby>","role":"time","label":"Zahl + Zähler"},{"text":"も","role":"actor","label":"sogar"},{"text":"V","role":"verb"}],"gloss":"»sogar/ganze … viel.« — der Sprecher findet die Menge erstaunlich groß. Muster: 数量 + も + V (z. B. 5回も). Gegenteil: しか + Vない (zu wenig).","ex":{"jp":"<ruby>毎朝<rt>まいあさ</rt></ruby> 2<ruby>時間<rt>じかん</rt></ruby><b>も</b> <ruby>電車<rt>でんしゃ</rt></ruby>に <ruby>乗<rt>の</rt></ruby>って います。","de":"Ich fahre jeden Morgen ganze 2 Stunden Bahn."},"simpel":"<b>も</b> hinter eine Mengenangabe heißt »so viel!« — Überraschung über eine große Menge.<br><span class=\"jp\">3<ruby>時間<rt>じかん</rt></ruby>も <ruby>待<rt>ま</rt></ruby>った</span> = „Ich habe ganze 3 Stunden gewartet“","rule":"も nach einer Zahlenangabe drückt aus, dass die Menge den Sprecher überrascht — »so viel/lang/oft!«. Hervorhebend, oft mit emotionalem Unterton (beeindruckt oder genervt). NICHT zu verwechseln mit dem も als »auch«."},{"l":1,"t":"N は 〜こと、〜こと(だ)","de":"X besteht aus: erstens …, zweitens … (Aufzählung)","slots":[{"text":"<ruby>大切<rt>たいせつ</rt></ruby>なのは、","role":"subj","label":"Wichtig ist:"},{"text":"[Inhalt 1]","role":"cond"},{"text":"こと、","role":"actor","label":"Punkt 1"},{"text":"[Inhalt 2]","role":"cond"},{"text":"ことだ","role":"plain","label":"Punkt 2 (Ende)"}],"gloss":"»Wichtig ist: erstens …, zweitens …« — zählt Punkte auf, je こと dahinter, am Ende こと + だ/です. Nach Verb (Grundform/ない形) und Adjektiv (い-Adj + こと, な-Adj + な + こと).","ex":{"jp":"<ruby>健康<rt>けんこう</rt></ruby>のために <ruby>大切<rt>たいせつ</rt></ruby>なのは、<ruby>食事<rt>しょくじ</rt></ruby>に <ruby>気<rt>き</rt></ruby>を つける<b>こと</b>、<ruby>運動<rt>うんどう</rt></ruby>する<b>ことだ</b>。","de":"Für die Gesundheit ist wichtig: auf die Ernährung achten und Sport treiben."},"simpel":"<b>こと</b> macht Sätze zu zählbaren Punkten zum Aufzählen — der letzte Punkt bekommt <b>だ/です</b>.<br><span class=\"jp\"><ruby>大切<rt>たいせつ</rt></ruby>なのは、あきらめない<b>ことだ</b></span> = „Wichtig ist, nicht aufzugeben“","rule":"こと nominalisiert ganze Sätze zu zählbaren »Punkten«. Sehr nützlich, um Definitionen zu geben oder Punkte aufzulisten — typisch für Essays und formelle Erklärungen. Der letzte こと-Punkt bekommt だ/です."},{"l":1,"t":"Vマス-Stamm + <ruby>始<rt>はじ</rt></ruby>める / <ruby>終<rt>お</rt></ruby>わる","de":"anfangen zu V / fertig sein mit V","slots":[{"text":"Subjekt は/が","role":"subj"},{"text":"(Objekt を)","role":"obj"},{"text":"V-マス-Stamm","role":"verb","label":"Hauptverb"},{"text":"<ruby>始<rt>はじ</rt></ruby>めた / <ruby>終<rt>お</rt></ruby>わった","role":"actor","label":"Aspekt"}],"gloss":"»fängt an / hört auf zu V.« — Aspekt-Wort hängt am ます-Stamm: 始める (anfangen), 終わる (fertig werden). Unregelmäßig: 来始める, し始める.","ex":{"jp":"<ruby>赤<rt>あか</rt></ruby>ちゃんが <ruby>歩<rt>ある</rt></ruby>き<b><ruby>始<rt>はじ</rt></ruby>めた</b>。","de":"Das Baby hat angefangen zu laufen."},"simpel":"ます-Stamm + <b><ruby>始<rt>はじ</rt></ruby>める</b> (anfangen) oder <b><ruby>終<rt>お</rt></ruby>わる</b> (fertig sein) — klebt direkt am Stamm.<br><span class=\"jp\"><ruby>食<rt>た</rt></ruby>べ<ruby>始<rt>はじ</rt></ruby>める</span> = „anfangen zu essen“","rule":"Zwei Hilfsverben, die den <b>Aspekt</b> einer Handlung markieren: 始める (anfangen) oder 終わる (zu Ende kommen). Sie hängen direkt an den ます-Stamm des Hauptverbs — wie ein Wort zusammenwachsen."},{"l":2,"t":"〜のでしょうか","de":"wohl …? / dürfte es wohl …? (höfliche Vermutungsfrage)","slots":[{"text":"Inhalt","role":"verb","label":"in einfache Form"},{"text":"(な)","role":"plain","label":"nur bei N/な-Adj"},{"text":"のでしょうか","role":"actor","label":"wohl?"}],"gloss":"»Ist das wohl …?« — höfliche, vorsichtige Nachfrage. Muster: einfache Form + のでしょうか (な-Adj/N + な + のでしょうか). Direkter wäre nur ですか.","ex":{"jp":"<ruby>彼<rt>かれ</rt></ruby>は どこへ <ruby>行<rt>い</rt></ruby>った<b>のでしょうか</b>。","de":"Wohin ist er wohl gegangen?"},"simpel":"Höfliche, vorsichtige Frage »wohl …?«. <b>のでしょうか</b> ans Plain-Verb hängen (N/な-Adj: + な).<br><span class=\"jp\"><ruby>彼<rt>かれ</rt></ruby>は <ruby>来<rt>こ</rt></ruby>ない<b>のでしょうか</b></span> = „Ob er wohl nicht kommt?“","rule":"Höfliche, vorsichtige Frage: Der Sprecher fragt nicht direkt, sondern tastend — »könnte es wohl sein, dass …?«. Kombination aus の (Erklärungs-Nominalisierer) + でしょう (Vermutung, Minna L32) + か (Fragepartikel). Klingt deutlich weicher und höflicher als ein einfaches ですか."},{"l":2,"t":"<ruby>自動詞<rt>じどうし</rt></ruby> ⇆ <ruby>他動詞<rt>たどうし</rt></ruby> (Vertiefung)","de":"Verbpaare: »passiert von selbst« ↔ »jemand macht es«","slots":[[{"text":"N が","role":"subj","label":"Subjekt"},{"text":"V<sub>intr.</sub>","role":"verb","label":"passiert von selbst"}],[{"text":"Person が","role":"actor","label":"Handelnder"},{"text":"N を","role":"obj","label":"Objekt"},{"text":"V<sub>tr.</sub>","role":"verb","label":"macht es aktiv"}]],"gloss":"»passiert von selbst« (自動詞: N が V) ↔ »jemand macht es« (他動詞: Person が N を V). Paare wie 集まる/集める, 決まる/決める, 変わる/変える.","ex":{"jp":"<ruby>人口<rt>じんこう</rt></ruby><b>が</b> <ruby>増<rt>ふ</rt></ruby>えて います。","de":"Die Bevölkerung nimmt zu. [自]"},"simpel":"Zwei Verben für eine Aktion: <b>自動詞</b> (が, passiert von selbst) ↔ <b>他動詞</b> (を, jemand macht es).<br><span class=\"jp\">ドアが <ruby>開<rt>あ</rt></ruby>く / ドアを <ruby>開<rt>あ</rt></ruby>ける</span> = „Tür geht auf / Tür öffnen“","rule":"Japanisch hat oft <b>zwei Verben</b> für dieselbe Aktion: ein <b>intransitives</b> (自動詞) für »passiert von selbst« und ein <b>transitives</b> (他動詞) für »jemand macht es aktiv«. Davon hängen Partikel (が vs. を) und Bedeutung von ている / てある ab. Wiederholung und Erweiterung von Minna L29 mit neuen Chuukyuu-Paaren."},{"l":2,"t":"V<sub>(よ)う</sub> + としても、〜ない","de":"auch wenn ich versuche zu V — es klappt nicht","slots":[{"text":"V-Willensform形","role":"verb","label":"ich will V"},{"text":"としても、","role":"actor","label":"auch wenn versucht"},{"text":"V-ない / V-れない","role":"verb","label":"klappt nicht"}],"gloss":"»Auch wenn ich versuche zu V, klappt es nicht.« — der Wille ist da, das Ergebnis nicht. Muster: VWillensform形 + としても、〜ない (z. B. 食べよう, しよう, 来よう).","ex":{"jp":"<ruby>忘<rt>わす</rt></ruby>れ<b>ようとしても</b>、<ruby>忘<rt>わす</rt></ruby>れられない。","de":"Auch wenn ich es vergessen will, kann ich es nicht."},"simpel":"Volitional-Form + <b>としても</b> + Verneinung: »auch wenn ich es versuche — es klappt nicht«.<br><span class=\"jp\"><ruby>忘<rt>わす</rt></ruby>れ<b>ようとしても</b>、<ruby>忘<rt>わす</rt></ruby>れられない</span> = „So sehr ich will, ich kann es nicht vergessen“","rule":"Konzessiv-Konstruktion: Der Wille zu handeln ist da, aber die Handlung scheitert oder ist sinnlos. Bildung: <b>Volitional-Form</b> (VWillensform形, »ich will V tun«) + としても + Verneinung/Schwierigkeit."},{"l":2,"t":"〜のは 〜 だ (Hervorhebung)","de":"Was/wer/wann … — das ist Y","slots":[{"text":"[Sachverhalt in V-Plain]","role":"verb","label":"Aktion"},{"text":"のは","role":"actor"},{"text":"[Hervorgehobenes]","role":"obj","label":"Person/Zeit/Ort"},{"text":"だ/です","role":"plain"}],"gloss":"»Das, was [Aktion], ist Y.« — schiebt die wichtige Info ans Satzende. Muster: Veinfache Form + のは + [Person/Sache/Zeit/Ort] + だ.","ex":{"jp":"この <ruby>絵<rt>え</rt></ruby>を <ruby>描<rt>か</rt></ruby>いた<b>のは</b> <ruby>子供<rt>こども</rt></ruby><b>だ</b>。","de":"Wer dieses Bild gemalt hat, war ein Kind."},"simpel":"Spaltsatz: das Wichtige (wer/was/wann) rückt mit <b>のは … だ</b> ans Ende und wird betont.<br><span class=\"jp\">この <ruby>絵<rt>え</rt></ruby>を <ruby>描<rt>か</rt></ruby>いた<b>のは</b> <ruby>子供<rt>こども</rt></ruby><b>だ</b></span> = „Wer das gemalt hat, war ein Kind“","rule":"Spaltsatz-Konstruktion (»cleft sentence«): Ein Teil des Satzes wird durch <code>のは … だ</code> ans Ende gerückt und dadurch hervorgehoben. Beantwortet implizit eine Frage: »Wer war's? Was genau? Wann eigentlich?«"},{"l":2,"t":"ている / てある / ておく — Überblick","de":"Zustand (passiv) ↔ vorbereitet (absichtlich) ↔ vorbereiten (aktiv)","slots":[[{"text":"N が","role":"subj"},{"text":"V<sub>intr.</sub>-て いる","role":"verb","label":"Zustand"}],[{"text":"N が","role":"subj"},{"text":"V<sub>tr.</sub>-て ある","role":"verb","label":"absichtlich vorbereitet"}],[{"text":"<ruby>私<rt>わたし</rt></ruby> が","role":"actor"},{"text":"N を","role":"obj"},{"text":"V-て おく","role":"verb","label":"ich bereite vor"}]],"gloss":"ている = »ist gerade im Zustand X«. てある = »wurde absichtlich gemacht und ist noch so« (Vテ + ある). ておく = »mache es jetzt, damit es später erledigt ist« (gespr. 〜とく).","ex":{"jp":"<ruby>窓<rt>まど</rt></ruby>が <ruby>開<rt>あ</rt></ruby>いて <b>います</b>。","de":"Das Fenster ist offen. [ている — Zustand]"},"simpel":"<b>ている</b> = Zustand, <b>てある</b> = absichtlich vorbereitet (sichtbar), <b>ておく</b> = vorsorglich erledigen.<br><span class=\"jp\"><ruby>窓<rt>まど</rt></ruby>が <ruby>開<rt>あ</rt></ruby>いて いる / <ruby>開<rt>あ</rt></ruby>けて ある</span> = „Fenster ist offen / wurde geöffnet“","rule":"Drei Konstruktionen mit て-Form, die ständig verwechselt werden. <b>ている</b> = Zustand oder Andauer (oft mit 自動詞). <b>てある</b> = Resultat einer absichtlichen Handlung, das noch sichtbar ist (nur mit 他動詞). <b>ておく</b> = ich bereite jetzt aktiv etwas für später vor."},{"l":3,"t":"〜einfache Form + ような N","de":"ein N, wie es … ist / so eines, das …","slots":[{"text":"Vergleichs-Inhalt","role":"cond","label":"wie was?"},{"text":"(の/な)","role":"plain","label":"je nach Wortart"},{"text":"ような","role":"actor","label":"so beschaffen"},{"text":"N","role":"obj","label":"Nomen"}],"gloss":"»ein N, das so ist wie [Inhalt].« — verknüpft einen Vergleich mit einem Nomen. Muster: V/い-Adj + ような + N (な-Adj + な, N + の + ような).","ex":{"jp":"<ruby>夢<rt>ゆめ</rt></ruby><b>のような</b> <ruby>話<rt>はなし</rt></ruby>だ。","de":"Das ist eine Geschichte wie aus einem Traum."},"simpel":"<b>ような</b> verbindet eine Beschreibung attributiv mit einem Nomen — »ein N, das so ist wie …«.<br><span class=\"jp\"><ruby>夢<rt>ゆめ</rt></ruby>のような <ruby>話<rt>はなし</rt></ruby></span> = „eine Geschichte wie aus einem Traum“","rule":"<code>ような</code> verbindet einen Satz attributiv mit einem Nomen — »ein N, das so beschaffen ist wie …«. Der Vergleich/die Beschreibung steht vor <code>ような</code>, das beschriebene Nomen dahinter."},{"l":3,"t":"N のよう / のような / のように","de":"wie ein N (3 Positionen: Prädikat / Attribut / Adverb)","slots":[[{"text":"〜は N の","role":"obj"},{"text":"ようだ","role":"verb","label":"① Prädikat"}],[{"text":"N の","role":"obj"},{"text":"ような","role":"actor"},{"text":"N₂","role":"subj","label":"② Attribut"}],[{"text":"N の","role":"obj"},{"text":"ように","role":"actor"},{"text":"V","role":"verb","label":"③ Adverb"}]],"gloss":"»wie ein N.« — derselbe Vergleich an drei Stellen: のようだ am Satzende, のような vor Nomen, のように vor Verb. Auch mit Verben (Veinfache Form + ようだ).","ex":{"jp":"<ruby>彼<rt>かれ</rt></ruby>は <ruby>子<rt>こ</rt></ruby>ども<b>のようだ</b>。","de":"Er ist wie ein Kind. [① Prädikat]"},"simpel":"Ein Vergleich, drei Positionen: <b>ようだ</b> am Satzende, <b>ような</b> vor Nomen, <b>ように</b> vor Verb.<br><span class=\"jp\"><ruby>子<rt>こ</rt></ruby>どものように <ruby>笑<rt>わら</rt></ruby>う</span> = „lachen wie ein Kind“","rule":"Drei Formen für denselben Vergleich — die <b>Position im Satz</b> bestimmt die Form: am <b>Satzende</b> als Prädikat (ようだ), vor einem <b>Nomen</b> als Attribut (ような), vor einem <b>Verb</b> als Adverb (ように)."},{"l":3,"t":"N ばかり / V<sub>て</sub> ばかり いる","de":"immer nur N / immer nur V-en (kritisch)","slots":[{"text":"Subjekt は","role":"subj"},{"text":"N / V-て","role":"verb","label":"das eine"},{"text":"ばかり","role":"actor","label":"immer nur"},{"text":"いる / だ","role":"plain"}],"gloss":"»immer nur N / immer nur V-en.« — kritisch-bedauernd, nichts anderes. Muster: N + ばかり, Vテ + ばかり + いる. (だけ ist neutral, しか〜ない = zu wenig.)","ex":{"jp":"<ruby>息子<rt>むすこ</rt></ruby>は ゲームを して<b>ばかりいる</b>。","de":"Mein Sohn spielt immer nur Videospiele."},"simpel":"<b>ばかり</b> = »immer nur das« mit kritischem Ton. Bei Verb: <b>V-て + ばかり + いる</b>.<br><span class=\"jp\">ゲームを して<b>ばかり いる</b></span> = „spielt immer nur Videospiele“","rule":"<code>ばかり</code> = einschränkend mit <b>negativem</b> oder bedauerndem Unterton: »immer nur das, nichts anderes«. Bei Nomen: direkt dranhängen. Bei Verben: <code>V-て + ばかり + いる</code>. Klingt häufig wie eine Beschwerde."},{"l":3,"t":"N を <ruby>欲<rt>ほ</rt></ruby>しがる / Vマス-Stamm + たがる","de":"jemand anders möchte … (Wunsch dritter Personen)","slots":[{"text":"Andere Person は/が","role":"actor","label":"er/sie (nicht ich)"},{"text":"N を / V-Stamm","role":"obj"},{"text":"<ruby>欲<rt>ほ</rt></ruby>しがって いる / たがって いる","role":"verb","label":"möchte (3. Person)"}],"gloss":"»jemand anders möchte …« — fremder Wunsch, daher meist mit ています. N を 欲しがっている (will N), Vマス-Stamm + たがっている (möchte V-en). Ich selbst: 欲しい / たい.","ex":{"jp":"<ruby>子<rt>こ</rt></ruby>どもたちが おもちゃ<b>を</b> <ruby>欲<rt>ほ</rt></ruby>しがって います。","de":"Die Kinder wollen Spielzeug haben."},"simpel":"Wünsche <b>anderer</b> Personen: <b>欲しがる</b> (N を) / V-Stamm + <b>たがる</b> — meist mit ている.<br><span class=\"jp\"><ruby>子<rt>こ</rt></ruby>どもが おもちゃを <ruby>欲<rt>ほ</rt></ruby>しがって いる</span> = „Das Kind will Spielzeug“","rule":"Ein eigener Wunsch heißt <code><ruby>欲<rt>ほ</rt></ruby>しい / 〜たい</code>. Bei Wünschen <b>anderer Personen</b> muss man dagegen <code><ruby>欲<rt>ほ</rt></ruby>しがる / 〜たがる</code> nutzen — Japanisch unterscheidet streng, weil man fremde Gefühle nur von außen beobachten kann."},{"l":3,"t":"つい + Vテ しまう","de":"aus Versehen / wider Willen / habe es leider doch getan","slots":[{"text":"つい (ついつい)","role":"time","label":"unbeabsichtigt"},{"text":"V-て","role":"verb"},{"text":"しまった","role":"actor","label":"leider passiert"}],"gloss":"»Habe leider doch X getan.« — aus Versehen, ohne es zu wollen, mit Reue. Muster: つい + Vテ + しまう/しまった (gespr. 〜ちゃった). Gegenteil: わざと (absichtlich).","ex":{"jp":"<ruby>食<rt>た</rt></ruby>べないつもりだったのに、<b>つい</b> <ruby>食<rt>た</rt></ruby>べて しまった。","de":"Eigentlich wollte ich nicht essen — habe es aber doch getan."},"simpel":"<b>つい</b> + <b>てしまう</b>: »ich wollte eigentlich nicht — ist aber leider doch passiert«.<br><span class=\"jp\"><b>つい</b> <ruby>食<rt>た</rt></ruby>べて <b>しまった</b></span> = „Ich hab's leider doch gegessen“","rule":"<code>つい</code> = unwillentlich, ungewollt, dem Impuls nachgegeben. Sehr oft kombiniert mit <code>てしまう</code> (Minna L29 — »leider passiert, vollendet«). Ergebnis: »Ich wollte eigentlich nicht — aber es ist trotzdem passiert.«"},{"l":3,"t":"〜のは 〜 からだ","de":"Der Grund, warum X passiert, ist Y","slots":[{"text":"[Sachverhalt X]","role":"cond","label":"das, was passiert"},{"text":"のは、","role":"actor"},{"text":"[Grund Y]","role":"verb"},{"text":"からだ / からです","role":"plain","label":"weil"}],"gloss":"»Dass X, liegt daran, dass Y.« — schiebt den Grund ans Satzende und betont ihn. Muster: 〜のは、〜からだ. Frage: なぜ 〜のですか.","ex":{"jp":"<ruby>日本語<rt>にほんご</rt></ruby>が <ruby>上手<rt>じょうず</rt></ruby>な<b>のは</b>、<ruby>毎日<rt>まいにち</rt></ruby> <ruby>練習<rt>れんしゅう</rt></ruby>している<b>からだ</b>。","de":"Dass sein Japanisch so gut ist, liegt daran, dass er täglich übt."},"simpel":"Kausaler Spaltsatz: »Dass X — das liegt daran, dass Y«. Der Grund rückt mit <b>のは … からだ</b> ans Ende.<br><span class=\"jp\"><ruby>遅<rt>おく</rt></ruby>れた<b>のは</b>、<ruby>電車<rt>でんしゃ</rt></ruby>が <ruby>止<rt>と</rt></ruby>まった<b>からだ</b></span> = „Ich bin zu spät, weil der Zug stehenblieb“","rule":"Kausale Spaltsatz-Konstruktion: »Dass X — das liegt daran, dass Y.« Hervorhebung des Grundes. Verwandt mit der Hervorhebungs-Struktur 〜のは 〜だ (L2), nur mit Fokus auf <b>Grund/Ursache</b>."},{"l":4,"t":"V<sub>て</sub> いく / V<sub>て</sub> きた (Entwicklung über Zeit)","de":"wird sich entwickeln (→ Zukunft) / hat sich entwickelt (→ Jetzt)","slots":[[{"text":"これから・だんだん …","role":"time","label":"Zukunfts-Signal"},{"text":"V-て いく","role":"verb","label":"→ Zukunft"}],[{"text":"これまで・<ruby>最近<rt>さいきん</rt></ruby> …","role":"time","label":"Vergangenheits-Signal"},{"text":"V-て きた","role":"verb","label":"→ Jetzt"}]],"gloss":"»entwickelt sich weiter« — ていく zeigt in die Zukunft (»von jetzt an weiter so«), てきた zeigt bis zur Gegenwart (»hat sich bis jetzt so entwickelt«). Oft mit これから / だんだん.","ex":{"jp":"これからも <ruby>温暖化<rt>おんだんか</rt></ruby>が <ruby>進<rt>すす</rt></ruby>んで <b>いく</b> だろう。","de":"Die Erderwärmung wird sich wohl weiter fortsetzen."},"simpel":"Entwicklung über Zeit: <b>ていく</b> = von jetzt in die Zukunft, <b>てきた</b> = von früher bis jetzt.<br><span class=\"jp\"><ruby>増<rt>ふ</rt></ruby>えて <b>きた</b> / <ruby>増<rt>ふ</rt></ruby>えて <b>いく</b></span> = „hat zugenommen / wird zunehmen“","rule":"Aspekt für <b>Veränderung über Zeit</b>. <code>ていく</code> = ein Trend geht ab jetzt in die Zukunft weiter. <code>てきた</code> = ein Trend hat sich von der Vergangenheit bis jetzt entwickelt. Vertiefung von Minna L43 (dort: konkrete Bewegung) — hier abstrakt-zeitlich."},{"l":4,"t":"[<ruby>表<rt>ひょう</rt></ruby>/グラフ] で <ruby>見<rt>み</rt></ruby>ると、〜ことが わかる","de":"Wenn man [Quelle] betrachtet, sieht man, dass …","slots":[{"text":"<ruby>表<rt>ひょう</rt></ruby> / グラフ","role":"obj","label":"Quelle"},{"text":"で <ruby>見<rt>み</rt></ruby>ると、","role":"actor","label":"betrachtet man"},{"text":"[Inhalt]","role":"verb","label":"in einfache Form"},{"text":"ことが わかる","role":"plain","label":"erkennt man"}],"gloss":"»Wenn man [Quelle] anschaut, sieht man, dass …« — Standardsatz für Datenanalyse. Muster: [Quelle] を/で 見ると、〜ことが わかる. Auch: 調査によると.","ex":{"jp":"このグラフ<b>で <ruby>見<rt>み</rt></ruby>ると</b>、<ruby>日本<rt>にほん</rt></ruby>の <ruby>人口<rt>じんこう</rt></ruby>が <ruby>減<rt>へ</rt></ruby>って いる <b>ことが わかる</b>。","de":"Wenn man diese Grafik betrachtet, erkennt man, dass Japans Bevölkerung abnimmt."},"simpel":"Schablone für Datenanalyse: erst Quelle nennen, dann Erkenntnis mit <b>〜ことが わかる</b>.<br><span class=\"jp\">グラフで <ruby>見<rt>み</rt></ruby>ると、<ruby>人口<rt>じんこう</rt></ruby>が <ruby>減<rt>へ</rt></ruby>って いる<b>ことが わかる</b></span> = „Die Grafik zeigt: die Bevölkerung sinkt“","rule":"Standard-Schablone für die <b>Interpretation von Daten</b> in Berichten, Aufsätzen und Präsentationen. Erst die Quelle nennen (Tabelle, Grafik, Studie), dann die Erkenntnis daraus formulieren."},{"l":4,"t":"N₁ の ような N₂ (Beispiel-Funktion)","de":"ein N₂ wie zum Beispiel N₁","slots":[{"text":"N₁ の","role":"obj","label":"konkretes Beispiel"},{"text":"ような","role":"actor","label":"wie z.B."},{"text":"N₂","role":"subj","label":"Kategorie"}],"gloss":"»ein N₂ wie zum Beispiel N₁.« — N₁ ist ein Beispiel, das zeigt, welche Art N₂ gemeint ist. Muster: N₁ + の + ような + N₂. Ähnlich gesprochen: N₁ など.","ex":{"jp":"すし<b>のような</b> <ruby>日本食<rt>にほんしょく</rt></ruby>が <ruby>好<rt>す</rt></ruby>きです。","de":"Ich mag japanisches Essen wie zum Beispiel Sushi."},"simpel":"Hier ist N₁ ein <b>konkretes Beispiel</b> für N₂ — »ein N₂ wie zum Beispiel N₁«.<br><span class=\"jp\">すしのような <ruby>日本食<rt>にほんしょく</rt></ruby></span> = „japanisches Essen wie z.B. Sushi“","rule":"Hier dient N₁ als <b>konkretes Beispiel</b> für die allgemeinere Kategorie N₂. Anders als bei einfachem »wie« (L3) — der Akzent liegt auf »zum Beispiel«: »Sushi und ähnliche japanische Gerichte«."},{"l":4,"t":"X は Y ほど 〜ない","de":"X ist nicht so … wie Y (negativer Vergleich)","slots":[{"text":"X は","role":"subj","label":"das Kleinere"},{"text":"Y","role":"obj","label":"Standard"},{"text":"ほど","role":"actor","label":"so wie"},{"text":"Adj + ない","role":"verb","label":"nicht so sehr"}],"gloss":"»X ist nicht so [Adj] wie Y.« — Y ist der Maßstab, X reicht nicht heran. Muster: X は Y ほど + Adj/Vない (い-Adj → くない, な-Adj → ではない).","ex":{"jp":"<ruby>今日<rt>きょう</rt></ruby>は <ruby>昨日<rt>きのう</rt></ruby><b>ほど</b> <ruby>寒<rt>さむ</rt></ruby>く ない。","de":"Heute ist nicht so kalt wie gestern."},"simpel":"Negativer Vergleich: »X ist <b>nicht so</b> … wie Y«. Y ist der Maßstab, mit <b>ほど</b> markiert.<br><span class=\"jp\"><ruby>今日<rt>きょう</rt></ruby>は <ruby>昨日<rt>きのう</rt></ruby><b>ほど</b> <ruby>寒<rt>さむ</rt></ruby>く ない</span> = „Heute ist nicht so kalt wie gestern“","rule":"Vergleich mit Verneinung: »X ist <b>nicht so</b> [Eigenschaft] wie Y«. <code>ほど</code> markiert den Vergleichsstandard. Wichtig: <b>X ist kleiner/weniger</b>, Y ist der höhere Standard."},{"l":4,"t":"<ruby>比較<rt>ひかく</rt></ruby> — Vergleichsformen im Überblick","de":"Alle wichtigen Vergleichsstrukturen auf einen Blick","slots":[[{"text":"A より","role":"obj","label":"Basis"},{"text":"B の ほうが","role":"subj","label":"besser"},{"text":"Adj です","role":"verb"}],[{"text":"〜の <ruby>中<rt>なか</rt></ruby>で","role":"place","label":"Gruppe"},{"text":"X が","role":"subj"},{"text":"<ruby>一番<rt>いちばん</rt></ruby> Adj です","role":"verb","label":"am meisten"}]],"gloss":"Vergleiche auf einen Blick: A より B の ほうが Adj (B mehr), A は B ほど Adj-ない (A weniger), 〜の中で一番 (am meisten), 同じくらい (gleich), Vば 〜ほど (je … desto).","ex":{"jp":"バス<b>より</b> <ruby>電車<rt>でんしゃ</rt></ruby>の <b>ほうが</b> <ruby>速<rt>はや</rt></ruby>い。","de":"Der Zug ist schneller als der Bus."},"simpel":"Vergleiche auf einen Blick: <b>より/ほうが</b> (B > A), <b>ほど〜ない</b> (A < B), <b><ruby>一番<rt>いちばん</rt></ruby></b> (Superlativ).<br><span class=\"jp\">バス<b>より</b> <ruby>電車<rt>でんしゃ</rt></ruby>の <b>ほうが</b> <ruby>速<rt>はや</rt></ruby>い</span> = „Der Zug ist schneller als der Bus“","rule":"Übersichtskarte: Alle Vergleichs-Werkzeuge nebeneinander. Wichtig ist zu wissen, <b>aus welcher Richtung</b> der Vergleich kommt (»A > B« oder »A < B«) und ob die Aussage <b>positiv</b> oder <b>verneint</b> ist."},{"l":5,"t":"い-Adj / な-Adj + さ (Nominalisierung)","de":"Aus Adjektiv wird Nomen: »die X-keit«","slots":[{"text":"Adj-さ","role":"subj","label":"nominalisiert"},{"text":"は","role":"plain"},{"text":"[Grad/Maß]","role":"obj","label":"Zahl/Antwort"},{"text":"です","role":"plain"}],"gloss":"»die X-keit.« — さ macht aus einer Eigenschaft ein messbares Nomen. Muster: い-Adj い → さ (長さ, 高さ), な-Adj + さ. Ausnahme: いい/よい → よさ.","ex":{"jp":"この <ruby>山<rt>やま</rt></ruby>の <ruby>高<rt>たか</rt></ruby><b>さ</b>は 3776メートルです。","de":"Die Höhe dieses Berges beträgt 3776 Meter."},"simpel":"<b>さ</b> verwandelt ein Adjektiv in ein messbares Nomen: <ruby>高<rt>たか</rt></ruby>い → <ruby>高<rt>たか</rt></ruby>さ (»die Höhe«).<br><span class=\"jp\">この <ruby>山<rt>やま</rt></ruby>の <ruby>高<rt>たか</rt></ruby><b>さ</b></span> = „die Höhe dieses Berges“","rule":"Adjektive lassen sich mit <code>さ</code> in <b>Nomen</b> verwandeln, die einen <b>messbaren Grad</b> ausdrücken: <code><ruby>高<rt>たか</rt></ruby>い</code> (hoch) → <code><ruby>高<rt>たか</rt></ruby>さ</code> (die Höhe). Sehr produktive Regel — funktioniert mit fast allen Adjektiven."},{"l":5,"t":"<ruby>連用<rt>れんよう</rt></ruby><ruby>中止<rt>ちゅうし</rt></ruby><ruby>形<rt>けい</rt></ruby> (Schriftstil-Verbindung)","de":"Sätze mit ます-Stamm verbinden (Schriftsprache)","slots":[{"text":"V₁-Stamm","role":"verb","label":"Verb 1 ohne ます"},{"text":"、","role":"plain"},{"text":"V₂-Stamm","role":"verb","label":"Verb 2 ohne ます"},{"text":"、…","role":"plain"},{"text":"V<sub>n</sub>-た/ます","role":"actor","label":"Endverb mit Tempus"}],"gloss":"Verbindet Sätze im Schriftstil mit dem ます-Stamm statt der テ-Form; nur das letzte Verb trägt Tempus und Höflichkeit. Geschrieben: Vマス-Stamm、… (い-Adj: 〜く、). Ausnahme: する → し、.","ex":{"jp":"<ruby>朝<rt>あさ</rt></ruby> <ruby>起<rt>お</rt></ruby><b>き</b>、<ruby>顔<rt>かお</rt></ruby>を <ruby>洗<rt>あら</rt></ruby><b>い</b>、<ruby>朝食<rt>ちょうしょく</rt></ruby>を <ruby>食<rt>た</rt></ruby>べた。","de":"Ich stand morgens auf, wusch mir das Gesicht und frühstückte. [schriftlich]"},"simpel":"Im <b>Schriftstil</b> verbindet man Sätze mit dem ます-Stamm statt mit der て-Form — Tempus nur am Schluss.<br><span class=\"jp\"><ruby>朝<rt>あさ</rt></ruby> <ruby>起<rt>お</rt></ruby><b>き</b>、<ruby>顔<rt>かお</rt></ruby>を <ruby>洗<rt>あら</rt></ruby>った</span> = „Ich stand auf und wusch mein Gesicht“","rule":"In <b>geschriebenen Texten</b> (Berichte, Romane, Zeitungen) werden Teilsätze oft nicht mit der て-Form, sondern mit dem <b>ます-Stamm</b> verbunden. Das wirkt eleganter und literarischer. Tempus und Höflichkeit nur am <b>letzten</b> Verb."},{"l":5,"t":"V<sub>Grund/ない</sub> + ものだ (allgemeine Norm)","de":"so ist das halt / das ist nun einmal so","slots":[{"text":"(<ruby>一般的<rt>いっぱんてき</rt></ruby>に)","role":"time","label":"allgemein"},{"text":"V-Grundform / V-ない","role":"verb"},{"text":"ものだ","role":"actor","label":"so ist das halt"}],"gloss":"»So ist das halt.« — eine allgemeine Wahrheit/Norm, keine persönliche Meinung. Muster: VGrundform/ない形 + ものだ. Verneinung der Norm: V-Grundform + ものではない.","ex":{"jp":"<ruby>人<rt>ひと</rt></ruby>は <ruby>年<rt>とし</rt></ruby>を <ruby>取<rt>と</rt></ruby>る<b>ものだ</b>。","de":"Menschen werden älter — so ist das nun einmal."},"simpel":"<b>V-Grundform + ものだ</b> = »so ist das nun mal« — allgemeine Wahrheit oder gesellschaftliche Norm.<br><span class=\"jp\"><ruby>人<rt>ひと</rt></ruby>は <ruby>年<rt>とし</rt></ruby>を <ruby>取<rt>と</rt></ruby>る<b>ものだ</b></span> = „Menschen werden eben älter“","rule":"<code>ものだ</code> drückt eine <b>allgemeine Wahrheit oder gesellschaftliche Norm</b> aus — »so ist das nun mal, das gehört dazu«. Wirkt belehrend oder erfahrungsweise. Anschluss meist mit einfache Form (Grundform/ない形)."},{"l":5,"t":"もの と こと の <ruby>整理<rt>せいり</rt></ruby> (Übersicht)","de":"もの vs. こと: konkret/erlebbar ↔ abstrakt/sachlich","slots":[[{"text":"V-Grundform + もの","role":"verb","label":"konkret/erlebt"}],[{"text":"V-Grundform + こと","role":"verb","label":"abstrakt/sachlich"}]],"gloss":"もの (konkret, persönlich-warm) vs. こと (abstrakt, sachlich) — gleicher Anschluss (V-Grundform + もの/こと), andere Nuance. もの bei 感じる/好き, こと bei 知る/必要.","ex":{"jp":"<ruby>食<rt>た</rt></ruby>べる<b>もの</b>に <ruby>気<rt>き</rt></ruby>を つけて います。","de":"Ich achte auf das, was ich esse. [konkret — das Essen selbst]"},"simpel":"<b>もの</b> = konkret/erlebbar, <b>こと</b> = abstrakt/sachlich. Im Zweifel ist <b>こと</b> immer korrekt.<br><span class=\"jp\"><ruby>食<rt>た</rt></ruby>べる<b>もの</b> / <ruby>食<rt>た</rt></ruby>べる<b>こと</b></span> = „das Essen (Ding) / das Essen (Handlung)“","rule":"Beide nominalisieren Sätze, aber mit unterschiedlicher Nuance. <code>もの</code> = <b>konkret, greifbar, persönlich-erlebbar</b> (das Ding/Erlebnis selbst). <code>こと</code> = <b>abstrakt, sachlich, faktisch</b> (die Handlung/Tatsache)."},{"l":5,"t":"〜と いう ことだ (Hörensagen, schriftlich)","de":"es heißt, dass … / mit anderen Worten: …","slots":[{"text":"(Quelle に よると)","role":"actor","label":"laut wem"},{"text":"einfache Form","role":"verb","label":"in einfache Form"},{"text":"と いう ことだ","role":"plain","label":"es heißt"}],"gloss":"»Es heißt, dass …« / »mit anderen Worten: …« — Hörensagen aus formellen Quellen oder Zusammenfassung. Muster: einfache Form + ということだ (な-Adj/N + だ + ということだ). Gesprochen eher そうだ.","ex":{"jp":"<ruby>来年<rt>らいねん</rt></ruby>から <ruby>消費税<rt>しょうひぜい</rt></ruby>が <ruby>上<rt>あ</rt></ruby>がる<b>と いう ことだ</b>。","de":"Es heißt, dass die Konsumsteuer nächstes Jahr steigen wird."},"simpel":"Formelles Hörensagen oder Zusammenfassung: »es heißt, dass …« bzw. »das heißt also …«.<br><span class=\"jp\"><ruby>来年<rt>らいねん</rt></ruby> <ruby>税<rt>ぜい</rt></ruby>が <ruby>上<rt>あ</rt></ruby>がる<b>と いう ことだ</b></span> = „Es heißt, die Steuer steigt nächstes Jahr“","rule":"<b>Formelle Variante</b> des Hörensagen-そうだ (Minna L47). Zwei Funktionen: ① <b>Hörensagen</b> aus Berichten, Nachrichten, Studien. ② <b>Zusammenfassung</b> einer komplexen Aussage (»das heißt also …«)."},{"l":5,"t":"<ruby>長<rt>なが</rt></ruby>い <ruby>文<rt>ぶん</rt></ruby>を <ruby>読<rt>よ</rt></ruby>むコツ (Lese-Strategie)","de":"Lange Mittelstufen-Sätze entschlüsseln","slots":[{"text":"[Subjekt]は","role":"subj","label":"Anfang"},{"text":"[Nebensatz] ので、","role":"cond","label":"Grund"},{"text":"[Objekt]を","role":"obj"},{"text":"[V] と","role":"verb","label":"Zitat-Inhalt"},{"text":"<ruby>思<rt>おも</rt></ruby>って います","role":"actor","label":"Hauptverb GANZ AM ENDE"}],"gloss":"Lese-Richtung: <b>von hinten nach vorne</b> denken. Erst das Hauptverb finden — alles davor sind Modifikatoren.","ex":{"jp":"<ruby>環境問題<rt>かんきょうもんだい</rt></ruby>が <ruby>深刻<rt>しんこく</rt></ruby>に なって いる<b>ので</b>、<ruby>私<rt>わたし</rt></ruby>たちは <ruby>生活習慣<rt>せいかつしゅうかん</rt></ruby>を <ruby>変<rt>か</rt></ruby>える <ruby>必要<rt>ひつよう</rt></ruby>が ある<b>と</b> <ruby>思<rt>おも</rt></ruby>います。","de":"Da die Umweltprobleme ernster werden, denke ich, dass wir unsere Lebensgewohnheiten ändern müssen."},"simpel":"Keine Grammatik, sondern eine Lesehilfe: Japanisch ist ende-fokussiert — lange Sätze <b>von hinten</b> erfassen.<br><span class=\"jp\">… <ruby>必要<rt>ひつよう</rt></ruby>が ある<b>と <ruby>思<rt>おも</rt></ruby>います</b></span> = „Hauptverb steht ganz am Satzende“","rule":"Ab Chuukyuu werden Sätze sehr lang — mehrere Nebensätze, Nominalausdrücke, Konjunktionen. Diese Karte ist <b>kein Grammatikpunkt</b>, sondern eine <b>Lese-Strategie</b>. Wichtig: das japanische Hauptverb steht <b>am Ende</b>, also rückwärts lesen."},{"l":6,"t":"N によって [Passiv] — Urheber im Passiv","de":"von / durch N (im Passiv, formell)","slots":[{"text":"[Werk] は","role":"subj","label":"Ergebnis"},{"text":"[Urheber]","role":"actor","label":"Schöpfer"},{"text":"によって","role":"plain","label":"durch"},{"text":"V-Passiv","role":"verb","label":"Passiv"}],"gloss":"»wurde durch [Urheber] V-t.« — formelles Passiv, das betont, wer etwas erschaffen/entschieden hat (Erfindungen, Kunst, Gesetze). Muster: [Werk] は [Urheber] + によって + VPassiv.","ex":{"jp":"この <ruby>小説<rt>しょうせつ</rt></ruby>は <ruby>夏目漱石<rt>なつめそうせき</rt></ruby><b>によって</b> <ruby>書<rt>か</rt></ruby>かれた。","de":"Dieser Roman wurde von Natsume Sōseki geschrieben."},"simpel":"Im Passiv markiert <b>によって</b> den Urheber (Erfinder, Autor …) — formeller als einfaches に.<br><span class=\"jp\"><ruby>電話<rt>でんわ</rt></ruby>は ベル<b>によって</b> <ruby>発明<rt>はつめい</rt></ruby>された</span> = „Das Telefon wurde von Bell erfunden“","rule":"<code>によって</code> markiert im Passivsatz den <b>Urheber</b> einer wichtigen Handlung: Erfinder, Autor, Architekt, Komitee, historische Figur. Formeller und betonter als das einfache <code>に</code> aus Minna L37. Standard für Erfindungen, Kunstwerke, historische Beschlüsse."},{"l":6,"t":"〜ため(に) — Grund / Ursache","de":"wegen / aufgrund von (Ursache, nicht Absicht)","slots":[{"text":"[Grund / Ursache]","role":"cond","label":"was eingetreten ist"},{"text":"ために、","role":"actor","label":"wegen"},{"text":"[Folge]","role":"verb","label":"was daraus folgt"}],"gloss":"»wegen [Grund] [Folge].« — nennt eine Ursache außerhalb der eigenen Kontrolle, oft neutral/negativ. Muster: Veinfache Form/N + の/な-Adj + な + ために. (Zweck: V-Grundform + ために.)","ex":{"jp":"<ruby>台風<rt>たいふう</rt></ruby>の<b>ために</b>、<ruby>電車<rt>でんしゃ</rt></ruby>が <ruby>止<rt>と</rt></ruby>まりました。","de":"Wegen des Taifuns hielt der Zug an."},"simpel":"<b>ため(に)</b> als <b>Grund</b>: »wegen«. Anschluss mit た-Form / Nomen + の (eingetretene Ursache).<br><span class=\"jp\"><ruby>台風<rt>たいふう</rt></ruby>の<b>ために</b>、<ruby>電車<rt>でんしゃ</rt></ruby>が <ruby>止<rt>と</rt></ruby>まった</span> = „Wegen des Taifuns hielt der Zug“","rule":"<code>ため(に)</code> als <b>Ursache</b>: ein Umstand führt zu einer Folge, meist ohne aktive Steuerung des Sprechers. Klingt formell-schriftlich. Anschluss: <b>た-Form / einfache Form</b> bei Verb (= geschehener Sachverhalt); <b>N + の</b> bei Nomen. <b>Wichtig:</b> Ist das Verb im <code>Grundform</code> (Wörterbuchform) → dann ist es <b>Zweck</b>, nicht Grund (siehe nächste Karte)!"},{"l":6,"t":"〜ため(に) — Übersicht: Grund vs. Zweck","de":"wegen ↔ damit / um zu — eine Form, zwei Bedeutungen","slots":[[{"text":"V-Grund + ために","role":"verb","label":"Zweck (aktiv)"},{"text":"→ »um zu V« / »damit«","role":"plain"}],[{"text":"V-た + ために","role":"verb","label":"Grund (passiv)"},{"text":"→ »wegen«","role":"plain"}]],"gloss":"Eine Form, zwei Bedeutungen: 食べる+ために = um zu essen (Zweck), 食べた+ために = weil ich gegessen habe (Grund). Bei Nomen (家族のために) entscheidet der Kontext.","ex":{"jp":"<ruby>健康<rt>けんこう</rt></ruby>の<b>ために</b>、<ruby>毎日<rt>まいにち</rt></ruby> <ruby>運動<rt>うんどう</rt></ruby>して います。","de":"Um gesund zu bleiben, treibe ich täglich Sport. [Zweck]"},"simpel":"Die Verbform entscheidet: <b>Grundform + ために</b> = Zweck (»um zu«), <b>た-Form + ために</b> = Grund (»wegen«).<br><span class=\"jp\"><ruby>食<rt>た</rt></ruby>べる ために / <ruby>食<rt>た</rt></ruby>べた ために</span> = „um zu essen / weil ich gegessen habe“","rule":"<b>Sammelkarte</b>: <code>ために</code> ist berüchtigt, weil es zwei sehr verschiedene Dinge bedeuten kann — <b>Zweck</b> (Minna L42, »damit / um zu«) oder <b>Grund</b> (L6, »wegen«). Der Unterschied steckt in der <b>Verbform vor ために</b>: Grundform = Zweck, た-Form/einfache Form = Grund. Bei Nomen entscheidet der Kontext."},{"l":6,"t":"V<sub>た</sub> / N の / Adj + まま","de":"so wie es ist / im Zustand bleibend","slots":[{"text":"[Zustand: V-た / V-ない / N の / Adj]","role":"cond","label":"Ausgangszustand"},{"text":"まま (で)","role":"actor","label":"bleibt so"},{"text":"[Handlung]","role":"verb","label":"V₂"}],"gloss":"»Etwas im selben Zustand lassen und dann V₂.« Bildung: Vた/Vない + まま, N+の+まま, い-Adj+まま, な-Adj+な+まま.","ex":{"jp":"<ruby>靴<rt>くつ</rt></ruby>を <ruby>履<rt>は</rt></ruby>いた<b>まま</b>、<ruby>家<rt>いえ</rt></ruby>に <ruby>入<rt>はい</rt></ruby>って しまった。","de":"Ich bin (versehentlich) mit Schuhen ins Haus gegangen."},"simpel":"<b>まま</b> = ein Zustand bleibt unverändert, obwohl man ihn normalerweise ändern würde.<br><span class=\"jp\"><ruby>靴<rt>くつ</rt></ruby>を <ruby>履<rt>は</rt></ruby>いた<b>まま</b> <ruby>入<rt>はい</rt></ruby>った</span> = „mit Schuhen hereingekommen“","rule":"<code>まま</code> beschreibt: ein <b>Zustand bleibt unverändert</b>, während eine zweite Handlung passiert — typisch dann, wenn man normalerweise den Zustand <b>ändern würde</b>. Daraus entsteht oft ein leicht unangemessener oder unbequemer Eindruck (»mit Schuhen ins Haus«). Anschluss: V-た-Form, N + の, oder Adjektiv."},{"l":7,"t":"Vタ ものだ (Nostalgie)","de":"früher pflegte ich … (wehmütige Erinnerung)","slots":[{"text":"<ruby>昔<rt>むかし</rt></ruby> / 子供のころ","role":"time","label":"früher"},{"text":"よく","role":"actor","label":"oft"},{"text":"V-た","role":"verb"},{"text":"ものだ","role":"plain","label":"Nostalgie"}],"gloss":"»Früher habe ich oft V gemacht.« Wehmütige Erinnerung an eine Gewohnheit von früher. Bildung: Vた + ものだ, oft mit よく.","ex":{"jp":"<ruby>子供<rt>こども</rt></ruby>のころ、よく この <ruby>川<rt>かわ</rt></ruby>で <ruby>泳<rt>およ</rt></ruby>いだ<b>ものだ</b>。","de":"Als Kind schwamm ich früher oft in diesem Fluss."},"simpel":"<b>V-た + ものだ</b> = wehmütige Erinnerung: »früher pflegte ich oft …«. Gern mit <b>よく</b>.<br><span class=\"jp\"><ruby>昔<rt>むかし</rt></ruby>は よく <ruby>泳<rt>およ</rt></ruby>いだ<b>ものだ</b></span> = „Früher schwamm ich oft“","rule":"<code>V-た + ものだ</code> drückt Nostalgie aus: eine Gewohnheit oder Erfahrung, die in der Vergangenheit häufig oder regelmäßig vorkam, heute aber nicht mehr. Ton ist wehmütig-warm. Wichtige Ergänzung: oft mit Zeitangaben wie <ruby>子供<rt>こども</rt></ruby>のころ, <ruby>学生<rt>がくせい</rt></ruby>のとき, <ruby>昔<rt>むかし</rt></ruby>."},{"l":7,"t":"N / V + として","de":"als (in der Funktion/Kapazität von)","slots":[{"text":"Subjekt は","role":"subj"},{"text":"N","role":"obj","label":"Rolle"},{"text":"として","role":"actor","label":"als"},{"text":"V / Adj","role":"verb"}],"gloss":"»Als [Rolle/Funktion].« Bildung: N+として. Z.B. 〜として有名だ = bekannt als.","ex":{"jp":"<ruby>教師<rt>きょうし</rt></ruby><b>として</b> 30<ruby>年間<rt>ねんかん</rt></ruby> <ruby>働<rt>はたら</rt></ruby>きました。","de":"Ich arbeitete 30 Jahre lang als Lehrer."},"simpel":"<b>として</b> = »als« in der Rolle/Funktion von N — nicht für Richtung (に) oder Urheber (によって).<br><span class=\"jp\"><ruby>教師<rt>きょうし</rt></ruby><b>として</b> <ruby>働<rt>はたら</rt></ruby>く</span> = „als Lehrer arbeiten“","rule":"<code>として</code> markiert die <b>Rolle, Funktion oder Eigenschaft</b>, in der jemand oder etwas auftritt. Auf Deutsch: »als«, aber nur bei Rollen — nicht beim Passiv (da: によって)."},{"l":7,"t":"〜といっても","de":"auch wenn man X sagt — in Wirklichkeit nur Y","slots":[{"text":"X (klingt groß)","role":"obj","label":"was gesagt wird"},{"text":"といっても、","role":"actor","label":"aber eigentlich"},{"text":"Y (Einschränkung)","role":"verb","label":"die Wahrheit"}],"gloss":"»Auch wenn man X sagt, ist es eigentlich nur Y.« Bildung: N/VPlain + といっても.","ex":{"jp":"<ruby>料理<rt>りょうり</rt></ruby>ができる<b>といっても</b>、<ruby>簡単<rt>かんたん</rt></ruby>なものしか <ruby>作<rt>つく</rt></ruby>れません。","de":"Auch wenn ich kochen kann — nur einfache Sachen."},"simpel":"<b>といっても</b> relativiert nach unten: »auch wenn X groß klingt — in Wirklichkeit nur Y«.<br><span class=\"jp\"><ruby>近<rt>ちか</rt></ruby>い<b>といっても</b>、<ruby>歩<rt>ある</rt></ruby>いて 20<ruby>分<rt>ぷん</rt></ruby></span> = „Nah heißt: 20 Minuten zu Fuß“","rule":"Relativiert eine Aussage oder ein Wort: »Auch wenn ich X sage — das solltest du nicht wörtlich/vollständig nehmen, denn eigentlich ist es nur Y.« Typisch für Bescheidenheit oder Einschränkung einer positiven Aussage."},{"l":7,"t":"Vル より Vル ほうが 〜","de":"lieber V₂ als V₁ / V₂ ist [Adj]-er als V₁","slots":[{"text":"V₁ / N₁","role":"obj","label":"Vergleichsbasis"},{"text":"より","role":"plain","label":"als"},{"text":"V₂ / N₂","role":"subj","label":"das Bessere"},{"text":"ほうが Adj (です)","role":"verb"}],"gloss":"»V₂/N₂ ist [Adj]-er als V₁/N₁« oder »lieber V₂ als V₁«. より = das Verglichene, ほうが = das Bevorzugte. Bildung: V₁より V₂ほうが.","ex":{"jp":"<ruby>読<rt>よ</rt></ruby>む<b>より</b> <ruby>書<rt>か</rt></ruby>く<b>ほうが</b> <ruby>難<rt>むずか</rt></ruby>しい。","de":"Schreiben ist schwerer als Lesen."},"simpel":"Handlungen vergleichen: <b>より</b> = die Basis, <b>ほうが</b> = das Bevorzugte/Bessere.<br><span class=\"jp\"><ruby>読<rt>よ</rt></ruby>む<b>より</b> <ruby>書<rt>か</rt></ruby>く<b>ほうが</b> <ruby>難<rt>むずか</rt></ruby>しい</span> = „Schreiben ist schwerer als Lesen“","rule":"Vergleich zweier <b>Handlungen</b> (oder Nomen): <code>より</code> = als (Basis), <code>ほうが</code> = der bevorzugte/bessere. Ergänzt die Vergleichs-Übersicht aus L4 um den Verb-Vergleich. Auch für persönliche Präferenzen: »ich mag lieber V₂ als V₁«."},{"l":7,"t":"〜なら (Reaktions-Konditional)","de":"wenn es um X geht / falls X (Thema aufgreifen)","slots":[{"text":"[bekanntes Thema X]","role":"cond","label":"aufgegriffen"},{"text":"なら、","role":"actor","label":"wenn das so ist"},{"text":"[Reaktion/Empfehlung]","role":"verb"}],"gloss":"»Wenn das so ist (wie du sagst), dann …« Greift etwas Gesagtes auf und reagiert darauf. Bildung: N/VPlain + なら.","ex":{"jp":"<ruby>京都<rt>きょうと</rt></ruby>へ <ruby>行<rt>い</rt></ruby>く<b>なら</b>、<ruby>金閣寺<rt>きんかくじ</rt></ruby>は <ruby>外<rt>はず</rt></ruby>せない。","de":"Wenn du nach Kyoto fährst, ist der Goldene Pavillon ein Muss."},"simpel":"<b>なら</b> greift ein bekanntes Thema auf und reagiert darauf mit Rat oder Empfehlung.<br><span class=\"jp\"><ruby>京都<rt>きょうと</rt></ruby>へ <ruby>行<rt>い</rt></ruby>く<b>なら</b>、<ruby>金閣寺<rt>きんかくじ</rt></ruby>だ</span> = „Wenn schon Kyoto, dann der Goldene Pavillon“","rule":"<code>なら</code> ist ein <b>Reaktions-Konditional</b>: es greift etwas auf, das vorher erwähnt wurde oder implizit bekannt ist, und reagiert mit Empfehlung, Kommentar oder Warnung. Unterschied zu ば/たら/と: なら setzt das Thema <b>X als bereits gegeben voraus</b> (»wenn X so ist, wie ich verstehe — dann …«)."},{"l":7,"t":"「なら・と・ば・たら」<ruby>整理<rt>せいり</rt></ruby>","de":"Die 4 Konditionale im Überblick","slots":[[{"text":"と","role":"cond","label":"Automat"},{"text":"→ Naturgesetz / Anleitung","role":"plain"}],[{"text":"たら","role":"cond","label":"Sequenz"},{"text":"→ konkreter nächster Schritt","role":"plain"}],[{"text":"ば","role":"cond","label":"Hypothese"},{"text":"→ allgemein / Rat","role":"plain"}],[{"text":"なら","role":"cond","label":"Reaktion"},{"text":"→ Empfehlung auf Thema","role":"plain"}]],"gloss":"Die 4 wenn-Formen: と = passiert automatisch, たら = danach/wenn, ば = falls (Annahme), なら = wenn es um X geht (Reaktion).","ex":{"jp":"この ボタンを <ruby>押<rt>お</rt></ruby>す<b>と</b>、ドアが <ruby>開<rt>あ</rt></ruby>く。","de":"Wenn man diesen Knopf drückt, öffnet sich die Tür. [と — Automat]"},"simpel":"<b>と</b> = Automatismus, <b>たら</b> = Sequenz, <b>ば</b> = Hypothese/Rat, <b>なら</b> = Reaktion aufs Thema.<br><span class=\"jp\">と・たら・ば・なら</span> = „vier »wenn«, vier Nuancen“","rule":"<b>Sammelkarte</b>: Alle vier Konditionalformen nebeneinander. Jede hat ihr Spezialgebiet — Überlappungen gibt es, aber die Kernbedeutungen sind klar verschieden. Vertiefung zu Minna L23 (と), L25 (たら), L35 (なら), L43 (ば)."},{"l":7,"t":"Vテ <ruby>欲<rt>ほ</rt></ruby>しい / Vナイで <ruby>欲<rt>ほ</rt></ruby>しい","de":"Ich möchte, dass du [V] / nicht [V]","slots":[{"text":"(Person) に","role":"actor","label":"von wem"},{"text":"V-て / V-ないで","role":"verb","label":"was sie tun/nicht tun"},{"text":"<ruby>欲<rt>ほ</rt></ruby>しい","role":"plain","label":"ich wünsche mir"}],"gloss":"»Ich möchte, dass du V machst (oder nicht machst).« Du wünschst, jemand anderes handelt. Bildung: (Person に) Vテ+欲しい / Vないで+欲しい.","ex":{"jp":"もっと <ruby>早<rt>はや</rt></ruby>く <ruby>来<rt>き</rt></ruby>て <ruby>欲<rt>ほ</rt></ruby>しかった。","de":"Ich hätte mir gewünscht, dass du früher kommst."},"simpel":"Wunsch an eine andere Person: <b>V-て + ほしい</b> (du sollst …) / <b>V-ないで + ほしい</b> (du sollst nicht …).<br><span class=\"jp\"><ruby>嘘<rt>うそ</rt></ruby>を つかないで <ruby>欲<rt>ほ</rt></ruby>しい</span> = „Ich möchte, dass du nicht lügst“","rule":"Wunsch an eine <b>andere Person</b>: »ich möchte, dass du etwas tust / nicht tust«. Ich = Subjekt (mit は), die andere Person = Empfänger des Wunsches (mit に), die Handlung = V-て + ほしい. <b>Nicht verwechseln</b> mit てみたい (ich selbst möchte ausprobieren) und mit 欲しい (ich möchte ein Ding haben)."},{"l":8,"t":"〜あいだ / 〜あいだに","de":"während [ganze Zeit] / während [irgendwann darin]","slots":[[{"text":"V₁-ている","role":"cond","label":"Zeitspanne"},{"text":"あいだ、","role":"actor","label":"ganze Zeit"},{"text":"V₂ (dauerhaft)","role":"verb"}],[{"text":"V₁-ている","role":"cond","label":"Zeitspanne"},{"text":"あいだに、","role":"actor","label":"einmal darin"},{"text":"V₂ (punktuell)","role":"verb"}]],"gloss":"あいだ = V₂ läuft die ganze Zeit durch; あいだに = V₂ passiert einmal irgendwann darin. Bildung: Vテいる+あいだ(に) bzw. N+の+あいだ(に).","ex":{"jp":"<ruby>父<rt>ちち</rt></ruby>が <ruby>昼寝<rt>ひるね</rt></ruby>して いる<b>あいだ</b>、<ruby>静<rt>しず</rt></ruby>かに して いました。","de":"Während Vater Mittagsschlaf hielt, war ich die ganze Zeit leise."},"simpel":"<b>あいだ</b> = die ganze Zeitspanne lang, <b>あいだに</b> = irgendwann einmal innerhalb der Zeitspanne.<br><span class=\"jp\"><ruby>寝<rt>ね</rt></ruby>て いる<b>あいだに</b> <ruby>電話<rt>でんわ</rt></ruby>が <ruby>来<rt>き</rt></ruby>た</span> = „Während ich schlief, kam ein Anruf“","rule":"Beide Formen beschreiben eine <b>Zeitspanne</b> (V₁), in der etwas anderes passiert. <code>あいだ</code>: V₂ läuft <b>die ganze Zeit</b> parallel (dauerhaft). <code>あいだに</code>: V₂ passiert <b>einmal irgendwann</b> innerhalb der Zeitspanne (punktuell)."},{"l":8,"t":"〜わけではない","de":"es ist nicht so, dass … / nicht unbedingt","slots":[{"text":"(Vermutung des Anderen)","role":"cond","label":"Missverständnis"},{"text":"V / Adj","role":"verb"},{"text":"わけではない","role":"actor","label":"nicht so (generell)"}],"gloss":"»Es heißt nicht, dass immer/grundsätzlich X gilt.« Sanfte Einschränkung. Bildung: VPlain/い-Adj+わけではない, な-Adj/N+な+わけではない.","ex":{"jp":"<ruby>嫌<rt>きら</rt></ruby>いな<b>わけではない</b>けど、あまり <ruby>食<rt>た</rt></ruby>べたくない。","de":"Es ist nicht so, dass ich es nicht mag — ich will es nur gerade nicht."},"simpel":"<b>わけではない</b> = sanfte Einschränkung: »es ist nicht so, dass … (immer/generell)«.<br><span class=\"jp\"><ruby>嫌<rt>きら</rt></ruby>いな<b>わけではない</b></span> = „Es ist nicht so, dass ich es nicht mag“","rule":"Relativiert oder verneint eine <b>Verallgemeinerung</b>. »Es stimmt nicht generell, dass X.« Oft zur sanften Korrektur eines Missverständnisses. Milder als einfaches ではない — man schränkt ein, ohne zu widersprechen."},{"l":8,"t":"Vル / Vナイ ことがある","de":"es kommt manchmal vor, dass …","slots":[{"text":"Subjekt は/が","role":"subj"},{"text":"(たまに)","role":"time","label":"manchmal"},{"text":"V-Grundform / V-ない","role":"verb"},{"text":"ことがある","role":"actor","label":"kommt vor"}],"gloss":"»Manchmal kommt es vor, dass V (oder nicht V).« Bildung: V-Grundform/Vない + ことがある. Oft mit たまに/時々. (Nicht verwechseln mit Vた+ことがある = Erfahrung.)","ex":{"jp":"<ruby>電車<rt>でんしゃ</rt></ruby>が <ruby>遅<rt>おく</rt></ruby>れる<b>ことがあります</b>。","de":"Es kommt vor, dass der Zug Verspätung hat."},"simpel":"<b>V-Grundform/ない + ことがある</b> = »es kommt manchmal vor, dass …« (≠ た-Form = Erfahrung).<br><span class=\"jp\"><ruby>電車<rt>でんしゃ</rt></ruby>が <ruby>遅<rt>おく</rt></ruby>れる<b>ことがある</b></span> = „Manchmal hat der Zug Verspätung“","rule":"<code>V<sub>Grund/ない</sub> + ことがある</code> = gelegentlich, nicht regelmäßig. Unterschied zu <code>V<sub>た</sub> + ことがある</code> (Minna L19 — Erfahrung in der Vergangenheit): <b>た-Form = Erfahrung (mindestens einmal passiert). Grundform/ない = wiederkehrend gelegentlich.</b>"},{"l":8,"t":"Vル まで、V₂","de":"bis V₁ passiert, V₂ (durchgehend)","slots":[{"text":"V₁-Grundform","role":"cond","label":"Zielpunkt"},{"text":"まで、","role":"actor","label":"bis"},{"text":"V₂ (dauerhaft)","role":"verb","label":"läuft durch"}],"gloss":"»V₂ läuft durch, bis V₁ eintritt.« Bildung: V-Grundform/N + まで + V₂. Achtung: までに = Frist (bis spätestens).","ex":{"jp":"<ruby>雨<rt>あめ</rt></ruby>が <ruby>止<rt>や</rt></ruby>む<b>まで</b>、ここで <ruby>待<rt>ま</rt></ruby>ちましょう。","de":"Warten wir hier, bis der Regen aufhört."},"simpel":"<b>まで</b> = durchgehend bis (warten), <b>までに</b> = Deadline (bis spätestens erledigen).<br><span class=\"jp\"><ruby>雨<rt>あめ</rt></ruby>が <ruby>止<rt>や</rt></ruby>む<b>まで</b> <ruby>待<rt>ま</rt></ruby>つ</span> = „warten, bis der Regen aufhört“","rule":"<code>まで</code> = bis zu einem Zielpunkt. <code>V₁ まで、V₂</code>: V₂ läuft <b>durchgehend</b>, bis V₁ eintritt. Wichtige Abgrenzung: <code>まで</code> = durchgehend bis; <code>まで に</code> = Deadline (erledigen bis spätestens)."},{"l":8,"t":"N によって (je nach)","de":"je nach N / abhängig von N (2. Bedeutung)","slots":[{"text":"N","role":"obj","label":"Variable"},{"text":"によって","role":"actor","label":"je nach"},{"text":"Ergebnis","role":"verb"},{"text":"が <ruby>違<rt>ちが</rt></ruby>う","role":"plain","label":"ist verschieden"}],"gloss":"»Je nach N ist das Ergebnis verschieden.« Bildung: N+によって + 違う/異なる.","ex":{"jp":"<ruby>国<rt>くに</rt></ruby><b>によって</b>、<ruby>文化<rt>ぶんか</rt></ruby>が <ruby>違<rt>ちが</rt></ruby>います。","de":"Je nach Land ist die Kultur verschieden."},"simpel":"<b>によって</b> Bedeutung 2: »je nach N verschieden« — oft mit <ruby>違<rt>ちが</rt></ruby>う / <ruby>異<rt>こと</rt></ruby>なる.<br><span class=\"jp\"><ruby>国<rt>くに</rt></ruby><b>によって</b> <ruby>文化<rt>ぶんか</rt></ruby>が <ruby>違<rt>ちが</rt></ruby>う</span> = „Je nach Land ist die Kultur anders“","rule":"<code>によって</code> Bedeutung 2: <b>Variation, die von N abhängt</b> — »je nach N ist es anders«. Oft mit <code><ruby>違<rt>ちが</rt></ruby>う / <ruby>異<rt>こと</rt></ruby>なる / <ruby>変<rt>か</rt></ruby>わる</code> am Satzende kombiniert. Nicht mit Urheber-Passiv (L6) oder Mittel (L10) verwechseln."},{"l":8,"t":"「として・について・によって」<ruby>整理<rt>せいり</rt></ruby>","de":"als / über / je nach (Übersicht Postpositionen)","slots":[[{"text":"N として","role":"actor","label":"als Rolle"},{"text":"→ <ruby>専門家<rt>せんもんか</rt></ruby>として<ruby>話<rt>はな</rt></ruby>す","role":"plain"}],[{"text":"N について","role":"actor","label":"Thema"},{"text":"→ <ruby>環境<rt>かんきょう</rt></ruby>について<ruby>話<rt>はな</rt></ruby>す","role":"plain"}],[{"text":"N によって","role":"actor","label":"variiert"},{"text":"→ <ruby>国<rt>くに</rt></ruby>によって<ruby>違<rt>ちが</rt></ruby>う","role":"plain"}]],"gloss":"Drei Postpositionen: として = als/in der Rolle, について = über/zum Thema, によって = durch/je nach/von wem. Alle mit N + Partikel.","ex":{"jp":"<ruby>専門家<rt>せんもんか</rt></ruby><b>として</b> <ruby>意見<rt>いけん</rt></ruby>を <ruby>述<rt>の</rt></ruby>べます。","de":"Als Experte äußere ich meine Meinung."},"simpel":"Drei Postpositionen: <b>として</b> = als (Rolle), <b>について</b> = über (Thema), <b>によって</b> = je nach / durch.<br><span class=\"jp\"><ruby>環境<rt>かんきょう</rt></ruby><b>について</b> <ruby>話<rt>はな</rt></ruby>す</span> = „über die Umwelt sprechen“","rule":"<b>Sammelkarte</b>: Drei wichtige Postpositionen nach Nomen — als Übersicht zum Klarhalten und Vergleichen. Alle drei kommen in Chuukyuu häufig vor."},{"l":9,"t":"〜にともなって / にともなう N","de":"im Zuge von / parallel dazu (Entwicklung)","slots":[{"text":"N の / V-Grundform","role":"cond","label":"Entwicklung A"},{"text":"にともなって、","role":"actor","label":"im Zuge von"},{"text":"Entwicklung B","role":"verb"}],"gloss":"»Im Zuge von A verändert sich auch B.« — zwei Dinge entwickeln sich parallel. Anschluss: N + にともなって; attributiv: にともなう + N.","ex":{"jp":"<ruby>経済<rt>けいざい</rt></ruby>の<ruby>発展<rt>はってん</rt></ruby><b>にともなって</b>、<ruby>生活水準<rt>せいかつすいじゅん</rt></ruby>が <ruby>上<rt>あ</rt></ruby>がった。","de":"Im Zuge der Wirtschaftsentwicklung stieg der Lebensstandard."},"simpel":"<b>にともなって</b> = zwei Entwicklungen verlaufen parallel: »im Zuge von A verändert sich B«.<br><span class=\"jp\"><ruby>人口<rt>じんこう</rt></ruby>が <ruby>増<rt>ふ</rt></ruby>える<b>にともなって</b> …</span> = „Mit wachsender Bevölkerung …“","rule":"Drückt aus, dass <b>zwei Veränderungen parallel verlaufen</b>: wenn A zunimmt/wächst, nimmt/wächst B ebenfalls. Formell-schriftlich, typisch für gesellschaftliche oder wirtschaftliche Trends. Anschluss: N + にともなって oder V-Grundform + にともなって."},{"l":9,"t":"<ruby>接続詞<rt>せつぞくし</rt></ruby>: つまり / <ruby>一方<rt>いっぽう</rt></ruby>","de":"das heißt / andererseits (Satz-Konjunktionen)","slots":[[{"text":"Aussage A。","role":"cond"},{"text":"つまり、","role":"actor","label":"d.h."},{"text":"Zusammenfassung B","role":"verb"}],[{"text":"Aspekt A。","role":"cond"},{"text":"一方、","role":"actor","label":"andererseits"},{"text":"Aspekt B","role":"verb"}]],"gloss":"Satz-Verbinder: つまり = das heißt (fasst zusammen), 一方 = andererseits (stellt zwei Seiten nebeneinander). Stehen am Satzanfang.","ex":{"jp":"<ruby>会議<rt>かいぎ</rt></ruby>に <ruby>出席<rt>しゅっせき</rt></ruby>できなかった。<b>つまり</b>、<ruby>重要<rt>じゅうよう</rt></ruby>な <ruby>議論<rt>ぎろん</rt></ruby>を <ruby>聞<rt>き</rt></ruby>けなかった。","de":"Ich konnte nicht an der Sitzung teilnehmen. Das heißt, die wichtige Diskussion habe ich verpasst."},"simpel":"<b>つまり</b> = »das heißt« (fasst zusammen), <b>一方</b> = »andererseits« (stellt zwei Aspekte gegenüber).<br><span class=\"jp\">A。<b>一方</b>、B。</span> = „A. Andererseits B.“","rule":"Zwei wichtige <b>schriftsprachliche Konjunktionen</b>. <code>つまり</code> = fasst zusammen/reformuliert (»das heißt, das läuft auf X hinaus«). <code>一方</code> = stellt zwei Aspekte nebeneinander (»auf der anderen Seite«)."},{"l":9,"t":"Na / N + である","de":"ist … (schriftsprachliches だ/です)","slots":[{"text":"N / な-Adj","role":"subj"},{"text":"である / ではない","role":"verb","label":"ist / ist nicht (formell)"}],"gloss":"»N/Adj ist X.« Wie だ/です, nur schriftsprachlich. Bildung: N/な-Adj + である. Verneinung: ではない.","ex":{"jp":"これは <ruby>重要<rt>じゅうよう</rt></ruby>な <ruby>問題<rt>もんだい</rt></ruby><b>である</b>。","de":"Dies ist ein wichtiges Problem."},"simpel":"<b>である</b> ist das schriftsprachliche <b>だ/です</b> — Standard in Berichten und Aufsätzen.<br><span class=\"jp\">これは <ruby>重要<rt>じゅうよう</rt></ruby>な <ruby>問題<rt>もんだい</rt></ruby><b>である</b></span> = „Dies ist ein wichtiges Problem“","rule":"<code>である</code> ist das schriftsprachlich-formelle Äquivalent von <code>だ</code>. Standard in Berichten, Essays, Nachrichten. Im Gespräch steif. Negation: <code>ではない</code>. Vergangenheit: <code>であった</code>."},{"l":9,"t":"lassen-Passiv — Kausativ-Passiv","de":"gezwungen werden zu V (unfreiwillig)","slots":[{"text":"<ruby>被害者<rt>ひがいしゃ</rt></ruby> は","role":"subj","label":"gezwungene Person"},{"text":"<ruby>加害者<rt>かがいしゃ</rt></ruby> に","role":"actor","label":"zwingende Person"},{"text":"(Objekt を)","role":"obj"},{"text":"V-させられる","role":"verb","label":"wird gezwungen"}],"gloss":"»Jemand wird (vom Veranlasser) gezwungen, V zu tun« – unfreiwillig. Bildung: Gr.II 未然形+させられる, Gr.I a-Reihe+される. する→させられる, 来る→来させられる. Veranlasser mit に.","ex":{"jp":"<ruby>子供<rt>こども</rt></ruby>のとき、<ruby>嫌<rt>きら</rt></ruby>いな <ruby>野菜<rt>やさい</rt></ruby>を <ruby>食<rt>た</rt></ruby>べ<b>させられた</b>。","de":"Als Kind wurde ich gezwungen, Gemüse zu essen, das ich nicht mochte."},"simpel":"Kausativ + Passiv: »ich werde <b>gezwungen</b>, etwas zu tun« — immer unfreiwillig, immer negativ.<br><span class=\"jp\"><ruby>残業<rt>ざんぎょう</rt></ruby><b>させられた</b></span> = „Ich wurde zu Überstunden gezwungen“","rule":"Kausativ + Passiv kombiniert: »ich werde von jmd. gezwungen, etwas zu tun — gegen meinen Willen.« Der Ton ist <b>immer negativ</b>."},{"l":9,"t":"Passiv・lassen-Form・lassen-Passiv Übersicht","de":"Passiv / Kausativ / Kausativ-Passiv","slots":[[{"text":"A は B に","role":"subj"},{"text":"V-られる","role":"verb","label":"Passiv: von B betroffen"}],[{"text":"A は B を","role":"subj"},{"text":"V-させる","role":"verb","label":"lassen-Form: B veranlassen"}],[{"text":"A は B に","role":"subj"},{"text":"V-させられる","role":"verb","label":"lassen-Passiv: von B gezwungen"}]],"gloss":"Passiv = Betroffener (う→aれる / る→られる), lassen-Form = Veranlasser (う→aせる / る→させる), lassen-Passiv = zum Tun gezwungen (させられる / Gr.I aされる).","ex":{"jp":"<ruby>先生<rt>せんせい</rt></ruby>に <ruby>褒<rt>ほ</rt></ruby>め<b>られた</b>。","de":"Ich wurde vom Lehrer gelobt. [Passiv]"},"simpel":"Drei Perspektiven: <b>Passiv</b> = betroffen werden, <b>lassen-Form</b> = veranlassen, <b>lassen-Passiv</b> = gezwungen werden.<br><span class=\"jp\"><ruby>読<rt>よ</rt></ruby>まれる / <ruby>読<rt>よ</rt></ruby>ませる / <ruby>読<rt>よ</rt></ruby>まされる</span> = „gelesen werden / lesen lassen / lesen müssen“","rule":"<b>Sammelkarte</b>: Die drei komplexen Verbformen — Bildung, Bedeutung, Perspektive auf einen Blick."},{"l":9,"t":"Vテ <ruby>欲<rt>ほ</rt></ruby>しいものだ","de":"Ich wünsche mir wirklich, dass … (eindringlich)","slots":[{"text":"(Adressat に)","role":"actor","label":"optional"},{"text":"V-て / V-ないで","role":"verb"},{"text":"ほしいものだ","role":"plain","label":"wünsche mir sehr"}],"gloss":"»Ich wünsche mir von Herzen, dass V.« Eindringlicher und emotionaler als てほしい. Bildung: Vテ+ほしいものだ / Vないで+ほしいものだ.","ex":{"jp":"<ruby>政治家<rt>せいじか</rt></ruby>には もっと <ruby>本気<rt>ほんき</rt></ruby>で <ruby>取<rt>と</rt></ruby>り<ruby>組<rt>く</rt></ruby>んで<b>ほしいものだ</b>。","de":"Ich wünschte mir wirklich, dass Politiker ernster an die Sache herangehen."},"simpel":"<b>てほしい + ものだ</b> = eindringlicher, fast seufzender Wunsch an »die Welt«.<br><span class=\"jp\">もっと <ruby>読書<rt>どくしょ</rt></ruby>して<b>ほしいものだ</b></span> = „Ich wünschte wirklich, sie würden mehr lesen“","rule":"てほしい (L7) + ものだ (L5) kombiniert = <b>eindringlicher, emotionaler Wunsch</b>. Stärker als einfaches てほしい. Oft mit Seufzer- oder Resignationston. Für allgemeine Wünsche an »die Welt«."},{"l":10,"t":"N によって (Mittel / Methode)","de":"durch / mittels N (3. Bedeutung von によって)","slots":[{"text":"N","role":"obj","label":"Mittel"},{"text":"によって","role":"actor","label":"durch / mittels"},{"text":"Ergebnis / V","role":"verb"}],"gloss":"»Durch/mittels N (wird das Ergebnis erreicht).« Formell. Bildung: N+によって + V (oft Passiv). Im Alltag sagt man で.","ex":{"jp":"インターネット<b>によって</b>、<ruby>世界中<rt>せかいじゅう</rt></ruby>の <ruby>情報<rt>じょうほう</rt></ruby>が <ruby>手<rt>て</rt></ruby>に <ruby>入<rt>はい</rt></ruby>る。","de":"Durch das Internet gelangt man an Informationen aus aller Welt."},"simpel":"<b>によって</b> Bedeutung 3: »durch / mittels N« (formell). Im Alltag dafür meist <b>で</b>.<br><span class=\"jp\">インターネット<b>によって</b> <ruby>調<rt>しら</rt></ruby>べる</span> = „mittels Internet recherchieren“","rule":"<code>によって</code> Bedeutung 3: <b>Mittel oder Methode</b> — »durch den Einsatz von N wird Y erreicht«. Formell-schriftlich. Im Alltag nimmt man dafür meist で."},{"l":10,"t":"Vル / N の <ruby>代<rt>か</rt></ruby>わりに","de":"anstelle von / statt / als Ausgleich dafür","slots":[{"text":"A / V₁","role":"obj","label":"was ersetzt wird"},{"text":"の<ruby>代<rt>か</rt></ruby>わりに、","role":"actor","label":"anstatt"},{"text":"B / V₂","role":"verb","label":"Ersatz"}],"gloss":"»Statt A macht man B« oder »dafür als Ausgleich B«. Bildung: N+の/V-Grundform + 代わりに. Für Ausgleich: その代わり.","ex":{"jp":"バター<b>の<ruby>代<rt>か</rt></ruby>わりに</b>、オリーブオイルを <ruby>使<rt>つか</rt></ruby>った。","de":"Statt Butter habe ich Olivenöl verwendet."},"simpel":"<b>代わりに</b> = ① Ersatz (B statt A) oder ② Ausgleich (Nachteil, aber dafür Vorteil).<br><span class=\"jp\">バター<b>の<ruby>代<rt>か</rt></ruby>わりに</b> オイルを <ruby>使<rt>つか</rt></ruby>う</span> = „statt Butter Öl verwenden“","rule":"Zwei Verwendungen mit gemeinsamem Kern »an Stelle von«: ① <b>Ersatz</b> — N の 代わりに / V<sub>Grund</sub> 代わりに = »anstatt N / statt etwas zu tun« (バターの 代わりに オイル). ② <b>Ausgleich</b> — meist als その代わり am Satzanfang: ein Nachteil wird durch einen Vorteil aufgewogen (»eng, aber dafür billig«). Anschluss merken: Nomen braucht <b>の</b> (N<b>の</b> 代わりに), das Verb steht in der Wörterbuchform direkt davor."},{"l":10,"t":"Vテくる / Vテいく (Sprecher-Perspektive)","de":"Richtung relativ zum Sprecher (Vertiefung)","slots":[[{"text":"V-て くる","role":"verb","label":"→ zum Sprecher / bis jetzt"}],[{"text":"V-て いく","role":"verb","label":"← vom Sprecher / ab jetzt"}]],"gloss":"Sprecher ist der Mittelpunkt: てくる = kommt näher / von früher bis jetzt, ていく = entfernt sich / von jetzt in die Zukunft. Bildung: Vテ+くる/いく (in Hiragana).","ex":{"jp":"<ruby>向<rt>む</rt></ruby>こうから <ruby>子供<rt>こども</rt></ruby>が <ruby>走<rt>はし</rt></ruby>って<b>きた</b>。","de":"Von drüben rannte ein Kind auf mich zu."},"simpel":"Sprecher als Mittelpunkt: <b>てくる</b> = auf mich zu / bis jetzt, <b>ていく</b> = von mir weg / ab jetzt.<br><span class=\"jp\"><ruby>走<rt>はし</rt></ruby>って <b>きた</b> / <ruby>去<rt>さ</rt></ruby>って <b>いった</b></span> = „kam herangerannt / ging fort“","rule":"Vertiefung von Minna L43 + L4: <code>てくる</code> und <code>ていく</code> aus der <b>Sprecher-Perspektive</b>. くる = auf Sprecher zu (physisch oder zeitlich: bis jetzt). いく = vom Sprecher weg (physisch oder zeitlich: in Zukunft)."},{"l":10,"t":"Vル べきだ / べきでない","de":"sollte V / sollte nicht V (moralisch-normativ)","slots":[{"text":"Subjekt は","role":"subj"},{"text":"V-Grundform","role":"verb"},{"text":"べきだ / べきではない","role":"actor","label":"moralisches Sollen"}],"gloss":"»Man sollte V tun – so gehört es sich.« Moralisch. Bildung: V-Grundform+べきだ, Verneinung べきではない. Bei する: するべき oder すべき.","ex":{"jp":"<ruby>約束<rt>やくそく</rt></ruby>は <ruby>守<rt>まも</rt></ruby>る<b>べきだ</b>。","de":"Man sollte Versprechen halten."},"simpel":"<b>べきだ</b> = moralisches Sollen (stärker als ほうがいい, schwächer als なければならない).<br><span class=\"jp\"><ruby>約束<rt>やくそく</rt></ruby>は <ruby>守<rt>まも</rt></ruby>る<b>べきだ</b></span> = „Man sollte Versprechen halten“","rule":"<code>べきだ</code> = moralisches oder logisches Sollen. Stärker als <code>ほうがいい</code> (Rat), schwächer als <code>なければならない</code> (Pflicht). Standard für gesellschaftliche Normen und logische Schlussfolgerungen."},{"l":10,"t":"Vナイずに","de":"ohne zu V — schriftsprachliches ないで","slots":[{"text":"V-ない-Stamm","role":"verb","label":"ohne V₁"},{"text":"ずに、","role":"actor","label":"ohne"},{"text":"V₂","role":"verb","label":"macht V₂"}],"gloss":"»V₂ tun, ohne V₁ getan zu haben.« Schriftsprachliches ないで. Bildung: Vない-Stamm + ずに. Achtung: する → せずに.","ex":{"jp":"<ruby>何<rt>なに</rt></ruby>も <ruby>言<rt>い</rt></ruby>わ<b>ずに</b>、<ruby>部屋<rt>へや</rt></ruby>を <ruby>出<rt>で</rt></ruby>て <ruby>行<rt>い</rt></ruby>った。","de":"Er verließ das Zimmer, ohne etwas zu sagen."},"simpel":"<b>ずに</b> = schriftsprachliches <b>ないで</b> (»ohne zu …«). Achtung: する → <b>せずに</b>!<br><span class=\"jp\"><ruby>何<rt>なに</rt></ruby>も <ruby>言<rt>い</rt></ruby>わ<b>ずに</b> <ruby>出<rt>で</rt></ruby>て <ruby>行<rt>い</rt></ruby>った</span> = „Er ging, ohne etwas zu sagen“","rule":"<code>ずに</code> = schriftsprachliche Variante von <code>ないで</code> (Minna L34). Bildung: ない-Stamm + ずに. Wichtige Ausnahme: <code>する → せずに</code>!"},{"l":10,"t":"<ruby>敬語<rt>けいご</rt></ruby> Übersicht","de":"Keigo — drei Ebenen der Höflichkeit","slots":[[{"text":"Respekt-Keigo: <ruby>先生<rt>せんせい</rt></ruby>が","role":"actor","label":"andere Person"},{"text":"いらっしゃいます","role":"verb","label":"② Respekt-Keigo"}],[{"text":"Bescheiden-Keigo: <ruby>私<rt>わたし</rt></ruby>が","role":"subj","label":"ich"},{"text":"参ります","role":"verb","label":"③ Bescheiden-Keigo"}],[{"text":"丁寧: 〜さんが","role":"subj"},{"text":"行きます","role":"verb","label":"① 丁寧語"}]],"gloss":"Drei Höflichkeitsebenen: 丁寧語 = neutral höflich (です/ます), Respekt-Keigo = das Gegenüber erhöhen, Bescheiden-Keigo = sich selbst kleiner machen. Niemals mischen.","ex":{"jp":"<ruby>先生<rt>せんせい</rt></ruby>は 何と <b>おっしゃいました</b>か。","de":"Was hat der Lehrer gesagt? [② Respekt-Keigo]"},"simpel":"Drei Höflichkeitsebenen: <b>丁寧語</b> (neutral), <b>Respekt-Keigo</b> (andere erhöhen), <b>Bescheiden-Keigo</b> (sich selbst senken).<br><span class=\"jp\"><ruby>先生<rt>せんせい</rt></ruby>が いらっしゃる / <ruby>私<rt>わたし</rt></ruby>が <ruby>参<rt>まい</rt></ruby>る</span> = „Der Lehrer kommt / ich komme“","rule":"<b>Abschlusskarte</b>: Wiederholung Minna L50 mit Chuukyuu-Erweiterung. Drei Ebenen: ① 丁寧語 (neutrale Höflichkeit), ② Respekt-Keigo (andere erhöhen), ③ Bescheiden-Keigo (sich selbst erniedrigen)."},{"l":11,"t":"〜はず(だ) / 〜はずがない","de":"müsste (eigentlich) so sein / kann unmöglich sein","slots":[{"text":"N は","role":"subj"},{"text":"V<sub>einf</sub>","role":"verb"},{"text":"はずだ","role":"plain","label":"müsste"}],"gloss":"»Logisch müsste es so sein.« はずだ = begründete Erwartung, はずがない = ausgeschlossen. Anschluss wie ans Nomen (N + の, な-Adj + な).","ex":{"jp":"<ruby>彼<rt>かれ</rt></ruby>は もう <ruby>着<rt>つ</rt></ruby>いた<b>はず</b>です。","de":"Er müsste schon angekommen sein."},"simpel":"<b>はず</b> = logische Erwartung: »es müsste so sein«. Verneint <b>はずがない</b> = »das kann nicht sein«.<br><span class=\"jp\">4<ruby>時<rt>じ</rt></ruby>に <ruby>着<rt>つ</rt></ruby>く<b>はず</b>です</span> = „müsste um 4 ankommen“","rule":"はず drückt eine aus Fakten/Logik abgeleitete Erwartung aus — nicht ein bloßes Gefühl, sondern »nach allem, was ich weiß, müsste es so sein«. はずだ = begründete Erwartung; はずがない = »ausgeschlossen, unmöglich«. Anschluss wie ans Nomen."},{"l":11,"t":"〜に <ruby>違<rt>ちが</rt></ruby>いない","de":"es muss ganz sicher … sein (starke Überzeugung)","slots":[{"text":"N は","role":"subj"},{"text":"[Vermutung]","role":"cond"},{"text":"に違いない","role":"plain","label":"muss sicher sein"}],"gloss":"»Aus den Indizien: es muss so sein.« Starke Überzeugung. Anschluss Plain; な-Adj/Nomen OHNE だ. Lockerer: に決まっている.","ex":{"jp":"<ruby>電気<rt>でんき</rt></ruby>が ついている。<ruby>家<rt>いえ</rt></ruby>に いる<b>に違いない</b>。","de":"Das Licht brennt. Sie muss zu Hause sein."},"simpel":"Feste Überzeugung aus Indizien: »es muss … sein«.<br><span class=\"jp\"><ruby>犯人<rt>はんにん</rt></ruby>は <ruby>彼<rt>かれ</rt></ruby>に<b>違いない</b></span> = „Der Täter muss er sein“","rule":"に違いない zeigt eine starke Schlussfolgerung des Sprechers: »ich bin (fast) sicher, dass …«. Stärker als 〜だろう, subjektiver als 〜はず. Anschluss an einfache Form; bei な-Adj/Nomen ohne だ."},{"l":11,"t":"〜わけがない / 〜わけにはいかない","de":"kann unmöglich … / darf/kann (aus Prinzip) nicht …","slots":[{"text":"V<sub>Grund</sub>","role":"verb"},{"text":"わけにはいかない","role":"plain","label":"geht nicht"}],"gloss":"わけがない = logisch ausgeschlossen. わけにはいかない = möglich, aber aus Vernunft/Moral unmöglich. Vない + わけにはいかない = »ich MUSS (kann es nicht lassen)«.","ex":{"jp":"あんな <ruby>簡単<rt>かんたん</rt></ruby>な <ruby>問題<rt>もんだい</rt></ruby>を <ruby>間違<rt>まちが</rt></ruby>える<b>わけがない</b>。","de":"So eine leichte Aufgabe kann ich unmöglich falsch machen."},"simpel":"<b>わけがない</b> = »völlig ausgeschlossen«. <b>わけにはいかない</b> = »geht (aus Vernunft/Moral) nicht«.<br><span class=\"jp\"><ruby>今<rt>いま</rt></ruby> <ruby>休<rt>やす</rt></ruby>む<b>わけにはいかない</b></span> = „ich kann jetzt unmöglich Pause machen“","rule":"Zwei verschiedene わけ-Muster: 〜わけがない = logisch unmöglich (»das kann gar nicht sein«). 〜わけにはいかない = es ist zwar möglich, aber aus sozialen/moralischen/vernünftigen Gründen geht es nicht."},{"l":11,"t":"〜<ruby>恐<rt>おそ</rt></ruby>れがある","de":"es besteht die Gefahr, dass … (Negatives)","slots":[{"text":"[Negatives]","role":"cond"},{"text":"<ruby>恐<rt>おそ</rt></ruby>れがある","role":"plain","label":"es droht"}],"gloss":"»Es besteht die Gefahr, dass …« — nur für Unerwünschtes, schriftsprachlich. VGrundform / N + の.","ex":{"jp":"<ruby>大雨<rt>おおあめ</rt></ruby>で <ruby>川<rt>かわ</rt></ruby>が あふれる<b>恐れがあります</b>。","de":"Durch den Starkregen droht der Fluss über die Ufer zu treten."},"simpel":"Warnung vor etwas Schlechtem: »es droht/es besteht die Gefahr, dass …«.<br><span class=\"jp\"><ruby>台風<rt>たいふう</rt></ruby>が <ruby>来<rt>く</rt></ruby>る<b>恐れがある</b></span> = „es droht ein Taifun“","rule":"〜恐れがある warnt vor einer möglichen negativen Entwicklung. Schriftsprachlich, typisch für Nachrichten und Warnungen. Nur für Unerwünschtes! Anschluss: VGrundform / N + の."},{"l":11,"t":"〜に <ruby>決<rt>き</rt></ruby>まっている","de":"das ist doch todsicher … / natürlich …","slots":[{"text":"[Aussage]","role":"cond"},{"text":"に<ruby>決<rt>き</rt></ruby>まっている","role":"plain","label":"todsicher"}],"gloss":"»Das ist doch todsicher so.« Subjektive Gewissheit, umgangssprachlich, oft emotional. Plain-Anschluss, な-Adj/N ohne だ.","ex":{"jp":"<ruby>試験<rt>しけん</rt></ruby><ruby>前<rt>まえ</rt></ruby>だから、<ruby>忙<rt>いそが</rt></ruby>しい<b>に決まっている</b>。","de":"Vor der Prüfung ist er doch todsicher beschäftigt."},"simpel":"Sprecher ist völlig überzeugt: »das ist doch klar/todsicher«.<br><span class=\"jp\">こんな <ruby>時間<rt>じかん</rt></ruby>、<ruby>寝<rt>ね</rt></ruby>ている<b>に決まっている</b></span> = „um die Zeit schläft er doch todsicher“","rule":"に決まっている = die (subjektive) Überzeugung des Sprechers, dass etwas selbstverständlich/todsicher so ist. Umgangssprachlich, oft mit leichter Emotion (Ungeduld, »das ist doch offensichtlich«). Anschluss Plain; な-Adj/Nomen ohne だ."},{"l":12,"t":"〜ようになる (allmähliche Veränderung)","de":"dazu kommen, dass … / (nach und nach) anfangen zu (können)","slots":[{"text":"N は","role":"subj"},{"text":"V<sub>Kann</sub>","role":"verb"},{"text":"ように なる","role":"plain","label":"kommt dazu"}],"gloss":"»Es kommt (allmählich) dazu, dass …« — neue Fähigkeit/Gewohnheit über die Zeit. Gegenteil: 〜なくなる.","ex":{"jp":"<ruby>練習<rt>れんしゅう</rt></ruby>して、<ruby>日本語<rt>にほんご</rt></ruby>が <ruby>話<rt>はな</rt></ruby>せる<b>ようになりました</b>。","de":"Durch Üben habe ich Japanisch sprechen gelernt."},"simpel":"Zustandswechsel über Zeit — früher nicht, jetzt schon. Oft mit Potenzialform.<br><span class=\"jp\"><ruby>泳<rt>およ</rt></ruby>げる<b>ようになった</b></span> = „habe schwimmen gelernt“","rule":"V<sub>Grund/Kann</sub> + ようになる zeigt eine Veränderung über die Zeit: ein neuer Zustand oder eine neue Fähigkeit entsteht allmählich. Verneinung/Gegenteil: 〜なくなる (»es hört auf, dass …«)."},{"l":12,"t":"〜ようにする (sich etw. angewöhnen)","de":"sich bemühen zu … / darauf achten, dass …","slots":[{"text":"[Vorsatz]","role":"cond"},{"text":"ように する","role":"plain","label":"achte darauf"}],"gloss":"»Ich achte bewusst darauf, zu …« — Absicht/Gewohnheit. Vない + ようにする = »darauf achten, NICHT zu …«. ようにしている = laufende Gewohnheit.","ex":{"jp":"<ruby>健康<rt>けんこう</rt></ruby>のため、<ruby>毎日<rt>まいにち</rt></ruby> <ruby>運動<rt>うんどう</rt></ruby>する<b>ようにしています</b>。","de":"Der Gesundheit zuliebe achte ich darauf, täglich Sport zu treiben."},"simpel":"Bewusste Bemühung/Gewohnheit: »ich achte darauf, zu …«.<br><span class=\"jp\"><ruby>毎日<rt>まいにち</rt></ruby> <ruby>歩<rt>ある</rt></ruby>く<b>ようにして</b>います</span> = „ich achte darauf, täglich zu gehen“","rule":"V<sub>Grund/ない</sub> + ようにする drückt eine bewusste Anstrengung oder Gewohnheit aus. ようにしている = laufende Gewohnheit; ようにしてください = höfliche Bitte »achten Sie bitte darauf, zu …«."},{"l":12,"t":"〜(よ)うとする","de":"versuchen zu … / gerade im Begriff sein zu …","slots":[{"text":"V<sub>(よ)う</sub>","role":"verb","label":"Willensform"},{"text":"とする","role":"plain","label":"versuchen"}],"gloss":"»Ich setze an / versuche zu …« oder »bin gerade dabei zu …«. Willensform + とする. Verneint 〜(よ)うとしない = keine Anstalten machen.","ex":{"jp":"ドアを <ruby>開<rt>あ</rt></ruby>け<b>ようとした</b>が、<ruby>開<rt>あ</rt></ruby>かなかった。","de":"Ich wollte die Tür öffnen, doch sie ging nicht auf."},"simpel":"Willensform + とする = »ansetzen/versuchen zu …«.<br><span class=\"jp\"><ruby>出<rt>で</rt></ruby>かけ<b>ようとした</b> とき</span> = „als ich gerade gehen wollte“","rule":"Willensform (V<sub>よう/おう</sub>) + とする: (1) »versuchen zu …« (Anlauf nehmen), (2) »gerade im Begriff sein zu …« (kurz davor). Verneint 〜(よ)うとしない = »macht keine Anstalten zu …«."},{"l":12,"t":"〜ところ (だ) — gerade …","de":"gerade dabei / gerade eben getan / kurz davor","slots":[{"text":"V<sub>Grund/ている/た</sub>","role":"verb"},{"text":"ところだ","role":"plain","label":"Phase"}],"gloss":"Drei Phasen: するところ (davor) → しているところ (dabei) → したところ (danach). Zeitliche Phase, nicht der Ort.","ex":{"jp":"<ruby>今<rt>いま</rt></ruby>から <ruby>出<rt>で</rt></ruby>かける<b>ところです</b>。","de":"Ich bin gerade im Begriff loszugehen."},"simpel":"<b>ところ</b> markiert die zeitliche Phase einer Handlung.<br>V<sub>Grund</sub>ところ = gleich · V<sub>て</sub>いるところ = mittendrin · V<sub>た</sub>ところ = eben fertig","rule":"ところ (»Punkt/Stelle«) zeigt die Phase: Grundform + ところだ = »gerade im Begriff«; ているところだ = »mitten dabei«; たところだ = »eben gerade getan«. Zeitlich, nicht örtlich."},{"l":12,"t":"Vマス + <ruby>切<rt>き</rt></ruby>る / <ruby>切<rt>き</rt></ruby>れない","de":"etw. vollständig tun / es nicht bis zum Ende schaffen","slots":[{"text":"V<sub>ますStamm</sub>","role":"verb"},{"text":"きる / きれない","role":"plain","label":"ganz / nicht ganz"}],"gloss":"きる = komplett, restlos, bis zum Ende (oft mit Anstrengung). きれない = zu viel/zu groß, um es zu schaffen. 数えきれない »unzählbar«.","ex":{"jp":"この <ruby>本<rt>ほん</rt></ruby>を <ruby>一日<rt>いちにち</rt></ruby>で <ruby>読<rt>よ</rt></ruby>み<b>きった</b>。","de":"Ich habe dieses Buch an einem Tag ganz durchgelesen."},"simpel":"<b>〜きる</b> = ganz/restlos zu Ende; <b>〜きれない</b> = »nicht zu schaffen«, zu viel.<br><span class=\"jp\"><ruby>食<rt>た</rt></ruby>べ<b>きれない</b></span> = „kann nicht alles aufessen“","rule":"V<sub>ます</sub>-Stamm + きる = eine Handlung vollständig / bis zum Ende ausführen (使いきる »ganz aufbrauchen«, 走りきる »durchhalten«). Negativ きれない = »es ist zu viel/zu groß, um es fertigzubringen«."},{"l":13,"t":"〜うちに / 〜ないうちに","de":"während (noch) … / bevor …","slots":[{"text":"[Zustand]","role":"cond"},{"text":"うちに","role":"actor","label":"solange / bevor"},{"text":"[Handlung]","role":"verb"}],"gloss":"»Solange (noch) A gilt, tu B« bzw. mit ない »bevor A eintritt, tu B«. Zeitfenster ausnutzen.","ex":{"jp":"<ruby>明<rt>あか</rt></ruby>るい<b>うちに</b> <ruby>帰<rt>かえ</rt></ruby>りましょう。","de":"Lass uns heimgehen, solange es noch hell ist."},"simpel":"Zeitfenster nutzen: »solange (noch) …« bzw. »bevor …«.<br><span class=\"jp\"><ruby>熱<rt>あつ</rt></ruby>い<b>うちに</b> <ruby>食<rt>た</rt></ruby>べて</span> = „iss, solange es noch heiß ist“","rule":"〜うちに = »während ein (meist vorteilhafter) Zustand noch anhält«, oft mit Handlungsaufforderung. 〜ないうちに = »bevor ein (unerwünschter) Zustand eintritt«. Anschluss: V<sub>ている/Grund/ない</sub>, い-Adj, な-Adj + な, N + の."},{"l":13,"t":"〜た とたん(に)","de":"kaum dass … / im selben Moment, als …","slots":[{"text":"V<sub>た</sub>","role":"verb","label":"Moment A"},{"text":"とたん(に)","role":"actor","label":"im selben Moment"},{"text":"[plötzlich B]","role":"cond"}],"gloss":"»Kaum dass A geschah, geschah (überraschend) B.« Nur た-Form davor; B ist unkontrolliert und vergangen.","ex":{"jp":"<ruby>立<rt>た</rt></ruby>ち<ruby>上<rt>あ</rt></ruby>がった<b>とたん</b>、めまいが した。","de":"Kaum war ich aufgestanden, wurde mir schwindelig."},"simpel":"Zwei Ereignisse direkt hintereinander, das zweite meist überraschend.<br><span class=\"jp\">ドアを <ruby>開<rt>あ</rt></ruby>けた<b>とたん</b></span> = „kaum dass ich die Tür öffnete“","rule":"V<sub>た</sub> + とたん(に): »genau in dem Moment, als A geschah, geschah (plötzlich, unerwartet) B«. B ist meist ungeplant und in der Vergangenheit. Nur mit der た-Form davor."},{"l":13,"t":"〜<ruby>最中<rt>さいちゅう</rt></ruby>に","de":"gerade mitten in … / mittendrin, als …","slots":[{"text":"[laufende Handlung]","role":"cond"},{"text":"<ruby>最中<rt>さいちゅう</rt></ruby>に","role":"actor","label":"mittendrin"},{"text":"[Störung]","role":"verb"}],"gloss":"»Genau mitten in der laufenden Handlung passiert (störend) …« V<sub>ている</sub> / N + の davor.","ex":{"jp":"<ruby>会議<rt>かいぎ</rt></ruby>の<b>最中に</b> <ruby>電話<rt>でんわ</rt></ruby>が <ruby>鳴<rt>な</rt></ruby>った。","de":"Mitten in der Sitzung klingelte das Telefon."},"simpel":"Etwas passiert mitten in einer laufenden Handlung — meist störend.<br><span class=\"jp\"><ruby>食事<rt>しょくじ</rt></ruby>の<b>最中に</b></span> = „mitten beim Essen“","rule":"〜最中に betont, dass etwas GENAU in der intensivsten Phase einer laufenden Handlung geschieht — häufig eine Störung. Anschluss: V<sub>ている</sub> / N + の."},{"l":13,"t":"〜<ruby>次第<rt>しだい</rt></ruby> / 〜<ruby>次第<rt>しだい</rt></ruby>で","de":"sobald … / je nach … (hängt ab von)","slots":[{"text":"V<sub>ます</sub>","role":"verb"},{"text":"<ruby>次第<rt>しだい</rt></ruby>","role":"plain","label":"sobald"}],"gloss":"(1) V<sub>ます</sub> + 次第 = »sobald …« (formell, Zukunft). (2) N + 次第だ/で = »hängt von N ab / je nach N«.","ex":{"jp":"<ruby>会議<rt>かいぎ</rt></ruby>が <ruby>終<rt>お</rt></ruby>わり<b>次第</b>、<ruby>電話<rt>でんわ</rt></ruby>します。","de":"Sobald die Sitzung zu Ende ist, rufe ich an."},"simpel":"V<sub>ます</sub>+次第 = »sobald …« (formell). N+次第で = »je nach …«.<br><span class=\"jp\"><ruby>着<rt>つ</rt></ruby>き<b>次第</b> <ruby>連絡<rt>れんらく</rt></ruby>します</span> = „sobald ich ankomme, melde ich mich“","rule":"Zwei Verwendungen: (1) V<sub>ます</sub>-Stamm + 次第 = »sobald / unmittelbar nachdem …«, sehr formell (Geschäft, nur Zukunft). (2) N + 次第だ / 次第で = »es hängt von N ab / je nach N«."},{"l":13,"t":"Vマス + つつある","de":"ist gerade dabei, sich (allmählich) zu … / zusehends","slots":[{"text":"N が","role":"subj"},{"text":"V<sub>ます</sub>","role":"verb"},{"text":"つつある","role":"plain","label":"zusehends"}],"gloss":"»Ein Prozess läuft ab und schreitet voran.« Schriftsprachlich, betont den Verlauf der Veränderung. Nur mit Veränderungsverben.","ex":{"jp":"<ruby>森<rt>もり</rt></ruby>が <ruby>消<rt>き</rt></ruby>え<b>つつある</b>。","de":"Die Wälder verschwinden zusehends."},"simpel":"Ein Vorgang ist im Verlauf: »entwickelt sich allmählich zu …«.<br><span class=\"jp\"><ruby>景気<rt>けいき</rt></ruby>が <ruby>回復<rt>かいふく</rt></ruby>し<b>つつある</b></span> = „die Konjunktur erholt sich zusehends“","rule":"V<sub>ます</sub>-Stamm + つつある: ein Prozess läuft gerade ab und schreitet voran. Schriftsprachlich; betont (anders als 〜ている) den Verlauf bzw. die Tendenz einer Veränderung."},{"l":14,"t":"〜おかげで / 〜せいで","de":"dank … (positiv) / wegen … (negativ)","slots":[{"text":"[Grund]","role":"cond"},{"text":"おかげで / せいで","role":"actor","label":"dank / wegen"},{"text":"[Ergebnis]","role":"verb"}],"gloss":"おかげで = dankbar (gutes Ergebnis), せいで = vorwurfsvoll (schlechtes Ergebnis). Neutralen Grund → から/ので.","ex":{"jp":"<ruby>先生<rt>せんせい</rt></ruby>の<b>おかげで</b> <ruby>合格<rt>ごうかく</rt></ruby>できた。","de":"Dank des Lehrers habe ich bestanden."},"simpel":"<b>おかげで</b> = »dank« (gutes Ergebnis). <b>せいで</b> = »wegen« (schlechtes Ergebnis).<br><span class=\"jp\"><ruby>雨<rt>あめ</rt></ruby>の<b>せいで</b> <ruby>遅<rt>おく</rt></ruby>れた</span> = „wegen des Regens zu spät“","rule":"Beide nennen einen Grund, aber mit Wertung: おかげで dankbar/positiv, せいで vorwurfsvoll/negativ. Anschluss wie ans Nomen (Plain, な-Adj + な, N + の)."},{"l":14,"t":"〜せいか","de":"vielleicht wegen … / womöglich weil …","slots":[{"text":"[vermuteter Grund]","role":"cond"},{"text":"せいか","role":"actor","label":"vielleicht weil"},{"text":"[Ergebnis]","role":"verb"}],"gloss":"»Vielleicht (weiß nicht genau) wegen … ist es so.« Unsicherer, spürbarer Grund. N + の + せいか.","ex":{"jp":"<ruby>緊張<rt>きんちょう</rt></ruby>の<b>せいか</b>、うまく <ruby>話<rt>はな</rt></ruby>せなかった。","de":"Vielleicht wegen der Nervosität konnte ich nicht gut sprechen."},"simpel":"Vermuteter, unsicherer Grund: »vielleicht weil …«.<br><span class=\"jp\"><ruby>年<rt>とし</rt></ruby>の<b>せいか</b> <ruby>疲<rt>つか</rt></ruby>れやすい</span> = „vielleicht wegen des Alters schnell müde“","rule":"せいか = »ich bin nicht sicher, aber vielleicht ist … der Grund«. Wie せいで, aber mit dem か der Unsicherheit — für einen spürbaren, aber nicht bewiesenen Zusammenhang."},{"l":14,"t":"〜ものだから / 〜もので","de":"weil (nun mal) … (Rechtfertigung / Erklärung)","slots":[{"text":"[Grund]","role":"cond"},{"text":"ものだから","role":"actor","label":"weil nun mal"},{"text":"[Folge/Ausrede]","role":"verb"}],"gloss":"»Weil es eben so war, konnte ich nicht anders.« Subjektive Rechtfertigung. Plain-Anschluss (な-Adj + な, N + な). Kein Befehl im Hauptsatz.","ex":{"jp":"<ruby>子<rt>こ</rt></ruby>どもが <ruby>熱<rt>ねつ</rt></ruby>を <ruby>出<rt>だ</rt></ruby>した<b>ものだから</b>、<ruby>休<rt>やす</rt></ruby>みました。","de":"Weil mein Kind Fieber bekam, bin ich zu Hause geblieben."},"simpel":"Persönliche Rechtfertigung: »ist ja/nun mal so, deshalb …«.<br><span class=\"jp\"><ruby>安<rt>やす</rt></ruby>かった<b>ものだから</b>、<ruby>買<rt>か</rt></ruby>いすぎた</span> = „es war ja so billig, drum kaufte ich zu viel“","rule":"〜ものだから (locker もので/もんで) gibt einen Grund als Entschuldigung/Erklärung an — »weil es eben so war, konnte ich nicht anders«. Subjektiv, rechtfertigend. Anschluss Plain (な-Adj + な, N + な)."},{"l":14,"t":"〜ものの","de":"zwar …, aber (doch) …","slots":[{"text":"[A: zwar]","role":"cond"},{"text":"ものの","role":"actor","label":"aber doch"},{"text":"[B: unerwartet]","role":"verb"}],"gloss":"»A trifft zwar zu, doch die erwartete Folge B bleibt aus.« Schriftsprachlich. Nicht mit の (Nominalisierung) verwechseln.","ex":{"jp":"<ruby>免許<rt>めんきょ</rt></ruby>は <ruby>取<rt>と</rt></ruby>った<b>ものの</b>、<ruby>車<rt>くるま</rt></ruby>が ない。","de":"Den Führerschein habe ich zwar, aber kein Auto."},"simpel":"Einräumung: »zwar A, aber (entgegen der Erwartung) B«.<br><span class=\"jp\"><ruby>買<rt>か</rt></ruby>った<b>ものの</b>、<ruby>使<rt>つか</rt></ruby>っていない</span> = „gekauft habe ich es zwar, aber ich nutze es nicht“","rule":"〜ものの verbindet zwei Sätze mit Widerspruch: A trifft zu, doch die erwartete Folge tritt nicht ein. Schriftlicher als 〜けど. Anschluss Plain (な-Adj + な/である, N + である)."},{"l":14,"t":"〜わりに(は)","de":"im Verhältnis zu … / für … (überraschend)","slots":[{"text":"[Maßstab A]","role":"cond"},{"text":"わりに(は)","role":"actor","label":"für / gemessen an"},{"text":"[unerwartetes B]","role":"verb"}],"gloss":"»Gemessen an A ist B unerwartet.« Vergleicht Erwartung mit Realität. Plain / N + の. Verwandt: 〜にしては.","ex":{"jp":"たくさん <ruby>食<rt>た</rt></ruby>べる<b>わりに</b> <ruby>太<rt>ふと</rt></ruby>らない。","de":"Für die Menge, die er isst, nimmt er erstaunlich wenig zu."},"simpel":"Ergebnis passt nicht zur Erwartung aus A: »für A überraschend …«.<br><span class=\"jp\"><ruby>値段<rt>ねだん</rt></ruby>の<b>わりに</b> おいしい</span> = „für den Preis (erstaunlich) lecker“","rule":"〜わりに(は): »gemessen an A ist B unerwartet (viel/wenig/gut/schlecht)«. Vergleicht Erwartung mit Realität. Anschluss Plain (な-Adj + な, N + の)."},{"l":15,"t":"〜くせに","de":"obwohl … (mit Vorwurf / Verachtung)","slots":[{"text":"[A: obwohl]","role":"cond"},{"text":"くせに","role":"actor","label":"obwohl (Vorwurf)"},{"text":"[B: Kritik]","role":"verb"}],"gloss":"»Obwohl A — und das ist frech/unpassend — B.« Immer wertend/negativ. Meist gleiches Subjekt. Neutral wäre のに.","ex":{"jp":"<ruby>知<rt>し</rt></ruby>っている<b>くせに</b>、<ruby>教<rt>おし</rt></ruby>えて くれない。","de":"Obwohl er es weiß, sagt er es mir nicht."},"simpel":"Wie のに, aber mit Kritik/Verachtung: »obwohl … (und das ist frech/unpassend)«.<br><span class=\"jp\"><ruby>知<rt>し</rt></ruby>っている<b>くせに</b></span> = „obwohl er es doch weiß (Frechheit)“","rule":"〜くせに = adversativ »obwohl«, aber immer mit negativer Gefühlswertung (Vorwurf, Verachtung, Spott). Subjekt von Neben- und Hauptsatz meist dieselbe Person. Anschluss Plain (な-Adj + な, N + の)."},{"l":15,"t":"〜こそ","de":"gerade / genau dies / jetzt erst recht","slots":[{"text":"N","role":"subj","label":"Hervorhebung"},{"text":"こそ","role":"actor","label":"genau dies"},{"text":"[Aussage]","role":"verb"}],"gloss":"»Genau dieses, kein anderes / jetzt erst recht.« Starke Hervorhebung. 〜からこそ = »gerade weil«.","ex":{"jp":"<ruby>今<rt>いま</rt></ruby><b>こそ</b> <ruby>始<rt>はじ</rt></ruby>める ときだ。","de":"Jetzt erst recht ist es Zeit anzufangen."},"simpel":"Hebt ein Wort nachdrücklich hervor: »genau das, kein anderes«.<br><span class=\"jp\"><ruby>今<rt>いま</rt></ruby><b>こそ</b></span> = „jetzt erst recht / genau jetzt“","rule":"こそ hängst du an ein Nomen/Wort und betonst es stark: »genau dieses«. Häufig 今こそ (jetzt erst recht), こちらこそ (ganz meinerseits), 〜からこそ (gerade weil)."},{"l":15,"t":"〜さえ / 〜さえ〜ば","de":"sogar … / wenn nur … (dann reicht's)","slots":[{"text":"N さえ","role":"cond","label":"wenn nur N"},{"text":"…ば","role":"actor","label":"dann"},{"text":"[reicht es]","role":"verb"}],"gloss":"さえ = »sogar/selbst«. さえ〜ば = »die einzige nötige Bedingung; wenn die erfüllt ist, genügt es«. Vマス + さえすれば.","ex":{"jp":"<ruby>子<rt>こ</rt></ruby>ども<b>さえ</b> <ruby>知<rt>し</rt></ruby>っている。","de":"Sogar Kinder wissen das."},"simpel":"<b>さえ</b> = »sogar«; <b>さえ〜ば</b> = »wenn nur …, dann«.<br><span class=\"jp\"><ruby>水<rt>みず</rt></ruby><b>さえ</b> あれば</span> = „wenn es nur Wasser gibt“","rule":"さえ = »sogar/selbst« (extremes Beispiel). Kombiniert さえ〜ば = »die einzige Bedingung ist …; ist die erfüllt, reicht es«. Nomen + さえ; Verb ます-Stamm + さえ すれば."},{"l":15,"t":"〜ずには いられない","de":"ich kann nicht anders, als zu … / muss einfach","slots":[{"text":"V<sub>ない-Stamm</sub>","role":"verb"},{"text":"ずには いられない","role":"plain","label":"muss einfach"}],"gloss":"»Ich kann den Drang zu V nicht unterdrücken.« V<sub>ない</sub>-Stamm + ずには. する → せずに. Emotional/unwillkürlich.","ex":{"jp":"あの <ruby>映画<rt>えいが</rt></ruby>を <ruby>見<rt>み</rt></ruby>ると、<ruby>泣<rt>な</rt></ruby>か<b>ずには いられない</b>。","de":"Bei dem Film muss ich einfach weinen."},"simpel":"Ein Gefühl ist unwiderstehlich: »ich kann nicht anders, als zu …«.<br><span class=\"jp\"><ruby>笑<rt>わら</rt></ruby>わ<b>ずには いられない</b></span> = „ich muss einfach lachen“","rule":"V<sub>ない</sub>-Stamm + ずにはいられない (する→せずに): der Sprecher kann einen inneren Drang nicht unterdrücken. Formeller/emotionaler als 〜ないではいられない."},{"l":15,"t":"〜どころか","de":"von wegen … / ganz im Gegenteil","slots":[{"text":"[Erwartung X]","role":"cond"},{"text":"どころか","role":"actor","label":"von wegen"},{"text":"[Realität ≠ X]","role":"verb"}],"gloss":"»Von wegen X — in Wirklichkeit das Gegenteil / viel mehr.« Reißt die Erwartung des Hörers ein. Oft + 〜も…ない.","ex":{"jp":"<ruby>休<rt>やす</rt></ruby>む<b>どころか</b>、もっと <ruby>忙<rt>いそが</rt></ruby>しくなった。","de":"Von wegen ausruhen — es wurde nur noch stressiger."},"simpel":"Reißt eine Erwartung ein: »von wegen X — in Wirklichkeit …«.<br><span class=\"jp\"><ruby>休<rt>やす</rt></ruby>む<b>どころか</b></span> = „von wegen ausruhen (im Gegenteil)“","rule":"V/Adj/N + どころか: nennt eine Erwartung X und stellt klar, dass die Realität ganz anders ist — oft das Gegenteil oder viel extremer. Anschluss Plain / Nomen."},{"l":16,"t":"〜ことか","de":"wie sehr …! (emotionaler Ausruf)","slots":[{"text":"どんなに","role":"actor","label":"wie sehr"},{"text":"[Plain]","role":"cond"},{"text":"ことか","role":"plain","label":"…!"}],"gloss":"»Wie sehr … (!)« — Ausruf starker Emotion mit Fragewort, keine echte Frage. Gehoben.","ex":{"jp":"どんなに <ruby>心配<rt>しんぱい</rt></ruby>した<b>ことか</b>。","de":"Wie große Sorgen ich mir gemacht habe!"},"simpel":"Emotionaler Ausruf mit Fragewort: »wie sehr …!«.<br><span class=\"jp\">どんなに <ruby>嬉<rt>うれ</rt></ruby>しかった<b>ことか</b></span> = „wie sehr ich mich gefreut habe!“","rule":"Fragewort (どんなに / なんと / どれほど) + Plain + ことか: ein Ausruf starker Emotion, KEINE echte Frage. Schriftlich/gehoben. Anschluss Plain (な-Adj + な)."},{"l":16,"t":"〜ものか / 〜もんか","de":"niemals! / auf gar keinen Fall werde ich …","slots":[{"text":"[Plain]","role":"cond"},{"text":"ものか / もんか","role":"plain","label":"niemals!"}],"gloss":"»Als ob ich …! Auf keinen Fall.« Frageform, aber Bedeutung = starke Verneinung. Trotzig, gesprochen. もんか = lockerer.","ex":{"jp":"<ruby>二度<rt>にど</rt></ruby>と <ruby>行<rt>い</rt></ruby>く<b>ものか</b>。","de":"Da gehe ich nie wieder hin!"},"simpel":"Starke Verweigerung als rhetorische Frage: »niemals!«.<br><span class=\"jp\"><ruby>負<rt>ま</rt></ruby>ける<b>ものか</b></span> = „niemals verliere ich!“","rule":"V/Adj (Plain) + ものか (locker もんか): emphatische Verneinung in Frageform — »als ob ich …! auf keinen Fall«. Gesprochen, emotional/trotzig."},{"l":16,"t":"〜まい","de":"werde gewiss nicht … / wird wohl nicht …","slots":[{"text":"V","role":"verb"},{"text":"まい","role":"plain","label":"gewiss nicht"}],"gloss":"(1) »ich werde bestimmt nicht …« (Entschluss) oder (2) »wird wohl nicht …« (Vermutung). Gehoben. Anschluss variiert je Verbtyp.","ex":{"jp":"もう <ruby>泣<rt>な</rt></ruby>く<b>まい</b>と <ruby>決<rt>き</rt></ruby>めた。","de":"Ich habe beschlossen, nie wieder zu weinen."},"simpel":"Negative Willens- oder Vermutungsform: »ich werde ganz sicher nicht …«.<br><span class=\"jp\">もう <ruby>二度<rt>にど</rt></ruby>と <ruby>行<rt>い</rt></ruby>く<b>まい</b></span> = „ich gehe gewiss nie wieder hin“","rule":"〜まい: (1) negativer Wille »ich werde bestimmt nicht …« (Entschluss); (2) negative Vermutung »wird wohl nicht …«. Schriftlich/gehoben."},{"l":16,"t":"〜ことなく","de":"ohne (je) zu …","slots":[{"text":"V<sub>Grund</sub>","role":"verb"},{"text":"ことなく","role":"actor","label":"ohne je zu"},{"text":"[Haupthandlung]","role":"cond"}],"gloss":"»Ohne (auch nur einmal) zu V …« Schriftsprachlich, nachdrücklicher als 〜ないで. Betont das völlige Ausbleiben.","ex":{"jp":"<ruby>一度<rt>いちど</rt></ruby>も <ruby>休<rt>やす</rt></ruby>む<b>ことなく</b> <ruby>働<rt>はたら</rt></ruby>いた。","de":"Er arbeitete, ohne ein einziges Mal Pause zu machen."},"simpel":"Schriftliches »ohne zu …«: »ohne (auch nur einmal) zu …«.<br><span class=\"jp\">ふり<ruby>返<rt>かえ</rt></ruby>る<b>ことなく</b></span> = „ohne sich umzudrehen“","rule":"V<sub>Grund</sub> + ことなく = »ohne (auch nur einmal) zu …«. Schriftsprachlicher/nachdrücklicher als 〜ないで. Betont, dass etwas gar nicht geschah."},{"l":16,"t":"〜てこそ","de":"erst dadurch, dass … (wirklich)","slots":[{"text":"V<sub>て</sub>","role":"verb"},{"text":"こそ","role":"actor","label":"erst dadurch"},{"text":"[B: das Eigentliche]","role":"cond"}],"gloss":"»Erst wenn man wirklich A tut, ergibt sich B.« A ist die unverzichtbare Voraussetzung. Gehoben, oft in Weisheiten.","ex":{"jp":"<ruby>努力<rt>どりょく</rt></ruby>し<b>てこそ</b>、<ruby>成功<rt>せいこう</rt></ruby>が ある。","de":"Erst durch echte Anstrengung gibt es Erfolg."},"simpel":"Erst durch A wird B möglich/wahr: »erst wenn man wirklich A tut, …«.<br><span class=\"jp\"><ruby>努力<rt>どりょく</rt></ruby>し<b>てこそ</b></span> = „erst wenn man sich wirklich anstrengt“","rule":"V<sub>て</sub> + こそ: »erst dadurch, dass man (wirklich) A tut, ergibt sich B (das Eigentliche/Wertvolle)«. Hebt A als unverzichtbare Voraussetzung hervor. Gehoben."},{"l":17,"t":"〜に<ruby>対<rt>たい</rt></ruby>して","de":"gegenüber … / gegen … / im Gegensatz zu …","slots":[{"text":"N","role":"subj","label":"Adressat"},{"text":"に<ruby>対<rt>たい</rt></ruby>して","role":"actor","label":"gegenüber"},{"text":"[Haltung/Handlung]","role":"verb"}],"gloss":"»gegenüber / gegen N« (Adressat einer Haltung) oder »im Gegensatz zu« (Kontrast). Attributiv: に対する + N.","ex":{"jp":"<ruby>質問<rt>しつもん</rt></ruby><b>に対して</b> <ruby>答<rt>こた</rt></ruby>える。","de":"Auf die Frage antworten."},"simpel":"Richtung/Gegenüber einer Handlung — oder ein Kontrast.<br><span class=\"jp\"><ruby>先生<rt>せんせい</rt></ruby><b>に対して</b> <ruby>失礼<rt>しつれい</rt></ruby>だ</span> = „dem Lehrer gegenüber unhöflich“","rule":"N + に対して: (1) »gegenüber / gegen« — Ziel/Adressat einer Haltung oder Handlung; (2) Kontrast »im Gegensatz zu, wohingegen«. Attributiv: に対する + N."},{"l":17,"t":"〜に<ruby>比<rt>くら</rt></ruby>べて","de":"im Vergleich zu …","slots":[{"text":"N","role":"subj","label":"Vergleichsbasis"},{"text":"に<ruby>比<rt>くら</rt></ruby>べて","role":"actor","label":"verglichen mit"},{"text":"[Unterschied]","role":"verb"}],"gloss":"»Verglichen mit N ist …« — stellt die Vergleichsbasis heraus. Etwas formeller als より.","ex":{"jp":"<ruby>去年<rt>きょねん</rt></ruby><b>に比べて</b> <ruby>暑<rt>あつ</rt></ruby>い。","de":"Verglichen mit dem letzten Jahr ist es heiß."},"simpel":"Vergleichsbasis: »verglichen mit …«.<br><span class=\"jp\"><ruby>去年<rt>きょねん</rt></ruby><b>に比べて</b></span> = „im Vergleich zum letzten Jahr“","rule":"N + に比べて = »verglichen mit N«. Stellt einen Maßstab für einen Vergleich auf. Variante に比べ (formeller)."},{"l":17,"t":"〜に<ruby>加<rt>くわ</rt></ruby>えて","de":"zusätzlich zu … / neben …","slots":[{"text":"N","role":"subj","label":"Basis"},{"text":"に<ruby>加<rt>くわ</rt></ruby>えて","role":"actor","label":"zusätzlich zu"},{"text":"[+ etwas mehr]","role":"verb"}],"gloss":"»Zusätzlich zu N kommt noch …« — fügt eine weitere Sache hinzu, schriftlich, oft mit も.","ex":{"jp":"<ruby>雨<rt>あめ</rt></ruby><b>に加えて</b>、<ruby>風<rt>かぜ</rt></ruby>も <ruby>強<rt>つよ</rt></ruby>くなった。","de":"Zusätzlich zum Regen wurde auch der Wind stärker."},"simpel":"Etwas kommt hinzu: »zusätzlich zu …«.<br><span class=\"jp\"><ruby>雨<rt>あめ</rt></ruby><b>に加えて</b> <ruby>風<rt>かぜ</rt></ruby>も</span> = „zusätzlich zum Regen auch Wind“","rule":"N + に加えて = »zusätzlich zu N (kommt noch …)«. Fügt eine weitere Sache/Eigenschaft hinzu; schriftlich. Oft mit も im Folgeteil."},{"l":17,"t":"〜に<ruby>関<rt>かん</rt></ruby>して","de":"bezüglich … / in Bezug auf …","slots":[{"text":"N","role":"subj","label":"Thema"},{"text":"に<ruby>関<rt>かん</rt></ruby>して","role":"actor","label":"bezüglich"},{"text":"[Aussage]","role":"verb"}],"gloss":"»Bezüglich N / was N betrifft …« — formeller als について. Attributiv: に関する + N.","ex":{"jp":"<ruby>事件<rt>じけん</rt></ruby><b>に関して</b> <ruby>話<rt>はな</rt></ruby>す。","de":"Über den Vorfall sprechen."},"simpel":"Formelles »über/bezüglich«: das Thema einer Aussage.<br><span class=\"jp\">その <ruby>件<rt>けん</rt></ruby><b>に関して</b></span> = „bezüglich dieser Sache“","rule":"N + に関して = »bezüglich N / was N betrifft«, formeller als について. Attributiv: に関する + N."},{"l":17,"t":"〜において / 〜における","de":"in / bei / auf (Ort, Zeit, Bereich) — formell","slots":[{"text":"N","role":"time","label":"Ort/Zeit/Bereich"},{"text":"において","role":"actor","label":"in/bei"},{"text":"[Ereignis]","role":"verb"}],"gloss":"Formelles で: »in/bei/auf« für Ort, Zeit oder abstrakten Bereich. Nur schriftlich/formell. Attributiv: における + N.","ex":{"jp":"<ruby>会議<rt>かいぎ</rt></ruby><b>において</b> <ruby>決定<rt>けってい</rt></ruby>された。","de":"Bei der Sitzung wurde es beschlossen."},"simpel":"Formelles で für Ort/Zeit/Bereich: »in/bei«.<br><span class=\"jp\"><ruby>会議<rt>かいぎ</rt></ruby><b>において</b></span> = „bei der Sitzung“","rule":"N + において = formelles »in/bei/auf« für Ort, Zeitpunkt oder abstrakten Bereich (wie で, aber schriftlich). Attributiv: における + N."},{"l":18,"t":"Vマス / N + がち","de":"neigt zu … / oft … (meist negativ)","slots":[{"text":"V<sub>ます</sub> / N","role":"subj"},{"text":"がち","role":"plain","label":"neigt zu (oft)"}],"gloss":"»Neigt dazu / passiert oft« — meist etwas Negatives. Vます-Stamm oder Nomen + がち.","ex":{"jp":"<ruby>最近<rt>さいきん</rt></ruby> <ruby>疲<rt>つか</rt></ruby>れ<b>がち</b>だ。","de":"In letzter Zeit bin ich oft müde."},"simpel":"Tendenz, oft unerwünscht: »neigt dazu, zu …«.<br><span class=\"jp\"><ruby>忘<rt>わす</rt></ruby>れ<b>がち</b></span> = „vergisst oft / neigt zum Vergessen“","rule":"V<sub>ます</sub>-Stamm / Nomen + がち = »neigt zu …, tut oft …«, meist etwas Negatives/Unerwünschtes. 病気がち »kränklich«, 遅れがち »oft verspätet«."},{"l":18,"t":"〜っぽい","de":"wirkt wie … / neigt zu … / -haft","slots":[{"text":"N / V<sub>ます</sub>","role":"subj"},{"text":"っぽい","role":"plain","label":"wirkt wie / neigt zu"}],"gloss":"»Hat den Anschein/die Neigung von …« Wird wie ein い-Adjektiv gebeugt. 忘れっぽい »vergesslich«, 水っぽい »wässrig«.","ex":{"jp":"この スープは <ruby>水<rt>みず</rt></ruby><b>っぽい</b>。","de":"Diese Suppe ist wässrig."},"simpel":"»wirkt wie / hat viel von …« — macht Adjektive aus Nomen/Verben.<br><span class=\"jp\"><ruby>子<rt>こ</rt></ruby>ども<b>っぽい</b></span> = „kindisch“","rule":"N / V<sub>ます</sub> / Adj-Stamm + っぽい = »hat den Anschein/die Neigung von …«. Wird wie ein い-Adjektiv verwendet. 水っぽい »wässrig«, 忘れっぽい »vergesslich«, 怒りっぽい »reizbar«."},{"l":18,"t":"N + <ruby>向<rt>む</rt></ruby>き / N + <ruby>向<rt>む</rt></ruby>け","de":"geeignet für … / gerichtet an … (Zielgruppe)","slots":[{"text":"N","role":"subj","label":"Zielgruppe"},{"text":"<ruby>向<rt>む</rt></ruby>き / <ruby>向<rt>む</rt></ruby>け","role":"plain","label":"passt / extra für"}],"gloss":"向き = »passt (von selbst) zu« (zufällige Eignung). 向け = »eigens gemacht für« (bewusste Zielgruppe).","ex":{"jp":"この <ruby>仕事<rt>しごと</rt></ruby>は <ruby>女性<rt>じょせい</rt></ruby><b>向き</b>だ。","de":"Diese Arbeit eignet sich für Frauen."},"simpel":"<b>向き</b> = passt (von Natur) zu; <b>向け</b> = eigens gemacht für.<br><span class=\"jp\"><ruby>初心者<rt>しょしんしゃ</rt></ruby><b>向け</b></span> = „für Anfänger (gemacht)“","rule":"N + 向き = »passt/eignet sich für« (eine Eigenschaft passt zufällig). N + 向け = »eigens gerichtet an / hergestellt für« (bewusste Zielgruppe)."},{"l":18,"t":"〜らしい","de":"anscheinend … / typisch für … (echt …)","slots":[{"text":"[Plain] / N","role":"subj"},{"text":"らしい","role":"plain","label":"anscheinend / typisch"}],"gloss":"(1) Plain + らしい = »anscheinend« (aus Info). (2) N + らしい = »typisch/echt N« (男らしい). Wird wie い-Adj gebeugt.","ex":{"jp":"<ruby>彼<rt>かれ</rt></ruby>は <ruby>来<rt>こ</rt></ruby>ない<b>らしい</b>。","de":"Anscheinend kommt er nicht."},"simpel":"Zwei Sinne: »anscheinend« (Hörensagen) und »typisch/echt …«.<br><span class=\"jp\"><ruby>春<rt>はる</rt></ruby><b>らしい</b> <ruby>天気<rt>てんき</rt></ruby></span> = „echtes Frühlingswetter“","rule":"(1) Plain + らしい = »anscheinend / es heißt« (Vermutung aus zuverlässiger Info). (2) N + らしい = »typisch für N, wie es sich für N gehört« (男らしい »männlich«, 学生らしい »wie ein echter Student«)."},{"l":18,"t":"〜かのようだ / かのように","de":"(gerade) so, als ob …","slots":[{"text":"まるで","role":"actor","label":"gerade so"},{"text":"[Plain]","role":"cond"},{"text":"かのようだ","role":"plain","label":"als ob"}],"gloss":"»So, als ob … (in Wahrheit aber nicht).« Irrealer Vergleich, oft mit まるで. Adverbial かのように, attributiv かのような.","ex":{"jp":"まるで <ruby>何<rt>なに</rt></ruby>も なかった<b>かのように</b> <ruby>話<rt>はな</rt></ruby>す。","de":"Er redet, als ob nichts gewesen wäre."},"simpel":"Irrealer Vergleich, oft mit まるで: »als ob …«.<br><span class=\"jp\">まるで <ruby>夢<rt>ゆめ</rt></ruby>を <ruby>見<rt>み</rt></ruby>ている<b>かのようだ</b></span> = „als ob man träumt“","rule":"Plain + かのようだ = »so, als ob (in Wirklichkeit aber nicht)«. Vergleich mit etwas Irrealem/Unwahrem, oft mit まるで. Adverbial かのように, attributiv かのような."},{"l":19,"t":"〜たびに","de":"jedes Mal, wenn …","slots":[{"text":"V<sub>Grund</sub> / N の","role":"cond"},{"text":"たびに","role":"actor","label":"jedes Mal"},{"text":"[B]","role":"verb"}],"gloss":"»Jedes Mal, wenn A (geschieht), (geschieht) B.« Regelmäßige Kopplung. Nomen braucht の.","ex":{"jp":"<ruby>彼<rt>かれ</rt></ruby>に <ruby>会<rt>あ</rt></ruby>う<b>たびに</b>、<ruby>元気<rt>げんき</rt></ruby>を もらう。","de":"Jedes Mal, wenn ich ihn treffe, gibt er mir Energie."},"simpel":"»immer wenn A, (dann) B«.<br><span class=\"jp\"><ruby>会<rt>あ</rt></ruby>う<b>たびに</b></span> = „jedes Mal, wenn wir uns treffen“","rule":"V<sub>Grund</sub> / N + の + たびに = »jedes Mal, wenn / bei jedem …«. B tritt regelmäßig zusammen mit A auf."},{"l":19,"t":"〜ば〜ほど","de":"je …, desto …","slots":[{"text":"V<sub>ば</sub>","role":"cond","label":"je …"},{"text":"V<sub>Grund</sub> + ほど","role":"actor","label":"desto …"},{"text":"[Folge]","role":"verb"}],"gloss":"»Je mehr A, desto mehr B.« Dasselbe Wort zweimal (ば-Form + Grundform + ほど).","ex":{"jp":"<ruby>考<rt>かんが</rt></ruby>えれば <ruby>考<rt>かんが</rt></ruby>える<b>ほど</b> わからない。","de":"Je mehr ich nachdenke, desto weniger verstehe ich."},"simpel":"Proportional: »je mehr A, desto mehr B«.<br><span class=\"jp\"><ruby>考<rt>かんが</rt></ruby>えれば <ruby>考<rt>かんが</rt></ruby>える<b>ほど</b></span> = „je mehr ich nachdenke“","rule":"V<sub>ば</sub> + V<sub>Grund</sub> + ほど (い-Adj: ければ〜いほど; な-Adj: なら〜なほど): »je …, desto …«. Beide Male dasselbe Wort."},{"l":19,"t":"N + だらけ","de":"voller … (meist unangenehm)","slots":[{"text":"N","role":"subj"},{"text":"だらけ","role":"plain","label":"voller (negativ)"}],"gloss":"»Übersät/ganz voller N« — fast immer negativ (Schmutz, Fehler, Blut). Betont die unangenehme Menge.","ex":{"jp":"<ruby>部屋<rt>へや</rt></ruby>が ほこり<b>だらけ</b>だ。","de":"Das Zimmer ist voller Staub."},"simpel":"Übervoll mit etwas Unangenehmem: »voller …«.<br><span class=\"jp\"><ruby>間違<rt>まちが</rt></ruby>い<b>だらけ</b></span> = „voller Fehler“","rule":"N + だらけ = »ganz/übersät voller N«, fast immer negativ (Schmutz, Fehler, Blut …). Betont die unangenehm große Menge/Verteilung."},{"l":19,"t":"〜だけでなく(〜も)","de":"nicht nur …, (sondern auch) …","slots":[{"text":"[A]","role":"cond"},{"text":"だけでなく","role":"actor","label":"nicht nur"},{"text":"[B] も","role":"verb","label":"sondern auch"}],"gloss":"»Nicht nur A, sondern auch B.« Zweiter Teil oft mit も. Formeller: 〜のみならず.","ex":{"jp":"この <ruby>店<rt>みせ</rt></ruby>は <ruby>安<rt>やす</rt></ruby>い<b>だけでなく</b>、おいしい。","de":"Dieser Laden ist nicht nur billig, sondern auch lecker."},"simpel":"Fügt hinzu: »nicht nur A, sondern auch B«.<br><span class=\"jp\"><ruby>安<rt>やす</rt></ruby>い<b>だけでなく</b></span> = „nicht nur billig …“","rule":"…だけでなく + …も = »nicht nur A, sondern auch B«. Anschluss wie ans Nomen (Plain, な-Adj + な, N direkt). Formeller: 〜のみならず."},{"l":19,"t":"〜とおり(に) / N + どおり","de":"so wie … / gemäß …","slots":[{"text":"V<sub>Grund/た</sub> / N の","role":"cond"},{"text":"とおり(に)","role":"actor","label":"so wie"},{"text":"[Handlung]","role":"verb"}],"gloss":"»Genau so wie A.« An Nomen direkt → どおり (時間どおり, 期待どおり). ≈ 〜ように.","ex":{"jp":"<ruby>私<rt>わたし</rt></ruby>が <ruby>言<rt>い</rt></ruby>う<b>とおりに</b> して。","de":"Mach genau so, wie ich sage."},"simpel":"Etwas geschieht genau wie A: »so wie …«.<br><span class=\"jp\"><ruby>言<rt>い</rt></ruby>った<b>とおりに</b></span> = „genau so, wie ich gesagt habe“","rule":"V<sub>Grund/た</sub> / N + の + とおり(に) = »genau so wie …«. An ein Nomen direkt angehängt wird とおり klanglich zu どおり: 予定どおり »planmäßig«."},{"l":20,"t":"〜にとって","de":"für … / aus Sicht von …","slots":[{"text":"N","role":"subj","label":"Perspektive"},{"text":"にとって","role":"actor","label":"für / aus Sicht von"},{"text":"[Bewertung]","role":"verb"}],"gloss":"»Für N / aus der Sicht von N (ist etwas wichtig/schwer …).« Leitet eine Bewertung aus jds. Perspektive ein.","ex":{"jp":"<ruby>私<rt>わたし</rt></ruby><b>にとって</b> <ruby>家族<rt>かぞく</rt></ruby>は <ruby>一番<rt>いちばん</rt></ruby> <ruby>大切<rt>たいせつ</rt></ruby>だ。","de":"Für mich ist die Familie das Wichtigste."},"simpel":"Standpunkt einer Bewertung: »für jdn / aus jds. Sicht«.<br><span class=\"jp\"><ruby>私<rt>わたし</rt></ruby><b>にとって</b></span> = „für mich (aus meiner Sicht)“","rule":"N + にとって = »für N / aus der Sicht von N«, leitet eine Bewertung aus jemandes Perspektive ein (wichtig, schwer, wertvoll …). Attributiv: にとっての + N."},{"l":20,"t":"〜あげく(に)","de":"nach langem … schließlich (meist schlecht)","slots":[{"text":"V<sub>た</sub>","role":"cond","label":"nach langem A"},{"text":"あげく(に)","role":"actor","label":"schließlich"},{"text":"[schlechtes B]","role":"verb"}],"gloss":"»Nach langem/mühsamem A kam es schließlich zu (meist schlechtem) B.« Nur nach た-Form / N + の.","ex":{"jp":"<ruby>悩<rt>なや</rt></ruby>んだ<b>あげく</b>、<ruby>留学<rt>りゅうがく</rt></ruby>を やめた。","de":"Nach langem Grübeln gab ich den Auslandsaufenthalt auf."},"simpel":"Nach viel A ein (meist übles) Endergebnis.<br><span class=\"jp\"><ruby>悩<rt>なや</rt></ruby>んだ<b>あげく</b></span> = „nach langem Grübeln schließlich“","rule":"V<sub>た</sub> / N + の + あげく(に) = »nach langem/vielem A kam es schließlich zu B« — B ist meist ein negatives Endergebnis. Betont den mühsamen Prozess davor."},{"l":20,"t":"〜<ruby>気<rt>き</rt></ruby>がする","de":"ich habe das Gefühl, dass …","slots":[{"text":"[Plain]","role":"cond"},{"text":"<ruby>気<rt>き</rt></ruby>がする","role":"plain","label":"habe das Gefühl"}],"gloss":"»Ich habe das (unsichere) Gefühl, dass …« Subjektive Ahnung ohne Beweis, oft mit ような.","ex":{"jp":"どこかで <ruby>会<rt>あ</rt></ruby>ったような <b><ruby>気<rt>き</rt></ruby>がする</b>。","de":"Ich habe das Gefühl, wir sind uns schon mal begegnet."},"simpel":"Vage Ahnung/Empfindung: »mir ist, als ob …«.<br><span class=\"jp\"><ruby>忘<rt>わす</rt></ruby>れた <ruby>気<rt>き</rt></ruby>がする</span> = „ich habe das Gefühl, es vergessen zu haben“","rule":"Plain (+ ような) + 気がする = »ich habe das (unsichere) Gefühl, dass …«. Subjektive Ahnung ohne Beweis."},{"l":20,"t":"〜ふりをする","de":"so tun, als ob … / vorgeben zu …","slots":[{"text":"[Plain] / N の","role":"cond"},{"text":"ふりをする","role":"plain","label":"so tun, als ob"}],"gloss":"»Vorgeben zu … / so tun, als ob.« Verhalten ≠ Wirklichkeit. N + の + ふり (子どものふり).","ex":{"jp":"<ruby>聞<rt>き</rt></ruby>こえない<b>ふりをした</b>。","de":"Ich tat, als hörte ich es nicht."},"simpel":"Vortäuschen: »so tun, als ob …«.<br><span class=\"jp\"><ruby>寝<rt>ね</rt></ruby>た<b>ふりをする</b></span> = „sich schlafend stellen“","rule":"Plain + ふりをする (N + の + ふり) = »vorgeben zu … / so tun, als ob«. Die Wirklichkeit ist anders als das gezeigte Verhalten."},{"l":20,"t":"〜<ruby>一方<rt>いっぽう</rt></ruby>だ","de":"wird nur immer … (einseitige Tendenz)","slots":[{"text":"N は","role":"subj"},{"text":"V<sub>Grund</sub>","role":"verb"},{"text":"<ruby>一方<rt>いっぽう</rt></ruby>だ","role":"plain","label":"nur immer …"}],"gloss":"»Entwickelt sich immer weiter (nur) in eine Richtung.« Meist negativ. Nur mit Veränderungsverben.","ex":{"jp":"<ruby>物価<rt>ぶっか</rt></ruby>は <ruby>上<rt>あ</rt></ruby>がる<b>一方だ</b>。","de":"Die Preise steigen nur immer weiter."},"simpel":"Einseitige, fortschreitende Tendenz: »wird nur immer …«.<br><span class=\"jp\"><ruby>悪<rt>わる</rt></ruby>くなる<b>一方だ</b></span> = „wird nur immer schlechter“","rule":"V<sub>Grund</sub> + 一方だ = »die Lage entwickelt sich immer weiter (nur) in eine Richtung«, oft negativ. Betont eine stetige, einseitige Veränderung."},{"l":20,"t":"〜ところだった","de":"beinahe wäre … (passiert)","slots":[{"text":"もう<ruby>少<rt>すこ</rt></ruby>しで","role":"actor","label":"um ein Haar"},{"text":"V<sub>Grund</sub>","role":"verb"},{"text":"ところだった","role":"plain","label":"beinahe wäre …"}],"gloss":"»Beinahe wäre … passiert (ist aber nicht).« Oft mit もう少しで/あぶなく. Immer Grundform + ところだった.","ex":{"jp":"もう<ruby>少<rt>すこ</rt></ruby>しで <ruby>電車<rt>でんしゃ</rt></ruby>に <ruby>乗<rt>の</rt></ruby>り<ruby>遅<rt>おく</rt></ruby>れる<b>ところだった</b>。","de":"Beinahe hätte ich den Zug verpasst."},"simpel":"Um ein Haar wäre etwas passiert (ist aber nicht).<br><span class=\"jp\">もう<ruby>少<rt>すこ</rt></ruby>しで <ruby>落<rt>お</rt></ruby>ちる<b>ところだった</b></span> = „beinahe wäre ich gefallen“","rule":"V<sub>Grund</sub> + ところだった = »um ein Haar wäre … passiert (ist aber gerade nicht)«. Oft mit もう少しで / あぶなく. Erleichterung oder Schreck im Nachhinein."},{"l":21,"t":"1 · Vマス + 始める","de":"anfangen zu … (+Plus: 〜終わる)","slots":[{"text":"<ruby>朝<rt>あさ</rt></ruby>","role":"plain"},{"text":"5<ruby>時<rt>じ</rt></ruby>に","role":"plain"},{"text":"<ruby>山<rt>やま</rt></ruby>を","role":"plain"},{"text":"<ruby>登<rt>のぼ</rt></ruby>り<b>始めました</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Um 5 Uhr morgens begannen wir den Aufstieg.«","ex":{"jp":"<ruby>朝<rt>あさ</rt></ruby> 5<ruby>時<rt>じ</rt></ruby>に <ruby>山<rt>やま</rt></ruby>を <ruby>登<rt>のぼ</rt></ruby>り<b>始めました</b>。","de":"Um 5 Uhr morgens begannen wir den Aufstieg."},"simpel":"ます-Stamm + <b><ruby>始<rt>はじ</rt></ruby>める</b> = »anfangen zu …« — klebt direkt am Stamm.<br><span class='jp'><ruby>山<rt>やま</rt></ruby>を <ruby>登<rt>のぼ</rt></ruby>り<b>始めた</b></span> = „begann den Berg zu besteigen“<br>📖 Buch-Satz: 「<ruby>登<rt>のぼ</rt></ruby>り<ruby>始<rt>はじ</rt></ruby>めた」","rule":"V<sub>ます</sub>-Stamm + 始める markiert den Beginn einer Handlung. Das Gegenstück 〜終わる markiert den Abschluss. Neutraler Anfang (auch geplant) — plötzliches Losbrechen wäre 〜出す (Punkt 16)."},{"l":21,"t":"2 · 〜ように言う/言われる","de":"jdm. sagen, dass er … soll","slots":[{"text":"<ruby>山小屋<rt>やまごや</rt></ruby>の","role":"plain"},{"text":"<ruby>人<rt>ひと</rt></ruby>に、<ruby>水<rt>みず</rt></ruby>を","role":"plain"},{"text":"たくさん","role":"plain"},{"text":"<ruby>持<rt>も</rt></ruby>って","role":"plain"},{"text":"いく<b>ように","role":"plain"},{"text":"言われました</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Die Leute von der Berghütte sagten mir, ich solle viel Wasser mitnehmen.«","ex":{"jp":"<ruby>山小屋<rt>やまごや</rt></ruby>の <ruby>人<rt>ひと</rt></ruby>に、<ruby>水<rt>みず</rt></ruby>を たくさん <ruby>持<rt>も</rt></ruby>って いく<b>ように 言われました</b>。","de":"Die Leute von der Berghütte sagten mir, ich solle viel Wasser mitnehmen."},"simpel":"Aufforderung indirekt wiedergeben; passiv = »mir wurde gesagt, ich solle …«.<br><span class='jp'><ruby>水<rt>みず</rt></ruby>を <ruby>持<rt>も</rt></ruby>って いく<b>ように 言われた</b></span> = „man sagte mir, ich solle Wasser mitnehmen“<br>📖 Buch-Satz: 「<ruby>持<rt>も</rt></ruby>って いくように <ruby>言<rt>い</rt></ruby>われた」","rule":"V<sub>Grund/ない</sub> + ように + 言う/頼む/注意する/伝える: gibt Bitten/Anweisungen indirekt wieder. Sehr häufig im Passiv: 〜ように言われた »mir wurde gesagt, dass ich … soll«."},{"l":21,"t":"3 · 〜ということだ","de":"es heißt, dass … / das bedeutet also …","slots":[{"text":"<ruby>高山病<rt>こうざんびょう</rt></ruby>に","role":"plain"},{"text":"なる","role":"plain"},{"text":"<ruby>人<rt>ひと</rt></ruby>も","role":"plain"},{"text":"いる<b>ということ</b>を","role":"plain"},{"text":"<ruby>知<rt>し</rt></ruby>った。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich erfuhr, dass manche höhenkrank werden.«","ex":{"jp":"<ruby>返事<rt>へんじ</rt></ruby>が ないのは、<ruby>興味<rt>きょうみ</rt></ruby>が ない<b>ということだ</b>。","de":"Keine Antwort bedeutet: kein Interesse."},"simpel":"📦 <b>ということ schnürt einen ganzen Satz zu EINEM Paket</b> — das man weiterreicht.<br>Am Ende <b>ということだ</b> = »es heißt, dass …« (Hörensagen) oder »das bedeutet also …« (Schluss).<br><span class=\"jp\"><ruby>返事<rt>へんじ</rt></ruby>が ないのは、<ruby>興味<rt>きょうみ</rt></ruby>がない<b>ということだ</b></span> = »Keine Antwort heißt: kein Interesse.«<br>📖 Buch-Satz: 「<ruby>病気<rt>びょうき</rt></ruby>に なる <ruby>人<rt>ひと</rt></ruby>も いる ということ」","rule":"Satz + ということ = »die Tatsache/Info, dass …« (der ganze Satz als ein Nomen-Paket).<br>Am Satzende <b>ということだ</b>: (1) <b>Hörensagen</b> »es heißt, dass …«; (2) <b>Schlussfolgerung</b> »das bedeutet also …«."},{"l":21,"t":"4 · 〜だろうと思う","de":"ich dachte/denke, dass wohl …","slots":[{"text":"<ruby>彼<rt>かれ</rt></ruby>は","role":"plain"},{"text":"もう","role":"plain"},{"text":"<ruby>着<rt>つ</rt></ruby>いている<b>だろうと","role":"plain"},{"text":"思います</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich denke, er ist wohl schon angekommen.«","ex":{"jp":"<ruby>夏<rt>なつ</rt></ruby>だから <ruby>大丈夫<rt>だいじょうぶ</rt></ruby><b>だろうと 思った</b>。","de":"Weil Sommer war, dachte ich, es würde schon gehen."},"simpel":"Vermutung + <b>と思う</b>: »ich dachte, es wird wohl …«.<br><span class='jp'><ruby>大丈夫<rt>だいじょうぶ</rt></ruby><b>だろうと 思った</b></span> = „ich dachte, es geht schon“<br>📖 Buch-Satz: 「<ruby>大丈夫<rt>だいじょうぶ</rt></ruby>だろうと <ruby>思<rt>おも</rt></ruby>った」","rule":"Plain + だろう + と思う: die eigene Vermutung, abgeschwächt und subjektiv — »wird wohl … , denke ich«. な-Adj/Nomen ohne だ direkt + だろう. Vergangenheit: 〜だろうと思った (oft mit Enttäuschung, wenn es anders kam)."},{"l":21,"t":"5 · 〜そうだ (Anschein)","de":"sieht … aus / sah nicht … aus","slots":[{"text":"この","role":"plain"},{"text":"<ruby>問題<rt>もんだい</rt></ruby>は","role":"plain"},{"text":"<ruby>難<rt>むずか</rt></ruby>し<b>そう</b>だ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Diese Aufgabe sieht schwierig aus.«","ex":{"jp":"ガイドブックでは、そんなに <ruby>大変<rt>たいへん</rt></ruby><b>じゃなさそう</b>だった。","de":"Laut Reiseführer sah es nicht so anstrengend aus."},"simpel":"Anschein: »sieht … aus«. Verneint: <b>じゃなさそう</b> »sieht nicht … aus«.<br><span class='jp'><ruby>大変<rt>たいへん</rt></ruby><b>じゃなさそう</b>だった</span> = „sah nicht anstrengend aus“<br>📖 Buch-Satz: 「<ruby>大変<rt>たいへん</rt></ruby>じゃなさそうだった」","rule":"Anschein-そう: い-Adj-Stamm/な-Adj + そうだ (»sieht … aus«). Verneinung: い-Adj くなさそう, な-Adj/N じゃなさそう, Verben そうもない/そうにない. Vergangenheit: そうだった."},{"l":21,"t":"6 · 〜と（＋たら）","de":"als/sobald man …, (da entdeckte man) … (unerwarteter Zustand)","slots":[{"text":"<ruby>待<rt>ま</rt></ruby>ち<ruby>合<rt>あ</rt></ruby>わせの","role":"plain"},{"text":"<ruby>場所<rt>ばしょ</rt></ruby>に","role":"plain"},{"text":"<ruby>着<rt>つ</rt></ruby>く<b>と</b>、<ruby>友<rt>とも</rt></ruby>だちは","role":"plain"},{"text":"もう","role":"plain"},{"text":"<ruby>来<rt>き</rt></ruby>ていた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Als ich am Treffpunkt ankam, waren die Freunde schon da.«","ex":{"jp":"<ruby>気<rt>き</rt></ruby>がつく<b>と</b>、<ruby>外<rt>そと</rt></ruby>は すっかり <ruby>暗<rt>くら</rt></ruby>くなっていた。","de":"Als ich es bemerkte, war es draußen schon ganz dunkel geworden."},"simpel":"V-Grundform + と: »als/sobald ich X tat, (da war/geschah unerwartet) Y«. Der Nachsatz ist oft ein entdeckter Zustand (〜ていた).<br><span class=jp><ruby>気<rt>き</rt></ruby>がつく<b>と</b>、<ruby>外<rt>そと</rt></ruby>は すっかり <ruby>暗<rt>くら</rt></ruby>くなっていた</span> = „Als ich es bemerkte, war es draußen schon ganz dunkel.“<br>📖 Buch-Satz: 「<ruby>気<rt>き</rt></ruby>がつくと」","rule":"V-Grundform + と verbindet zwei Ereignisse: Sobald/als man X tut, stellt man (oft überrascht) Y fest. Y ist meist ein Zustand in der Vergangenheit (〜ていた / 〜た). ＋Plus: 〜たら wird genauso verwendet.<br>⚠ Der Nachsatz ist eine Feststellung/Entdeckung — kein Wille, keine Bitte, kein Befehl."},{"l":21,"t":"7 · 〜ほど","de":"so sehr, dass … — ほど nennt die MESSLATTE für den Grad","slots":[{"text":"<ruby>脚<rt>あし</rt></ruby>の","role":"plain"},{"text":"<ruby>筋<rt>きん</rt></ruby>トレが","role":"plain"},{"text":"きつすぎて、<ruby>立<rt>た</rt></ruby>って","role":"plain"},{"text":"いるのも","role":"plain"},{"text":"つらい<b>ほど</b>だ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Der Leg Day war so hart, dass sogar Stehen wehtut. (① Stehen tut weh)«","ex":{"jp":"<ruby>脚<rt>あし</rt></ruby>の <ruby>筋<rt>きん</rt></ruby>トレが きつすぎて、<ruby>立<rt>た</rt></ruby>って いるのも つらい<b>ほど</b>だ。","de":"Der Leg Day war so hart, dass sogar Stehen wehtut. (① Stehen tut weh)"},"simpel":"<b>ほど</b> beantwortet »<b>WIE SEHR?</b>« mit einer konkreten <b>Messlatte</b>. Zwei Teile:<br>① <b>Messlatte</b> (krasse Folge, zeigt WIE sehr) → steht <b>VOR</b> ほど.<br>② <b>Hauptaussage</b> (was du sagen willst) → steht <b>NACH</b> ほど.<br><span class=\"jp\">①<ruby>立<rt>た</rt></ruby>って いるのも つらい <b>ほど</b> ②<ruby>疲<rt>つか</rt></ruby>れた</span><br>= »②so müde, dass ①sogar Stehen wehtut«<br>📖 Buch-Satz: 「<ruby>立<rt>た</rt></ruby>って いるのも つらいほど」","rule":"ほど koppelt eine <b>Messlatte ①</b> (ein anschauliches Beispiel für den Grad) an eine <b>Hauptaussage ②</b>.<br><b>Formel: ① Messlatte + ほど + ② Hauptaussage.</b><br>Deutsch ist umgekehrt: »②so …, <u>dass</u> ①…« — darum wirkt es vertauscht.<br>⚠ Die Messlatte ① ist NICHT die Hauptsache — sie zeigt nur, wie stark ② ist."},{"l":21,"t":"8 · 〜ていく／〜てくる","de":"von mir weg / ab jetzt (ていく) ↔ zu mir her / bis jetzt (てくる)","slots":[{"text":"[Verb て-Form]","role":"verb","label":"Handlung"},{"text":"くる","role":"actor","label":"→ zu mir / bis jetzt"},{"text":"／いく","role":"plain","label":"→ weg / ab jetzt"}],"gloss":"て-Form + くる = auf mich zu / bis jetzt. て-Form + いく = von mir weg / ab jetzt weiter.","ex":{"jp":"<ruby>傘<rt>かさ</rt></ruby>を <ruby>持<rt>も</rt></ruby>って<b>いって</b>ね。","de":"Nimm den Schirm mit (weg von hier)."},"simpel":"Stell dir vor: <b>ICH</b> stehe im <b>Hier &amp; Jetzt</b>.<br>• <b>〜てくる</b> = kommt <b>zu mir her</b> / <b>bis jetzt</b>.<br>• <b>〜ていく</b> = geht <b>von mir weg</b> / <b>ab jetzt weiter</b>.<br><span class=\"jp\"><ruby>持<rt>も</rt></ruby>って<b>くる</b></span> = mitbringen (her) ↔ <span class=\"jp\"><ruby>持<rt>も</rt></ruby>って<b>いく</b></span> = mitnehmen (weg)<br>📖 Buch-Satz: 「どんどん <ruby>登<rt>のぼ</rt></ruby>って いく」","rule":"Bezugspunkt ist immer <b>der Sprecher (»hier / jetzt«)</b>.<br><b>くる</b> (kommen) → auf mich zu / bis zum Jetzt.<br><b>いく</b> (gehen) → von mir weg / vom Jetzt in die Zukunft.<br>Gilt räumlich (Bewegung) UND zeitlich (Veränderung) — gleiche Logik."},{"l":21,"t":"9 · Vマス + 続ける","de":"weiter/unaufhörlich …","slots":[{"text":"<ruby>彼<rt>かれ</rt></ruby>は","role":"plain"},{"text":"<ruby>夢<rt>ゆめ</rt></ruby>を","role":"plain"},{"text":"<ruby>追<rt>お</rt></ruby>い<b>続けて</b>","role":"plain"},{"text":"いる。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Er verfolgt weiter unbeirrt seinen Traum.«","ex":{"jp":"<ruby>休<rt>やす</rt></ruby>まずに 3<ruby>時間<rt>じかん</rt></ruby>も <ruby>登<rt>のぼ</rt></ruby>り<b>続けました</b>。","de":"Ich stieg ganze drei Stunden ohne Pause weiter."},"simpel":"ます-Stamm + <b><ruby>続<rt>つづ</rt></ruby>ける</b> = »ohne aufzuhören weiter …«.<br><span class='jp'><ruby>登<rt>のぼ</rt></ruby>り<b>続けた</b></span> = „stieg unaufhörlich weiter“<br>📖 Buch-Satz: 「<ruby>登<rt>のぼ</rt></ruby>り<ruby>続<rt>つづ</rt></ruby>けた」","rule":"V<sub>ます</sub>-Stamm + 続ける: die Handlung dauert an, ohne Unterbrechung — oft mit Durchhalte-Nuance. Anhaltender Zustand: 〜続けている."},{"l":21,"t":"10 · 〜なら","de":"wenn (du) … (willst), dann (rate ich) …","slots":[{"text":"<ruby>上<rt>うえ</rt></ruby>まで","role":"plain"},{"text":"<ruby>行<rt>い</rt></ruby>きたい<b>なら</b>、ちゃんと","role":"plain"},{"text":"<ruby>準備<rt>じゅんび</rt></ruby>した","role":"plain"},{"text":"ほうが","role":"plain"},{"text":"いい。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wenn du bis zum Gipfel willst, solltest du dich richtig vorbereiten.«","ex":{"jp":"<ruby>上<rt>うえ</rt></ruby>まで <ruby>行<rt>い</rt></ruby>きたい<b>なら</b>、ちゃんと <ruby>準備<rt>じゅんび</rt></ruby>した ほうが いい。","de":"Wenn du bis zum Gipfel willst, solltest du dich richtig vorbereiten."},"simpel":"<b>なら</b> reagiert auf Gesagtes/Gewolltes: »wenn du … willst, dann …«.<br><span class='jp'><ruby>上<rt>うえ</rt></ruby>まで <ruby>行<rt>い</rt></ruby>きたい<b>なら</b></span> = „wenn du bis oben willst, (dann) …“<br>📖 Buch-Satz: 「<ruby>上<rt>うえ</rt></ruby>まで <ruby>行<rt>い</rt></ruby>きたいなら」","rule":"[Thema/Wunsch] + なら + Ratschlag/Urteil: greift auf, was der andere gesagt oder vor hat, und gibt dazu eine Empfehlung. Typisch nach 〜たい: 行きたいなら »wenn du gehen willst«."},{"l":22,"t":"11 · 〜って","de":"locker für という/は (»namens … / was … angeht«)","slots":[{"text":"クロ<b>って</b>","role":"plain"},{"text":"<ruby>名前<rt>なまえ</rt></ruby>は、ぼくが","role":"plain"},{"text":"つけた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Den Namen „Kuro“ habe ich ihm gegeben.«","ex":{"jp":"クロ<b>って</b> <ruby>名前<rt>なまえ</rt></ruby>は、ぼくが つけた。","de":"Den Namen „Kuro“ habe ich ihm gegeben."},"simpel":"<b>って</b> ist das gesprochene という/は: »namens X« oder »X? (was das angeht)«.<br><span class='jp'>クロ<b>って</b> <ruby>名前<rt>なまえ</rt></ruby></span> = „der Name ‚Kuro‘“<br>📖 Buch-Satz: 「クロって <ruby>名前<rt>なまえ</rt></ruby>」","rule":"って ersetzt in lockerer Sprache: (1) という (クロって名前 = クロという名前), (2) Themen-は (これって何? = これは何?), (3) Zitat と (行くって言った). Sehr häufig im Gespräch."},{"l":22,"t":"12 · lassen-Form + てもらう","de":"(die Erlaubnis) bekommen, zu …","slots":[{"text":"<ruby>両親<rt>りょうしん</rt></ruby>に","role":"plain"},{"text":"<ruby>犬<rt>いぬ</rt></ruby>を","role":"plain"},{"text":"<ruby>飼<rt>か</rt></ruby>わせて<b>もらいました</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Meine Eltern erlaubten mir, einen Hund zu halten.«","ex":{"jp":"<ruby>両親<rt>りょうしん</rt></ruby>に <ruby>犬<rt>いぬ</rt></ruby>を <ruby>飼<rt>か</rt></ruby>わせて<b>もらいました</b>。","de":"Meine Eltern erlaubten mir, einen Hund zu halten."},"simpel":"Kausativ-て + もらう = »man ließ mich … (ich durfte)«.<br><span class='jp'><ruby>飼<rt>か</rt></ruby>わせて<b>もらった</b></span> = „ich durfte ihn halten“<br>📖 Buch-Satz: 「<ruby>飼<rt>か</rt></ruby>わせて もらった」","rule":"V<sub>lassen-て</sub> + もらう/くれる: jemand erlaubt mir wohlwollend, etwas zu tun — »ich durfte (dank ihm)«. Höflich-dankbar: 〜させていただく."},{"l":22,"t":"13 · lassen-Passiv","de":"gezwungen werden, zu … (musste)","slots":[{"text":"<ruby>毎日<rt>まいにち</rt></ruby>","role":"plain"},{"text":"<ruby>散歩<rt>さんぽ</rt></ruby>に","role":"plain"},{"text":"<ruby>行<rt>い</rt></ruby>くと、<ruby>親<rt>おや</rt></ruby>に","role":"plain"},{"text":"<ruby>約束<rt>やくそく</rt></ruby><b>させられた</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Meine Eltern nahmen mir das Versprechen ab, täglich Gassi zu gehen.«","ex":{"jp":"<ruby>毎日<rt>まいにち</rt></ruby> <ruby>散歩<rt>さんぽ</rt></ruby>に <ruby>行<rt>い</rt></ruby>くと、<ruby>親<rt>おや</rt></ruby>に <ruby>約束<rt>やくそく</rt></ruby><b>させられた</b>。","de":"Meine Eltern nahmen mir das Versprechen ab, täglich Gassi zu gehen."},"simpel":"Kausativ-Passiv = »ich wurde dazu gebracht / musste (widerwillig)«.<br><span class='jp'><ruby>約束<rt>やくそく</rt></ruby><b>させられた</b></span> = „ich musste (es) versprechen“<br>📖 Buch-Satz: 「<ruby>約束<rt>やくそく</rt></ruby>させられた」","rule":"V<sub>lassen-Passiv</sub> (させられる/…される): jemand zwingt mich zu etwas, das ich nicht (gern) tue. う-Verben oft Kurzform (行かされる), する→させられる."},{"l":22,"t":"14 · 〜たがる","de":"(er/sie) will … (3. Person)","slots":[{"text":"クロは","role":"plain"},{"text":"<ruby>朝<rt>あさ</rt></ruby>から","role":"plain"},{"text":"<ruby>散歩<rt>さんぽ</rt></ruby>に","role":"plain"},{"text":"<ruby>行<rt>い</rt></ruby>き<b>たがって</b>","role":"plain"},{"text":"いる。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Kuro will schon seit dem Morgen unbedingt Gassi gehen.«","ex":{"jp":"クロは <ruby>朝<rt>あさ</rt></ruby>から <ruby>散歩<rt>さんぽ</rt></ruby>に <ruby>行<rt>い</rt></ruby>き<b>たがって</b> いる。","de":"Kuro will schon seit dem Morgen unbedingt Gassi gehen."},"simpel":"Wunsch der 3. Person: ます-Stamm + <b>たがる</b>.<br><span class='jp'><ruby>行<rt>い</rt></ruby>き<b>たがって</b> いる</span> = „(der Hund) will unbedingt los“<br>📖 Buch-Satz: 「<ruby>散歩<rt>さんぽ</rt></ruby>に <ruby>行<rt>い</rt></ruby>きたがって」","rule":"たい ist nur für die eigene Person; bei Dritten nutzt man V<sub>ます</sub> + たがる (»zeigt, dass er … will«). Meist たがっている. Ebenso: ほしい → ほしがる."},{"l":22,"t":"15 · 〜たとたん(に)","de":"kaum dass … / im selben Moment","slots":[{"text":"<ruby>窓<rt>まど</rt></ruby>を","role":"plain"},{"text":"<ruby>開<rt>あ</rt></ruby>けた<b>とたん</b>、<ruby>風<rt>かぜ</rt></ruby>が","role":"plain"},{"text":"<ruby>入<rt>はい</rt></ruby>って","role":"plain"},{"text":"きた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Kaum öffnete ich das Fenster, wehte Wind herein.«","ex":{"jp":"<ruby>玄関<rt>げんかん</rt></ruby>を <ruby>出<rt>で</rt></ruby>た<b>とたん</b>、クロが <ruby>走<rt>はし</rt></ruby>り<ruby>出<rt>だ</rt></ruby>した。","de":"Kaum waren wir aus der Haustür, rannte Kuro los."},"simpel":"Zwei Ereignisse Schlag auf Schlag, das zweite überraschend.<br><span class='jp'><ruby>玄関<rt>げんかん</rt></ruby>を <ruby>出<rt>で</rt></ruby>た<b>とたん</b></span> = „kaum aus der Haustür …“<br>📖 Buch-Satz: 「<ruby>玄関<rt>げんかん</rt></ruby>を <ruby>出<rt>で</rt></ruby>たとたん」","rule":"V<sub>た</sub> + とたん(に): »genau in dem Moment, als A geschah, geschah (unerwartet) B«. B ist unkontrolliert und vergangen; kein Wille/Befehl."},{"l":22,"t":"16 · Vマス + 出す","de":"plötzlich los-…","slots":[{"text":"クロは","role":"plain"},{"text":"<ruby>全速力<rt>ぜんそくりょく</rt></ruby>で","role":"plain"},{"text":"<ruby>走<rt>はし</rt></ruby>り<b>出した</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Kuro rannte mit voller Geschwindigkeit los.«","ex":{"jp":"クロは <ruby>全速力<rt>ぜんそくりょく</rt></ruby>で <ruby>走<rt>はし</rt></ruby>り<b>出した</b>。","de":"Kuro rannte mit voller Geschwindigkeit los."},"simpel":"ます-Stamm + <b><ruby>出<rt>だ</rt></ruby>す</b> = »plötzlich anfangen« (losrennen, losweinen).<br><span class='jp'><ruby>走<rt>はし</rt></ruby>り<b>出す</b></span> = „losrennen“<br>📖 Buch-Satz: 「<ruby>全速力<rt>ぜんそくりょく</rt></ruby>で <ruby>走<rt>はし</rt></ruby>り<ruby>出<rt>だ</rt></ruby>す」","rule":"V<sub>ます</sub>-Stamm + 出す: etwas bricht plötzlich, unkontrolliert los. Anders als 〜始める (neutral, Punkt 1) schwingt Überraschung mit."},{"l":22,"t":"17 · 〜(よ)うとする","de":"versuchen / sich bemühen zu … — verneint: sich weigern (Kritik)","slots":[{"text":"<ruby>小<rt>ちい</rt></ruby>さい","role":"plain"},{"text":"<ruby>子<rt>こ</rt></ruby>どもが","role":"plain"},{"text":"<ruby>道<rt>みち</rt></ruby>を","role":"plain"},{"text":"<ruby>渡<rt>わた</rt></ruby>ろう<b>としている</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ein kleines Kind versucht (gerade), die Straße zu überqueren.«","ex":{"jp":"<ruby>小<rt>ちい</rt></ruby>さい <ruby>子<rt>こ</rt></ruby>どもが <ruby>道<rt>みち</rt></ruby>を <ruby>渡<rt>わた</rt></ruby>ろう<b>としている</b>。","de":"Ein kleines Kind versucht (gerade), die Straße zu überqueren."},"simpel":"Willensform + とする = <b>versuchen / gerade ansetzen</b>, etw. zu tun. Verneint <b>〜ようとしない</b> = sich weigern (mit Kritik).<br><span class=\"jp\"><ruby>帰<rt>かえ</rt></ruby>ろう<b>とする</b></span> = „(gerade) heimgehen wollen / es versuchen“<br>📖 Buch-Satz: 「<ruby>帰<rt>かえ</rt></ruby>ろうとする」","rule":"Willensform (〜よう／おう) + とする:<br>① <b>versuchen / sich bemühen</b>, etw. zu tun (<ruby>渡<rt>わた</rt></ruby>ろうとしている = versucht (gerade) hinüberzugehen).<br>② <b>gerade im Begriff sein</b> (<ruby>帰<rt>かえ</rt></ruby>ろうとしたとき = gerade als ich gehen wollte).<br>Verneint <b>〜(よ)うとしない</b> = »macht keine Anstalten / weigert sich« — drückt oft <b>Kritik</b> aus, dass jemand etwas NICHT tut."},{"l":22,"t":"18 · 〜こともある","de":"es kommt (auch) vor, dass …","slots":[{"text":"<ruby>散歩<rt>さんぽ</rt></ruby>の","role":"plain"},{"text":"<ruby>帰<rt>かえ</rt></ruby>りに、コンビニに","role":"plain"},{"text":"<ruby>寄<rt>よ</rt></ruby>る<b>こともある</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Auf dem Rückweg vom Spaziergang schauen wir manchmal am Konbini vorbei.«","ex":{"jp":"<ruby>散歩<rt>さんぽ</rt></ruby>の <ruby>帰<rt>かえ</rt></ruby>りに、コンビニに <ruby>寄<rt>よ</rt></ruby>る<b>こともある</b>。","de":"Auf dem Rückweg vom Spaziergang schauen wir manchmal am Konbini vorbei."},"simpel":"Gelegentliches: »manchmal passiert es, dass …«.<br><span class='jp'><ruby>寄<rt>よ</rt></ruby>る<b>こともある</b></span> = „manchmal schauen wir (dort) vorbei“<br>📖 Buch-Satz: 「コンビニに <ruby>寄<rt>よ</rt></ruby>る こともある」","rule":"V<sub>Grund/ない</sub> + こともある: etwas ist nicht die Regel, kommt aber vor. Stärker »nur manchmal« als schlichtes ときどき; auch 〜ないこともある (»es kommt vor, dass nicht«)."},{"l":22,"t":"19 · lassen-Form + ておく","de":"jdn. (erstmal) … lassen (und so belassen)","slots":[{"text":"クロを","role":"plain"},{"text":"<ruby>外<rt>そと</rt></ruby>で","role":"plain"},{"text":"<ruby>待<rt>ま</rt></ruby>たせて<b>おいて</b>、<ruby>買<rt>か</rt></ruby>い<ruby>物<rt>もの</rt></ruby>を","role":"plain"},{"text":"した。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich ließ Kuro draußen warten und erledigte den Einkauf.«","ex":{"jp":"クロを <ruby>外<rt>そと</rt></ruby>で <ruby>待<rt>ま</rt></ruby>たせて<b>おいて</b>、<ruby>買<rt>か</rt></ruby>い<ruby>物<rt>もの</rt></ruby>を した。","de":"Ich ließ Kuro draußen warten und erledigte den Einkauf."},"simpel":"Kausativ + <b>ておく</b>: »jemanden (vorerst) warten/machen lassen«.<br><span class='jp'><ruby>待<rt>ま</rt></ruby>たせて<b>おいて</b></span> = „ihn warten lassen (und derweil …)“<br>📖 Buch-Satz: 「<ruby>待<rt>ま</rt></ruby>たせて おいて」","rule":"V<sub>lassen-て</sub> + おく: man lässt jemanden in einem Zustand/einer Tätigkeit und belässt es dabei (Vorbereitungs-/Belassen-おく auf den Kausativ angewandt). 待たせておく »warten lassen«, 遊ばせておく »spielen lassen«."},{"l":22,"t":"20 · Passiv + てしまう","de":"😩 (ungewollt) etwas wird MIR angetan — und zwar komplett/leider","slots":[{"text":"<ruby>部屋<rt>へや</rt></ruby><ruby>中<rt>じゅう</rt></ruby>","role":"plain"},{"text":"おもちゃ","role":"plain"},{"text":"だらけに","role":"plain"},{"text":"なって<b>しまった</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Das ganze Zimmer ist (leider) voller Spielzeug geworden.«","ex":{"jp":"クロに <ruby>顔<rt>かお</rt></ruby><ruby>中<rt>じゅう</rt></ruby> なめられて<b>しまいました</b>。","de":"Kuro hat mir das ganze Gesicht abgeschleckt."},"simpel":"😩 <b>»Es wird MIR angetan — und zwar komplett/leider«:</b><br>Passiv-て + <b>しまう</b> = etwas Unangenehmes passiert mir, restlos/ärgerlich.<br>Extra-Baustein: <b>N + <ruby>中<rt>じゅう</rt></ruby></b> = »das GANZE N« (<ruby>顔<rt>かお</rt></ruby><ruby>中<rt>じゅう</rt></ruby> = das ganze Gesicht).<br><span class=\"jp\">クロに <ruby>顔<rt>かお</rt></ruby><ruby>中<rt>じゅう</rt></ruby> なめられて<b>しまいました</b></span> = »Kuro hat mir das GANZE Gesicht abgeschleckt.«<br>📖 Buch-Satz: 「<ruby>顔<rt>かお</rt></ruby><ruby>中<rt>じゅう</rt></ruby> なめられてしまいました」","rule":"<b>Passiv + てしまう</b>: Betroffenheits-Passiv (»mir wird … angetan«) + しまう (»restlos / leider«) = etwas Unangenehmes passiert mir ungewollt und vollständig.<br>Eigener Baustein: <b>N + 中（じゅう）</b> = »das ganze N« (<ruby>顔<rt>かお</rt></ruby>中, <ruby>部屋<rt>へや</rt></ruby>中); bei Zeit <ruby>一日<rt>いちにち</rt></ruby>中 = »den ganzen Tag«."},{"l":23,"t":"21 · N による","de":"per / mittels … (das Werkzeug oder der Weg der Handlung)","slots":[{"text":"お<ruby>申<rt>もう</rt></ruby>し<ruby>込<rt>こ</rt></ruby>みは","role":"plain"},{"text":"インターネット<b>による</b>","role":"plain"},{"text":"<ruby>受付<rt>うけつけ</rt></ruby>のみ","role":"plain"},{"text":"です。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Die Anmeldung erfolgt ausschließlich per Internet.«","ex":{"jp":"お<ruby>申<rt>もう</rt></ruby>し<ruby>込<rt>こ</rt></ruby>みは インターネット<b>による</b> <ruby>受付<rt>うけつけ</rt></ruby>のみ です。","de":"Die Anmeldung erfolgt ausschließlich per Internet."},"simpel":"🚚 <b>による = per / auf dem Weg von</b> — N ist das »Werkzeug« oder der »Transportweg« der Handlung.<br><span class=\"jp\">インターネット<b>による</b> お<ruby>申<rt>もう</rt></ruby>し<ruby>込<rt>こ</rt></ruby>み</span> = »Anmeldung <b>per</b> Internet«<br>📖 Buch-Satz: 「インターネットによる お<ruby>申<rt>もう</rt></ruby>し<ruby>込<rt>こ</rt></ruby>み」","rule":"N₁ + による + N₂ = das <b>Mittel/den Weg</b> für N₂ nennen (»N₂ per N₁«). Formell, typisch in Aushängen. Vor einem Verb: <b>によって</b> (<ruby>話<rt>はな</rt></ruby>し<ruby>合<rt>あ</rt></ruby>いによって <ruby>解決<rt>かいけつ</rt></ruby>).<br>⚠ による hat noch andere Jobs (Ursache, Urheber im Passiv, »je nach«) — hier: das Mittel."},{"l":23,"t":"22 · 〜に<ruby>対<rt>たい</rt></ruby>して","de":"auf … (gerichtet) / gegenüber / im Verhältnis (auf N kommen …)","slots":[{"text":"お<ruby>客<rt>きゃく</rt></ruby>さま<b>に対して</b>","role":"plain"},{"text":"<ruby>失礼<rt>しつれい</rt></ruby>な","role":"plain"},{"text":"<ruby>言<rt>い</rt></ruby>い<ruby>方<rt>かた</rt></ruby>は","role":"plain"},{"text":"しない","role":"plain"},{"text":"こと。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Kunden gegenüber keine unhöflichen Ausdrücke!«","ex":{"jp":"100<ruby>区画<rt>くかく</rt></ruby>の <ruby>募集<rt>ぼしゅう</rt></ruby><b>に対して</b>、300<ruby>件<rt>けん</rt></ruby>の <ruby>応募<rt>おうぼ</rt></ruby>が あった。","de":"Auf die Ausschreibung von 100 Parzellen kamen 300 Bewerbungen."},"simpel":"🎯 <b>Pfeil auf ein Ziel:</b> に対して richtet etwas <b>AUF/GEGEN</b> N.<br>• gegenüber jdm.: <span class=\"jp\">お<ruby>客<rt>きゃく</rt></ruby>さま<b>に対して</b></span> (dem Kunden gegenüber)<br>• Verhältnis: <span class=\"jp\"><ruby>学生<rt>がくせい</rt></ruby>10<ruby>人<rt>にん</rt></ruby><b>に対して</b> <ruby>先生<rt>せんせい</rt></ruby>1<ruby>人<rt>にん</rt></ruby></span> (auf 10 Schüler 1 Lehrer)<br>📖 Buch-Satz: 「100<ruby>区画<rt>くかく</rt></ruby>の <ruby>募集<rt>ぼしゅう</rt></ruby>に対して」","rule":"N + に対して richtet Handlung/Verhältnis <b>AUF</b> N:<br>① <b>gegenüber</b> jdm.: <ruby>親<rt>おや</rt></ruby>に対して<ruby>失礼<rt>しつれい</rt></ruby>だ.<br>② <b>Verhältnis »auf N kommen X«</b>: 10<ruby>人<rt>にん</rt></ruby>に対して1<ruby>人<rt>にん</rt></ruby>.<br>③ <b>Gegensatz »wohingegen«</b>: <ruby>兄<rt>あに</rt></ruby>は<ruby>静<rt>しず</rt></ruby>か、それに対して<ruby>弟<rt>おとうと</rt></ruby>は…"},{"l":23,"t":"23 · 〜ため(に)","de":"wegen / da … (Grund, formell)","slots":[{"text":"<ruby>希望者<rt>きぼうしゃ</rt></ruby>が","role":"plain"},{"text":"<ruby>多<rt>おお</rt></ruby>い<b>ため</b>、<ruby>抽選<rt>ちゅうせん</rt></ruby>と","role":"plain"},{"text":"なります。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Da es viele Interessenten gibt, entscheidet das Los.«","ex":{"jp":"<ruby>希望者<rt>きぼうしゃ</rt></ruby>が <ruby>多<rt>おお</rt></ruby>い<b>ため</b>、<ruby>抽選<rt>ちゅうせん</rt></ruby>と なります。","de":"Da es viele Interessenten gibt, entscheidet das Los."},"simpel":"<b>ため</b> als Grund: »da/weil …« (formell, Aushang-Stil).<br><span class='jp'><ruby>希望者<rt>きぼうしゃ</rt></ruby>が <ruby>多<rt>おお</rt></ruby>い<b>ため</b></span> = „da es viele Interessenten gibt“<br>📖 Buch-Satz: 「<ruby>希望者<rt>きぼうしゃ</rt></ruby>が <ruby>多<rt>おお</rt></ruby>いため」","rule":"Plain + ため(に): nennt formell den Grund (»da/wegen«). In Bekanntmachungen sehr häufig, oft ohne に. Nicht verwechseln mit Zweck-ため (»um zu«, mit Willensverben)."},{"l":23,"t":"24 · 〜につき","de":"pro … (formell; auch: wegen)","slots":[{"text":"お<ruby>申<rt>もう</rt></ruby>し<ruby>込<rt>こ</rt></ruby>みは","role":"plain"},{"text":"1<ruby>家族<rt>かぞく</rt></ruby><b>につき</b>","role":"plain"},{"text":"1<ruby>区画<rt>くかく</rt></ruby>まで。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Anmeldung: maximal eine Parzelle pro Familie.«","ex":{"jp":"お<ruby>申<rt>もう</rt></ruby>し<ruby>込<rt>こ</rt></ruby>みは 1<ruby>家族<rt>かぞく</rt></ruby><b>につき</b> 1<ruby>区画<rt>くかく</rt></ruby>まで。","de":"Anmeldung: maximal eine Parzelle pro Familie."},"simpel":"<b>につき</b> = »pro X« in Regeln/Aushängen.<br><span class='jp'>1<ruby>家族<rt>かぞく</rt></ruby><b>につき</b> 1<ruby>区画<rt>くかく</rt></ruby></span> = „pro Familie eine Parzelle“<br>📖 Buch-Satz: 「1<ruby>家族<rt>かぞく</rt></ruby>につき 1<ruby>区画<rt>くかく</rt></ruby>」","rule":"N + につき: (1) »pro N« bei Mengen/Preisen (formell); (2) »wegen N« auf Schildern (工事中につき). Alltag: 〜あたり (pro) bzw. 〜だから (wegen)."},{"l":23,"t":"25 · 〜のとおり / どおり","de":"📐 genau wie … (1:1 nach Vorlage)","slots":[{"text":"<ruby>説明書<rt>せつめいしょ</rt></ruby><b>のとおり</b>に","role":"plain"},{"text":"<ruby>組<rt>く</rt></ruby>み<ruby>立<rt>た</rt></ruby>てて","role":"plain"},{"text":"ください。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Bitte genau nach Anleitung zusammenbauen.«","ex":{"jp":"<ruby>募集<rt>ぼしゅう</rt></ruby><ruby>内容<rt>ないよう</rt></ruby>は <ruby>下記<rt>かき</rt></ruby><b>のとおり</b>です。","de":"Die Ausschreibungsdetails sind wie unten angegeben."},"simpel":"📐 <b>1:1 wie die Vorlage/Schablone:</b> とおり／どおり = »genau wie …«.<br><span class=\"jp\"><ruby>予定<rt>よてい</rt></ruby><b>どおり</b></span> = »genau nach Plan« · <span class=\"jp\"><ruby>説明書<rt>せつめいしょ</rt></ruby>の<b>とおり</b>に</span> = »genau nach Anleitung«<br>📖 Buch-Satz: 「<ruby>下記<rt>かき</rt></ruby>のとおり」","rule":"»genau wie die Vorlage«:<br>• Direkt an ein Nomen geklebt → <b>どおり</b>: <ruby>予定<rt>よてい</rt></ruby>どおり (nach Plan), <ruby>時間<rt>じかん</rt></ruby>どおり (pünktlich).<br>• Mit の, oder nach einem Verb → <b>とおり</b>: <ruby>説明書<rt>せつめいしょ</rt></ruby>のとおり, <ruby>言<rt>い</rt></ruby>ったとおり.<br>Aushang-Trio: <ruby>下記<rt>かき</rt></ruby>のとおり (wie unten), <ruby>次<rt>つぎ</rt></ruby>のとおり (wie folgt), <ruby>以上<rt>いじょう</rt></ruby>のとおり (wie oben)."},{"l":23,"t":"26 · 〜を<ruby>通<rt>とお</rt></ruby>して","de":"durch/über … (als Weg, Mittel oder Erfahrung)","slots":[{"text":"この","role":"plain"},{"text":"<ruby>地方<rt>ちほう</rt></ruby>は","role":"plain"},{"text":"<ruby>一年<rt>いちねん</rt></ruby>を<b><ruby>通<rt>とお</rt></ruby>して</b>","role":"plain"},{"text":"<ruby>雨<rt>あめ</rt></ruby>が","role":"plain"},{"text":"<ruby>少<rt>すく</rt></ruby>ない。","role":"plain"}],"gloss":"Baue den Beispielsatz: »In dieser Region regnet es das ganze Jahr über wenig.«","ex":{"jp":"<ruby>野菜<rt>やさい</rt></ruby><ruby>作<rt>づく</rt></ruby>りを<b><ruby>通<rt>とお</rt></ruby>して</b>、<ruby>自然<rt>しぜん</rt></ruby>の <ruby>大切<rt>たいせつ</rt></ruby>さを <ruby>学<rt>まな</rt></ruby>べます。","de":"Über den Gemüseanbau lernt man den Wert der Natur."},"simpel":"🚇 <b>Durch einen Kanal/Tunnel hindurch:</b> を通して = etwas kommt <b>DURCH</b> N zu dir.<br><span class=\"jp\">スポーツを<b>通して</b> <ruby>友<rt>とも</rt></ruby>だちが できた</span> = »Durch den Sport habe ich Freunde gefunden« (Sport = der Durchgang)<br>📖 Buch-Satz: 「<ruby>野菜<rt>やさい</rt></ruby><ruby>作<rt>づく</rt></ruby>りを<ruby>通<rt>とお</rt></ruby>して」","rule":"N + を通して: N ist der <b>Kanal/Weg</b>, durch den etwas geschieht (Mittel oder Erfahrung). Auch Zeitraum: <ruby>一年<rt>いちねん</rt></ruby>を通して = »das ganze Jahr hindurch«. を通じて ist etwas schriftlicher."},{"l":23,"t":"27 · N のような N","de":"(so etwas) wie … (Beispiel)","slots":[{"text":"<ruby>彼女<rt>かのじょ</rt></ruby>は","role":"plain"},{"text":"<ruby>先生<rt>せんせい</rt></ruby><b>のように</b>","role":"plain"},{"text":"ていねいに","role":"plain"},{"text":"<ruby>教<rt>おし</rt></ruby>えて","role":"plain"},{"text":"くれた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Sie erklärte es mir sorgfältig wie eine Lehrerin.«","ex":{"jp":"<ruby>収穫祭<rt>しゅうかくさい</rt></ruby><b>のような</b> <ruby>楽<rt>たの</rt></ruby>しい イベントも あります。","de":"Es gibt auch schöne Veranstaltungen wie das Erntefest."},"simpel":"<b>のような</b> nennt ein Beispiel vor einem Nomen.<br><span class='jp'>パーティー<b>のような</b> イベント</span> = „Veranstaltungen wie eine Party“<br>📖 Buch-Satz: 「パーティーのような <ruby>楽<rt>たの</rt></ruby>しい イベント」","rule":"N₁ + のような + N₂: N₁ ist Beispiel oder Vergleichsbild für N₂. Adverbial: のように. Beispiel-Funktion (»wie z. B.«) und Vergleich (»wie ein/e«) — Kontext entscheidet."},{"l":23,"t":"28 · 〜によれば","de":"laut … (Quelle; + そう/ということ)","slots":[{"text":"ご<ruby>利用<rt>りよう</rt></ruby>の","role":"plain"},{"text":"<ruby>方<rt>かた</rt></ruby>の","role":"plain"},{"text":"お<ruby>話<rt>はなし</rt></ruby><b>によれば</b>、<ruby>週末<rt>しゅうまつ</rt></ruby>が","role":"plain"},{"text":"<ruby>楽<rt>たの</rt></ruby>しみに","role":"plain"},{"text":"なった<b>ということです</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Nach Aussage der Nutzer freuen sie sich nun aufs Wochenende.«","ex":{"jp":"ご<ruby>利用<rt>りよう</rt></ruby>の <ruby>方<rt>かた</rt></ruby>の お<ruby>話<rt>はなし</rt></ruby><b>によれば</b>、<ruby>週末<rt>しゅうまつ</rt></ruby>が <ruby>楽<rt>たの</rt></ruby>しみに なった<b>ということです</b>。","de":"Nach Aussage der Nutzer freuen sie sich nun aufs Wochenende."},"simpel":"<b>によれば</b> nennt die Quelle: »laut/nach Aussage von …«.<br><span class='jp'><ruby>利用者<rt>りようしゃ</rt></ruby>の <ruby>話<rt>はなし</rt></ruby><b>によれば</b></span> = „laut den Nutzern …“<br>📖 Buch-Satz: 「<ruby>利用<rt>りよう</rt></ruby>されている <ruby>方<rt>かた</rt></ruby>の お<ruby>話<rt>はなし</rt></ruby>によれば」","rule":"N + によれば/によると markiert die Informationsquelle; das Satzende trägt Hörensagen (〜そうだ/〜ということだ/〜らしい). によれば wirkt eine Spur schriftlicher als によると."},{"l":23,"t":"29 · 〜ということだ/です","de":"es heißt, dass … (Wiedergabe)","slots":[{"text":"みなさん、<ruby>家族<rt>かぞく</rt></ruby>との","role":"plain"},{"text":"<ruby>時間<rt>じかん</rt></ruby>が","role":"plain"},{"text":"<ruby>増<rt>ふ</rt></ruby>えて","role":"plain"},{"text":"<ruby>楽<rt>たの</rt></ruby>しかった<b>ということです</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Es heißt, alle hätten mehr schöne Familienzeit gehabt.«","ex":{"jp":"みなさん、<ruby>家族<rt>かぞく</rt></ruby>との <ruby>時間<rt>じかん</rt></ruby>が <ruby>増<rt>ふ</rt></ruby>えて <ruby>楽<rt>たの</rt></ruby>しかった<b>ということです</b>。","de":"Es heißt, alle hätten mehr schöne Familienzeit gehabt."},"simpel":"Zitiert Gehörtes wörtlich-neutral: »(sie sagen,) dass es schön war«.<br><span class='jp'><ruby>楽<rt>たの</rt></ruby>しかった<b>ということです</b></span> = „es heißt, es sei schön gewesen“<br>📖 Buch-Satz: 「<ruby>楽<rt>たの</rt></ruby>しかった ということです」","rule":"[Satz Plain] + ということだ: gibt Gehörtes/Gelesenes wieder, ohne es zu bewerten — schriftlicher als 〜そうだ. Auch als Schluss: »das bedeutet …« (つまり…ということだ)."},{"l":23,"t":"30 · 〜について","de":"über / zu … (Thema)","slots":[{"text":"<ruby>活動<rt>かつどう</rt></ruby><b>について</b>","role":"plain"},{"text":"<ruby>詳<rt>くわ</rt></ruby>しい","role":"plain"},{"text":"ことは、ホームページを","role":"plain"},{"text":"ご<ruby>覧<rt>らん</rt></ruby>ください。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Näheres zu den Aktivitäten finden Sie auf der Homepage.«","ex":{"jp":"<ruby>活動<rt>かつどう</rt></ruby><b>について</b> <ruby>詳<rt>くわ</rt></ruby>しい ことは、ホームページを ご<ruby>覧<rt>らん</rt></ruby>ください。","de":"Näheres zu den Aktivitäten finden Sie auf der Homepage."},"simpel":"<b>について</b> markiert das Thema: »über/zu X«.<br><span class='jp'><ruby>活動<rt>かつどう</rt></ruby><b>について</b> <ruby>詳<rt>くわ</rt></ruby>しくは …</span> = „Näheres zu den Aktivitäten …“<br>📖 Buch-Satz: 「<ruby>農園<rt>のうえん</rt></ruby>の <ruby>活動<rt>かつどう</rt></ruby>について」","rule":"N + について: »über N (sprechen/schreiben/fragen)«. Attributiv についての + N. In Aushängen: 〜について詳しくは… (»Näheres zu … finden Sie …«). Formeller: に関して."},{"l":24,"t":"31 · 〜てる(んだ)","de":"gesprochenes ている (+ Erklär-んだ)","slots":[{"text":"<ruby>大会<rt>たいかい</rt></ruby>の","role":"plain"},{"text":"ために","role":"plain"},{"text":"<ruby>毎日<rt>まいにち</rt></ruby>","role":"plain"},{"text":"<ruby>練習<rt>れんしゅう</rt></ruby>して<b>るんだ</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Für den Wettkampf trainiere ich nämlich jeden Tag.«","ex":{"jp":"<ruby>大会<rt>たいかい</rt></ruby>の ために <ruby>毎日<rt>まいにち</rt></ruby> <ruby>練習<rt>れんしゅう</rt></ruby>して<b>るんだ</b>。","de":"Für den Wettkampf trainiere ich nämlich jeden Tag."},"simpel":"Im Gespräch schrumpft <b>ている → てる</b>; <b>んだ</b> erklärt.<br><span class='jp'><ruby>練習<rt>れんしゅう</rt></ruby>して<b>るんだ</b></span> = „ich trainiere nämlich (gerade jeden Tag)“<br>📖 Buch-Satz: 「<ruby>毎日<rt>まいにち</rt></ruby> <ruby>練習<rt>れんしゅう</rt></ruby>してるんだ」","rule":"ている wird gesprochen fast immer zu てる (している→してる, しています→してます). んだ/んです fügt die Erklär-/Hintergrund-Nuance hinzu. Zusammen: 〜てるんだ »(weißt du,) ich … nämlich gerade«."},{"l":24,"t":"32 · 〜なきゃ","de":"muss … (gesprochen für なければならない)","slots":[{"text":"もう","role":"plain"},{"text":"こんな","role":"plain"},{"text":"<ruby>時間<rt>じかん</rt></ruby>!","role":"plain"},{"text":"<ruby>帰<rt>かえ</rt></ruby>ら<b>なきゃ</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Schon so spät! Ich muss heim.«","ex":{"jp":"<ruby>友<rt>とも</rt></ruby>だちの <ruby>大会<rt>たいかい</rt></ruby>だから、<ruby>応援<rt>おうえん</rt></ruby>に <ruby>行<rt>い</rt></ruby>か<b>なきゃ</b>。","de":"Es ist der Wettkampf meines Freundes — da muss ich anfeuern!"},"simpel":"<b>なきゃ</b> = geschrumpftes なければ(ならない): »ich muss …«.<br><span class='jp'><ruby>行<rt>い</rt></ruby>か<b>なきゃ</b></span> = „da muss ich hin!“<br>📖 Buch-Satz: 「<ruby>応援<rt>おうえん</rt></ruby>に <ruby>行<rt>い</rt></ruby>かなきゃ」","rule":"V<sub>ない</sub>-Stamm + なきゃ (= なければならない) bzw. なくちゃ (= なくてはいけない): gesprochene Pflicht. Das ならない/いけない fällt oft komplett weg."},{"l":24,"t":"33 · 〜っけ","de":"wie war das nochmal? (Vergewisserung)","slots":[{"text":"この","role":"plain"},{"text":"<ruby>話<rt>はなし</rt></ruby>、<ruby>前<rt>まえ</rt></ruby>に","role":"plain"},{"text":"した<b>っけ</b>?","role":"plain"}],"gloss":"Baue den Beispielsatz: »Habe ich dir das schon mal erzählt?«","ex":{"jp":"<ruby>大会<rt>たいかい</rt></ruby>、<ruby>君<rt>きみ</rt></ruby>も <ruby>出<rt>で</rt></ruby>るん<b>だっけ</b>?","de":"Du machst doch auch beim Wettkampf mit — oder wie war das?"},"simpel":"<b>っけ</b> fragt nach halb Vergessenem: »… nochmal?«.<br><span class='jp'><ruby>出<rt>で</rt></ruby>るん<b>だっけ</b></span> = „du machst doch mit, oder (wie war das)?“<br>📖 Buch-Satz: 「<ruby>出<rt>で</rt></ruby>るんだっけ」","rule":"Satz + っけ: der Sprecher vergewissert sich über etwas, das er wusste, aber vergessen hat. Anschluss meist über だ/た: 〜だっけ / 〜たっけ (何時だっけ, 会ったっけ)."},{"l":24,"t":"34 · N って","de":"»was X angeht / X, sowas wie …« (+Plus: 〜みたい)","slots":[{"text":"<ruby>強<rt>つよ</rt></ruby>い","role":"plain"},{"text":"<ruby>選手<rt>せんしゅ</rt></ruby><b>って</b>、<ruby>練習<rt>れんしゅう</rt></ruby>の","role":"plain"},{"text":"<ruby>量<rt>りょう</rt></ruby>が","role":"plain"},{"text":"<ruby>違<rt>ちが</rt></ruby>うんだね。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Starke Athleten — bei denen ist das Trainingspensum einfach anders.«","ex":{"jp":"<ruby>強<rt>つよ</rt></ruby>い <ruby>選手<rt>せんしゅ</rt></ruby><b>って</b>、<ruby>練習<rt>れんしゅう</rt></ruby>の <ruby>量<rt>りょう</rt></ruby>が <ruby>違<rt>ちが</rt></ruby>うんだね。","de":"Starke Athleten — bei denen ist das Trainingspensum einfach anders."},"simpel":"<b>って</b> hebt lockeres Thema hervor: »starke Athleten, die sind doch …«.<br><span class='jp'><ruby>強<rt>つよ</rt></ruby>い <ruby>選手<rt>せんしゅ</rt></ruby><b>って</b></span> = „starke Schwimmer (was die angeht) …“<br>📖 Buch-Satz: 「<ruby>強<rt>つよ</rt></ruby>い <ruby>選手<rt>せんしゅ</rt></ruby>って」","rule":"N + って als lockerer Themen-/Definitionsmarker (= は/というのは): leitet eine allgemeine Aussage oder Nachfrage über N ein. +Plus im Buch: 〜みたい (»wie/scheinbar«, Punkt-übergreifend)."},{"l":24,"t":"35 · V たって","de":"selbst wenn … (gesprochenes ても)","slots":[{"text":"<ruby>今<rt>いま</rt></ruby>から","role":"plain"},{"text":"がんばっ<b>たって</b>、もう","role":"plain"},{"text":"<ruby>間<rt>ま</rt></ruby>に<ruby>合<rt>あ</rt></ruby>わないよ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Selbst wenn du dich jetzt noch anstrengst, reicht es nicht mehr.«","ex":{"jp":"<ruby>今<rt>いま</rt></ruby>から がんばっ<b>たって</b>、もう <ruby>間<rt>ま</rt></ruby>に<ruby>合<rt>あ</rt></ruby>わないよ。","de":"Selbst wenn du dich jetzt noch anstrengst, reicht es nicht mehr."},"simpel":"<b>たって</b> = lockeres ても: »selbst wenn du dich anstrengst …«.<br><span class='jp'>がんばっ<b>たって</b></span> = „selbst wenn man sich anstrengt“<br>📖 Buch-Satz: 「がんばったって」","rule":"V<sub>た</sub>-Basis + って = 〜ても in gesprochener Sprache: »selbst wenn / auch wenn«. Verneint: なくたって (= なくても). Adjektive: 高くたって."},{"l":24,"t":"36 · 〜に決まってる","de":"das ist doch todsicher …","slots":[{"text":"[Aussage]","role":"cond"},{"text":"に<ruby>決<rt>き</rt></ruby>まってる","role":"plain","label":"doch klar!"}],"gloss":"»Das ist doch todsicher so!« — salopp-emotional; formeller: に違いない.","ex":{"jp":"<ruby>優勝<rt>ゆうしょう</rt></ruby>なんて <ruby>無理<rt>むり</rt></ruby><b>に決まってる</b>よ。","de":"Den Sieg holen? Das ist doch todsicher unmöglich!"},"simpel":"Volle Überzeugung, salopp: »ist doch klar!«.<br><span class='jp'><ruby>無理<rt>むり</rt></ruby><b>に決まってる</b>よ</span> = „das ist doch todsicher unmöglich!“<br>📖 Buch-Satz: 「<ruby>無理<rt>むり</rt></ruby>に<ruby>決<rt>き</rt></ruby>まってるよ」","rule":"Plain/N + に決まっている (gesprochen 決まってる): subjektive Gewissheit »ganz sicher, logisch!«. Emotionaler/salopper als に違いない."},{"l":24,"t":"37 · 〜なきゃだめ(じゃない)","de":"du musst doch …! (Vorwurf)","slots":[{"text":"もっと","role":"plain"},{"text":"<ruby>早<rt>はや</rt></ruby>く","role":"plain"},{"text":"<ruby>言<rt>い</rt></ruby>わ<b>なきゃ","role":"plain"},{"text":"だめじゃない</b>か。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Das hättest du doch früher sagen müssen!«","ex":{"jp":"<ruby>友<rt>とも</rt></ruby>だちの <ruby>大会<rt>たいかい</rt></ruby>なんだから、<ruby>行<rt>い</rt></ruby>か<b>なきゃ だめじゃない</b>。","de":"Es ist der Wettkampf deines Freundes — da musst du doch hin!"},"simpel":"Pflicht + Vorwurf: »du MUSST doch hin, oder etwa nicht?!«.<br><span class='jp'><ruby>行<rt>い</rt></ruby>か<b>なきゃ だめじゃない</b></span> = „du musst doch hingehen!“<br>📖 Buch-Satz: 「<ruby>行<rt>い</rt></ruby>かなきゃ だめじゃない」","rule":"V<sub>なきゃ</sub> + だめ = »muss unbedingt« (gesprochen). Angehängtes じゃない(か) macht daraus einen Vorwurf/eine nachdrückliche Bestätigung: »… doch wohl!«."},{"l":24,"t":"38 · N だって","de":"sogar … / auch … (betont)","slots":[{"text":"<ruby>強<rt>つよ</rt></ruby>い","role":"plain"},{"text":"<ruby>選手<rt>せんしゅ</rt></ruby><b>だって</b>、<ruby>緊張<rt>きんちょう</rt></ruby>する","role":"plain"},{"text":"ことは","role":"plain"},{"text":"ある。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Sogar starke Athleten sind manchmal nervös.«","ex":{"jp":"<ruby>強<rt>つよ</rt></ruby>い <ruby>選手<rt>せんしゅ</rt></ruby><b>だって</b>、<ruby>緊張<rt>きんちょう</rt></ruby>する ことは ある。","de":"Sogar starke Athleten sind manchmal nervös."},"simpel":"<b>だって</b> nach Nomen = »sogar/selbst X«.<br><span class='jp'><ruby>強<rt>つよ</rt></ruby>い <ruby>選手<rt>せんしゅ</rt></ruby><b>だって</b> <ruby>負<rt>ま</rt></ruby>ける</span> = „sogar starke Athleten verlieren“<br>📖 Buch-Satz: 「<ruby>強<rt>つよ</rt></ruby>い <ruby>選手<rt>せんしゅ</rt></ruby>だって」","rule":"N + だって: (1) »sogar/selbst« (= でも/さえ), (2) »auch« (私だって = ich doch auch). Mit Fragewort + だって = »jede/r« (だれだって). Nur gesprochen."},{"l":24,"t":"39 · 〜みたいだ","de":"scheint … / anscheinend (gesprochen)","slots":[{"text":"<ruby>毎日<rt>まいにち</rt></ruby>","role":"plain"},{"text":"<ruby>朝<rt>あさ</rt></ruby>","role":"plain"},{"text":"5<ruby>時<rt>じ</rt></ruby>から","role":"plain"},{"text":"<ruby>練習<rt>れんしゅう</rt></ruby>。<ruby>大変<rt>たいへん</rt></ruby><b>みたいだ</b>ね。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Jeden Tag ab 5 Uhr Training — scheint hart zu sein.«","ex":{"jp":"<ruby>毎日<rt>まいにち</rt></ruby> <ruby>朝<rt>あさ</rt></ruby> 5<ruby>時<rt>じ</rt></ruby>から <ruby>練習<rt>れんしゅう</rt></ruby>。<ruby>大変<rt>たいへん</rt></ruby><b>みたいだ</b>ね。","de":"Jeden Tag ab 5 Uhr Training — scheint hart zu sein."},"simpel":"<b>みたい</b> = gesprochenes ようだ: »scheint wohl …«.<br><span class='jp'><ruby>大変<rt>たいへん</rt></ruby><b>みたいだ</b>ね</span> = „scheint hart zu sein, was?“<br>📖 Buch-Satz: 「<ruby>大変<rt>たいへん</rt></ruby>みたいだね」","rule":"Plain/N + みたいだ: Vermutung aus Beobachtung (»scheint«), Vergleich (»wie«: みたいに/みたいな). Lockerer als ようだ; beugt wie な-Adjektiv."},{"l":24,"t":"40 · 〜ばよかった","de":"hätte ich (doch) … sollen (Reue)","slots":[{"text":"ぼくも","role":"plain"},{"text":"<ruby>水泳<rt>すいえい</rt></ruby>を","role":"plain"},{"text":"<ruby>続<rt>つづ</rt></ruby>けて","role":"plain"},{"text":"おけ<b>ば","role":"plain"},{"text":"よかった</b>","role":"plain"},{"text":"なあ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Hätte ich doch auch mit dem Schwimmen weitergemacht …«","ex":{"jp":"ぼくも <ruby>水泳<rt>すいえい</rt></ruby>を <ruby>続<rt>つづ</rt></ruby>けて おけ<b>ば よかった</b> なあ。","de":"Hätte ich doch auch mit dem Schwimmen weitergemacht …"},"simpel":"Reue: »hätte ich doch …!« — ば-Form + よかった.<br><span class='jp'>やって おけ<b>ば よかった</b></span> = „hätte ich es (vorher) mal gemacht“<br>📖 Buch-Satz: 「やって おけば よかった」","rule":"V<sub>ば</sub> + よかった: Bedauern über Nicht-Getanes (»hätte ich doch …«). Verneint: なければよかった (»hätte ich bloß nicht …«). Hier mit ておく: やっておけばよかった »hätte ich vorbereitend tun sollen«."},{"l":24,"t":"41 · 〜てばかりいる","de":"nichts als … / andauernd nur …","slots":[{"text":"<ruby>弟<rt>おとうと</rt></ruby>は","role":"plain"},{"text":"ゲームを","role":"plain"},{"text":"して<b>ばかり","role":"plain"},{"text":"いる</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Mein kleiner Bruder zockt andauernd nur.«","ex":{"jp":"<ruby>高校<rt>こうこう</rt></ruby><ruby>時代<rt>じだい</rt></ruby>、ぼくは <ruby>遊<rt>あそ</rt></ruby>んで<b>ばかり いた</b>。","de":"In der Oberschulzeit habe ich nichts als gefaulenzt."},"simpel":"<b>てばかりいる</b> = »macht nichts anderes als …« (leicht tadelnd).<br><span class='jp'><ruby>遊<rt>あそ</rt></ruby>んで<b>ばかり いた</b></span> = „habe nur gespielt/gefaulenzt“<br>📖 Buch-Satz: 「<ruby>遊<rt>あそ</rt></ruby>んで ばかり いた」","rule":"V<sub>て</sub> + ばかりいる: jemand tut andauernd nur eine Sache (meist kritisch/bereuend). Auch N + ばかり (甘いものばかり食べる »isst nur Süßes«)."},{"l":25,"t":"42 · N のように","de":"(genau) wie … (Vergleich)","slots":[{"text":"<ruby>本当<rt>ほんとう</rt></ruby>の","role":"plain"},{"text":"ハム<b>のように</b>","role":"plain"},{"text":"おいしく","role":"plain"},{"text":"できます。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Er gelingt so lecker wie echter Schinken.«","ex":{"jp":"<ruby>本当<rt>ほんとう</rt></ruby>の ハム<b>のように</b> おいしく できます。","de":"Er gelingt so lecker wie echter Schinken."},"simpel":"<b>のように</b> vergleicht: »wie echter Schinken«.<br><span class='jp'><ruby>本当<rt>ほんとう</rt></ruby>の ハム<b>のように</b> おいしい</span> = „lecker wie echter Schinken“<br>📖 Buch-Satz: 「<ruby>本当<rt>ほんとう</rt></ruby>の ハムのように」","rule":"N + のように + V/Adj: Vergleich »(genau) wie N«. Vor Nomen のような (Punkt 27). Nach Verben heißt ように auch »damit/so dass« — Kontext beachten."},{"l":25,"t":"43 · 〜はもちろん","de":"… sowieso, und auch …","slots":[{"text":"サンドイッチ<b>は","role":"plain"},{"text":"もちろん</b>、サラダや","role":"plain"},{"text":"パスタ<b>にも</b>","role":"plain"},{"text":"<ruby>合<rt>あ</rt></ruby>います。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Passt natürlich zu Sandwiches — aber auch zu Salat und Pasta.«","ex":{"jp":"サンドイッチ<b>は もちろん</b>、サラダや パスタ<b>にも</b> <ruby>合<rt>あ</rt></ruby>います。","de":"Passt natürlich zu Sandwiches — aber auch zu Salat und Pasta."},"simpel":"A ist klar, B kommt dazu: »für Sandwiches sowieso, aber auch …«.<br><span class='jp'>サンドイッチ<b>は もちろん</b>、ほかの <ruby>料理<rt>りょうり</rt></ruby><b>にも</b></span><br>📖 Buch-Satz: 「サンドイッチは もちろん、ほかの <ruby>料理<rt>りょうり</rt></ruby>にも」","rule":"N₁ + はもちろん、N₂ + も/にも: »N₁ versteht sich von selbst — und auch N₂«. Erst das Offensichtliche, dann die Erweiterung. Schriftlicher: はもとより."},{"l":25,"t":"44 · 〜でも〜でも / どちらでも","de":"egal ob … oder …","slots":[{"text":"とり<ruby>肉<rt>にく</rt></ruby>は","role":"plain"},{"text":"もも<ruby>肉<rt>にく</rt></ruby><b>でも</b>","role":"plain"},{"text":"むね<ruby>肉<rt>にく</rt></ruby><b>でも</b>、<b>どちらでも</b>","role":"plain"},{"text":"いいです。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Beim Hähnchen geht Keule oder Brust — beides ist in Ordnung.«","ex":{"jp":"とり<ruby>肉<rt>にく</rt></ruby>は もも<ruby>肉<rt>にく</rt></ruby><b>でも</b> むね<ruby>肉<rt>にく</rt></ruby><b>でも</b>、<b>どちらでも</b> いいです。","de":"Beim Hähnchen geht Keule oder Brust — beides ist in Ordnung."},"simpel":"<b>でも…でも</b> = »egal ob A oder B«; <b>どちらでも</b> = »beides geht«.<br><span class='jp'>もも<ruby>肉<rt>にく</rt></ruby><b>でも</b> むね<ruby>肉<rt>にく</rt></ruby><b>でも</b> いい</span><br>📖 Buch-Satz: 「もも<ruby>肉<rt>にく</rt></ruby>でも むね<ruby>肉<rt>にく</rt></ruby>でも、どちらでも」","rule":"N + でも + N + でも (+いい/かまわない): beide Optionen sind zulässig. Fragewort + でも = totale Offenheit: どちらでも (beides), 何でも (alles), いつでも (jederzeit)."},{"l":25,"t":"45 · 〜のかわりに","de":"anstelle von … / als Ersatz","slots":[{"text":"はちみつ<b>の","role":"plain"},{"text":"かわりに</b>","role":"plain"},{"text":"さとうを","role":"plain"},{"text":"<ruby>使<rt>つか</rt></ruby>っても","role":"plain"},{"text":"いいです。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Statt Honig kann man auch Zucker verwenden.«","ex":{"jp":"はちみつ<b>の かわりに</b> さとうを <ruby>使<rt>つか</rt></ruby>っても いいです。","de":"Statt Honig kann man auch Zucker verwenden."},"simpel":"<b>かわりに</b> = »statt/als Ersatz für«.<br><span class='jp'>はちみつ<b>の かわりに</b> さとう</span> = „statt Honig Zucker“<br>📖 Buch-Satz: 「はちみつの かわりに」","rule":"N + の + かわりに: Ersatz (»statt N«). V<sub>Grund/た</sub> + かわりに: Ausgleich (»dafür, im Gegenzug«). Beide Lesarten sehr häufig."},{"l":25,"t":"46 · 〜ずに","de":"ohne zu … (schriftlich für ないで)","slots":[{"text":"とり<ruby>肉<rt>にく</rt></ruby>は","role":"plain"},{"text":"<ruby>切<rt>き</rt></ruby>ら<b>ずに</b>、そのまま","role":"plain"},{"text":"<ruby>使<rt>つか</rt></ruby>います。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Das Hähnchen wird nicht geschnitten, sondern im Ganzen verwendet.«","ex":{"jp":"とり<ruby>肉<rt>にく</rt></ruby>は <ruby>切<rt>き</rt></ruby>ら<b>ずに</b>、そのまま <ruby>使<rt>つか</rt></ruby>います。","de":"Das Hähnchen wird nicht geschnitten, sondern im Ganzen verwendet."},"simpel":"<b>ずに</b> = »ohne zu …« (eine Spur schriftlicher als ないで).<br><span class='jp'><ruby>切<rt>き</rt></ruby>ら<b>ずに</b> そのまま</span> = „ohne es zu schneiden, im Ganzen“<br>📖 Buch-Satz: 「とり<ruby>肉<rt>にく</rt></ruby>を <ruby>切<rt>き</rt></ruby>らずに」","rule":"V<sub>ない</sub>-Stamm + ずに = 〜ないで (»ohne zu V«). Ausnahme: する → せずに. In Rezepten und Anleitungen sehr üblich."},{"l":25,"t":"47 · 〜たまま","de":"im (unveränderten) Zustand belassen","slots":[{"text":"<ruby>電気<rt>でんき</rt></ruby>を","role":"plain"},{"text":"つけた<b>まま</b>","role":"plain"},{"text":"<ruby>寝<rt>ね</rt></ruby>て","role":"plain"},{"text":"しまった。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich bin bei angelassenem Licht eingeschlafen.«","ex":{"jp":"ビニール<ruby>袋<rt>ぶくろ</rt></ruby>に <ruby>入<rt>い</rt></ruby>れた<b>まま</b>、お<ruby>湯<rt>ゆ</rt></ruby>で ゆでます。","de":"Im Plastikbeutel belassen in heißem Wasser garen."},"simpel":"<b>たまま</b> = »so belassen, wie es ist«.<br><span class='jp'><ruby>袋<rt>ふくろ</rt></ruby>に <ruby>入<rt>い</rt></ruby>れた<b>まま</b> ゆでる</span> = „im Beutel (gelassen) kochen“<br>📖 Buch-Satz: 「ビニール<ruby>袋<rt>ぶくろ</rt></ruby>に <ruby>入<rt>い</rt></ruby>れたまま」","rule":"V<sub>た</sub> + まま: der einmal hergestellte Zustand bleibt bestehen, während etwas anderes geschieht. Auch N + の + まま (そのまま »einfach so«)."},{"l":25,"t":"48 · ます-Stamm als Verbinder","de":"Sätze im Schriftstil mit dem ます-Stamm verketten","slots":[{"text":"<ruby>材料<rt>ざいりょう</rt></ruby>を","role":"plain"},{"text":"ボウルに","role":"plain"},{"text":"<ruby>入<rt>い</rt></ruby>れ、よく","role":"plain"},{"text":"<ruby>混<rt>ま</rt></ruby>ぜます。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Die Zutaten in eine Schüssel geben und gut vermischen.«","ex":{"jp":"<ruby>材料<rt>ざいりょう</rt></ruby>を ボウルに <ruby>入<rt>い</rt></ruby>れ、よく <ruby>混<rt>ま</rt></ruby>ぜます。","de":"Die Zutaten in eine Schüssel geben und gut vermischen."},"simpel":"📝 <b>Rezept-/Telegrammstil:</b> Geschrieben lässt man das <code>て</code> weg und verkettet mit dem <b>bloßen ます-Stamm</b> + Komma — wie abgehackte Kochschritte.<br><span class=\"jp\">ボウルに <ruby>入<rt>い</rt></ruby>れ、<ruby>混<rt>ま</rt></ruby>ぜる</span> = »in die Schüssel geben und mischen«<br>📖 Buch-Satz: 「ボウルに <ruby>入<rt>い</rt></ruby>れ、…」","rule":"て-Form → bloßer ます-Stamm + Komma: <ruby>入<rt>い</rt></ruby>れて→入れ、 / <ruby>混<rt>ま</rt></ruby>ぜて→混ぜ、. Nur geschrieben (Rezept, Bericht, Zeitung). Bedeutung = て-Form; Zeit &amp; Höflichkeit nur am letzten Verb."},{"l":25,"t":"49 · 〜たところへ/に","de":"genau dahin/da, wo(hin) gerade …","slots":[{"text":"うわさを","role":"plain"},{"text":"して","role":"plain"},{"text":"いた<b>ところへ</b>、<ruby>本人<rt>ほんにん</rt></ruby>が","role":"plain"},{"text":"<ruby>現<rt>あらわ</rt></ruby>れた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Gerade als wir über ihn redeten, tauchte er selbst auf.«","ex":{"jp":"お<ruby>湯<rt>ゆ</rt></ruby>が ふっとうした<b>ところへ</b>、<ruby>袋<rt>ふくろ</rt></ruby>ごと <ruby>入<rt>い</rt></ruby>れます。","de":"Sobald das Wasser kocht, den ganzen Beutel hineingeben."},"simpel":"<b>たところへ</b> = »genau in dem Moment/dorthin, wo …«.<br><span class='jp'>ふっとうした<b>ところへ</b> <ruby>入<rt>い</rt></ruby>れる</span> = „(genau) ins kochende Wasser geben“<br>📖 Buch-Satz: 「ふっとうした ところへ」","rule":"V<sub>た</sub> + ところへ/に: in die Situation, die gerade entstanden ist, kommt etwas hinzu (räumlich oder zeitlich: »gerade als …, da …«)."},{"l":25,"t":"50 · Vマス + きる","de":"restlos / ganz zu Ende …","slots":[{"text":"<ruby>保存料<rt>ほぞんりょう</rt></ruby>が","role":"plain"},{"text":"ないので、2、3<ruby>日<rt>にち</rt></ruby>で","role":"plain"},{"text":"<ruby>食<rt>た</rt></ruby>べ<b>きって</b>","role":"plain"},{"text":"ください。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ohne Konservierungsstoffe — bitte binnen 2–3 Tagen aufessen.«","ex":{"jp":"<ruby>保存料<rt>ほぞんりょう</rt></ruby>が ないので、2、3<ruby>日<rt>にち</rt></ruby>で <ruby>食<rt>た</rt></ruby>べ<b>きって</b> ください。","de":"Ohne Konservierungsstoffe — bitte binnen 2–3 Tagen aufessen."},"simpel":"<b>きる</b> = komplett aufbrauchen: »innerhalb von 2–3 Tagen aufessen«.<br><span class='jp'><ruby>食<rt>た</rt></ruby>べ<b>きって</b> ください</span> = „bitte ganz aufessen“<br>📖 Buch-Satz: 「2、3<ruby>日<rt>にち</rt></ruby>で <ruby>食<rt>た</rt></ruby>べきって ください」","rule":"V<sub>ます</sub>-Stamm + きる = eine Handlung vollständig zu Ende führen (使いきる aufbrauchen, 読みきる durchlesen). Negativ きれない = »nicht ganz schaffen« (食べきれない)."},{"l":26,"t":"51 · 〜のおかげで","de":"dank … (positives Ergebnis)","slots":[{"text":"<ruby>豊<rt>ゆた</rt></ruby>かな","role":"plain"},{"text":"<ruby>自然<rt>しぜん</rt></ruby>の<b>おかげで</b>、おいしい","role":"plain"},{"text":"<ruby>米<rt>こめ</rt></ruby>が","role":"plain"},{"text":"<ruby>育<rt>そだ</rt></ruby>ちます。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Dank der reichen Natur gedeiht köstlicher Reis.«","ex":{"jp":"<ruby>豊<rt>ゆた</rt></ruby>かな <ruby>自然<rt>しぜん</rt></ruby>の<b>おかげで</b>、おいしい <ruby>米<rt>こめ</rt></ruby>が <ruby>育<rt>そだ</rt></ruby>ちます。","de":"Dank der reichen Natur gedeiht köstlicher Reis."},"simpel":"<b>おかげで</b> = »dank« (dankbar, gutes Ergebnis).<br><span class='jp'><ruby>自然<rt>しぜん</rt></ruby>の<b>おかげで</b></span> = „dank der Natur“<br>📖 Buch-Satz: 「<ruby>自然<rt>しぜん</rt></ruby>の おかげで」","rule":"N + の + おかげで (Plain + おかげで): nennt dankbar den Grund für ein gutes Ergebnis. Negativ-vorwurfsvoll wäre せいで. Ironisch kann おかげで auch bei Schlechtem stehen."},{"l":26,"t":"52 · 〜を通じて","de":"… hindurch (Zeitraum) / über …","slots":[{"text":"<ruby>里山<rt>さとやま</rt></ruby>では","role":"plain"},{"text":"<ruby>四季<rt>しき</rt></ruby><b>を通じて</b>","role":"plain"},{"text":"さまざまな","role":"plain"},{"text":"<ruby>生<rt>い</rt></ruby>き<ruby>物<rt>もの</rt></ruby>が","role":"plain"},{"text":"<ruby>見<rt>み</rt></ruby>られます。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Im Satoyama sieht man durch alle Jahreszeiten hindurch vielfältige Lebewesen.«","ex":{"jp":"<ruby>里山<rt>さとやま</rt></ruby>では <ruby>四季<rt>しき</rt></ruby><b>を通じて</b> さまざまな <ruby>生<rt>い</rt></ruby>き<ruby>物<rt>もの</rt></ruby>が <ruby>見<rt>み</rt></ruby>られます。","de":"Im Satoyama sieht man durch alle Jahreszeiten hindurch vielfältige Lebewesen."},"simpel":"<b>を通じて</b> mit Zeitwort = »den ganzen Zeitraum hindurch«.<br><span class='jp'><ruby>四季<rt>しき</rt></ruby><b>を通じて</b></span> = „durch alle vier Jahreszeiten“<br>📖 Buch-Satz: 「<ruby>四季<rt>しき</rt></ruby>を<ruby>通<rt>つう</rt></ruby>じて」","rule":"N(Zeit) + を通じて/を通して = »den Zeitraum hindurch, ohne Unterbrechung«. Mit Nicht-Zeit-N: »über/durch N« (Mittel/Vermittler, Punkt 26). を通じて ist die schriftlichere Form."},{"l":26,"t":"53 · 〜と思いませんか","de":"finden Sie nicht (auch)? (Appell)","slots":[{"text":"この","role":"plain"},{"text":"<ruby>美<rt>うつく</rt></ruby>しい","role":"plain"},{"text":"<ruby>里山<rt>さとやま</rt></ruby>を","role":"plain"},{"text":"<ruby>守<rt>まも</rt></ruby>りたい<b>と","role":"plain"},{"text":"思いませんか</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Möchten Sie dieses schöne Satoyama nicht auch bewahren?«","ex":{"jp":"この <ruby>美<rt>うつく</rt></ruby>しい <ruby>里山<rt>さとやま</rt></ruby>を <ruby>守<rt>まも</rt></ruby>りたい<b>と 思いませんか</b>。","de":"Möchten Sie dieses schöne Satoyama nicht auch bewahren?"},"simpel":"Rhetorischer Appell: »Möchten Sie nicht auch …?«.<br><span class='jp'><ruby>守<rt>まも</rt></ruby>りたい<b>と 思いませんか</b></span> = „möchten Sie sie nicht auch schützen?“<br>📖 Buch-Satz: 「<ruby>守<rt>まも</rt></ruby>りたいと <ruby>思<rt>おも</rt></ruby>いませんか」","rule":"[Meinung/Wunsch] + と思いませんか: lädt den Hörer ein, zuzustimmen — typisch für Aufrufe, Werbung, Essays. Mit 〜たい davor: »Haben Sie nicht auch Lust …?«."},{"l":26,"t":"54 · 〜というと","de":"wenn von … die Rede ist, (dann denkt man) …","slots":[{"text":"<ruby>自然<rt>しぜん</rt></ruby><ruby>保護<rt>ほご</rt></ruby><b>というと</b>、<ruby>手<rt>て</rt></ruby>を","role":"plain"},{"text":"つけない","role":"plain"},{"text":"ことだと","role":"plain"},{"text":"<ruby>思<rt>おも</rt></ruby>われがちだ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Bei „Naturschutz“ denkt man leicht: bloß nichts anrühren.«","ex":{"jp":"<ruby>自然<rt>しぜん</rt></ruby><ruby>保護<rt>ほご</rt></ruby><b>というと</b>、<ruby>手<rt>て</rt></ruby>を つけない ことだと <ruby>思<rt>おも</rt></ruby>われがちだ。","de":"Bei „Naturschutz“ denkt man leicht: bloß nichts anrühren."},"simpel":"<b>というと</b> greift ein Stichwort auf: »apropos Naturschutz …«.<br><span class='jp'><ruby>自然<rt>しぜん</rt></ruby><ruby>保護<rt>ほご</rt></ruby><b>というと</b></span> = „wenn man ‚Naturschutz‘ hört, …“<br>📖 Buch-Satz: 「<ruby>自然<rt>しぜん</rt></ruby><ruby>保護<rt>ほご</rt></ruby>というと」","rule":"N + というと/といえば/といったら: nimmt ein Thema auf und nennt die typische Assoziation oder präzisiert nach. Oft um dann zu korrigieren: »… denkt man an X, aber eigentlich …«."},{"l":26,"t":"55 · 〜べきだ","de":"sollte (unbedingt) … (Überzeugung)","slots":[{"text":"<ruby>自然<rt>しぜん</rt></ruby>は","role":"plain"},{"text":"そのまま","role":"plain"},{"text":"<ruby>残<rt>のこ</rt></ruby>す<b>べきだ</b>と","role":"plain"},{"text":"<ruby>考<rt>かんが</rt></ruby>える","role":"plain"},{"text":"<ruby>人<rt>ひと</rt></ruby>も","role":"plain"},{"text":"<ruby>多<rt>おお</rt></ruby>い。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Viele meinen, man solle die Natur unangetastet lassen.«","ex":{"jp":"<ruby>自然<rt>しぜん</rt></ruby>は そのまま <ruby>残<rt>のこ</rt></ruby>す<b>べきだ</b>と <ruby>考<rt>かんが</rt></ruby>える <ruby>人<rt>ひと</rt></ruby>も <ruby>多<rt>おお</rt></ruby>い。","de":"Viele meinen, man solle die Natur unangetastet lassen."},"simpel":"<b>べきだ</b> = »man sollte (aus Überzeugung/Pflicht)«.<br><span class='jp'>そのまま <ruby>残<rt>のこ</rt></ruby>す<b>べきだ</b></span> = „man sollte es unangetastet erhalten“<br>📖 Buch-Satz: 「そのまま <ruby>残<rt>のこ</rt></ruby>すべきだ」","rule":"V<sub>Grund</sub> + べきだ: starke normative Empfehlung (»sollte/gehört sich«). する→すべきだ auch möglich. Verneint べきではない. Für Gesetzes-Pflichten eher なければならない."},{"l":26,"t":"56 · 〜にとって","de":"👓 für … / aus Sicht von … (Bewertungs-Brille)","slots":[{"text":"<ruby>里山<rt>さとやま</rt></ruby>は","role":"plain"},{"text":"<ruby>人<rt>ひと</rt></ruby><b>にとって</b>も","role":"plain"},{"text":"<ruby>生<rt>い</rt></ruby>き<ruby>物<rt>もの</rt></ruby><b>にとって</b>も","role":"plain"},{"text":"いい","role":"plain"},{"text":"<ruby>環境<rt>かんきょう</rt></ruby>だ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Das Satoyama ist ein gutes Umfeld für Menschen wie für Tiere.«","ex":{"jp":"<ruby>里山<rt>さとやま</rt></ruby>は <ruby>人<rt>ひと</rt></ruby><b>にとって</b>も <ruby>生<rt>い</rt></ruby>き<ruby>物<rt>もの</rt></ruby><b>にとって</b>も いい <ruby>環境<rt>かんきょう</rt></ruby>だ。","de":"Das Satoyama ist ein gutes Umfeld für Menschen wie für Tiere."},"simpel":"👓 <b>Durch die Brille von X betrachtet:</b> にとって = »für X / aus X’ Sicht« — bei Bewertungen (wichtig, schwer, wertvoll …).<br><span class=\"jp\"><ruby>私<rt>わたし</rt></ruby><b>にとって</b> <ruby>家族<rt>かぞく</rt></ruby>は <ruby>宝物<rt>たからもの</rt></ruby>です</span> = »Für MICH ist die Familie ein Schatz.«<br>📖 Buch-Satz: 「<ruby>人<rt>ひと</rt></ruby>にとっても <ruby>生<rt>い</rt></ruby>き<ruby>物<rt>もの</rt></ruby>にとっても」","rule":"N + にとって: <b>aus wessen Sicht</b> eine Bewertung gilt. Wie eine Brille — dieselbe Sache sieht je nach Träger anders aus (für mich Schatz, für andere egal).<br>Vor Nomen: にとっての + N.<br>⚠ nicht に対して (Pfeil AUF ein Ziel, Punkt 22)."},{"l":26,"t":"57 · 〜ば〜ほど","de":"je …, desto …","slots":[{"text":"<ruby>木<rt>き</rt></ruby>は","role":"plain"},{"text":"<ruby>育<rt>そだ</rt></ruby>てば","role":"plain"},{"text":"<ruby>育<rt>そだ</rt></ruby>つ<b>ほど</b>、<ruby>森<rt>もり</rt></ruby>が","role":"plain"},{"text":"<ruby>豊<rt>ゆた</rt></ruby>かに","role":"plain"},{"text":"なる。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Je mehr die Bäume wachsen, desto reicher wird der Wald.«","ex":{"jp":"<ruby>木<rt>き</rt></ruby>は <ruby>育<rt>そだ</rt></ruby>てば <ruby>育<rt>そだ</rt></ruby>つ<b>ほど</b>、<ruby>森<rt>もり</rt></ruby>が <ruby>豊<rt>ゆた</rt></ruby>かに なる。","de":"Je mehr die Bäume wachsen, desto reicher wird der Wald."},"simpel":"Dasselbe Wort zweimal: »je mehr die Bäume wachsen, desto …«.<br><span class='jp'><ruby>育<rt>そだ</rt></ruby>てば <ruby>育<rt>そだ</rt></ruby>つ<b>ほど</b></span><br>📖 Buch-Satz: 「<ruby>木<rt>き</rt></ruby>が <ruby>育<rt>そだ</rt></ruby>てば <ruby>育<rt>そだ</rt></ruby>つほど」","rule":"V<sub>ば</sub> + V<sub>Grund</sub> + ほど (い-Adj ければ〜いほど, な-Adj なら〜なほど): proportionale Kopplung »je …, desto …«."},{"l":26,"t":"58 · N による N","de":"durch … verursacht (Ursache)","slots":[{"text":"<ruby>手入<rt>てい</rt></ruby>れを","role":"plain"},{"text":"しない","role":"plain"},{"text":"<ruby>森<rt>もり</rt></ruby>では、<ruby>大雨<rt>おおあめ</rt></ruby><b>による</b>","role":"plain"},{"text":"<ruby>山崩<rt>やまくず</rt></ruby>れが","role":"plain"},{"text":"<ruby>起<rt>お</rt></ruby>こりやすい。","role":"plain"}],"gloss":"Baue den Beispielsatz: »In ungepflegten Wäldern kommt es leicht zu Erdrutschen durch Starkregen.«","ex":{"jp":"<ruby>手入<rt>てい</rt></ruby>れを しない <ruby>森<rt>もり</rt></ruby>では、<ruby>大雨<rt>おおあめ</rt></ruby><b>による</b> <ruby>山崩<rt>やまくず</rt></ruby>れが <ruby>起<rt>お</rt></ruby>こりやすい。","de":"In ungepflegten Wäldern kommt es leicht zu Erdrutschen durch Starkregen."},"simpel":"<b>による</b> als Ursache: »Erdrutsche durch Starkregen«.<br><span class='jp'><ruby>大雨<rt>おおあめ</rt></ruby><b>による</b> <ruby>山崩<rt>やまくず</rt></ruby>れ</span><br>📖 Buch-Satz: 「<ruby>大雨<rt>おおあめ</rt></ruby>による <ruby>山崩<rt>やまくず</rt></ruby>れ」","rule":"N₁ + による + N₂: N₁ ist die Ursache von N₂ (Nachrichten-/Berichtsstil). Adverbial により/によって. Vgl. Punkt 21 (Mittel) — gleiche Form, andere Lesart."},{"l":26,"t":"59 · 〜ばかりでなく","de":"nicht nur …, sondern auch …","slots":[{"text":"<ruby>里山<rt>さとやま</rt></ruby>は","role":"plain"},{"text":"<ruby>田舎<rt>いなか</rt></ruby><b>ばかりでなく</b>、<ruby>東京<rt>とうきょう</rt></ruby>の","role":"plain"},{"text":"<ruby>近<rt>ちか</rt></ruby>く<b>にも</b>","role":"plain"},{"text":"あります。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Satoyama gibt es nicht nur auf dem Land, sondern auch nahe Tokio.«","ex":{"jp":"<ruby>里山<rt>さとやま</rt></ruby>は <ruby>田舎<rt>いなか</rt></ruby><b>ばかりでなく</b>、<ruby>東京<rt>とうきょう</rt></ruby>の <ruby>近<rt>ちか</rt></ruby>く<b>にも</b> あります。","de":"Satoyama gibt es nicht nur auf dem Land, sondern auch nahe Tokio."},"simpel":"»Nicht nur auf dem Land — auch in Tokio.«<br><span class='jp'><ruby>田舎<rt>いなか</rt></ruby><b>ばかりでなく</b> <ruby>東京<rt>とうきょう</rt></ruby><b>にも</b></span><br>📖 Buch-Satz: 「<ruby>田舎<rt>いなか</rt></ruby>ばかりでなく <ruby>東京<rt>とうきょう</rt></ruby>にも」","rule":"N/Plain + ばかりでなく、… も/にも/まで: »nicht nur A, sondern auch B«. Etwas schriftlicher als だけでなく; noch stärker: ばかりか."},{"l":26,"t":"60 · 〜たびに","de":"jedes Mal, wenn …","slots":[{"text":"<ruby>里山<rt>さとやま</rt></ruby>へ","role":"plain"},{"text":"<ruby>行<rt>い</rt></ruby>く<b>たびに</b>、<ruby>新<rt>あたら</rt></ruby>しい","role":"plain"},{"text":"<ruby>発見<rt>はっけん</rt></ruby>が","role":"plain"},{"text":"あります。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Bei jedem Satoyama-Besuch gibt es neue Entdeckungen.«","ex":{"jp":"<ruby>里山<rt>さとやま</rt></ruby>へ <ruby>行<rt>い</rt></ruby>く<b>たびに</b>、<ruby>新<rt>あたら</rt></ruby>しい <ruby>発見<rt>はっけん</rt></ruby>が あります。","de":"Bei jedem Satoyama-Besuch gibt es neue Entdeckungen."},"simpel":"»Jedes Mal, wenn ich hinfahre, …«.<br><span class='jp'><ruby>行<rt>い</rt></ruby>く<b>たびに</b></span> = „bei jedem Besuch“<br>📖 Buch-Satz: 「<ruby>里山<rt>さとやま</rt></ruby>へ <ruby>行<rt>い</rt></ruby>くたびに」","rule":"V<sub>Grund</sub> / N + の + たびに: bei jeder Wiederholung von A tritt B auf. Oft mit Entdeckungen/Gefühlen: 行くたびに 新しい発見がある."},{"l":26,"t":"61 · 〜さ ＋ 〜はずだ","de":"① die …-heit/-keit (Adj→Nomen) ② müsste (logisch) gewiss …","slots":[{"text":"この","role":"plain"},{"text":"<ruby>店<rt>みせ</rt></ruby>の","role":"plain"},{"text":"<ruby>人気<rt>にんき</rt></ruby>の","role":"plain"},{"text":"<ruby>理由<rt>りゆう</rt></ruby>が","role":"plain"},{"text":"わかる<b>はず</b>だ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Man versteht gewiss, warum dieser Laden so beliebt ist.«","ex":{"jp":"<ruby>一度<rt>いちど</rt></ruby> <ruby>訪<rt>おとず</rt></ruby>れれば、<ruby>里山<rt>さとやま</rt></ruby>の すばらし<b>さ</b>が わかる<b>はず</b>です。","de":"Wer einmal hinfährt, wird die Großartigkeit des Satoyama gewiss erkennen."},"simpel":"Zwei Bausteine:<br>① <b>〜さ</b> macht aus einem Adjektiv ein <b>Ding</b> (die »-heit/-keit«): <ruby>大切<rt>たいせつ</rt></ruby>い→<b><ruby>大切<rt>たいせつ</rt></ruby>さ</b> (die Wichtig-keit).<br>② <b>〜はずだ</b> = »müsste (logisch) gewiss …«.<br><span class=\"jp\">すばらし<b>さ</b>が わかる<b>はず</b>です</span> = »…wird die Großartigkeit gewiss erkennen.«<br>📖 Buch-Satz: 「すばらしさが わかるはずです」","rule":"① <b>〜さ</b>: い-Adj-Stamm / な-Adj + さ macht ein <b>Nomen</b> daraus — die »-heit/-keit«: <ruby>大切<rt>たいせつ</rt></ruby>さ, <ruby>便利<rt>べんり</rt></ruby>さ, <ruby>高<rt>たか</rt></ruby>さ.<br>② <b>〜はずだ</b>: logisch begründete Erwartung »nach meiner Rechnung müsste gewiss …« (fester als das bloße だろう)."},{"l":27,"t":"62 · 〜ですと","de":"wenn (es) … ist, (dann) … (Service-Sprache)","slots":[{"text":"この","role":"plain"},{"text":"<ruby>時間<rt>じかん</rt></ruby><b>ですと</b>、<ruby>道<rt>みち</rt></ruby>が","role":"plain"},{"text":"<ruby>混<rt>こ</rt></ruby>んで","role":"plain"},{"text":"います。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Um diese Uhrzeit sind die Straßen voll.«","ex":{"jp":"その ご<ruby>予算<rt>よさん</rt></ruby><b>ですと</b>、<ruby>駅前<rt>えきまえ</rt></ruby>は <ruby>難<rt>むずか</rt></ruby>しいですね。","de":"Bei diesem Budget wird es direkt am Bahnhof schwierig."},"simpel":"Höfliches と-Konditional im Beratungsgespräch.<br><span class='jp'>その ご<ruby>予算<rt>よさん</rt></ruby><b>ですと</b></span> = „bei diesem Budget …“<br>📖 Buch-Satz: 「その ご<ruby>予算<rt>よさん</rt></ruby>ですと」","rule":"N/Aussage + ですと: höfliche Variante des と-Konditionals (»wenn/bei …, dann zwangsläufig …«), typisch für Verkäufer und Berater. Danach folgt die sachliche Konsequenz."},{"l":27,"t":"63 · 〜ようなら","de":"falls es (danach) aussieht / falls …","slots":[{"text":"お<ruby>時間<rt>じかん</rt></ruby>が","role":"plain"},{"text":"ある<b>ようなら</b>、<ruby>実際<rt>じっさい</rt></ruby>に","role":"plain"},{"text":"<ruby>物件<rt>ぶっけん</rt></ruby>を","role":"plain"},{"text":"ご<ruby>案内<rt>あんない</rt></ruby>します。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Falls Sie Zeit haben, zeige ich Ihnen die Objekte gern vor Ort.«","ex":{"jp":"お<ruby>時間<rt>じかん</rt></ruby>が ある<b>ようなら</b>、<ruby>実際<rt>じっさい</rt></ruby>に <ruby>物件<rt>ぶっけん</rt></ruby>を ご<ruby>案内<rt>あんない</rt></ruby>します。","de":"Falls Sie Zeit haben, zeige ich Ihnen die Objekte gern vor Ort."},"simpel":"<b>ようなら</b> = »falls es so ist/aussieht, dass …«.<br><span class='jp'>お<ruby>時間<rt>じかん</rt></ruby>が ある<b>ようなら</b></span> = „falls Sie Zeit haben (sollten)“<br>📖 Buch-Satz: 「お<ruby>時間<rt>じかん</rt></ruby>が あるようなら」","rule":"Plain + ようなら (= ようだったら): vorsichtige Bedingung auf Basis eines Anscheins — »falls es sich so darstellt, dass …«. Höflich-distanziert, gern in Vorschlägen."},{"l":27,"t":"64 · 〜てくる","de":"ist (allmählich) … geworden (bis jetzt)","slots":[{"text":"この","role":"plain"},{"text":"<ruby>辺<rt>へん</rt></ruby>は","role":"plain"},{"text":"<ruby>最近<rt>さいきん</rt></ruby>","role":"plain"},{"text":"<ruby>人気<rt>にんき</rt></ruby>が","role":"plain"},{"text":"<ruby>出<rt>で</rt></ruby>て<b>きたんです</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Diese Gegend ist in letzter Zeit nämlich beliebt geworden.«","ex":{"jp":"この <ruby>辺<rt>へん</rt></ruby>は <ruby>最近<rt>さいきん</rt></ruby> <ruby>人気<rt>にんき</rt></ruby>が <ruby>出<rt>で</rt></ruby>て<b>きたんです</b>。","de":"Diese Gegend ist in letzter Zeit nämlich beliebt geworden."},"simpel":"<b>てきた</b> = Entwicklung bis jetzt: »ist beliebt geworden«.<br><span class='jp'><ruby>人気<rt>にんき</rt></ruby>が <ruby>出<rt>で</rt></ruby>て<b>きた</b>んです</span><br>📖 Buch-Satz: 「<ruby>人気<rt>にんき</rt></ruby>が <ruby>出<rt>で</rt></ruby>て きたんです」","rule":"V<sub>て</sub> + くる: eine Veränderung hat begonnen und reicht bis jetzt (人気が出てきた, 寒くなってきた). Gegenstück ていく = ab jetzt weiter (Punkt 8). +んです erklärt dem Kunden die Lage."},{"l":27,"t":"65 · 〜ものですから","de":"weil nun mal … (höfliche Rechtfertigung)","slots":[{"text":"<ruby>借<rt>か</rt></ruby>りたい","role":"plain"},{"text":"<ruby>方<rt>かた</rt></ruby>が","role":"plain"},{"text":"<ruby>増<rt>ふ</rt></ruby>えて","role":"plain"},{"text":"いる<b>ものですから</b>、<ruby>家賃<rt>やちん</rt></ruby>も","role":"plain"},{"text":"<ruby>上<rt>あ</rt></ruby>がって","role":"plain"},{"text":"いまして。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Da die Nachfrage nun mal steigt, sind auch die Mieten gestiegen.«","ex":{"jp":"<ruby>借<rt>か</rt></ruby>りたい <ruby>方<rt>かた</rt></ruby>が <ruby>増<rt>ふ</rt></ruby>えて いる<b>ものですから</b>、<ruby>家賃<rt>やちん</rt></ruby>も <ruby>上<rt>あ</rt></ruby>がって いまして。","de":"Da die Nachfrage nun mal steigt, sind auch die Mieten gestiegen."},"simpel":"Grund als höfliche Entschuldigung: »es ist nun mal so, dass …«.<br><span class='jp'><ruby>増<rt>ふ</rt></ruby>えて いる<b>ものですから</b></span><br>📖 Buch-Satz: 「<ruby>借<rt>か</rt></ruby>りたい <ruby>人<rt>ひと</rt></ruby>が <ruby>増<rt>ふ</rt></ruby>えて いる ものですから」","rule":"Plain + ものですから (locker もので/もんで): rechtfertigt höflich einen unangenehmen Umstand (»ich kann nichts dafür — es ist eben so«). Kein Befehl im Hauptsatz."},{"l":27,"t":"66 · 〜なんか いかがですか","de":"wie wäre es (zum Beispiel) mit …?","slots":[{"text":"こちらの","role":"plain"},{"text":"お<ruby>部屋<rt>へや</rt></ruby><b>なんか</b>","role":"plain"},{"text":"いかがですか。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wie wäre es zum Beispiel mit dieser Wohnung?«","ex":{"jp":"こちらの お<ruby>部屋<rt>へや</rt></ruby><b>なんか</b> いかがですか。","de":"Wie wäre es zum Beispiel mit dieser Wohnung?"},"simpel":"Vorschlag mit Beispiel-なんか: »wie wär's etwa mit dem hier?«.<br><span class='jp'>こちら<b>なんか</b> いかがですか</span><br>📖 Buch-Satz: 「こちら なんか いかがですか」","rule":"N + なんか + いかがですか/どうですか: unverbindlicher Vorschlag (»z. B. so etwas wie N«). Dieses なんか ist das Beispiel-なんか (= など), nicht das abwertende."},{"l":27,"t":"67 · 〜かと思いますが","de":"ich denke (wohl) …, aber (vorsichtig)","slots":[{"text":"こちらの","role":"plain"},{"text":"ほうが","role":"plain"},{"text":"お<ruby>得<rt>とく</rt></ruby><b>かと","role":"plain"},{"text":"思います</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Dieses hier dürfte günstiger sein, meine ich.«","ex":{"jp":"<ruby>駅<rt>えき</rt></ruby>にも <ruby>近<rt>ちか</rt></ruby>いですし、<ruby>便利<rt>べんり</rt></ruby><b>かと 思いますが</b>。","de":"Auch bahnhofsnah — dürfte recht praktisch sein, denke ich."},"simpel":"Abgeschwächte Meinung: »dürfte praktisch sein, denke ich«.<br><span class='jp'><ruby>便利<rt>べんり</rt></ruby><b>かと 思いますが</b></span><br>📖 Buch-Satz: 「<ruby>便利<rt>べんり</rt></ruby>かと <ruby>思<rt>おも</rt></ruby>いますが」","rule":"[Meinung] + かと思います: das か macht die Aussage vorsichtig-unaufdringlich (»dürfte wohl«). Das が am Ende überlässt dem Kunden das Urteil. Beratungs-/Geschäftssprache."},{"l":27,"t":"68 · 〜うちに","de":"im Laufe von … (unbemerkt) / solange","slots":[{"text":"<ruby>話<rt>はな</rt></ruby>して","role":"plain"},{"text":"いる<b>うちに</b>、<ruby>元気<rt>げんき</rt></ruby>が","role":"plain"},{"text":"<ruby>出<rt>で</rt></ruby>て","role":"plain"},{"text":"きた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Beim Reden kam die Energie zurück.«","ex":{"jp":"<ruby>住<rt>す</rt></ruby>んで いる<b>うちに</b>、だんだん <ruby>慣<rt>な</rt></ruby>れますよ。","de":"Beim Wohnen gewöhnen Sie sich nach und nach daran."},"simpel":"<b>ているうちに</b> = »während/im Laufe des …s (passiert von selbst)«.<br><span class='jp'><ruby>住<rt>す</rt></ruby>んで いる<b>うちに</b> <ruby>慣<rt>な</rt></ruby>れます</span><br>📖 Buch-Satz: 「<ruby>住<rt>す</rt></ruby>んで いる うちに <ruby>慣<rt>な</rt></ruby>れますよ」","rule":"V<sub>ている</sub> + うちに: während einer laufenden Handlung tritt unbemerkt eine Veränderung ein (»beim Wohnen gewöhnt man sich«). Auch »solange noch« (明るいうちに) und ないうちに (»bevor«)."},{"l":27,"t":"69 · 〜たばかり","de":"gerade erst … (+ なんだから: schließlich)","slots":[{"text":"<ruby>日本<rt>にほん</rt></ruby>に","role":"plain"},{"text":"<ruby>来<rt>き</rt></ruby>た<b>ばかり</b>で、まだ","role":"plain"},{"text":"<ruby>道<rt>みち</rt></ruby>が","role":"plain"},{"text":"わからない。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich bin gerade erst in Japan angekommen und kenne die Wege noch nicht.«","ex":{"jp":"<ruby>卒業<rt>そつぎょう</rt></ruby>した<b>ばかり</b> なんだから、<ruby>焦<rt>あせ</rt></ruby>らなくて いいよ。","de":"Du hast doch gerade erst den Abschluss gemacht — kein Grund zur Eile."},"simpel":"<b>たばかり</b> = »gerade erst passiert«; <b>なんだから</b> begründet nachdrücklich.<br><span class='jp'><ruby>卒業<rt>そつぎょう</rt></ruby>した<b>ばかり</b> なんだから</span><br>📖 Buch-Satz: 「<ruby>卒業<rt>そつぎょう</rt></ruby>した ばかり なんだから」","rule":"V<sub>た</sub> + ばかり: die Handlung liegt (gefühlt) ganz kurz zurück. なんだから = »schließlich ist es so, dass« — nachdrückliche Begründung, oft vor Rat/Trost."},{"l":27,"t":"70 · 〜ばいいのに","de":"du solltest doch (einfach) … / schade, dass nicht","slots":[{"text":"<ruby>迷<rt>まよ</rt></ruby>って","role":"plain"},{"text":"いるなら、<ruby>実際<rt>じっさい</rt></ruby>に","role":"plain"},{"text":"<ruby>見<rt>み</rt></ruby>れば","role":"plain"},{"text":"<b>いいのに</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wenn du unsicher bist — schau es dir doch einfach an!«","ex":{"jp":"<ruby>迷<rt>まよ</rt></ruby>って いるなら、<ruby>実際<rt>じっさい</rt></ruby>に <ruby>見<rt>み</rt></ruby>れば <b>いいのに</b>。","de":"Wenn du unsicher bist — schau es dir doch einfach an!"},"simpel":"Rat + Bedauern: »schau es dir doch (einfach) an!«.<br><span class='jp'><ruby>見<rt>み</rt></ruby>れば <b>いいのに</b></span><br>📖 Buch-Satz: 「<ruby>見<rt>み</rt></ruby>れば いいのに」","rule":"V<sub>ば</sub> + いいのに: Empfehlung mit Unterton »warum tust du es nicht?« (leichtes Bedauern/Vorwurf). Ohne のに = neutraler Rat (見ればいい)."},{"l":27,"t":"71 · 〜てもらってもいいですか","de":"dürfte ich (Sie bitten) …?","slots":[{"text":"この","role":"plain"},{"text":"<ruby>部屋<rt>へや</rt></ruby>、<ruby>中<rt>なか</rt></ruby>を","role":"plain"},{"text":"<ruby>見<rt>み</rt></ruby>せて<b>もらっても","role":"plain"},{"text":"いいですか</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Dürfte ich mir diese Wohnung von innen ansehen?«","ex":{"jp":"この <ruby>部屋<rt>へや</rt></ruby>、<ruby>中<rt>なか</rt></ruby>を <ruby>見<rt>み</rt></ruby>せて<b>もらっても いいですか</b>。","de":"Dürfte ich mir diese Wohnung von innen ansehen?"},"simpel":"Sehr höfliche Bitte: »dürfte ich es mir zeigen lassen?«.<br><span class='jp'><ruby>見<rt>み</rt></ruby>せて<b>もらっても いいですか</b></span><br>📖 Buch-Satz: 「<ruby>見<rt>み</rt></ruby>せて もらっても いいですか」","rule":"V<sub>て</sub> + もらってもいいですか: Bitte als Erlaubnisfrage verpackt — weicher als 〜てください. Noch höflicher: 〜ていただいてもいいですか / 〜ていただけますか."},{"l":28,"t":"72 · ご/お〜いただく","de":"🙇 (bescheiden) sich etw. von jdm. tun lassen / empfangen (= höfliches てもらう)","slots":[{"text":"<ruby>本日<rt>ほんじつ</rt></ruby>は","role":"plain"},{"text":"お<ruby>時間<rt>じかん</rt></ruby>を","role":"plain"},{"text":"<ruby>取<rt>と</rt></ruby>って<b>いただき</b>、ありがとう","role":"plain"},{"text":"ございます。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Vielen Dank, dass Sie sich heute Zeit genommen haben.«","ex":{"jp":"<ruby>田中<rt>たなか</rt></ruby><ruby>先生<rt>せんせい</rt></ruby>に ご<ruby>紹介<rt>しょうかい</rt></ruby><b>いただきました</b>。","de":"Professor Tanaka hat mich (freundlicherweise) vermittelt."},"simpel":"🙇 <b>Keigo-Grundbild:</b> über MICH ducke ich mich, über DICH hebe ich dich hoch.<br>Hier: <b>ich ducke mich und empfange etwas von oben</b> — »Sie taten mir freundlicherweise …«. = höfliche Version von <b>てもらう</b>.<br><span class=\"jp\">ご<ruby>紹介<rt>しょうかい</rt></ruby><b>いただきました</b></span> = »Sie haben mich (freundlicherweise) vorgestellt.«<br>📖 Buch-Satz: 「ご<ruby>紹介<rt>しょうかい</rt></ruby>いただきました」","rule":"お + ますStamm + いただく (chin. Wort: ご + Nomen + いただく) = die bescheidene Form von <b>てもらう</b>: »ich lasse mir von Ihnen (freundlicherweise) … tun / empfange es von oben«.<br>お bei jap. Wörtern (お<ruby>越<rt>こ</rt></ruby>し), ご bei chin. Nomen (ご<ruby>連絡<rt>れんらく</rt></ruby>)."},{"l":28,"t":"73 · お〜する","de":"🙇 bescheiden: ich tue etw. für Sie","slots":[{"text":"お<ruby>待<rt>ま</rt></ruby>ちして","role":"plain"},{"text":"いました。どうぞ","role":"plain"},{"text":"こちらへ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wir haben Sie erwartet — bitte hier entlang.«","ex":{"jp":"お<ruby>待<rt>ま</rt></ruby>ちして いました。どうぞ こちらへ。","de":"Wir haben Sie erwartet — bitte hier entlang."},"simpel":"🙇 <b>Ich ducke mich und diene:</b> お + <b>meine</b> Handlung + する = »ich tue (bescheiden) für Sie«.<br><span class=\"jp\"><ruby>駅<rt>えき</rt></ruby>まで お<ruby>送<rt>おく</rt></ruby>りします</span> = »Ich bringe/geleite Sie zum Bahnhof.«<br>📖 Buch-Satz: 「お<ruby>待<rt>ま</rt></ruby>ちして いました」","rule":"お + ますStamm + する (chin. Wort: ご + Nomen + する) = die <b>eigene</b> Handlung bescheiden, wenn sie dem Gegenüber gilt: お<ruby>待<rt>ま</rt></ruby>ちする, お<ruby>送<rt>おく</rt></ruby>りする, ご<ruby>案内<rt>あんない</rt></ruby>する. Noch tiefer: お〜いたす.<br>⚠ NUR für MEINE Handlungen — nie für die des Gegenübers (das wäre 👑 Respekt-Keigo)."},{"l":28,"t":"74 · 〜ており / <ruby>存<rt>ぞん</rt></ruby>じ<ruby>上<rt>あ</rt></ruby>げる","de":"🙇 steifes ている (おる) + „ich kenne Sie“ (bescheiden)","slots":[{"text":"<ruby>御社<rt>おんしゃ</rt></ruby>の","role":"plain"},{"text":"<ruby>製品<rt>せいひん</rt></ruby>は","role":"plain"},{"text":"<ruby>来日<rt>らいにち</rt></ruby><ruby>前<rt>まえ</rt></ruby>から","role":"plain"},{"text":"<ruby>存<rt>ぞん</rt></ruby>じ<b>ており</b>、ずっと","role":"plain"},{"text":"<ruby>憧<rt>あこが</rt></ruby>れて","role":"plain"},{"text":"いました。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Die Produkte Ihres Hauses kannte ich schon vor meiner Ankunft und habe sie stets bewundert.«","ex":{"jp":"<ruby>御社<rt>おんしゃ</rt></ruby>の <ruby>製品<rt>せいひん</rt></ruby>は <ruby>来日<rt>らいにち</rt></ruby><ruby>前<rt>まえ</rt></ruby>から <ruby>存<rt>ぞん</rt></ruby>じ<b>ており</b>、ずっと <ruby>憧<rt>あこが</rt></ruby>れて いました。","de":"Die Produkte Ihres Hauses kannte ich schon vor meiner Ankunft und habe sie stets bewundert."},"simpel":"🙇 <b>Steifes Bewerbungs-/Brief-Japanisch:</b><br>• <b>おる</b> = förmliches, gebeugtes いる/ている.<br>• <b><ruby>存<rt>ぞん</rt></ruby>じ<ruby>上<rt>あ</rt></ruby>げる</b> = »ich kenne Sie« (bescheiden).<br><span class=\"jp\"><ruby>東京<rt>とうきょう</rt></ruby>に <ruby>住<rt>す</rt></ruby>んで<b>おります</b></span> = »Ich wohne in Tokio.«<br>📖 Buch-Satz: 「<ruby>存<rt>ぞん</rt></ruby>じており」","rule":"Vて + <b>おる</b> = bescheidenes/förmliches ている (おる statt いる): <ruby>住<rt>す</rt></ruby>んでおります, <ruby>存<rt>ぞん</rt></ruby>じております. Verbindend: …ており、….<br><b>存じ上げる</b> = bescheidenes <ruby>知<rt>し</rt></ruby>っている für <b>Personen</b> des Gegenübers; für Dinge/Sachverhalte: <ruby>存<rt>ぞん</rt></ruby>じております. Klingt nach Bewerbung, Brief, Bühne."},{"l":28,"t":"75 · お〜ですか","de":"Respekt-Keigo: haben/tun Sie …? (kompakt)","slots":[{"text":"N は","role":"obj"},{"text":"お + V<sub>ます</sub>","role":"verb","label":"Respekt-Keigo"},{"text":"ですか","role":"plain"}],"gloss":"Kompaktes Respekt-Keigo für Zustände des Gegenübers: お持ちですか = haben Sie dabei?","ex":{"jp":"ポートフォリオ、<ruby>作品<rt>さくひん</rt></ruby>は お<ruby>持<rt>も</rt></ruby>ち<b>ですか</b>。","de":"Haben Sie Ihr Portfolio, Ihre Arbeiten dabei?"},"simpel":"Respekt-Keigo-Kurzmuster: <b>お + ます-Stamm + ですか</b>.<br><span class='jp'>お<ruby>持<rt>も</rt></ruby>ち<b>ですか</b></span> = „haben Sie (dabei)?“<br>📖 Buch-Satz: 「<ruby>作品<rt>さくひん</rt></ruby>は お<ruby>持<rt>も</rt></ruby>ちですか」","rule":"お + V<sub>ます</sub> + です: kompakte Respektform für Handlungen/Zustände des Gegenübers (お持ちです = 持っていらっしゃる). Häufig: お持ちですか, おわかりですか, お急ぎですか."},{"l":28,"t":"76 · ご覧いただけますか","de":"dürfte ich Sie bitten, es anzusehen?","slots":[{"text":"こちらの","role":"plain"},{"text":"<ruby>作品<rt>さくひん</rt></ruby>を","role":"plain"},{"text":"ご<ruby>覧<rt>らん</rt></ruby><b>いただけますでしょうか</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Dürfte ich Sie bitten, sich diese Arbeit anzusehen?«","ex":{"jp":"こちらの <ruby>作品<rt>さくひん</rt></ruby>を ご<ruby>覧<rt>らん</rt></ruby><b>いただけますでしょうか</b>。","de":"Dürfte ich Sie bitten, sich diese Arbeit anzusehen?"},"simpel":"Doppelt höfliche Bitte ums Ansehen.<br><span class='jp'>ご<ruby>覧<rt>らん</rt></ruby><b>いただけますでしょうか</b></span><br>📖 Buch-Satz: 「ご<ruby>覧<rt>らん</rt></ruby>いただけますでしょうか」","rule":"ご覧になる = Respekt-Keigo für 見る. ご覧いただく = »(Sie) sehen es sich für mich an« (Bescheiden-Keigo側). Potential + ですか/でしょうか = superweiche Bitte: ご覧いただけますか → いただけますでしょうか."},{"l":28,"t":"77 · 〜でいらっしゃいます","de":"👑 Respekt-Kopula: Sie sind … (über den Anderen)","slots":[{"text":"[N über den Gast]","role":"subj"},{"text":"でいらっしゃいます","role":"plain","label":"👑 Sie sind …"}],"gloss":"Respekt-です für den Anderen. Über sich selbst: でございます.","ex":{"jp":"ご<ruby>専門<rt>せんもん</rt></ruby>は グラフィックデザイン<b>でいらっしゃいます</b>か。","de":"Ihr Fachgebiet ist Grafikdesign, richtig?"},"simpel":"👑 <b>Ich hebe dich aufs Podest:</b> でいらっしゃる = respektvolles »Sie sind …« (statt です), wenn es um DEN ANDEREN geht.<br><span class=\"jp\"><ruby>鈴木<rt>すずき</rt></ruby><ruby>様<rt>さま</rt></ruby><b>でいらっしゃいます</b>ね</span> = »Sie sind Herr Suzuki, nicht wahr?«<br>🙇 Über MICH ducke ich mich: <ruby>森<rt>もり</rt></ruby><b>でございます</b>.<br>📖 Buch-Satz: 「ご<ruby>専門<rt>せんもん</rt></ruby>はグラフィックデザインでいらっしゃいますか」","rule":"N + でいらっしゃる = Respekt-Keigo von だ/です, wenn das Prädikat die <b>respektierte Person</b> beschreibt (お<ruby>名前<rt>なまえ</rt></ruby>, ご<ruby>専門<rt>せんもん</rt></ruby>, ご<ruby>出身<rt>しゅっしん</rt></ruby> …).<br>👑 über DEN ANDEREN: でいらっしゃる. 🙇 über MICH: でございます (nur höflich, kein Heben)."},{"l":28,"t":"78 · 〜させていただく","de":"mit Ihrer Erlaubnis werde ich …","slots":[{"text":"それでは、<ruby>面接<rt>めんせつ</rt></ruby>を","role":"plain"},{"text":"<ruby>始<rt>はじ</rt></ruby>め<b>させて","role":"plain"},{"text":"いただきます</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Nun denn — ich erlaube mir, mit dem Gespräch zu beginnen.«","ex":{"jp":"それでは、<ruby>面接<rt>めんせつ</rt></ruby>を <ruby>始<rt>はじ</rt></ruby>め<b>させて いただきます</b>。","de":"Nun denn — ich erlaube mir, mit dem Gespräch zu beginnen."},"simpel":"Maximal bescheiden handeln: »ich erlaube mir, zu beginnen«.<br><span class='jp'><ruby>始<rt>はじ</rt></ruby>め<b>させて いただきます</b></span><br>📖 Buch-Satz: 「<ruby>始<rt>はじ</rt></ruby>めさせて いただきます」","rule":"V<sub>lassen-て</sub> + いただく: die eigene Handlung als gewährte Erlaubnis darstellen — Standard bei Präsentationen, Anrufen, Absagen. Nicht inflationär verwenden."},{"l":29,"t":"79 · 〜てからでなければ","de":"erst nachdem …, sonst nicht","slots":[{"text":"<ruby>花<rt>はな</rt></ruby>が","role":"plain"},{"text":"<ruby>咲<rt>さ</rt></ruby>いて<b>からでなければ</b>、<ruby>日<rt>ひ</rt></ruby>にちは","role":"plain"},{"text":"<ruby>決<rt>き</rt></ruby>められません。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Bevor die Blüten aufgehen, lässt sich kein Termin festlegen.«","ex":{"jp":"<ruby>花<rt>はな</rt></ruby>が <ruby>咲<rt>さ</rt></ruby>いて<b>からでなければ</b>、<ruby>日<rt>ひ</rt></ruby>にちは <ruby>決<rt>き</rt></ruby>められません。","de":"Bevor die Blüten aufgehen, lässt sich kein Termin festlegen."},"simpel":"Erst muss A passieren, sonst geht B nicht.<br><span class='jp'><ruby>咲<rt>さ</rt></ruby>いて<b>からでなければ</b></span> = „erst wenn sie blühen …“<br>📖 Buch-Satz: 「<ruby>花<rt>はな</rt></ruby>が <ruby>咲<rt>さ</rt></ruby>いて からでなければ」","rule":"V<sub>て</sub> + からでなければ/からでないと + Verneinung: »solange A nicht geschehen ist, ist B unmöglich«. Der Hauptsatz ist immer negativ (できない/わからない/だめ)."},{"l":29,"t":"80 · 〜かのように","de":"(gerade) so, als ob …","slots":[{"text":"<ruby>桜<rt>さくら</rt></ruby>の","role":"plain"},{"text":"<ruby>花<rt>はな</rt></ruby>びらが、まるで","role":"plain"},{"text":"<ruby>雪<rt>ゆき</rt></ruby>が","role":"plain"},{"text":"<ruby>降<rt>ふ</rt></ruby>って","role":"plain"},{"text":"いる<b>かのように</b>","role":"plain"},{"text":"<ruby>舞<rt>ま</rt></ruby>って","role":"plain"},{"text":"いた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Die Kirschblütenblätter tanzten, als ob es schneite.«","ex":{"jp":"<ruby>桜<rt>さくら</rt></ruby>の <ruby>花<rt>はな</rt></ruby>びらが、まるで <ruby>雪<rt>ゆき</rt></ruby>が <ruby>降<rt>ふ</rt></ruby>って いる<b>かのように</b> <ruby>舞<rt>ま</rt></ruby>って いた。","de":"Die Kirschblütenblätter tanzten, als ob es schneite."},"simpel":"Irrealer Vergleich: »als ob es schneite«.<br><span class='jp'><ruby>雪<rt>ゆき</rt></ruby>が <ruby>降<rt>ふ</rt></ruby>って いる<b>かのように</b></span><br>📖 Buch-Satz: 「<ruby>雪<rt>ゆき</rt></ruby>が <ruby>降<rt>ふ</rt></ruby>って いる かのように」","rule":"Plain + かのようだ/かのように/かのような: Vergleich mit etwas, das NICHT wirklich so ist — oft mit まるで. Literarischer als schlichtes ように."},{"l":29,"t":"81 · 〜ないうちに","de":"bevor … (das Fenster schließt)","slots":[{"text":"<ruby>花<rt>はな</rt></ruby>が","role":"plain"},{"text":"<ruby>散<rt>ち</rt></ruby>らない<b>うちに</b>、お<ruby>花見<rt>はなみ</rt></ruby>に","role":"plain"},{"text":"<ruby>行<rt>い</rt></ruby>きましょう。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Gehen wir zum Hanami, bevor die Blüten fallen!«","ex":{"jp":"<ruby>花<rt>はな</rt></ruby>が <ruby>散<rt>ち</rt></ruby>らない<b>うちに</b>、お<ruby>花見<rt>はなみ</rt></ruby>に <ruby>行<rt>い</rt></ruby>きましょう。","de":"Gehen wir zum Hanami, bevor die Blüten fallen!"},"simpel":"»Bevor die Blüten fallen (solange sie noch da sind)«.<br><span class='jp'><ruby>散<rt>ち</rt></ruby>らない<b>うちに</b></span><br>📖 Buch-Satz: 「<ruby>花<rt>はな</rt></ruby>が <ruby>散<rt>ち</rt></ruby>らない うちに」","rule":"V<sub>ない</sub> + うちに: etwas erledigen, BEVOR ein unerwünschter Zustand eintritt. Das positive Gegenstück (solange noch) ist Adj/ている + うちに (Punkt 68)."},{"l":29,"t":"82 · N 向けに","de":"eigens für … (+Plus: 〜向き)","slots":[{"text":"<ruby>花見<rt>はなみ</rt></ruby><ruby>客<rt>きゃく</rt></ruby><b>向けに</b>、お<ruby>弁当<rt>べんとう</rt></ruby>が","role":"plain"},{"text":"<ruby>売<rt>う</rt></ruby>られて","role":"plain"},{"text":"いる。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Für die Hanami-Gäste werden Bentos verkauft.«","ex":{"jp":"<ruby>花見<rt>はなみ</rt></ruby><ruby>客<rt>きゃく</rt></ruby><b>向けに</b>、お<ruby>弁当<rt>べんとう</rt></ruby>が <ruby>売<rt>う</rt></ruby>られて いる。","de":"Für die Hanami-Gäste werden Bentos verkauft."},"simpel":"<b>向け</b> = bewusst für eine Zielgruppe gemacht.<br><span class='jp'><ruby>花見<rt>はなみ</rt></ruby><ruby>客<rt>きゃく</rt></ruby><b>向けに</b></span> = „(extra) für Hanami-Gäste“<br>📖 Buch-Satz: 「<ruby>花見<rt>はなみ</rt></ruby><ruby>客<rt>きゃく</rt></ruby><ruby>向<rt>む</rt></ruby>けに」","rule":"N + 向け(に/の): eigens für die Zielgruppe N hergestellt/angeboten. +Plus 向き = »eignet sich (von Natur aus) für« — der Unterschied ist Absicht vs. Eignung."},{"l":29,"t":"83 · 〜によって（je nach）","de":"🎛️ je nach … (fällt unterschiedlich aus)","slots":[{"text":"お<ruby>花見<rt>はなみ</rt></ruby>の","role":"plain"},{"text":"<ruby>楽<rt>たの</rt></ruby>しみ<ruby>方<rt>かた</rt></ruby>は、<ruby>人<rt>ひと</rt></ruby><b>によって</b>","role":"plain"},{"text":"それぞれだ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wie man Hanami genießt, ist von Person zu Person verschieden.«","ex":{"jp":"お<ruby>花見<rt>はなみ</rt></ruby>の <ruby>楽<rt>たの</rt></ruby>しみ<ruby>方<rt>かた</rt></ruby>は、<ruby>人<rt>ひと</rt></ruby><b>によって</b> それぞれだ。","de":"Wie man Hanami genießt, ist von Person zu Person verschieden."},"simpel":"🎛️ <b>Die Stellschraube:</b> によって = »je nach X«. Dreh an X → das Ergebnis ändert sich.<br><span class=\"jp\"><ruby>国<rt>くに</rt></ruby><b>によって</b> <ruby>習慣<rt>しゅうかん</rt></ruby>が <ruby>違<rt>ちが</rt></ruby>う</span> = »Je nach Land sind die Bräuche anders.«<br>📖 Buch-Satz: 「<ruby>人<rt>ひと</rt></ruby>によって それぞれだ」","rule":"N + によって + <ruby>違<rt>ちが</rt></ruby>う／それぞれだ／さまざまだ: N ist die <b>Variable/Stellschraube</b>, an der sich etwas unterscheidet — »je nach N«.<br>Typische N: <ruby>人<rt>ひと</rt></ruby>／<ruby>国<rt>くに</rt></ruby>／<ruby>季節<rt>きせつ</rt></ruby>／<ruby>場合<rt>ばあい</rt></ruby>.<br>(による-Familie: hier »je nach« — 21 »per«, 58 »wegen«.)"},{"l":29,"t":"84 · 〜の最中に","de":"mitten in / mittendrin, als …","slots":[{"text":"<ruby>仕事<rt>しごと</rt></ruby>の<b>最中に</b>、<ruby>花見<rt>はなみ</rt></ruby>の","role":"plain"},{"text":"<ruby>誘<rt>さそ</rt></ruby>いの","role":"plain"},{"text":"<ruby>電話<rt>でんわ</rt></ruby>が","role":"plain"},{"text":"きた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Mitten in der Arbeit kam der Anruf mit der Hanami-Einladung.«","ex":{"jp":"<ruby>仕事<rt>しごと</rt></ruby>の<b>最中に</b>、<ruby>花見<rt>はなみ</rt></ruby>の <ruby>誘<rt>さそ</rt></ruby>いの <ruby>電話<rt>でんわ</rt></ruby>が きた。","de":"Mitten in der Arbeit kam der Anruf mit der Hanami-Einladung."},"simpel":"»Mitten in der Arbeit (kam etwas dazwischen)«.<br><span class='jp'><ruby>仕事<rt>しごと</rt></ruby>の<b>最中に</b></span><br>📖 Buch-Satz: 「<ruby>仕事<rt>しごと</rt></ruby>の <ruby>最中<rt>さいちゅう</rt></ruby>に」","rule":"N + の / V<sub>ている</sub> + 最中に: genau in der intensivsten Phase einer laufenden Handlung geschieht (störend) etwas anderes."},{"l":29,"t":"85 · 〜かけの N","de":"halb erledigt / angefangen (liegen geblieben)","slots":[{"text":"<ruby>机<rt>つくえ</rt></ruby>に","role":"plain"},{"text":"<ruby>飲<rt>の</rt></ruby>み<b>かけの</b>","role":"plain"},{"text":"コーヒーが","role":"plain"},{"text":"<ruby>置<rt>お</rt></ruby>いて","role":"plain"},{"text":"ある。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Auf dem Tisch steht ein halb getrunkener Kaffee.«","ex":{"jp":"やり<b>かけの</b> <ruby>仕事<rt>しごと</rt></ruby>が <ruby>気<rt>き</rt></ruby>に なって、<ruby>楽<rt>たの</rt></ruby>しめない。","de":"Die halb fertige Arbeit geht mir nicht aus dem Kopf — ich kann es nicht genießen."},"simpel":"<b>やりかけ</b> = angefangen und liegen gelassen.<br><span class='jp'>やり<b>かけの</b> <ruby>仕事<rt>しごと</rt></ruby></span> = „die halb fertige Arbeit“<br>📖 Buch-Satz: 「やりかけの <ruby>仕事<rt>しごと</rt></ruby>」","rule":"V<sub>ます</sub>-Stamm + かけ(の N): unvollendet abgebrochen. Verb: 〜かける auch »kurz davor« (死にかける) und »ansetzen« (言いかける)."},{"l":29,"t":"86 · 〜ずにはいられない","de":"ich kann nicht anders, als … (+Plus: ないではいられない)","slots":[{"text":"<ruby>満開<rt>まんかい</rt></ruby>と","role":"plain"},{"text":"<ruby>聞<rt>き</rt></ruby>いたら、<ruby>行<rt>い</rt></ruby>か<b>ずには","role":"plain"},{"text":"いられない</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wenn ich „volle Blüte“ höre, muss ich einfach hin.«","ex":{"jp":"<ruby>満開<rt>まんかい</rt></ruby>と <ruby>聞<rt>き</rt></ruby>いたら、<ruby>行<rt>い</rt></ruby>か<b>ずには いられない</b>。","de":"Wenn ich „volle Blüte“ höre, muss ich einfach hin."},"simpel":"Unwiderstehlicher Drang: »ich MUSS einfach hin«.<br><span class='jp'><ruby>行<rt>い</rt></ruby>か<b>ずには いられない</b></span><br>📖 Buch-Satz: 「<ruby>行<rt>い</rt></ruby>かずには いられない」","rule":"V<sub>ない</sub>-Stamm + ずにはいられない (する→せずに): ein innerer Drang lässt sich nicht unterdrücken. +Plus: 〜ないではいられない = gesprochenere Variante."},{"l":30,"t":"87 · 〜わけがない","de":"kann unmöglich … (logisch ausgeschlossen)","slots":[{"text":"あの","role":"plain"},{"text":"まじめな","role":"plain"},{"text":"<ruby>彼<rt>かれ</rt></ruby>が","role":"plain"},{"text":"うそを","role":"plain"},{"text":"つく<b>わけがない</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Der gewissenhafte Kerl kann unmöglich lügen.«","ex":{"jp":"<ruby>演劇<rt>えんげき</rt></ruby>で <ruby>食<rt>た</rt></ruby>べて いける? できる<b>わけがない</b>でしょう。","de":"Vom Theater leben? Das kann doch unmöglich klappen."},"simpel":"»Völlig ausgeschlossen, dass das klappt.«<br><span class='jp'>できる<b>わけがない</b></span><br>📖 Buch-Satz: 「できる わけがない」","rule":"Plain + わけがない: aus Sicht des Sprechers logisch unmöglich (»wie sollte das gehen?!«). Stärker und emotionaler als はずがない. Nicht mit わけではない (»nicht unbedingt«) verwechseln."},{"l":30,"t":"88 · 〜しかない","de":"nur … / es bleibt nur …","slots":[{"text":"<ruby>安定<rt>あんてい</rt></ruby>を","role":"plain"},{"text":"<ruby>考<rt>かんが</rt></ruby>えたら、この","role":"plain"},{"text":"<ruby>仕事<rt>しごと</rt></ruby><b>しか","role":"plain"},{"text":"ない</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wenn man an Sicherheit denkt, gibt es nur diesen Job.«","ex":{"jp":"<ruby>安定<rt>あんてい</rt></ruby>を <ruby>考<rt>かんが</rt></ruby>えたら、この <ruby>仕事<rt>しごと</rt></ruby><b>しか ない</b>。","de":"Wenn man an Sicherheit denkt, gibt es nur diesen Job."},"simpel":"<b>しか + Verneinung</b> = »nur«; <b>V しかない</b> = »bleibt nichts übrig als«.<br><span class='jp'>この <ruby>仕事<rt>しごと</rt></ruby><b>しか ない</b></span><br>📖 Buch-Satz: 「この <ruby>仕事<rt>しごと</rt></ruby>しか ない」","rule":"N + しか + Verneinung: »nur N (und sonst nichts)« — mit Mangel-Gefühl. V<sub>Grund</sub> + しかない: »es bleibt nur, zu …« (Resignation/Entschluss)."},{"l":30,"t":"89 · 〜からこそ","de":"gerade weil …","slots":[{"text":"あなたを","role":"plain"},{"text":"<ruby>心配<rt>しんぱい</rt></ruby>して","role":"plain"},{"text":"いる<b>からこそ</b>、<ruby>反対<rt>はんたい</rt></ruby>する","role":"plain"},{"text":"んです。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Gerade weil ich mir Sorgen um dich mache, bin ich dagegen.«","ex":{"jp":"あなたを <ruby>心配<rt>しんぱい</rt></ruby>して いる<b>からこそ</b>、<ruby>反対<rt>はんたい</rt></ruby>する んです。","de":"Gerade weil ich mir Sorgen um dich mache, bin ich dagegen."},"simpel":"Betont den wahren Grund: »gerade WEIL ich mir Sorgen mache«.<br><span class='jp'><ruby>心配<rt>しんぱい</rt></ruby>して いる<b>からこそ</b></span><br>📖 Buch-Satz: 「<ruby>心配<rt>しんぱい</rt></ruby>して いる からこそ」","rule":"Plain + からこそ: hebt den Grund nachdrücklich hervor — oft gegen die Erwartung des Hörers (»nicht obwohl, sondern gerade weil«). Ende gern mit のだ/んだ."},{"l":30,"t":"90 · 〜なんか","de":"so etwas wie … (abwertend) + ても","slots":[{"text":"<ruby>演劇<rt>えんげき</rt></ruby><b>なんか</b>","role":"plain"},{"text":"して","role":"plain"},{"text":"いても、<ruby>食<rt>た</rt></ruby>べて","role":"plain"},{"text":"いけないよ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Mit sowas wie Theater kannst du dich nicht ernähren.«","ex":{"jp":"<ruby>演劇<rt>えんげき</rt></ruby><b>なんか</b> して いても、<ruby>食<rt>た</rt></ruby>べて いけないよ。","de":"Mit sowas wie Theater kannst du dich nicht ernähren."},"simpel":"Abwertung + »selbst wenn«: »mit sowas wie Theater …«.<br><span class='jp'><ruby>演劇<rt>えんげき</rt></ruby><b>なんか</b> しても</span><br>📖 Buch-Satz: 「<ruby>演劇<rt>えんげき</rt></ruby>なんか しても」","rule":"N + なんか/なんて: spielt N herunter (abwertend oder bescheiden). Kombiniert mit ても: »selbst wenn man sowas (Unnützes) tut, …«. Vgl. das neutrale Beispiel-なんか (Punkt 66)."},{"l":30,"t":"91 · 〜っこない","de":"klappt nie im Leben (salopp)","slots":[{"text":"そんなの","role":"cond","label":"sowas"},{"text":"V<sub>ます</sub>","role":"verb"},{"text":"っこない","role":"plain","label":"nie!"}],"gloss":"»Definitiv unmöglich« — ます-Stamm + っこない; formeller: わけがない (87).","ex":{"jp":"<ruby>演劇<rt>えんげき</rt></ruby>だけで <ruby>生活<rt>せいかつ</rt></ruby>でき<b>っこない</b>。","de":"Allein vom Theater kann man nie im Leben leben."},"simpel":"Saloppes »unmöglich«: »davon kann man nie leben«.<br><span class='jp'><ruby>生活<rt>せいかつ</rt></ruby>でき<b>っこない</b></span><br>📖 Buch-Satz: 「<ruby>生活<rt>せいかつ</rt></ruby>でき っこない」","rule":"V<sub>ます</sub>-Stamm + っこない: emphatische Unmöglichkeit in lockerer Sprache (= 絶対に〜ない). Oft mit Potentialform: できっこない, わかりっこない."},{"l":30,"t":"92 · 〜からといって","de":"nur weil … (heißt das nicht …)","slots":[{"text":"<ruby>大学<rt>だいがく</rt></ruby>を","role":"plain"},{"text":"<ruby>出<rt>で</rt></ruby>た<b>からといって</b>、いい","role":"plain"},{"text":"<ruby>仕事<rt>しごと</rt></ruby>に","role":"plain"},{"text":"つける","role":"plain"},{"text":"とは","role":"plain"},{"text":"<ruby>限<rt>かぎ</rt></ruby>らない。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Nur weil man die Uni abgeschlossen hat, bekommt man nicht unbedingt einen guten Job.«","ex":{"jp":"<ruby>大学<rt>だいがく</rt></ruby>を <ruby>出<rt>で</rt></ruby>た<b>からといって</b>、いい <ruby>仕事<rt>しごと</rt></ruby>に つける とは <ruby>限<rt>かぎ</rt></ruby>らない。","de":"Nur weil man die Uni abgeschlossen hat, bekommt man nicht unbedingt einen guten Job."},"simpel":"Wehrt den Fehlschluss ab: »nur weil man die Uni abgeschlossen hat …«.<br><span class='jp'><ruby>出<rt>で</rt></ruby>た<b>からといって</b></span><br>📖 Buch-Satz: 「<ruby>大学<rt>だいがく</rt></ruby>を <ruby>出<rt>で</rt></ruby>た からといって」","rule":"Plain + からといって + Verneinung/Einschränkung: »aus A folgt nicht automatisch B«. Standard-Partner: とは限らない (93) oder わけではない. Gesprochen: からって."},{"l":30,"t":"93 · 〜とは限らない","de":"nicht unbedingt / nicht garantiert","slots":[{"text":"<ruby>安定<rt>あんてい</rt></ruby>した","role":"plain"},{"text":"<ruby>会社<rt>かいしゃ</rt></ruby>に","role":"plain"},{"text":"<ruby>入<rt>はい</rt></ruby>れば","role":"plain"},{"text":"<ruby>幸<rt>しあわ</rt></ruby>せだ<b>とは","role":"plain"},{"text":"限らない</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »In einer sicheren Firma zu sein macht nicht unbedingt glücklich.«","ex":{"jp":"<ruby>安定<rt>あんてい</rt></ruby>した <ruby>会社<rt>かいしゃ</rt></ruby>に <ruby>入<rt>はい</rt></ruby>れば <ruby>幸<rt>しあわ</rt></ruby>せだ<b>とは 限らない</b>。","de":"In einer sicheren Firma zu sein macht nicht unbedingt glücklich."},"simpel":"»Es ist nicht garantiert, dass …« — lässt Ausnahmen zu.<br><span class='jp'>できる<b>とは 限らない</b></span><br>📖 Buch-Satz: 「<ruby>就職<rt>しゅうしょく</rt></ruby>できる とは<ruby>限<rt>かぎ</rt></ruby>らない」","rule":"Plain + とは限らない: die Allgemein-Annahme gilt nicht immer. Oft mit 必ずしも (»nicht notwendigerweise«) und nach からといって (92)."},{"l":30,"t":"94 · 〜といったら","de":"was … angeht: unglaublich! (Ausruf)","slots":[{"text":"<ruby>父<rt>ちち</rt></ruby>の","role":"plain"},{"text":"がんこな","role":"plain"},{"text":"こと<b>といったら</b>、<ruby>誰<rt>だれ</rt></ruby>も","role":"plain"},{"text":"<ruby>説得<rt>せっとく</rt></ruby>できない。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Die Sturheit meines Vaters — da beißt sich jeder die Zähne aus.«","ex":{"jp":"<ruby>父<rt>ちち</rt></ruby>の がんこな こと<b>といったら</b>、<ruby>誰<rt>だれ</rt></ruby>も <ruby>説得<rt>せっとく</rt></ruby>できない。","de":"Die Sturheit meines Vaters — da beißt sich jeder die Zähne aus."},"simpel":"Emotionaler Ausruf über eine Eigenschaft: »diese Sturheit …!«.<br><span class='jp'>がんこな こと<b>といったら</b></span><br>📖 Buch-Satz: 「がんこな ことといったら」","rule":"N/〜こと + といったら: ruft eine Eigenschaft aus, die kaum in Worte zu fassen ist (Bewunderung ODER Genervtsein). Fortsetzung oft 言葉にならない/〜ほど oder offen gelassen."},{"l":30,"t":"95 · 〜くせに","de":"obwohl … (mit Vorwurf)","slots":[{"text":"<ruby>演劇<rt>えんげき</rt></ruby>の","role":"plain"},{"text":"こと、<ruby>何<rt>なに</rt></ruby>も","role":"plain"},{"text":"<ruby>知<rt>し</rt></ruby>らない<b>くせに</b>!","role":"plain"}],"gloss":"Baue den Beispielsatz: »Dabei hast du doch null Ahnung vom Theater!«","ex":{"jp":"<ruby>演劇<rt>えんげき</rt></ruby>の こと、<ruby>何<rt>なに</rt></ruby>も <ruby>知<rt>し</rt></ruby>らない<b>くせに</b>!","de":"Dabei hast du doch null Ahnung vom Theater!"},"simpel":"Vorwurfsvolles »obwohl«: »dabei hast du doch keine Ahnung!«.<br><span class='jp'><ruby>知<rt>し</rt></ruby>らない<b>くせに</b></span><br>📖 Buch-Satz: 「<ruby>何<rt>なに</rt></ruby>も <ruby>知<rt>し</rt></ruby>らない くせに」","rule":"Plain (な-Adj な / N の) + くせに: »obwohl« mit Kritik/Verachtung — der Widerspruch empört den Sprecher. Meist gleiches Subjekt in beiden Teilen; auch als Satzende (知らないくせに!)."},{"l":30,"t":"96 · 〜っぽい","de":"wirkt wie … / -haft (hier: kindisch)","slots":[{"text":"<ruby>役者<rt>やくしゃ</rt></ruby>に","role":"plain"},{"text":"なりたい","role":"plain"},{"text":"なんて、<ruby>子<rt>こ</rt></ruby>ども<b>っぽい</b>","role":"plain"},{"text":"<ruby>夢<rt>ゆめ</rt></ruby>だと","role":"plain"},{"text":"<ruby>言<rt>い</rt></ruby>われた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Schauspielerin werden? Das nannte er einen kindischen Traum.«","ex":{"jp":"<ruby>役者<rt>やくしゃ</rt></ruby>に なりたい なんて、<ruby>子<rt>こ</rt></ruby>ども<b>っぽい</b> <ruby>夢<rt>ゆめ</rt></ruby>だと <ruby>言<rt>い</rt></ruby>われた。","de":"Schauspielerin werden? Das nannte er einen kindischen Traum."},"simpel":"<b>っぽい</b> macht »-haft«-Adjektive: »ein kindischer Traum«.<br><span class='jp'><ruby>子<rt>こ</rt></ruby>ども<b>っぽい</b> <ruby>夢<rt>ゆめ</rt></ruby></span><br>📖 Buch-Satz: 「<ruby>子<rt>こ</rt></ruby>どもっぽい <ruby>夢<rt>ゆめ</rt></ruby>」","rule":"N/V<sub>ます</sub>/Adj-Stamm + っぽい: »hat den Anschein/die Neigung von« — wird wie ein い-Adjektiv gebeugt. 子どもっぽい ist (anders als 子どもらしい!) meist negativ."},{"l":31,"t":"97 · 〜のせいだ","de":"wegen … / … ist schuld","slots":[{"text":"N の","role":"subj","label":"Schuldiger"},{"text":"せいだ","role":"plain","label":"ist schuld"}],"gloss":"»N ist schuld (an etwas Schlechtem)« — Gegenstück zu おかげで.","ex":{"jp":"かぜを ひいたのは、<ruby>薄着<rt>うすぎ</rt></ruby>の<b>せいですよ</b>。","de":"Dass du dich erkältet hast, liegt an der dünnen Kleidung."},"simpel":"Schuldzuweisung: »das ist Onkels Schuld«.<br><span class='jp'>おじさんの<b>せいですよ</b></span><br>📖 Buch-Satz: 「おじさんの せいですよ」","rule":"N + の + せいだ/せいで: nennt vorwurfsvoll die Ursache eines schlechten Ergebnisses. Unsicher: せいか (»vielleicht wegen«); positiv: おかげで (51)."},{"l":31,"t":"98 · 〜のことだから","de":"so wie wir … kennen, bestimmt …","slots":[{"text":"<ruby>時間<rt>じかん</rt></ruby>に","role":"plain"},{"text":"<ruby>正確<rt>せいかく</rt></ruby>な","role":"plain"},{"text":"<ruby>彼<rt>かれ</rt></ruby>の","role":"plain"},{"text":"<b>ことだから</b>、もう","role":"plain"},{"text":"<ruby>着<rt>つ</rt></ruby>いて","role":"plain"},{"text":"いる","role":"plain"},{"text":"はずだ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Pünktlich wie er ist, ist er bestimmt schon da.«","ex":{"jp":"がんばりやの ゆきの <b>ことだから</b>、すぐ <ruby>元気<rt>げんき</rt></ruby>に なるよ。","de":"So eine Kämpferin wie Yuki ist bestimmt schnell wieder auf den Beinen."},"simpel":"Vermutung aus bekanntem Charakter: »typisch Yuki — bestimmt …«.<br><span class='jp'>ゆきの <b>ことだから</b></span><br>📖 Buch-Satz: 「ゆきの ことだから」","rule":"[Person] + の + ことだから: aus dem beiden Gesprächspartnern bekannten Charakter wird eine Vermutung abgeleitet. Nachsatz: だろう/はずだ/に違いない."},{"l":31,"t":"99 · N でも + 〜たらどう","de":"wie wär's, wenn du mal …?","slots":[{"text":"<ruby>気分<rt>きぶん</rt></ruby><ruby>転換<rt>てんかん</rt></ruby>に、<ruby>散歩<rt>さんぽ</rt></ruby><b>でも","role":"plain"},{"text":"したら","role":"plain"},{"text":"どう</b>?","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wie wär's zur Abwechslung mal mit einem Spaziergang?«","ex":{"jp":"<ruby>気分<rt>きぶん</rt></ruby><ruby>転換<rt>てんかん</rt></ruby>に、<ruby>散歩<rt>さんぽ</rt></ruby><b>でも したら どう</b>?","de":"Wie wär's zur Abwechslung mal mit einem Spaziergang?"},"simpel":"Sanfter Vorschlag: »mach doch mal z. B. einen Spaziergang«.<br><span class='jp'><ruby>散歩<rt>さんぽ</rt></ruby><b>でも したら どう</b>?</span><br>📖 Buch-Satz: 「<ruby>散歩<rt>さんぽ</rt></ruby>でも したら どう?」","rule":"N + でも (»z. B./oder so«) + V<sub>たら</sub> + どう(ですか): unaufdringlicher Ratschlag. でも hält den Vorschlag offen, たらどう fragt nach der Reaktion."},{"l":31,"t":"100 · 〜てばかりはいられない","de":"kann nicht ewig nur …","slots":[{"text":"いつまでも","role":"plain"},{"text":"<ruby>寝<rt>ね</rt></ruby>て<b>ばかりは","role":"plain"},{"text":"いられない</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich kann nicht ewig nur im Bett liegen.«","ex":{"jp":"いつまでも <ruby>寝<rt>ね</rt></ruby>て<b>ばかりは いられない</b>。","de":"Ich kann nicht ewig nur im Bett liegen."},"simpel":"»Ich kann nicht ewig nur im Bett liegen!«<br><span class='jp'><ruby>寝<rt>ね</rt></ruby>て<b>ばかりは いられない</b></span><br>📖 Buch-Satz: 「<ruby>寝<rt>ね</rt></ruby>て ばかりは いられない」","rule":"V<sub>て</sub> + ばかりはいられない (auch ばかりもいられない): man kann/darf nicht länger nur eine Sache tun — Zeit zu handeln. Kombiniert てばかり (41) mit いられない."},{"l":31,"t":"101 · 〜ことにする","de":"beschließen, zu …","slots":[{"text":"これからは","role":"plain"},{"text":"<ruby>規則正<rt>きそくただ</rt></ruby>しい","role":"plain"},{"text":"<ruby>生活<rt>せいかつ</rt></ruby>を","role":"plain"},{"text":"する<b>ことにした</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich habe beschlossen, ab jetzt geregelt zu leben.«","ex":{"jp":"これからは <ruby>規則正<rt>きそくただ</rt></ruby>しい <ruby>生活<rt>せいかつ</rt></ruby>を する<b>ことにした</b>。","de":"Ich habe beschlossen, ab jetzt geregelt zu leben."},"simpel":"Eigener Entschluss: »ich habe beschlossen, mein Leben zu ändern«.<br><span class='jp'><ruby>変<rt>か</rt></ruby>える<b>ことにした</b></span><br>📖 Buch-Satz: 「<ruby>生活<rt>せいかつ</rt></ruby>を <ruby>変<rt>か</rt></ruby>える ことにした」","rule":"V<sub>Grund/ない</sub> + ことにする: bewusste eigene Entscheidung. ことにしている = zur Gewohnheit gemachte Entscheidung. Fremdbestimmt: ことになる (»es wurde beschlossen«)."},{"l":31,"t":"102 · 〜っぱなし","de":"(an)gelassen und so belassen","slots":[{"text":"テレビを","role":"plain"},{"text":"つけ<b>っぱなし</b>で","role":"plain"},{"text":"<ruby>寝<rt>ね</rt></ruby>て","role":"plain"},{"text":"しまった。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich bin mit laufendem Fernseher eingeschlafen.«","ex":{"jp":"テレビを つけ<b>っぱなし</b>で <ruby>寝<rt>ね</rt></ruby>て しまった。","de":"Ich bin mit laufendem Fernseher eingeschlafen."},"simpel":"Etwas tun und (nachlässig) so lassen: »Fernseher angelassen«.<br><span class='jp'>つけ<b>っぱなし</b></span><br>📖 Buch-Satz: 「テレビを つけっぱなし」","rule":"V<sub>ます</sub>-Stamm + っぱなし: man tut etwas und lässt es dann so (oft nachlässig: つけっぱなし, 開けっぱなし) — oder ein Zustand dauert ununterbrochen (立ちっぱなし)."},{"l":31,"t":"103 · 〜だらけ","de":"voller … (unangenehm)","slots":[{"text":"<ruby>子<rt>こ</rt></ruby>どもたちは","role":"plain"},{"text":"どろ<b>だらけ</b>に","role":"plain"},{"text":"なって","role":"plain"},{"text":"<ruby>帰<rt>かえ</rt></ruby>って","role":"plain"},{"text":"きた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Die Kinder kamen schlammverschmiert nach Hause.«","ex":{"jp":"<ruby>部屋<rt>へや</rt></ruby><ruby>中<rt>じゅう</rt></ruby> ごみ<b>だらけ</b>じゃない!","de":"Dein ganzes Zimmer ist ja voller Müll!"},"simpel":"Übervoll mit Unangenehmem: »das ganze Zimmer voller Müll«.<br><span class='jp'>ごみ<b>だらけ</b></span><br>📖 Buch-Satz: 「<ruby>部屋<rt>へや</rt></ruby><ruby>中<rt>じゅう</rt></ruby> ごみだらけ」","rule":"N + だらけ: übersät/voll von etwas Negativem (ごみ, ほこり, 間違い, どろ). Mit N中 (»das ganze N«) kombiniert: 部屋中ごみだらけ."},{"l":31,"t":"104 · 〜気がする/しない","de":"das Gefühl haben (keine Lust verspüren)","slots":[{"text":"<ruby>熱<rt>ねつ</rt></ruby>の","role":"plain"},{"text":"せいか、<ruby>何<rt>なに</rt></ruby>も","role":"plain"},{"text":"<ruby>食<rt>た</rt></ruby>べる","role":"plain"},{"text":"<ruby>気<rt>き</rt></ruby>が","role":"plain"},{"text":"<b>しない</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Vielleicht wegen des Fiebers ist mir nach gar nichts zu essen.«","ex":{"jp":"<ruby>熱<rt>ねつ</rt></ruby>の せいか、<ruby>何<rt>なに</rt></ruby>も <ruby>食<rt>た</rt></ruby>べる <ruby>気<rt>き</rt></ruby>が <b>しない</b>。","de":"Vielleicht wegen des Fiebers ist mir nach gar nichts zu essen."},"simpel":"»Mir ist nicht nach Essen« — <b>気がしない</b>.<br><span class='jp'><ruby>食<rt>た</rt></ruby>べる <ruby>気<rt>き</rt></ruby>が <b>しない</b></span><br>📖 Buch-Satz: 「<ruby>何<rt>なに</rt></ruby>も <ruby>食<rt>た</rt></ruby>べる <ruby>気<rt>き</rt></ruby>が しない」","rule":"V<sub>Grund</sub> + 気がする/気がしない: das (unwillkürliche) Gefühl, etwas tun zu wollen — verneint: keinerlei Antrieb. Auch Vermutungs-気がする (»mir ist, als ob«)."},{"l":31,"t":"105 · 〜たりして","de":"am Ende noch … (scherzhafte Vermutung)","slots":[{"text":"<ruby>明日<rt>あした</rt></ruby>には","role":"plain"},{"text":"けろっと","role":"plain"},{"text":"<ruby>元気<rt>げんき</rt></ruby>に","role":"plain"},{"text":"なっ<b>たりして</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Und morgen bist du am Ende wieder putzmunter … haha.«","ex":{"jp":"<ruby>明日<rt>あした</rt></ruby>には けろっと <ruby>元気<rt>げんき</rt></ruby>に なっ<b>たりして</b>。","de":"Und morgen bist du am Ende wieder putzmunter … haha."},"simpel":"Halb im Scherz: »und am Ende bist du plötzlich wieder fit …«.<br><span class='jp'><ruby>元気<rt>げんき</rt></ruby>に なっ<b>たりして</b></span><br>📖 Buch-Satz: 「<ruby>元気<rt>げんき</rt></ruby>に なったりして」","rule":"V<sub>たり</sub> + して (Satzende): wirft halb scherzhaft eine Möglichkeit in den Raum — »wär ja möglich … haha (oder doch?)«. Reine Gesprächsfloskel."},{"l":31,"t":"106 · 〜らしい/らしくない","de":"(un)typisch für …","slots":[{"text":"<ruby>弱気<rt>よわき</rt></ruby>な","role":"plain"},{"text":"ことを","role":"plain"},{"text":"<ruby>言<rt>い</rt></ruby>うなんて、ゆき<b>らしくない</b>なあ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »So kleinlaut — das sieht Yuki gar nicht ähnlich.«","ex":{"jp":"<ruby>弱気<rt>よわき</rt></ruby>な ことを <ruby>言<rt>い</rt></ruby>うなんて、ゆき<b>らしくない</b>なあ。","de":"So kleinlaut — das sieht Yuki gar nicht ähnlich."},"simpel":"»Das sieht Yuki gar nicht ähnlich.«<br><span class='jp'>ゆき<b>らしくない</b>なあ</span><br>📖 Buch-Satz: 「ゆきらしくないなあ」","rule":"N + らしい: »typisch N, wie es sich für N gehört« (positiv). Verneint らしくない: »untypisch, passt nicht zu«. Zweite Lesart: Plain + らしい = »anscheinend« (Hörensagen)."},{"l":31,"t":"107 · 〜かと思った","de":"ich dachte (schon), es sei …","slots":[{"text":"<ruby>声<rt>こえ</rt></ruby>が","role":"plain"},{"text":"そっくりで、お<ruby>母<rt>かあ</rt></ruby>さん<b>かと","role":"plain"},{"text":"思った</b>よ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Die Stimme war so ähnlich — ich dachte schon, es sei deine Mutter.«","ex":{"jp":"<ruby>声<rt>こえ</rt></ruby>が そっくりで、お<ruby>母<rt>かあ</rt></ruby>さん<b>かと 思った</b>よ。","de":"Die Stimme war so ähnlich — ich dachte schon, es sei deine Mutter."},"simpel":"Kurzer Irrtum: »ich dachte schon, es wäre deine Mutter«.<br><span class='jp'>お<ruby>母<rt>かあ</rt></ruby>さん<b>かと 思った</b></span><br>📖 Buch-Satz: 「お<ruby>母<rt>かあ</rt></ruby>さんかと <ruby>思<rt>おも</rt></ruby>った」","rule":"N/Plain + かと思った: man hielt etwas kurz für etwas anderes — der Irrtum hat sich eben aufgeklärt. Auch erleichtert/erschrocken: 死ぬかと思った »ich dachte, ich sterbe«."},{"l":31,"t":"108 · 〜とか〜とか","de":"… und … (offene Aufzählung)","slots":[{"text":"<ruby>休<rt>やす</rt></ruby>みの","role":"plain"},{"text":"<ruby>日<rt>ひ</rt></ruby>は、<ruby>映画<rt>えいが</rt></ruby>を","role":"plain"},{"text":"<ruby>見<rt>み</rt></ruby>る<b>とか</b>","role":"plain"},{"text":"<ruby>本<rt>ほん</rt></ruby>を","role":"plain"},{"text":"<ruby>読<rt>よ</rt></ruby>む<b>とか</b>","role":"plain"},{"text":"して","role":"plain"},{"text":"いる。","role":"plain"}],"gloss":"Baue den Beispielsatz: »An freien Tagen schaue ich Filme, lese und so.«","ex":{"jp":"アイスクリーム<b>とか</b> みかん<b>とか</b>、<ruby>食<rt>た</rt></ruby>べたい <ruby>物<rt>もの</rt></ruby> ある?","de":"Eis, Mandarinen oder so — hast du auf irgendwas Appetit?"},"simpel":"Lockeres Aufzählen: »Eis, Mandarinen und sowas«.<br><span class='jp'>アイス<b>とか</b> みかん<b>とか</b></span><br>📖 Buch-Satz: 「アイスクリームとか みかんとか」","rule":"N とか N とか (V<sub>einf</sub> とか): unvollständige Beispiel-Aufzählung im Gespräch (»zum Beispiel … und …«). Schriftlicher: 〜や〜など."},{"l":31,"t":"109 · 〜のついでに","de":"bei der Gelegenheit von …","slots":[{"text":"<ruby>散歩<rt>さんぽ</rt></ruby>の<b>ついでに</b>","role":"plain"},{"text":"<ruby>手紙<rt>てがみ</rt></ruby>を","role":"plain"},{"text":"<ruby>出<rt>だ</rt></ruby>して","role":"plain"},{"text":"きた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Beim Spaziergang habe ich gleich den Brief eingeworfen.«","ex":{"jp":"<ruby>買<rt>か</rt></ruby>い<ruby>物<rt>もの</rt></ruby>の<b>ついでに</b>、お<ruby>見舞<rt>みま</rt></ruby>いに <ruby>寄<rt>よ</rt></ruby>って くれたの?","de":"Du hast beim Einkaufen einen Krankenbesuch drangehängt?"},"simpel":"Nebenbei miterledigt: »beim Einkaufen (gleich mit)«.<br><span class='jp'><ruby>買<rt>か</rt></ruby>い<ruby>物<rt>もの</rt></ruby>の<b>ついでに</b></span><br>📖 Buch-Satz: 「<ruby>買<rt>か</rt></ruby>い<ruby>物<rt>もの</rt></ruby>の ついでに」","rule":"N + の / V<sub>Grund・た</sub> + ついでに: die Gelegenheit einer Haupthandlung für eine Nebenhandlung nutzen. Haupthandlung zuerst, Nebensache folgt."},{"l":31,"t":"110 · 〜に違いない","de":"es muss (ganz sicher) … sein","slots":[{"text":"<ruby>元気<rt>げんき</rt></ruby>が","role":"plain"},{"text":"ない。<ruby>何<rt>なに</rt></ruby>か","role":"plain"},{"text":"あった<b>に違いない</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Sie ist so still — da muss etwas vorgefallen sein.«","ex":{"jp":"<ruby>元気<rt>げんき</rt></ruby>が ない。<ruby>何<rt>なに</rt></ruby>か あった<b>に違いない</b>。","de":"Sie ist so still — da muss etwas vorgefallen sein."},"simpel":"Starke Schlussfolgerung: »da muss etwas passiert sein«.<br><span class='jp'><ruby>何<rt>なに</rt></ruby>か あった<b>に違いない</b></span><br>📖 Buch-Satz: 「<ruby>何<rt>なに</rt></ruby>か あったに<ruby>違<rt>ちが</rt></ruby>いない」","rule":"Plain + に違いない (な-Adj/N ohne だ): der Sprecher ist sich aus Indizien (fast) sicher. Salopp: に決まってる (36)."},{"l":31,"t":"111 · これほど〜ことがない","de":"noch nie so … (Erfahrungs-Superlativ)","slots":[{"text":"これ<b>ほど</b>","role":"plain"},{"text":"つらい","role":"plain"},{"text":"かぜは","role":"plain"},{"text":"ひいた","role":"plain"},{"text":"<b>ことがない</b>よ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »So eine üble Erkältung hatte ich noch nie.«","ex":{"jp":"これ<b>ほど</b> つらい かぜは ひいた <b>ことがない</b>よ。","de":"So eine üble Erkältung hatte ich noch nie."},"simpel":"»So eine schlimme Erkältung hatte ich noch nie.«<br><span class='jp'>これ<b>ほど</b> つらい かぜは ひいた <b>ことがない</b></span><br>📖 Buch-Satz: 「これほど つらい かぜは ひいた ことがない」","rule":"これほど/こんなに + [Adj+N] + V<sub>た</sub>ことがない: die aktuelle Erfahrung übertrifft alles Bisherige. Kombination aus Grad-ほど (7) und Erfahrungs-たことがある."},{"l":31,"t":"112 · N 抜きで(は)","de":"ohne … (geht es nicht) (+Plus: てしかたがない)","slots":[{"text":"すし","role":"plain"},{"text":"は","role":"plain"},{"text":"わさび<b>抜きで</b>","role":"plain"},{"text":"お<ruby>願<rt>ねが</rt></ruby>いします。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Das Sushi bitte ohne Wasabi.«","ex":{"jp":"<ruby>文化祭<rt>ぶんかさい</rt></ruby>の <ruby>劇<rt>げき</rt></ruby>は、ゆき<b>抜きでは</b> <ruby>始<rt>はじ</rt></ruby>められないよ。","de":"Das Theaterstück beim Schulfest können wir ohne Yuki nicht anfangen."},"simpel":"<b>抜きで</b> = »ohne (das sonst Übliche)«.<br><span class='jp'>ゆき<b>抜きでは</b> <ruby>始<rt>はじ</rt></ruby>められない</span> = „ohne Yuki können wir nicht anfangen“<br>📖 Buch-Satz: 「ゆき<ruby>抜<rt>ぬ</rt></ruby>きでは <ruby>始<rt>はじ</rt></ruby>められない」","rule":"N + 抜きで(は/に): unter Weglassung von N — 抜きでは + Verneinung: »ohne N geht es nicht«. Auch wörtlich: わさび抜きで »ohne Wasabi«. +Plus: 〜てしかたがない (= てしょうがない, 113)."},{"l":31,"t":"113 · 〜てしょうがない","de":"unerträglich … / kann es kaum erwarten","slots":[{"text":"<ruby>早<rt>はや</rt></ruby>く","role":"plain"},{"text":"みんなと","role":"plain"},{"text":"<ruby>練習<rt>れんしゅう</rt></ruby>したくて<b>しょうがない</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich kann es kaum erwarten, wieder mit allen zu proben.«","ex":{"jp":"<ruby>早<rt>はや</rt></ruby>く みんなと <ruby>練習<rt>れんしゅう</rt></ruby>したくて<b>しょうがない</b>。","de":"Ich kann es kaum erwarten, wieder mit allen zu proben."},"simpel":"Übermächtiges Gefühl: »ich will unbedingt wieder proben!«.<br><span class='jp'>したくて<b>しょうがない</b></span><br>📖 Buch-Satz: 「<ruby>練習<rt>れんしゅう</rt></ruby>したくて しょうがない」","rule":"Gefühls-て-Form + しょうがない/しかたがない/たまらない: das Gefühl ist nicht zu bändigen. Mit 〜たくて: brennendes Wollen. Das große Finale des Buchs 😊."},{"l":32,"t":"1 · 〜につき","de":"wegen … (formelle Bekanntmachung)","slots":[{"text":"N","role":"subj","label":"Anlass"},{"text":"につき","role":"actor","label":"wegen"},{"text":"[Maßnahme/Angebot]","role":"plain"}],"gloss":"Bekanntmachungs-Floskel: »wegen/anlässlich N (gilt) …«. Zweite Lesart: pro N.","ex":{"jp":"<ruby>新規<rt>しんき</rt></ruby>オープン<b>につき</b>、スタッフを <ruby>募集<rt>ぼしゅう</rt></ruby>します。","de":"Anlässlich der Neueröffnung suchen wir Personal."},"simpel":"Aushang-Grund: »anlässlich/wegen der Neueröffnung«.<br><span class='jp'>オープン<b>につき</b></span><br>📖 Buch-Satz: 「オープンにつき」","rule":"N + につき: in Anzeigen/Aushängen (1) »wegen/anlässlich N« (オープンにつき, 工事中につき), (2) »pro N« (一人につき). Rein schriftlich-formell; im Gespräch のため/だから bzw. あたり."},{"l":32,"t":"2 · 〜を問わず","de":"unabhängig von … / ohne Rücksicht auf …","slots":[{"text":"この","role":"plain"},{"text":"<ruby>仕事<rt>しごと</rt></ruby>は","role":"plain"},{"text":"<ruby>昼夜<rt>ちゅうや</rt></ruby><b>を問わず</b>","role":"plain"},{"text":"<ruby>連絡<rt>れんらく</rt></ruby>が","role":"plain"},{"text":"<ruby>来<rt>く</rt></ruby>る。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Bei diesem Job kommen Anrufe zu jeder Tages- und Nachtzeit.«","ex":{"jp":"<ruby>国籍<rt>こくせき</rt></ruby><b>を問わず</b>、どなたでも <ruby>応募<rt>おうぼ</rt></ruby>できます。","de":"Unabhängig von der Nationalität kann sich jeder bewerben."},"simpel":"»Nationalität egal« — <b>を問わず</b>.<br><span class='jp'><ruby>国籍<rt>こくせき</rt></ruby><b>を問わず</b></span><br>📖 Buch-Satz: 「<ruby>国籍<rt>こくせき</rt></ruby>を<ruby>問<rt>と</rt></ruby>わず」","rule":"N + を問わず: das Kriterium N spielt keine Rolle (»ohne nach N zu fragen«). Typisch mit Paaren/Kategorien: 男女を問わず, 経験の有無を問わず, 昼夜を問わず. Schriftlich-formell."},{"l":32,"t":"3 · 〜に限り","de":"beschränkt auf … / nur für …","slots":[{"text":"N","role":"subj","label":"exklusiv"},{"text":"に<ruby>限<rt>かぎ</rt></ruby>り","role":"actor","label":"nur für"},{"text":"[Regel/Angebot]","role":"plain"}],"gloss":"Formelle Eingrenzung: »gilt ausschließlich für N«. Anzeige-/Gutschein-Sprache.","ex":{"jp":"N2レベル<ruby>以上<rt>いじょう</rt></ruby>の <ruby>方<rt>かた</rt></ruby><b>に限り</b>、<ruby>応募<rt>おうぼ</rt></ruby><ruby>可能<rt>かのう</rt></ruby>です。","de":"Bewerben können sich ausschließlich Personen ab N2-Niveau."},"simpel":"Exklusiv-Bedingung: »nur für Personen ab N2«.<br><span class='jp'>N2レベル<ruby>以上<rt>いじょう</rt></ruby>の <ruby>方<rt>かた</rt></ruby><b>に限り</b></span><br>📖 Buch-Satz: 「N2レベル<ruby>以上<rt>いじょう</rt></ruby>の <ruby>方<rt>かた</rt></ruby>に<ruby>限<rt>かぎ</rt></ruby>り」","rule":"N + に限り: »ausschließlich für N« — grenzt den Geltungsbereich formell ein (Anzeigen, Gutscheine, Regeln). Vgl. に限って (»ausgerechnet«, andere Nuance!) und に限らず (»nicht nur«, Punkt 72 als 〜に限らず)."},{"l":32,"t":"4 · 〜に<ruby>応<rt>おう</rt></ruby>じ(て)","de":"🎚️ je nach … gestaffelt / passend zu …","slots":[{"text":"<ruby>給与<rt>きゅうよ</rt></ruby>は","role":"plain"},{"text":"<ruby>経験<rt>けいけん</rt></ruby><ruby>年数<rt>ねんすう</rt></ruby><b>に<ruby>応<rt>おう</rt></ruby>じて</b>","role":"plain"},{"text":"<ruby>決定<rt>けってい</rt></ruby>します。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Das Gehalt wird entsprechend den Berufsjahren festgelegt.«","ex":{"jp":"<ruby>給与<rt>きゅうよ</rt></ruby>は <ruby>経験<rt>けいけん</rt></ruby><ruby>年数<rt>ねんすう</rt></ruby><b>に<ruby>応<rt>おう</rt></ruby>じて</b> <ruby>決定<rt>けってい</rt></ruby>します。","de":"Das Gehalt wird entsprechend den Berufsjahren festgelegt."},"simpel":"🎚️ <b>Die Staffelung / der Schieberegler:</b> に応じて = »je nach X gestaffelt / passend zu X«.<br><span class=\"jp\"><ruby>経験<rt>けいけん</rt></ruby><ruby>年数<rt>ねんすう</rt></ruby><b>に<ruby>応<rt>おう</rt></ruby>じて</b> <ruby>給与<rt>きゅうよ</rt></ruby>が <ruby>決<rt>き</rt></ruby>まる</span> = »Das Gehalt richtet sich nach den Berufsjahren« (mehr Erfahrung → mehr Gehalt)<br>📖 Buch-Satz: 「<ruby>経験<rt>けいけん</rt></ruby><ruby>年数<rt>ねんすう</rt></ruby>に<ruby>応<rt>おう</rt></ruby>じて」","rule":"N + に応じて = etwas <b>passt sich flexibel an N an</b> / ist nach N gestaffelt (Gehalt nach Erfahrung, Service nach Wunsch, Preis nach Menge). Attributiv: に応じた + N.<br>≈ によって (je nach), betont aber das <b>Sich-Anpassen/Staffeln</b>."},{"l":32,"t":"5 · 〜にかかわらず","de":"unabhängig davon, ob …","slots":[{"text":"<ruby>金額<rt>きんがく</rt></ruby>の","role":"plain"},{"text":"<ruby>大小<rt>だいしょう</rt></ruby><b>にかかわらず</b>、<ruby>領収書<rt>りょうしゅうしょ</rt></ruby>を","role":"plain"},{"text":"<ruby>発行<rt>はっこう</rt></ruby>します。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Unabhängig vom Betrag stellen wir eine Quittung aus.«","ex":{"jp":"<ruby>採否<rt>さいひ</rt></ruby><b>にかかわらず</b>、<ruby>結果<rt>けっか</rt></ruby>は ご<ruby>連絡<rt>れんらく</rt></ruby>します。","de":"Ob Zusage oder Absage — wir teilen Ihnen das Ergebnis mit."},"simpel":"»Ob Zu- oder Absage — wir melden uns«: <b>にかかわらず</b>.<br><span class='jp'><ruby>採否<rt>さいひ</rt></ruby><b>にかかわらず</b></span><br>📖 Buch-Satz: 「<ruby>採否<rt>さいひ</rt></ruby>にかかわらず」","rule":"N (oft Gegensatzpaar) + にかかわらず: das Ergebnis/der Unterschied ändert nichts (»gleichgültig ob«). 採否 (Annahme oder Ablehnung), 天候にかかわらず. Vgl. にもかかわらず (»obwohl«, Punkt 21) — nicht verwechseln!"},{"l":32,"t":"6 · 〜において","de":"🏛️ in / bei / im Rahmen von … (förmliches で)","slots":[{"text":"<ruby>面接<rt>めんせつ</rt></ruby>は","role":"plain"},{"text":"<ruby>当店<rt>とうてん</rt></ruby><b>において</b>","role":"plain"},{"text":"<ruby>行<rt>おこな</rt></ruby>います。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Das Vorstellungsgespräch findet in unserem Geschäft statt.«","ex":{"jp":"<ruby>面接<rt>めんせつ</rt></ruby>は <ruby>当店<rt>とうてん</rt></ruby><b>において</b> <ruby>行<rt>おこな</rt></ruby>います。","de":"Das Vorstellungsgespräch findet in unserem Geschäft statt."},"simpel":"🏛️ <b>Das förmliche »で« aus Urkunden &amp; Durchsagen:</b> において = »in / bei / im Rahmen von« (Ort, Zeit, Gebiet).<br><span class=\"jp\">ホテル<b>において</b> <ruby>開催<rt>かいさい</rt></ruby>されます</span> = »wird im Hotel abgehalten«<br>📖 Buch-Satz: 「<ruby>当店<rt>とうてん</rt></ruby>において」","rule":"N + において = förmliches <b>で</b> für Ort/Zeit/Bereich (»in/bei/auf dem Gebiet von«). Klingt nach Zeremonie, Schild, Bericht. Attributiv: N + における + N.<br>(<ruby>当店<rt>とうてん</rt></ruby>／<ruby>当社<rt>とうしゃ</rt></ruby> = »unser Geschäft/unsere Firma«, formelle Selbstbezeichnung.)"},{"l":32,"t":"7 · 〜の際に","de":"anlässlich / bei … (+Plus: 〜に際して)","slots":[{"text":"<ruby>面接<rt>めんせつ</rt></ruby>の<b>際に</b>、<ruby>履歴書<rt>りれきしょ</rt></ruby>を","role":"plain"},{"text":"お<ruby>持<rt>も</rt></ruby>ち","role":"plain"},{"text":"ください。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Bringen Sie zum Vorstellungsgespräch bitte Ihren Lebenslauf mit.«","ex":{"jp":"<ruby>面接<rt>めんせつ</rt></ruby>の<b>際に</b>、<ruby>履歴書<rt>りれきしょ</rt></ruby>を お<ruby>持<rt>も</rt></ruby>ち ください。","de":"Bringen Sie zum Vorstellungsgespräch bitte Ihren Lebenslauf mit."},"simpel":"Formelles とき: »beim Vorstellungsgespräch«.<br><span class='jp'><ruby>面接<rt>めんせつ</rt></ruby>の<b>際に</b></span><br>📖 Buch-Satz: 「<ruby>面接<rt>めんせつ</rt></ruby>の<ruby>際<rt>さい</rt></ruby>に」","rule":"N + の際(に) / V + 際(に): formell »bei/anlässlich/im Fall von«. +Plus 〜に際して: »anlässlich, zum Zeitpunkt des Beginns von« (noch zeremonieller: 入学に際して)."},{"l":32,"t":"8 · 〜こと","de":"Anweisungs-Stil: »… ist mitzubringen«","slots":[{"text":"レポートは","role":"plain"},{"text":"<ruby>金曜日<rt>きんようび</rt></ruby>までに","role":"plain"},{"text":"<ruby>提出<rt>ていしゅつ</rt></ruby>する<b>こと</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Der Bericht ist bis Freitag einzureichen.«","ex":{"jp":"<ruby>面接<rt>めんせつ</rt></ruby>には <ruby>履歴書<rt>りれきしょ</rt></ruby><ruby>持参<rt>じさん</rt></ruby><b>のこと</b>。","de":"Zum Gespräch ist der Lebenslauf mitzubringen."},"simpel":"Regel-Endung <b>のこと</b>: knappe schriftliche Anweisung.<br><span class='jp'><ruby>履歴書<rt>りれきしょ</rt></ruby><ruby>持参<rt>じさん</rt></ruby><b>のこと</b></span><br>📖 Buch-Satz: 「<ruby>履歴書<rt>りれきしょ</rt></ruby><ruby>持参<rt>じさん</rt></ruby>のこと」","rule":"[Anweisung] + こと: schriftlicher Anweisungsstil auf Aushängen/Regeln (»es gilt: …«). N + のこと oder V<sub>Grund/ない</sub> + こと (レポートは金曜までに出すこと). Unpersönlich-knapp."},{"l":33,"t":"9 · 〜て以来","de":"seit … (durchgehend bis heute)","slots":[{"text":"<ruby>入社<rt>にゅうしゃ</rt></ruby>して<b>以来</b>、5<ruby>年間<rt>ねんかん</rt></ruby>","role":"plain"},{"text":"ずっと","role":"plain"},{"text":"<ruby>営業部<rt>えいぎょうぶ</rt></ruby>で","role":"plain"},{"text":"<ruby>働<rt>はたら</rt></ruby>いて","role":"plain"},{"text":"きました。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Seit meinem Eintritt in die Firma habe ich fünf Jahre lang durchgehend im Vertrieb gearbeitet.«","ex":{"jp":"<ruby>入社<rt>にゅうしゃ</rt></ruby>して<b>以来</b>、5<ruby>年間<rt>ねんかん</rt></ruby> ずっと <ruby>営業部<rt>えいぎょうぶ</rt></ruby>で <ruby>働<rt>はたら</rt></ruby>いて きました。","de":"Seit meinem Eintritt in die Firma habe ich fünf Jahre lang durchgehend im Vertrieb gearbeitet."},"simpel":"»Seit meinem Firmeneintritt (die ganze Zeit)«.<br><span class='jp'><ruby>入社<rt>にゅうしゃ</rt></ruby>して<b>以来</b></span><br>📖 Buch-Satz: 「<ruby>入社<rt>にゅうしゃ</rt></ruby>して<ruby>以来<rt>いらい</rt></ruby>」","rule":"V<sub>て</sub> + 以来 / N + 以来: seit dem (einmaligen) Ereignis dauert der Zustand ununterbrochen an. Nur für Vergangenes mit Dauer-Wirkung; nicht für kürzlich Geplantes."},{"l":33,"t":"10 · 〜をはじめ","de":"allen voran … / angefangen bei …","slots":[{"text":"<ruby>部長<rt>ぶちょう</rt></ruby><b>をはじめ</b>、<ruby>部<rt>ぶ</rt></ruby>の","role":"plain"},{"text":"みなさまには","role":"plain"},{"text":"<ruby>大変<rt>たいへん</rt></ruby>","role":"plain"},{"text":"お<ruby>世話<rt>せわ</rt></ruby>に","role":"plain"},{"text":"なりました。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Allen voran dem Abteilungsleiter — und dem ganzen Team — verdanke ich sehr viel.«","ex":{"jp":"<ruby>部長<rt>ぶちょう</rt></ruby><b>をはじめ</b>、<ruby>部<rt>ぶ</rt></ruby>の みなさまには <ruby>大変<rt>たいへん</rt></ruby> お<ruby>世話<rt>せわ</rt></ruby>に なりました。","de":"Allen voran dem Abteilungsleiter — und dem ganzen Team — verdanke ich sehr viel."},"simpel":"Nennt den wichtigsten Vertreter zuerst: »allen voran der Abteilungsleiter«.<br><span class='jp'><ruby>部長<rt>ぶちょう</rt></ruby><b>をはじめ</b></span><br>📖 Buch-Satz: 「<ruby>部長<rt>ぶちょう</rt></ruby>をはじめ」","rule":"N + をはじめ(として): hebt aus einer Gruppe den repräsentativsten Vertreter hervor — »allen voran N, (und auch alle anderen)«. Förmlich, typisch für Reden und Dankesworte. Attributiv: をはじめとする + N."},{"l":33,"t":"11 · 〜のもとで","de":"unter (der Leitung/Obhut) von …","slots":[{"text":"<ruby>先輩方<rt>せんぱいがた</rt></ruby>の","role":"plain"},{"text":"ご<ruby>指導<rt>しどう</rt></ruby><b>のもとで</b>、<ruby>多<rt>おお</rt></ruby>くの","role":"plain"},{"text":"ことを","role":"plain"},{"text":"<ruby>学<rt>まな</rt></ruby>びました。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Unter der Anleitung meiner Senpai habe ich vieles gelernt.«","ex":{"jp":"<ruby>先輩方<rt>せんぱいがた</rt></ruby>の ご<ruby>指導<rt>しどう</rt></ruby><b>のもとで</b>、<ruby>多<rt>おお</rt></ruby>くの ことを <ruby>学<rt>まな</rt></ruby>びました。","de":"Unter der Anleitung meiner Senpai habe ich vieles gelernt."},"simpel":"»Unter der Anleitung der Senpai«.<br><span class='jp'>ご<ruby>指導<rt>しどう</rt></ruby><b>のもとで</b></span><br>📖 Buch-Satz: 「<ruby>先輩方<rt>せんぱいがた</rt></ruby>の ご<ruby>指導<rt>しどう</rt></ruby>のもとで」","rule":"N + のもとで/のもとに: unter dem Einfluss/Schutz/der Leitung von N (指導のもとで, 両親のもとで, 法のもとに). Förmlich; wörtlich »unter dem Fuß/der Basis von«."},{"l":33,"t":"12 · 〜はもとより","de":"📈 N sowieso — und (überraschend) sogar auch …","slots":[{"text":"<ruby>仕事<rt>しごと</rt></ruby>の","role":"plain"},{"text":"<ruby>進<rt>すす</rt></ruby>め<ruby>方<rt>かた</rt></ruby><b>はもとより</b>、<ruby>社会人<rt>しゃかいじん</rt></ruby>としての","role":"plain"},{"text":"<ruby>心構<rt>こころがま</rt></ruby>え<b>も</b>","role":"plain"},{"text":"<ruby>教<rt>おそ</rt></ruby>えて","role":"plain"},{"text":"いただきました。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Nicht nur die Arbeitsweise — auch die Haltung als Berufstätiger wurde mir vermittelt.«","ex":{"jp":"<ruby>仕事<rt>しごと</rt></ruby>の <ruby>進<rt>すす</rt></ruby>め<ruby>方<rt>かた</rt></ruby><b>はもとより</b>、<ruby>社会人<rt>しゃかいじん</rt></ruby>としての <ruby>心構<rt>こころがま</rt></ruby>え<b>も</b> <ruby>教<rt>おそ</rt></ruby>えて いただきました。","de":"Nicht nur die Arbeitsweise — auch die Haltung als Berufstätiger wurde mir vermittelt."},"simpel":"📈 <b>Steigerung »sowieso → und sogar«:</b> N はもとより = »N versteht sich von selbst — und darüber hinaus auch …«.<br><span class=\"jp\"><ruby>国内<rt>こくない</rt></ruby><b>はもとより</b>、<ruby>海外<rt>かいがい</rt></ruby>でも</span> = »im Inland sowieso — und sogar im Ausland«<br>📖 Buch-Satz: 「〜はもとより」","rule":"N + はもとより、… も/まで = »N ist selbstverständlich (klar) — und obendrein sogar auch …«. Der zweite Teil ist die Steigerung/Überraschung. Schriftlich-förmliche Variante von <b>はもちろん</b> (TRY! N3)."},{"l":33,"t":"13 · 〜ものだ","de":"so ist es (nun mal) — allgemeine Wahrheit / Norm","slots":[{"text":"<ruby>人<rt>ひと</rt></ruby>は","role":"plain"},{"text":"<ruby>失敗<rt>しっぱい</rt></ruby>から","role":"plain"},{"text":"<ruby>学<rt>まな</rt></ruby>ぶ<b>ものだ</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Der Mensch lernt nun mal aus Fehlern.«","ex":{"jp":"<ruby>人<rt>ひと</rt></ruby>は <ruby>失敗<rt>しっぱい</rt></ruby>から <ruby>学<rt>まな</rt></ruby>ぶ<b>ものだ</b>。","de":"Der Mensch lernt nun mal aus Fehlern."},"simpel":"🪧 <b>Spruch an der Wand / Kalenderweisheit:</b> ものだ sagt eine <b>allgemeine Wahrheit</b> mit Nachdruck — »so ist es eben«.<br><span class=\"jp\"><ruby>人<rt>ひと</rt></ruby>は <ruby>失敗<rt>しっぱい</rt></ruby>から <ruby>学<rt>まな</rt></ruby>ぶ<b>ものだ</b></span> = »Der Mensch lernt nun mal aus Fehlern.«<br>📖 Buch-Satz: 「<ruby>人<rt>ひと</rt></ruby>は <ruby>失敗<rt>しっぱい</rt></ruby>から <ruby>学<rt>まな</rt></ruby>ぶものだ」","rule":"Grundform / ない-Form + ものだ = eine <b>allgemeingültige Wahrheit oder Norm</b>: »so ist das nun mal / so gehört es sich«. Klingt wie ein Sprichwort.<br>Verneint <b>ものではない</b> = »das tut man nicht« (Verbot)."},{"l":33,"t":"14 · 〜<ruby>上<rt>うえ</rt></ruby>で","de":"🎯 beim / im Rahmen von X (ist Y wichtig)","slots":[{"text":"<ruby>仕事<rt>しごと</rt></ruby>を","role":"plain"},{"text":"する<b><ruby>上<rt>うえ</rt></ruby>で</b>、<ruby>信頼<rt>しんらい</rt></ruby><ruby>関係<rt>かんけい</rt></ruby>が","role":"plain"},{"text":"<ruby>何<rt>なに</rt></ruby>より","role":"plain"},{"text":"<ruby>大切<rt>たいせつ</rt></ruby>です。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Beim Arbeiten ist ein Vertrauensverhältnis das Allerwichtigste.«","ex":{"jp":"<ruby>仕事<rt>しごと</rt></ruby>を する<b><ruby>上<rt>うえ</rt></ruby>で</b>、<ruby>信頼<rt>しんらい</rt></ruby><ruby>関係<rt>かんけい</rt></ruby>が <ruby>何<rt>なに</rt></ruby>より <ruby>大切<rt>たいせつ</rt></ruby>です。","de":"Beim Arbeiten ist ein Vertrauensverhältnis das Allerwichtigste."},"simpel":"🎯 <b>»Beim Tun von X (ist Y wichtig)«:</b> V-Grundform + <ruby>上<rt>うえ</rt></ruby>で = »im Rahmen von X«. Danach meist <ruby>大切<rt>たいせつ</rt></ruby>だ / <ruby>必要<rt>ひつよう</rt></ruby>だ.<br><span class=\"jp\"><ruby>仕事<rt>しごと</rt></ruby>を する<b><ruby>上<rt>うえ</rt></ruby>で</b>、<ruby>信頼<rt>しんらい</rt></ruby>が <ruby>大切<rt>たいせつ</rt></ruby>だ</span> = »Beim Arbeiten ist Vertrauen wichtig.«<br>📖 Buch-Satz: 「<ruby>仕事<rt>しごと</rt></ruby>をする<ruby>上<rt>うえ</rt></ruby>で」","rule":"V-Grundform / N の + <ruby>上<rt>うえ</rt></ruby>で = »beim / im Rahmen von X (ist Y wichtig/nötig)«. Nachsatz meist <ruby>大切<rt>たいせつ</rt></ruby>だ／<ruby>必要<rt>ひつよう</rt></ruby>だ／<ruby>役<rt>やく</rt></ruby>に<ruby>立<rt>た</rt></ruby>つ.<br>⚠ <b>V-た</b> + 上で = »erst NACHDEM« (Buch-Punkt 117) — Grundform = »beim«, た-Form = »nachdem«."},{"l":33,"t":"15 · 〜ながら(も)","de":"leider / obwohl (einräumend)","slots":[{"text":"<ruby>残念<rt>ざんねん</rt></ruby><b>ながら</b>、この","role":"plain"},{"text":"<ruby>春<rt>はる</rt></ruby>で","role":"plain"},{"text":"<ruby>大阪<rt>おおさか</rt></ruby><ruby>支社<rt>ししゃ</rt></ruby>に","role":"plain"},{"text":"<ruby>転任<rt>てんにん</rt></ruby>する","role":"plain"},{"text":"ことに","role":"plain"},{"text":"なりました。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Bedauerlicherweise werde ich diesen Frühling in die Osaka-Filiale versetzt.«","ex":{"jp":"<ruby>残念<rt>ざんねん</rt></ruby><b>ながら</b>、この <ruby>春<rt>はる</rt></ruby>で <ruby>大阪<rt>おおさか</rt></ruby><ruby>支社<rt>ししゃ</rt></ruby>に <ruby>転任<rt>てんにん</rt></ruby>する ことに なりました。","de":"Bedauerlicherweise werde ich diesen Frühling in die Osaka-Filiale versetzt."},"simpel":"»Bedauerlicherweise« — einräumendes ながら.<br><span class='jp'><ruby>残念<rt>ざんねん</rt></ruby><b>ながら</b></span><br>📖 Buch-Satz: 「<ruby>残念<rt>ざんねん</rt></ruby>ながら」","rule":"N/Adj/V<sub>ます</sub> + ながら(も): einräumend »obwohl/zwar … doch« (nicht das gleichzeitige ながら!). Feste Wendungen: 残念ながら (leider), 失礼ながら (bei allem Respekt), 狭いながらも (klein, aber)."},{"l":33,"t":"16 · 〜を目的とした","de":"mit dem Ziel … / zum Zweck von …","slots":[{"text":"この","role":"plain"},{"text":"<ruby>会<rt>かい</rt></ruby>は","role":"plain"},{"text":"<ruby>国際<rt>こくさい</rt></ruby><ruby>交流<rt>こうりゅう</rt></ruby>を<b>目的として</b>","role":"plain"},{"text":"います。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Dieser Verein verfolgt das Ziel des internationalen Austauschs.«","ex":{"jp":"<ruby>輸出<rt>ゆしゅつ</rt></ruby><ruby>拡大<rt>かくだい</rt></ruby>を<b>目的とした</b> プロジェクトを <ruby>担当<rt>たんとう</rt></ruby>します。","de":"Ich übernehme ein Projekt mit dem Ziel der Exportausweitung."},"simpel":"»Ein Projekt mit dem Ziel Exportausweitung«.<br><span class='jp'>〜を<b>目的とした</b> プロジェクト</span><br>📖 Buch-Satz: 「<ruby>輸出<rt>ゆしゅつ</rt></ruby><ruby>拡大<rt>かくだい</rt></ruby>を<ruby>目的<rt>もくてき</rt></ruby>とした プロジェクト」","rule":"N₁ + を目的とした/を目的とする + N₂: N₂ verfolgt das Ziel N₁ (förmlich, Berichte/Projekte). Prädikativ: 〜を目的としている. Verwandt: を〜とする (»als … ansetzen«)."},{"l":33,"t":"17 · 〜をきっかけに","de":"… zum Anlass nehmen(d) (+Plus: 〜を契機に)","slots":[{"text":"この","role":"plain"},{"text":"<ruby>転勤<rt>てんきん</rt></ruby><b>をきっかけに</b>、<ruby>新<rt>あたら</rt></ruby>しい","role":"plain"},{"text":"ことにも","role":"plain"},{"text":"<ruby>挑戦<rt>ちょうせん</rt></ruby>したいと","role":"plain"},{"text":"<ruby>思<rt>おも</rt></ruby>います。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich möchte die Versetzung zum Anlass nehmen, auch Neues anzupacken.«","ex":{"jp":"この <ruby>転勤<rt>てんきん</rt></ruby><b>をきっかけに</b>、<ruby>新<rt>あたら</rt></ruby>しい ことにも <ruby>挑戦<rt>ちょうせん</rt></ruby>したいと <ruby>思<rt>おも</rt></ruby>います。","de":"Ich möchte die Versetzung zum Anlass nehmen, auch Neues anzupacken."},"simpel":"»Die Versetzung als Anstoß (für etwas Neues)«.<br><span class='jp'><ruby>転勤<rt>てんきん</rt></ruby><b>をきっかけに</b></span><br>📖 Buch-Satz: 「この <ruby>転勤<rt>てんきん</rt></ruby>をきっかけに」","rule":"N + をきっかけに(して): N ist der Auslöser/Anstoß für eine Veränderung. +Plus: 〜を契機に(けいき) = dieselbe Bedeutung, schriftlich-förmlicher."},{"l":33,"t":"18 · 〜からには","de":"wenn schon …, dann (auch richtig) (+Plus: 〜以上は/〜上は)","slots":[{"text":"<ruby>日本<rt>にほん</rt></ruby>に","role":"plain"},{"text":"<ruby>住<rt>す</rt></ruby>む<b>以上は</b>、<ruby>日本<rt>にほん</rt></ruby>の","role":"plain"},{"text":"ルールに","role":"plain"},{"text":"<ruby>従<rt>したが</rt></ruby>うべきだ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wenn man nun mal in Japan lebt, sollte man sich an die japanischen Regeln halten.«","ex":{"jp":"やる<b>からには</b>、<ruby>最後<rt>さいご</rt></ruby>まで やりぬく つもりです。","de":"Wenn ich es schon mache, ziehe ich es auch bis zum Ende durch."},"simpel":"»Wenn ich es schon mache, dann richtig!«<br><span class='jp'>やる<b>からには</b></span><br>📖 Buch-Satz: 「やるからには」","rule":"V<sub>einf</sub> + からには: aus der Entscheidung/Lage folgt eine selbstauferlegte Pflicht/Entschlossenheit. +Plus: 〜以上(は) und schriftliches 〜上は sind fast gleichbedeutend."},{"l":33,"t":"19 · 〜というわけではない","de":"es ist nicht (etwa) so, dass …","slots":[{"text":"<ruby>会<rt>あ</rt></ruby>えなく","role":"plain"},{"text":"なる<b>というわけでは","role":"plain"},{"text":"ありません</b>。<ruby>大阪<rt>おおさか</rt></ruby>は","role":"plain"},{"text":"<ruby>近<rt>ちか</rt></ruby>いですから。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Es ist ja nicht so, dass wir uns nie mehr sehen — Osaka ist nah.«","ex":{"jp":"<ruby>会<rt>あ</rt></ruby>えなく なる<b>というわけでは ありません</b>。<ruby>大阪<rt>おおさか</rt></ruby>は <ruby>近<rt>ちか</rt></ruby>いですから。","de":"Es ist ja nicht so, dass wir uns nie mehr sehen — Osaka ist nah."},"simpel":"Räumt ein Missverständnis aus: »das heißt nicht, dass …«.<br><span class='jp'>なくなる<b>というわけでは ありません</b></span><br>📖 Buch-Satz: 「なくなる というわけではありません」","rule":"Plain + というわけではない/わけではない: verneint eine naheliegende Schlussfolgerung teilweise (»nicht unbedingt/nicht etwa«). Sanfter als komplette Verneinung."},{"l":33,"t":"20 · 〜ことなく","de":"ohne (je) zu … (schriftlich)","slots":[{"text":"これまでと","role":"plain"},{"text":"<ruby>変<rt>か</rt></ruby>わる<b>ことなく</b>、ご<ruby>指導<rt>しどう</rt></ruby>","role":"plain"},{"text":"よろしく","role":"plain"},{"text":"お<ruby>願<rt>ねが</rt></ruby>いいたします。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich bitte Sie, mir unverändert wie bisher mit Rat zur Seite zu stehen.«","ex":{"jp":"これまでと <ruby>変<rt>か</rt></ruby>わる<b>ことなく</b>、ご<ruby>指導<rt>しどう</rt></ruby> よろしく お<ruby>願<rt>ねが</rt></ruby>いいたします。","de":"Ich bitte Sie, mir unverändert wie bisher mit Rat zur Seite zu stehen."},"simpel":"»Unverändert wie bisher« — <b>変わることなく</b>.<br><span class='jp'><ruby>変<rt>か</rt></ruby>わる<b>ことなく</b></span><br>📖 Buch-Satz: 「これまでと <ruby>変<rt>か</rt></ruby>わることなく」","rule":"V<sub>Grund</sub> + ことなく: »ohne (auch nur einmal) zu V« — schriftlich-feierlicher als ないで/ずに. In Reden gern mit 変わる/忘れる: 変わることなく = »unvermindert«."},{"l":33,"t":"21 · 〜にもかかわらず","de":"trotz … / obwohl …","slots":[{"text":"<ruby>雨<rt>あめ</rt></ruby><b>にもかかわらず</b>、<ruby>大勢<rt>おおぜい</rt></ruby>の","role":"plain"},{"text":"<ruby>方<rt>かた</rt></ruby>に","role":"plain"},{"text":"お<ruby>集<rt>あつ</rt></ruby>まりいただきました。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Trotz des Regens sind so viele von Ihnen gekommen.«","ex":{"jp":"<ruby>雨<rt>あめ</rt></ruby><b>にもかかわらず</b>、<ruby>大勢<rt>おおぜい</rt></ruby>の <ruby>方<rt>かた</rt></ruby>に お<ruby>集<rt>あつ</rt></ruby>まりいただきました。","de":"Trotz des Regens sind so viele von Ihnen gekommen."},"simpel":"»Trotz des Regens (sind Sie gekommen)«.<br><span class='jp'><ruby>雨<rt>あめ</rt></ruby><b>にもかかわらず</b></span><br>📖 Buch-Satz: 「<ruby>雨<rt>あめ</rt></ruby>にもかかわらず」","rule":"N/Plain + にもかかわらず: »trotz/obwohl« — das Ergebnis widerspricht der Erwartung; förmlich, oft mit Dank oder Erstaunen. ⚠ にかかわらず (Punkt 5, »unabhängig von«) ist ein anderes Muster!"},{"l":34,"t":"22 · 〜としての","de":"als … / in der Rolle von …","slots":[{"text":"<ruby>彼<rt>かれ</rt></ruby>は","role":"plain"},{"text":"プロ<b>として</b>","role":"plain"},{"text":"<ruby>働<rt>はたら</rt></ruby>いて","role":"plain"},{"text":"いる。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Er arbeitet als Profi.«","ex":{"jp":"スタッフ<b>としての</b> <ruby>心構<rt>こころがま</rt></ruby>えを <ruby>説明<rt>せつめい</rt></ruby>します。","de":"Ich erläutere die Grundhaltung, die man als Mitarbeiter braucht."},"simpel":"»Die Grundhaltung als Mitarbeiter«.<br><span class='jp'>スタッフ<b>としての</b> <ruby>心構<rt>こころがま</rt></ruby>え</span><br>📖 Buch-Satz: 「スタッフとしての <ruby>心構<rt>こころがま</rt></ruby>え」","rule":"N₁ + としての + N₂: N₂ in der Eigenschaft/Rolle N₁. Adverbial として (»als«): 親として, プロとして. Vor Nomen braucht es の: としての."},{"l":34,"t":"23 · 〜限り","de":"solange … (gilt der Zustand)","slots":[{"text":"この","role":"plain"},{"text":"<ruby>仕事<rt>しごと</rt></ruby>を","role":"plain"},{"text":"<ruby>続<rt>つづ</rt></ruby>ける<b>限り</b>、<ruby>笑顔<rt>えがお</rt></ruby>を","role":"plain"},{"text":"<ruby>忘<rt>わす</rt></ruby>れては","role":"plain"},{"text":"いけません。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Solange man diese Arbeit macht, darf man das Lächeln nie vergessen.«","ex":{"jp":"この <ruby>仕事<rt>しごと</rt></ruby>を <ruby>続<rt>つづ</rt></ruby>ける<b>限り</b>、<ruby>笑顔<rt>えがお</rt></ruby>を <ruby>忘<rt>わす</rt></ruby>れては いけません。","de":"Solange man diese Arbeit macht, darf man das Lächeln nie vergessen."},"simpel":"»Solange man diese Arbeit macht, (gilt …)«.<br><span class='jp'><ruby>続<rt>つづ</rt></ruby>ける<b>限り</b></span><br>📖 Buch-Satz: 「<ruby>仕事<rt>しごと</rt></ruby>を <ruby>続<rt>つづ</rt></ruby>ける<ruby>限<rt>かぎ</rt></ruby>り」","rule":"V<sub>Grund/ている</sub> + 限り(は): solange Bedingung A anhält, gilt B. Verneint 〜ない限り = »solange nicht / es sei denn« (謝らない限り、許さない)."},{"l":34,"t":"24 · 〜ざるを得ない","de":"nicht umhinkommen, zu … (müssen, widerwillig)","slots":[{"text":"お<ruby>客様<rt>きゃくさま</rt></ruby>からの","role":"plain"},{"text":"<ruby>苦情<rt>くじょう</rt></ruby>には、すぐ","role":"plain"},{"text":"<ruby>対応<rt>たいおう</rt></ruby>せ<b>ざるを得ない</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Auf Kundenbeschwerden muss man wohl oder übel sofort reagieren.«","ex":{"jp":"お<ruby>客様<rt>きゃくさま</rt></ruby>からの <ruby>苦情<rt>くじょう</rt></ruby>には、すぐ <ruby>対応<rt>たいおう</rt></ruby>せ<b>ざるを得ない</b>。","de":"Auf Kundenbeschwerden muss man wohl oder übel sofort reagieren."},"simpel":"»Man kommt nicht umhin, sich darum zu kümmern.«<br><span class='jp'><ruby>対応<rt>たいおう</rt></ruby>せ<b>ざるを得ない</b></span><br>📖 Buch-Satz: 「<ruby>対応<rt>たいおう</rt></ruby>せざるを<ruby>得<rt>え</rt></ruby>ない」","rule":"V<sub>ない</sub>-Stamm + ざるを得ない: es bleibt (widerwillig) keine andere Wahl — äußere Umstände zwingen. Ausnahme: する → せざるを得ない. Schriftlich-förmlich."},{"l":34,"t":"25 · 〜ばいいというものではない","de":"damit allein ist es nicht getan","slots":[{"text":"ミスを","role":"plain"},{"text":"したら、<ruby>謝<rt>あやま</rt></ruby>れば","role":"plain"},{"text":"いい<b>というものでは","role":"plain"},{"text":"ありません</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Bei einem Fehler ist es mit einer Entschuldigung allein nicht getan.«","ex":{"jp":"ミスを したら、<ruby>謝<rt>あやま</rt></ruby>れば いい<b>というものでは ありません</b>。","de":"Bei einem Fehler ist es mit einer Entschuldigung allein nicht getan."},"simpel":"»Sich nur zu entschuldigen reicht eben nicht.«<br><span class='jp'><ruby>謝<rt>あやま</rt></ruby>れば いい<b>というものでは ありません</b></span><br>📖 Buch-Satz: 「<ruby>謝<rt>あやま</rt></ruby>れば いい というものではありません」","rule":"[einfache Lösung] + というものではない: weist eine zu simple Annahme zurück — »so einfach ist es nicht / damit allein ist es nicht getan«. Oft nach 〜ばいい/〜たらいい."},{"l":34,"t":"26 · 〜はともかく(として)","de":"einmal dahingestellt / abgesehen von …","slots":[{"text":"<ruby>苦情<rt>くじょう</rt></ruby>が","role":"plain"},{"text":"<ruby>正当<rt>せいとう</rt></ruby>な","role":"plain"},{"text":"ものか","role":"plain"},{"text":"どうか<b>は","role":"plain"},{"text":"ともかくとして</b>、まず","role":"plain"},{"text":"<ruby>話<rt>はなし</rt></ruby>を","role":"plain"},{"text":"<ruby>聞<rt>き</rt></ruby>きましょう。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ob die Beschwerde berechtigt ist, sei dahingestellt — erst einmal hören wir zu.«","ex":{"jp":"<ruby>苦情<rt>くじょう</rt></ruby>が <ruby>正当<rt>せいとう</rt></ruby>な ものか どうか<b>は ともかくとして</b>、まず <ruby>話<rt>はなし</rt></ruby>を <ruby>聞<rt>き</rt></ruby>きましょう。","de":"Ob die Beschwerde berechtigt ist, sei dahingestellt — erst einmal hören wir zu."},"simpel":"»Ob berechtigt oder nicht, sei mal dahingestellt — …«<br><span class='jp'>〜か どうか<b>は ともかくとして</b></span><br>📖 Buch-Satz: 「<ruby>正当<rt>せいとう</rt></ruby>な ものか どうかは ともかくとして」","rule":"N/〜かどうか + はともかく(として): schiebt eine Frage bewusst beiseite, um zum Wichtigeren zu kommen. 味はともかく (der Geschmack sei dahingestellt), 冗談はともかく (Spaß beiseite)."},{"l":34,"t":"27 · 〜かねない","de":"könnte womöglich … (Negatives droht)","slots":[{"text":"<ruby>小<rt>ちい</rt></ruby>さな","role":"plain"},{"text":"ミスでも、お<ruby>客様<rt>きゃくさま</rt></ruby>の","role":"plain"},{"text":"<ruby>信頼<rt>しんらい</rt></ruby>を","role":"plain"},{"text":"<ruby>失<rt>うしな</rt></ruby>い<b>かねません</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Schon ein kleiner Fehler könnte das Vertrauen der Kunden kosten.«","ex":{"jp":"<ruby>小<rt>ちい</rt></ruby>さな ミスでも、お<ruby>客様<rt>きゃくさま</rt></ruby>の <ruby>信頼<rt>しんらい</rt></ruby>を <ruby>失<rt>うしな</rt></ruby>い<b>かねません</b>。","de":"Schon ein kleiner Fehler könnte das Vertrauen der Kunden kosten."},"simpel":"Warnung: »das könnte das Vertrauen kosten«.<br><span class='jp'><ruby>失<rt>うしな</rt></ruby>い<b>かねません</b></span><br>📖 Buch-Satz: 「<ruby>信頼<rt>しんらい</rt></ruby>を <ruby>失<rt>うしな</rt></ruby>いかねません」","rule":"V<sub>ます</sub>-Stamm + かねない: die (schlechte) Möglichkeit ist real — »es könnte durchaus passieren, dass«. Nur für Unerwünschtes. ⚠ 〜かねる (ohne ない) = »kann (höflich) nicht« — Gegenteil!"},{"l":34,"t":"28 · 〜というより","de":"eher … als … / genauer gesagt","slots":[{"text":"あの","role":"plain"},{"text":"<ruby>方<rt>かた</rt></ruby>は","role":"plain"},{"text":"お<ruby>客様<rt>きゃくさま</rt></ruby><b>というより</b>、もう","role":"plain"},{"text":"<ruby>家族<rt>かぞく</rt></ruby>の","role":"plain"},{"text":"ような","role":"plain"},{"text":"<ruby>存在<rt>そんざい</rt></ruby>です。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Er ist weniger ein Gast als vielmehr schon so etwas wie Familie.«","ex":{"jp":"あの <ruby>方<rt>かた</rt></ruby>は お<ruby>客様<rt>きゃくさま</rt></ruby><b>というより</b>、もう <ruby>家族<rt>かぞく</rt></ruby>の ような <ruby>存在<rt>そんざい</rt></ruby>です。","de":"Er ist weniger ein Gast als vielmehr schon so etwas wie Familie."},"simpel":"Präzisiert die Beschreibung: »eher X als Y«.<br><span class='jp'>お<ruby>客様<rt>きゃくさま</rt></ruby><b>というより</b></span><br>📖 Buch-Satz: 「お<ruby>客様<rt>きゃくさま</rt></ruby>というより」","rule":"A + というより(むしろ) + B: die Beschreibung A trifft es nicht ganz — B passt besser. Oft mit むしろ verstärkt. Für Nomen, Adjektive und Sätze."},{"l":34,"t":"29 · 〜てはいられない","de":"kann nicht (länger) … bleiben","slots":[{"text":"<ruby>他<rt>ほか</rt></ruby>の","role":"plain"},{"text":"ホテルも","role":"plain"},{"text":"<ruby>努力<rt>どりょく</rt></ruby>して","role":"plain"},{"text":"いますから、<ruby>安心<rt>あんしん</rt></ruby>して<b>は","role":"plain"},{"text":"いられません</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Auch die anderen Hotels strengen sich an — wir dürfen uns nicht in Sicherheit wiegen.«","ex":{"jp":"<ruby>他<rt>ほか</rt></ruby>の ホテルも <ruby>努力<rt>どりょく</rt></ruby>して いますから、<ruby>安心<rt>あんしん</rt></ruby>して<b>は いられません</b>。","de":"Auch die anderen Hotels strengen sich an — wir dürfen uns nicht in Sicherheit wiegen."},"simpel":"»Zum Ausruhen ist keine Zeit« — <b>てはいられない</b>.<br><span class='jp'><ruby>安心<rt>あんしん</rt></ruby>して<b>は いられません</b></span><br>📖 Buch-Satz: 「<ruby>安心<rt>あんしん</rt></ruby>しては いられません」","rule":"V<sub>て</sub> + はいられない: den Zustand kann/darf man sich nicht (länger) leisten — Handlungsdruck. Locker: ちゃいられない. Vgl. てばかりはいられない (TRY! N3, 100)."},{"l":35,"t":"30 · 〜つつ","de":"📰 während / und dabei zugleich (geschriebenes ながら)","slots":[{"text":"<ruby>将来<rt>しょうらい</rt></ruby>の","role":"plain"},{"text":"ことを","role":"plain"},{"text":"<ruby>考<rt>かんが</rt></ruby>え<b>つつ</b>、<ruby>勉強<rt>べんきょう</rt></ruby>を","role":"plain"},{"text":"<ruby>続<rt>つづ</rt></ruby>けて","role":"plain"},{"text":"いる。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich lerne weiter und denke dabei an die Zukunft.«","ex":{"jp":"<ruby>台風<rt>たいふう</rt></ruby>は <ruby>速度<rt>そくど</rt></ruby>を <ruby>速<rt>はや</rt></ruby>め<b>つつ</b>、<ruby>北上<rt>ほくじょう</rt></ruby>して います。","de":"Der Taifun zieht nordwärts und wird dabei schneller."},"simpel":"📰 <b>Das geschriebene ながら</b> (Nachrichten-/Berichtston): Vます-Stamm + つつ = »während / und dabei zugleich«.<br><span class=\"jp\"><ruby>台風<rt>たいふう</rt></ruby>は <ruby>速度<rt>そくど</rt></ruby>を <ruby>速<rt>はや</rt></ruby>め<b>つつ</b> <ruby>北上<rt>ほくじょう</rt></ruby></span> = »Der Taifun zieht nordwärts und wird dabei schneller.«<br>📖 Buch-Satz: 「<ruby>速度<rt>そくど</rt></ruby>を<ruby>速<rt>はや</rt></ruby>めつつ」","rule":"Vます-Stamm + つつ = »während/indem« — das <b>schriftliche ながら</b> (Nachrichten, Berichte).<br>Zweite Lesart <b>つつ(も)</b> = »obwohl« (Punkt 112). Mit ある: <b>つつある</b> = »ist dabei zu« (Punkt 71)."},{"l":35,"t":"31 · 〜にわたって","de":"über … hinweg (räumlich/zeitlich ausgedehnt)","slots":[{"text":"<ruby>広範囲<rt>こうはんい</rt></ruby><b>にわたって</b>、<ruby>強<rt>つよ</rt></ruby>い","role":"plain"},{"text":"<ruby>雨<rt>あめ</rt></ruby>が","role":"plain"},{"text":"<ruby>降<rt>ふ</rt></ruby>る","role":"plain"},{"text":"<ruby>見込<rt>みこ</rt></ruby>みです。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Über ein weites Gebiet hinweg ist mit starkem Regen zu rechnen.«","ex":{"jp":"<ruby>広範囲<rt>こうはんい</rt></ruby><b>にわたって</b>、<ruby>強<rt>つよ</rt></ruby>い <ruby>雨<rt>あめ</rt></ruby>が <ruby>降<rt>ふ</rt></ruby>る <ruby>見込<rt>みこ</rt></ruby>みです。","de":"Über ein weites Gebiet hinweg ist mit starkem Regen zu rechnen."},"simpel":"Ausdehnung: »über ein weites Gebiet hinweg«.<br><span class='jp'><ruby>広範囲<rt>こうはんい</rt></ruby><b>にわたって</b></span><br>📖 Buch-Satz: 「<ruby>広範囲<rt>こうはんい</rt></ruby>にわたって」","rule":"N + にわたって/にわたり: erstreckt sich über den ganzen Bereich/Zeitraum N (広範囲, 10年間, 全ページ). Attributiv: にわたる + N. Betont die beachtliche Ausdehnung; schriftlich."},{"l":35,"t":"32 · 〜から〜にかけて","de":"von … bis (hinein nach) … (ungefährer Bereich)","slots":[{"text":"<ruby>九州<rt>きゅうしゅう</rt></ruby><ruby>沿岸<rt>えんがん</rt></ruby>から","role":"plain"},{"text":"<ruby>四国<rt>しこく</rt></ruby><b>にかけて</b>、<ruby>波<rt>なみ</rt></ruby>が","role":"plain"},{"text":"<ruby>高<rt>たか</rt></ruby>く","role":"plain"},{"text":"なって","role":"plain"},{"text":"います。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Von der Küste Kyushus bis nach Shikoku wird die See rauer.«","ex":{"jp":"<ruby>九州<rt>きゅうしゅう</rt></ruby><ruby>沿岸<rt>えんがん</rt></ruby>から <ruby>四国<rt>しこく</rt></ruby><b>にかけて</b>、<ruby>波<rt>なみ</rt></ruby>が <ruby>高<rt>たか</rt></ruby>く なって います。","de":"Von der Küste Kyushus bis nach Shikoku wird die See rauer."},"simpel":"Von–bis mit weichen Grenzen: »von der Küste Kyushus bis nach Shikoku«.<br><span class='jp'>〜から 〜<b>にかけて</b></span><br>📖 Buch-Satz: 「<ruby>九州<rt>きゅうしゅう</rt></ruby><ruby>沿岸<rt>えんがん</rt></ruby>から <ruby>四国<rt>しこく</rt></ruby>にかけて」","rule":"A から B にかけて: ein Bereich/Zeitraum von A bis (ungefähr) B — die Grenzen sind unscharf. Räumlich und zeitlich (今夜から明日の朝にかけて)."},{"l":35,"t":"33 · 〜にともない/にともなって","de":"mit … (einhergehend)","slots":[{"text":"<ruby>台風<rt>たいふう</rt></ruby>の","role":"plain"},{"text":"<ruby>接近<rt>せっきん</rt></ruby><b>にともない</b>、<ruby>風<rt>かぜ</rt></ruby>が","role":"plain"},{"text":"<ruby>強<rt>つよ</rt></ruby>まって","role":"plain"},{"text":"います。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Mit der Annäherung des Taifuns frischt der Wind auf.«","ex":{"jp":"<ruby>台風<rt>たいふう</rt></ruby>の <ruby>接近<rt>せっきん</rt></ruby><b>にともない</b>、<ruby>風<rt>かぜ</rt></ruby>が <ruby>強<rt>つよ</rt></ruby>まって います。","de":"Mit der Annäherung des Taifuns frischt der Wind auf."},"simpel":"»Mit der Annäherung des Taifuns (nimmt … zu)«.<br><span class='jp'><ruby>接近<rt>せっきん</rt></ruby><b>にともない</b></span><br>📖 Buch-Satz: 「<ruby>台風<rt>たいふう</rt></ruby>の <ruby>接近<rt>せっきん</rt></ruby>にともない」","rule":"N/V<sub>Grund</sub> + にともない/にともなって: Veränderung A bringt Veränderung B mit sich (»einhergehend mit«). Förmlich-berichtend; attributiv にともなう + N."},{"l":35,"t":"34 · 〜おそれがある","de":"es besteht die Gefahr, dass …","slots":[{"text":"<ruby>非常<rt>ひじょう</rt></ruby>に","role":"plain"},{"text":"<ruby>激<rt>はげ</rt></ruby>しい","role":"plain"},{"text":"<ruby>雨<rt>あめ</rt></ruby>が","role":"plain"},{"text":"<ruby>降<rt>ふ</rt></ruby>る","role":"plain"},{"text":"<b>おそれがあります</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Es drohen äußerst heftige Regenfälle.«","ex":{"jp":"<ruby>非常<rt>ひじょう</rt></ruby>に <ruby>激<rt>はげ</rt></ruby>しい <ruby>雨<rt>あめ</rt></ruby>が <ruby>降<rt>ふ</rt></ruby>る <b>おそれがあります</b>。","de":"Es drohen äußerst heftige Regenfälle."},"simpel":"Amtliche Warnung: »es drohen (starke) Regenfälle«.<br><span class='jp'><ruby>降<rt>ふ</rt></ruby>る <b>おそれがあります</b></span><br>📖 Buch-Satz: 「<ruby>雨<rt>あめ</rt></ruby>が <ruby>降<rt>ふ</rt></ruby>る おそれがあります」","rule":"V<sub>Grund</sub>/N の + おそれがある: es droht etwas Unerwünschtes — Standard in Warnungen/Nachrichten. Nur für Negatives; neutral-möglich wäre 可能性がある."},{"l":35,"t":"35 · 〜とともに","de":"zusammen mit … / zugleich mit …","slots":[{"text":"<ruby>強風<rt>きょうふう</rt></ruby><b>とともに</b>、<ruby>激<rt>はげ</rt></ruby>しい","role":"plain"},{"text":"<ruby>雨<rt>あめ</rt></ruby>が","role":"plain"},{"text":"<ruby>降<rt>ふ</rt></ruby>り<ruby>出<rt>だ</rt></ruby>す","role":"plain"},{"text":"でしょう。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Zusammen mit starkem Wind dürfte heftiger Regen einsetzen.«","ex":{"jp":"<ruby>強風<rt>きょうふう</rt></ruby><b>とともに</b>、<ruby>激<rt>はげ</rt></ruby>しい <ruby>雨<rt>あめ</rt></ruby>が <ruby>降<rt>ふ</rt></ruby>り<ruby>出<rt>だ</rt></ruby>す でしょう。","de":"Zusammen mit starkem Wind dürfte heftiger Regen einsetzen."},"simpel":"»Zusammen mit starkem Wind (kommt der Regen)«.<br><span class='jp'><ruby>強風<rt>きょうふう</rt></ruby><b>とともに</b></span><br>📖 Buch-Satz: 「<ruby>強風<rt>きょうふう</rt></ruby>とともに」","rule":"N + とともに: (1) »zusammen/gemeinsam mit N«, (2) »zugleich mit N / im Zuge von N« (時代とともに変わる). Förmlicher als と一緒に; auch V-Grundform + とともに (»in dem Moment, da«)."},{"l":35,"t":"36 · 〜次第","de":"sobald … (unmittelbar danach)","slots":[{"text":"<ruby>現地<rt>げんち</rt></ruby>との","role":"plain"},{"text":"<ruby>中継<rt>ちゅうけい</rt></ruby>が","role":"plain"},{"text":"つながり<b>次第</b>、<ruby>最新<rt>さいしん</rt></ruby><ruby>情報<rt>じょうほう</rt></ruby>を","role":"plain"},{"text":"お<ruby>伝<rt>つた</rt></ruby>えします。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Sobald die Live-Schalte vor Ort steht, bringen wir die neuesten Informationen.«","ex":{"jp":"<ruby>現地<rt>げんち</rt></ruby>との <ruby>中継<rt>ちゅうけい</rt></ruby>が つながり<b>次第</b>、<ruby>最新<rt>さいしん</rt></ruby><ruby>情報<rt>じょうほう</rt></ruby>を お<ruby>伝<rt>つた</rt></ruby>えします。","de":"Sobald die Live-Schalte vor Ort steht, bringen wir die neuesten Informationen."},"simpel":"»Sobald die Live-Schalte steht, (berichten wir)«.<br><span class='jp'>つながり<b>次第</b></span><br>📖 Buch-Satz: 「<ruby>中継<rt>ちゅうけい</rt></ruby>が つながり<ruby>次第<rt>しだい</rt></ruby>」","rule":"V<sub>ます</sub>-Stamm + 次第: »sobald A eintritt, sofort B« — B ist eine geplante/zugesagte Handlung (kein Vergangenes). N + 次第だ/で = »hängt von N ab« (Punkt 114)."},{"l":36,"t":"37 · 〜たきり","de":"seit … (ist nichts mehr gefolgt)","slots":[{"text":"<ruby>彼<rt>かれ</rt></ruby>は","role":"plain"},{"text":"<ruby>京都<rt>きょうと</rt></ruby>に","role":"plain"},{"text":"<ruby>行<rt>い</rt></ruby>った<b>きり</b>、<ruby>連絡<rt>れんらく</rt></ruby>が","role":"plain"},{"text":"ない。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Seit er nach Kyoto gefahren ist, hat er sich nicht mehr gemeldet.«","ex":{"jp":"<ruby>彼<rt>かれ</rt></ruby>は <ruby>京都<rt>きょうと</rt></ruby>に <ruby>行<rt>い</rt></ruby>った<b>きり</b>、<ruby>連絡<rt>れんらく</rt></ruby>が ない。","de":"Seit er nach Kyoto gefahren ist, hat er sich nicht mehr gemeldet."},"simpel":"»Seit der Kyoto-Reise (war nichts mehr)«.<br><span class='jp'><ruby>行<rt>い</rt></ruby>った<b>きり</b></span><br>📖 Buch-Satz: 「<ruby>京都<rt>きょうと</rt></ruby>に <ruby>行<rt>い</rt></ruby>ったきり」","rule":"V<sub>た</sub> + きり(で): nach der Handlung blieb die erwartete Fortsetzung aus (行ったきり帰らない). Auch 寝たきり (bettlägerig), これっきり (das war's dann)."},{"l":36,"t":"38 · 〜どころではない","de":"jetzt ist nicht die Zeit für …","slots":[{"text":"<ruby>熱<rt>ねつ</rt></ruby>が","role":"plain"},{"text":"39<ruby>度<rt>ど</rt></ruby>も","role":"plain"},{"text":"あって、<ruby>勉強<rt>べんきょう</rt></ruby><b>どころではない</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Bei 39 Grad Fieber ist an Lernen nicht zu denken.«","ex":{"jp":"<ruby>就活<rt>しゅうかつ</rt></ruby>で <ruby>忙<rt>いそが</rt></ruby>しくて、<ruby>旅行<rt>りょこう</rt></ruby><b>どころじゃない</b>よ。","de":"Mit der Jobsuche bin ich so beschäftigt — an Reisen ist nicht zu denken."},"simpel":"»An Reisen ist gerade nicht zu denken!«<br><span class='jp'><ruby>旅行<rt>りょこう</rt></ruby><b>どころじゃない</b></span><br>📖 Buch-Satz: 「<ruby>旅行<rt>りょこう</rt></ruby>どころじゃない」","rule":"N/V<sub>Grund</sub> + どころではない/どころじゃない: die Lage lässt X überhaupt nicht zu — »dafür ist jetzt wirklich nicht der Moment«. Emotional-abwehrend."},{"l":36,"t":"39 · 〜ものの","de":"zwar …, aber (doch) …","slots":[{"text":"<ruby>情報<rt>じょうほう</rt></ruby>は","role":"plain"},{"text":"<ruby>集<rt>あつ</rt></ruby>めて","role":"plain"},{"text":"いる<b>ものの</b>、まだ","role":"plain"},{"text":"<ruby>一社<rt>いっしゃ</rt></ruby>も","role":"plain"},{"text":"<ruby>受<rt>う</rt></ruby>けて","role":"plain"},{"text":"いない。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Informationen sammle ich zwar — beworben habe ich mich aber noch nirgends.«","ex":{"jp":"<ruby>情報<rt>じょうほう</rt></ruby>は <ruby>集<rt>あつ</rt></ruby>めて いる<b>ものの</b>、まだ <ruby>一社<rt>いっしゃ</rt></ruby>も <ruby>受<rt>う</rt></ruby>けて いない。","de":"Informationen sammle ich zwar — beworben habe ich mich aber noch nirgends."},"simpel":"»Infos sammle ich zwar, aber …«<br><span class='jp'><ruby>集<rt>あつ</rt></ruby>めて いる<b>ものの</b></span><br>📖 Buch-Satz: 「<ruby>情報<rt>じょうほう</rt></ruby>は <ruby>集<rt>あつ</rt></ruby>めて いるものの」","rule":"Plain + ものの: A trifft zu, doch die erwartete Folge bleibt aus. Schriftlicher als けど; oft mit は beim Thema (情報は…ものの)."},{"l":36,"t":"40 · 〜ことに","de":"…erweise (Gefühl zuerst)","slots":[{"text":"<ruby>困<rt>こま</rt></ruby>った<b>ことに</b>、<ruby>面接<rt>めんせつ</rt></ruby>の","role":"plain"},{"text":"<ruby>日<rt>ひ</rt></ruby>が","role":"plain"},{"text":"<ruby>重<rt>かさ</rt></ruby>なって","role":"plain"},{"text":"しまった。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Dummerweise überschneiden sich die Interviewtermine.«","ex":{"jp":"<ruby>困<rt>こま</rt></ruby>った<b>ことに</b>、<ruby>面接<rt>めんせつ</rt></ruby>の <ruby>日<rt>ひ</rt></ruby>が <ruby>重<rt>かさ</rt></ruby>なって しまった。","de":"Dummerweise überschneiden sich die Interviewtermine."},"simpel":"Gefühl als Vorspann: »dummerweise / erfreulicherweise …«.<br><span class='jp'><ruby>困<rt>こま</rt></ruby>った<b>ことに</b></span><br>📖 Buch-Satz: 「<ruby>困<rt>こま</rt></ruby>った ことに」","rule":"Gefühls-Adj/V<sub>た</sub> + ことに: stellt die Bewertung VOR den Satz (困ったことに, 残念なことに, うれしいことに). Schriftlich-erzählend."},{"l":36,"t":"41 · 〜にしては","de":"für … (überraschend anders)","slots":[{"text":"<ruby>人気<rt>にんき</rt></ruby>の","role":"plain"},{"text":"<ruby>業界<rt>ぎょうかい</rt></ruby><b>にしては</b>、<ruby>給料<rt>きゅうりょう</rt></ruby>が","role":"plain"},{"text":"<ruby>安<rt>やす</rt></ruby>い。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Für eine so beliebte Branche sind die Gehälter niedrig.«","ex":{"jp":"<ruby>人気<rt>にんき</rt></ruby>の <ruby>業界<rt>ぎょうかい</rt></ruby><b>にしては</b>、<ruby>給料<rt>きゅうりょう</rt></ruby>が <ruby>安<rt>やす</rt></ruby>い。","de":"Für eine so beliebte Branche sind die Gehälter niedrig."},"simpel":"»Für eine beliebte Branche (erstaunlich …)«.<br><span class='jp'><ruby>業界<rt>ぎょうかい</rt></ruby><b>にしては</b></span><br>📖 Buch-Satz: 「<ruby>人気<rt>にんき</rt></ruby>の <ruby>業界<rt>ぎょうかい</rt></ruby>にしては」","rule":"N/Plain + にしては: gemessen am Standard von N fällt etwas aus dem Rahmen (»für N erstaunlich«). ≈ わりに(は), aber mit konkretem Bezugspunkt."},{"l":36,"t":"42 · 〜ことか","de":"wie oft/sehr …! (Ausruf)","slots":[{"text":"この","role":"plain"},{"text":"<ruby>日<rt>ひ</rt></ruby>を","role":"plain"},{"text":"どんなに","role":"plain"},{"text":"<ruby>待<rt>ま</rt></ruby>って","role":"plain"},{"text":"いた<b>ことか</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wie sehr ich diesen Tag herbeigesehnt habe!«","ex":{"jp":"エントリーシートを <ruby>何回<rt>なんかい</rt></ruby> <ruby>書<rt>か</rt></ruby>いた<b>ことか</b>。","de":"Wie viele Bewerbungsbögen ich schon geschrieben habe!"},"simpel":"»Wie oft ich das schon geschrieben habe!«<br><span class='jp'><ruby>何回<rt>なんかい</rt></ruby> <ruby>書<rt>か</rt></ruby>いた<b>ことか</b></span><br>📖 Buch-Satz: 「<ruby>何回<rt>なんかい</rt></ruby> <ruby>書<rt>か</rt></ruby>いたことか」","rule":"Fragewort (何回/どんなに/どれほど) + Plain + ことか: emotionaler Ausruf, keine echte Frage. Auch 〜ことだろう."},{"l":36,"t":"43 · 〜さえ〜ば","de":"wenn nur … (dann reicht das)","slots":[{"text":"やる<ruby>気<rt>き</rt></ruby><b>さえ","role":"plain"},{"text":"あれば</b>、<ruby>経験<rt>けいけん</rt></ruby>は","role":"plain"},{"text":"なくても","role":"plain"},{"text":"いい","role":"plain"},{"text":"そうだ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wenn nur der Wille da ist, sei Erfahrung nicht nötig, heißt es.«","ex":{"jp":"やる<ruby>気<rt>き</rt></ruby><b>さえ あれば</b>、<ruby>経験<rt>けいけん</rt></ruby>は なくても いい そうだ。","de":"Wenn nur der Wille da ist, sei Erfahrung nicht nötig, heißt es."},"simpel":"»Wenn nur der Wille da ist, …«<br><span class='jp'>やる<ruby>気<rt>き</rt></ruby><b>さえ あれば</b></span><br>📖 Buch-Satz: 「やる<ruby>気<rt>き</rt></ruby>さえ あれば」","rule":"N + さえ + ば-Form: die einzige entscheidende Bedingung — ist sie erfüllt, genügt es. Vマス + さえすれば; て-Form + さえいれば."},{"l":36,"t":"44 · 〜ようがない","de":"es gibt keine Möglichkeit, zu …","slots":[{"text":"<ruby>何<rt>なに</rt></ruby>を","role":"plain"},{"text":"<ruby>準備<rt>じゅんび</rt></ruby>すれば","role":"plain"},{"text":"いいか","role":"plain"},{"text":"わからないと、がんばり<b>ようがない</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wenn man nicht weiß, was man vorbereiten soll, kann man sich gar nicht erst anstrengen.«","ex":{"jp":"<ruby>何<rt>なに</rt></ruby>を <ruby>準備<rt>じゅんび</rt></ruby>すれば いいか わからないと、がんばり<b>ようがない</b>。","de":"Wenn man nicht weiß, was man vorbereiten soll, kann man sich gar nicht erst anstrengen."},"simpel":"»Da kann man sich gar nicht anstrengen (ohne Ansatzpunkt)«.<br><span class='jp'>がんばり<b>ようがない</b></span><br>📖 Buch-Satz: 「がんばりようがない」","rule":"V<sub>ます</sub>-Stamm + ようがない: es fehlt jedes Mittel/jeder Weg, die Handlung auszuführen (連絡しようがない = keine Kontaktmöglichkeit). Stärker als できない: prinzipiell unmöglich."},{"l":36,"t":"45 · 〜あげく","de":"nach langem … schließlich (meist übel)","slots":[{"text":"さんざん","role":"plain"},{"text":"<ruby>苦労<rt>くろう</rt></ruby>した<b>あげく</b>、<ruby>結局<rt>けっきょく</rt></ruby>","role":"plain"},{"text":"あきらめて","role":"plain"},{"text":"しまった。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Nach all der Plackerei gab er es am Ende doch auf.«","ex":{"jp":"さんざん <ruby>苦労<rt>くろう</rt></ruby>した<b>あげく</b>、<ruby>結局<rt>けっきょく</rt></ruby> あきらめて しまった。","de":"Nach all der Plackerei gab er es am Ende doch auf."},"simpel":"»Nach all der Mühe kam am Ende …«<br><span class='jp'><ruby>苦労<rt>くろう</rt></ruby>した<b>あげく</b></span><br>📖 Buch-Satz: 「<ruby>苦労<rt>くろう</rt></ruby>した あげく」","rule":"V<sub>た</sub>/N の + あげく(に): nach langem, zehrendem Prozess folgt ein (meist negatives) Ende. Neutral-förmlich: 〜末に."},{"l":36,"t":"46 · 〜もんじゃない","de":"so etwas tut man nicht (Ermahnung)","slots":[{"text":"あきらめる","role":"plain"},{"text":"なんて、そんな","role":"plain"},{"text":"こと","role":"plain"},{"text":"<ruby>考<rt>かんが</rt></ruby>える<b>もんじゃない</b>よ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ans Aufgeben denkt man gar nicht erst!«","ex":{"jp":"あきらめる なんて、そんな こと <ruby>考<rt>かんが</rt></ruby>える<b>もんじゃない</b>よ。","de":"Ans Aufgeben denkt man gar nicht erst!"},"simpel":"Sanfte Moral-Ermahnung: »so etwas denkt man doch nicht!«<br><span class='jp'><ruby>考<rt>かんが</rt></ruby>える<b>もんじゃない</b></span><br>📖 Buch-Satz: 「そんな こと <ruby>考<rt>かんが</rt></ruby>える もんじゃない」","rule":"V<sub>Grund</sub> + もんじゃない (= ものではない): allgemein-moralische Ermahnung »so etwas gehört sich nicht«. Positiv: もんだ (»so gehört es sich«). Gesprochen もん, geschrieben もの."},{"l":36,"t":"47 · 〜だけ〜てみる","de":"einfach mal so viel wie möglich …","slots":[{"text":"エントリーシートは","role":"plain"},{"text":"<ruby>出<rt>だ</rt></ruby>す<b>だけ</b>","role":"plain"},{"text":"<ruby>出<rt>だ</rt></ruby>して","role":"plain"},{"text":"<ruby>見<rt>み</rt></ruby>よう。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Reichen wir erst mal alle Bewerbungen ein, die gehen — dann sehen wir weiter.«","ex":{"jp":"エントリーシートは <ruby>出<rt>だ</rt></ruby>す<b>だけ</b> <ruby>出<rt>だ</rt></ruby>して <ruby>見<rt>み</rt></ruby>よう。","de":"Reichen wir erst mal alle Bewerbungen ein, die gehen — dann sehen wir weiter."},"simpel":"»Erst mal alles einreichen, was geht — dann sieht man weiter.«<br><span class='jp'><ruby>出<rt>だ</rt></ruby>す<b>だけ</b> <ruby>出<rt>だ</rt></ruby>して みる</span><br>📖 Buch-Satz: 「<ruby>出<rt>だ</rt></ruby>すだけ <ruby>出<rt>だ</rt></ruby>して みる」","rule":"V<sub>Grund</sub> + だけ + V<sub>て</sub>みる (dasselbe Verb doppelt): »so viel wie eben geht erst einmal tun (dann weitersehen)«. Auch がんばれるだけがんばる (55): Potentialform + だけ = »so viel man kann«."},{"l":37,"t":"48 · 〜ばかりに","de":"nur weil … (kam es zum Übel)","slots":[{"text":"<ruby>経験<rt>けいけん</rt></ruby>が","role":"plain"},{"text":"なかった<b>ばかりに</b>、なかなか","role":"plain"},{"text":"<ruby>採用<rt>さいよう</rt></ruby>されなかった。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Nur weil mir die Erfahrung fehlte, wurde ich lange nicht eingestellt.«","ex":{"jp":"<ruby>経験<rt>けいけん</rt></ruby>が なかった<b>ばかりに</b>、なかなか <ruby>採用<rt>さいよう</rt></ruby>されなかった。","de":"Nur weil mir die Erfahrung fehlte, wurde ich lange nicht eingestellt."},"simpel":"»Nur weil mir die Erfahrung fehlte, (ging alles schief)«.<br><span class='jp'>なかった<b>ばかりに</b></span><br>📖 Buch-Satz: 「<ruby>経験<rt>けいけん</rt></ruby>が なかった ばかりに」","rule":"Plain + ばかりに: ein einziger Grund führte zu einem bedauerlichen Ergebnis — mit Reue/Bitterkeit. Nachsatz ist immer negativ."},{"l":37,"t":"49 · 〜ことはない","de":"kein Grund, zu … / musst nicht …","slots":[{"text":"<ruby>君<rt>きみ</rt></ruby>が","role":"plain"},{"text":"<ruby>謝<rt>あやま</rt></ruby>る<b>ことはない</b>。<ruby>悪<rt>わる</rt></ruby>いのは","role":"plain"},{"text":"<ruby>向<rt>む</rt></ruby>こうだ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Du musst dich nicht entschuldigen — schuld ist die andere Seite.«","ex":{"jp":"まだ <ruby>若<rt>わか</rt></ruby>いんだから、あきらめる<b>ことはない</b>よ。","de":"Du bist noch jung — kein Grund aufzugeben."},"simpel":"Beruhigung: »du brauchst nicht aufzugeben«.<br><span class='jp'>あきらめる<b>ことはない</b></span><br>📖 Buch-Satz: 「あきらめる ことはない」","rule":"V<sub>Grund</sub> + ことはない: »es besteht kein Anlass/keine Notwendigkeit zu V« — tröstend oder ratend. Vgl. ないことはない (54)."},{"l":37,"t":"50 · 〜に比べて","de":"verglichen mit …","slots":[{"text":"<ruby>同期<rt>どうき</rt></ruby>の","role":"plain"},{"text":"<ruby>人<rt>ひと</rt></ruby><b>に比べて</b>、<ruby>仕事<rt>しごと</rt></ruby>が","role":"plain"},{"text":"<ruby>遅<rt>おそ</rt></ruby>い","role":"plain"},{"text":"<ruby>気<rt>き</rt></ruby>が","role":"plain"},{"text":"した。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Verglichen mit den Jahrgangskollegen kam ich mir langsam vor.«","ex":{"jp":"<ruby>同期<rt>どうき</rt></ruby>の <ruby>人<rt>ひと</rt></ruby><b>に比べて</b>、<ruby>仕事<rt>しごと</rt></ruby>が <ruby>遅<rt>おそ</rt></ruby>い <ruby>気<rt>き</rt></ruby>が した。","de":"Verglichen mit den Jahrgangskollegen kam ich mir langsam vor."},"simpel":"»Verglichen mit den Kollegen des gleichen Jahrgangs …«<br><span class='jp'><ruby>同期<rt>どうき</rt></ruby>の <ruby>人<rt>ひと</rt></ruby><b>に比べて</b></span><br>📖 Buch-Satz: 「<ruby>同期<rt>どうき</rt></ruby>の <ruby>人<rt>ひと</rt></ruby>に<ruby>比<rt>くら</rt></ruby>べて」","rule":"N + に比べて/に比べ: Vergleichsbasis herausstellen. 同期 = Kollegen desselben Eintrittsjahrgangs (wichtige Firmen-Vokabel!)."},{"l":37,"t":"51 · 〜ものか","de":"niemals! (trotzige Verweigerung)","slots":[{"text":"こんな","role":"plain"},{"text":"ことで","role":"plain"},{"text":"<ruby>負<rt>ま</rt></ruby>ける<b>ものか</b>と","role":"plain"},{"text":"<ruby>思<rt>おも</rt></ruby>った。","role":"plain"}],"gloss":"Baue den Beispielsatz: »„So leicht verliere ich nicht!“, dachte ich.«","ex":{"jp":"こんな ことで <ruby>負<rt>ま</rt></ruby>ける<b>ものか</b>と <ruby>思<rt>おも</rt></ruby>った。","de":"„So leicht verliere ich nicht!“, dachte ich."},"simpel":"»Verlieren? Niemals!«<br><span class='jp'><ruby>負<rt>ま</rt></ruby>ける<b>ものか</b></span><br>📖 Buch-Satz: 「<ruby>負<rt>ま</rt></ruby>けるものか」","rule":"Plain + ものか/もんか: emphatische Verneinung in Frageform — der Sprecher schließt es kategorisch aus. Trotz und Kampfgeist."},{"l":37,"t":"52 · 〜というものだ","de":"👉 DAS nennt man … / so ist … eben (das Wesen)","slots":[{"text":"<ruby>厳<rt>きび</rt></ruby>しくても","role":"plain"},{"text":"<ruby>部下<rt>ぶか</rt></ruby>を","role":"plain"},{"text":"<ruby>育<rt>そだ</rt></ruby>てる。それが","role":"plain"},{"text":"<ruby>上司<rt>じょうし</rt></ruby><b>というものよ</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Streng sein und doch die Leute fördern — genau das macht einen Chef aus.«","ex":{"jp":"<ruby>厳<rt>きび</rt></ruby>しくても <ruby>部下<rt>ぶか</rt></ruby>を <ruby>育<rt>そだ</rt></ruby>てる。それが <ruby>上司<rt>じょうし</rt></ruby><b>というものよ</b>。","de":"Streng sein und doch die Leute fördern — genau das macht einen Chef aus."},"simpel":"👉 <b>Zeigefinger auf eine Situation:</b> »<b>DAS</b> nennt man … / genau das ist … «.<br><span class=\"jp\"><ruby>助<rt>たす</rt></ruby>け<ruby>合<rt>あ</rt></ruby>うのが <ruby>友達<rt>ともだち</rt></ruby><b>というものだ</b></span> = »Einander helfen — DAS ist Freundschaft.«<br>📖 Buch-Satz: 「それが <ruby>上司<rt>じょうし</rt></ruby>というものよ」","rule":"N + というものだ: zeigt mit dem Finger auf eine Situation und benennt ihr <b>Wesen</b> — »genau das macht … aus / so ist … eben«. Auch als Urteil: それは わがままというものだ (»das nenne ich Egoismus«)."},{"l":37,"t":"53 · 〜ばこそ","de":"gerade weil … (und nur deshalb)","slots":[{"text":"ぼくの","role":"plain"},{"text":"ことを","role":"plain"},{"text":"<ruby>思<rt>おも</rt></ruby>えば<b>こそ</b>、<ruby>厳<rt>きび</rt></ruby>しく","role":"plain"},{"text":"して","role":"plain"},{"text":"くれたのだ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Gerade weil sie an mich dachte, war sie so streng mit mir.«","ex":{"jp":"ぼくの ことを <ruby>思<rt>おも</rt></ruby>えば<b>こそ</b>、<ruby>厳<rt>きび</rt></ruby>しく して くれたのだ。","de":"Gerade weil sie an mich dachte, war sie so streng mit mir."},"simpel":"»Gerade weil sie an mich dachte (war sie streng)«.<br><span class='jp'><ruby>思<rt>おも</rt></ruby>えば<b>こそ</b></span><br>📖 Buch-Satz: 「ぼくの ことを <ruby>思<rt>おも</rt></ruby>えばこそ」","rule":"V<sub>ば</sub> + こそ: der Grund wird exklusiv-betont — »einzig und gerade deshalb«. Gehobener als からこそ; Satzende oft のだ."},{"l":37,"t":"54 · 〜ないことはない","de":"nicht, dass nicht … (durchaus)","slots":[{"text":"<ruby>仕事<rt>しごと</rt></ruby>が","role":"plain"},{"text":"わからない<b>ことはなかった</b>が、<ruby>時間<rt>じかん</rt></ruby>が","role":"plain"},{"text":"かかった。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Verstanden habe ich die Arbeit durchaus — es dauerte nur.«","ex":{"jp":"<ruby>仕事<rt>しごと</rt></ruby>が わからない<b>ことはなかった</b>が、<ruby>時間<rt>じかん</rt></ruby>が かかった。","de":"Verstanden habe ich die Arbeit durchaus — es dauerte nur."},"simpel":"Doppelte Verneinung: »verstehen konnte ich es durchaus«.<br><span class='jp'>わからない<b>ことはなかった</b></span><br>📖 Buch-Satz: 「わからない ことはなかった」","rule":"V<sub>ない</sub> + ことはない/こともない: doppelte Verneinung = zurückhaltendes Ja (»durchaus, schon, im Prinzip«). Einschränkung schwingt mit."},{"l":37,"t":"55 · 〜(Kann-Form)だけ…","de":"so viel man (nur) kann","slots":[{"text":"<ruby>結果<rt>けっか</rt></ruby>は","role":"plain"},{"text":"<ruby>気<rt>き</rt></ruby>に","role":"plain"},{"text":"せず、がんばれる<b>だけ</b>","role":"plain"},{"text":"がんばろう。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Egal was rauskommt — kämpfen wir, so hart wir nur können.«","ex":{"jp":"<ruby>結果<rt>けっか</rt></ruby>は <ruby>気<rt>き</rt></ruby>に せず、がんばれる<b>だけ</b> がんばろう。","de":"Egal was rauskommt — kämpfen wir, so hart wir nur können."},"simpel":"»So hart kämpfen, wie ich nur kann.«<br><span class='jp'>がんばれる<b>だけ</b> がんばろう</span><br>📖 Buch-Satz: 「がんばれる<b>だけ</b> がんばろう」","rule":"V<sub>Kann</sub> + だけ + dasselbe V: die Handlung bis zur eigenen Grenze ausreizen (できるだけ, 食べられるだけ). Vgl. Punkt 47 (出すだけ出してみる)."},{"l":37,"t":"56 · 〜(んだ)もん","de":"weil doch …! (gesprochene Begründung)","slots":[{"text":"<ruby>食<rt>た</rt></ruby>べたく","role":"plain"},{"text":"ない<b>もん</b>。おなか","role":"plain"},{"text":"いっぱいなんだ<b>もん</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Will nicht essen! Bin doch satt!«","ex":{"jp":"だって、<ruby>毎日<rt>まいにち</rt></ruby> <ruby>努力<rt>どりょく</rt></ruby>してたんだ<b>もん</b>。","de":"Na klar — ich habe doch jeden Tag geackert!"},"simpel":"Kindlich-vertraute Rechtfertigung: »ich hab doch (wirklich) geackert!«<br><span class='jp'>してたんだ<b>もん</b></span><br>📖 Buch-Satz: 「<ruby>努力<rt>どりょく</rt></ruby>してたんだもん」","rule":"Satz + (んだ)もん/もの: gesprochene, leicht trotzig-vertraute Begründung (»weil nun mal / doch!«). Typisch Kinder, enge Freunde; erwachsen wirkt es kokett."},{"l":37,"t":"57 · 〜わけにはいかない","de":"darf (aus Prinzip) nicht …","slots":[{"text":"みんなが","role":"plain"},{"text":"<ruby>期待<rt>きたい</rt></ruby>して","role":"plain"},{"text":"いるから、<ruby>失敗<rt>しっぱい</rt></ruby>する<b>わけにはいかない</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Alle setzen auf mich — scheitern kommt nicht in Frage.«","ex":{"jp":"みんなが <ruby>期待<rt>きたい</rt></ruby>して いるから、<ruby>失敗<rt>しっぱい</rt></ruby>する<b>わけにはいかない</b>。","de":"Alle setzen auf mich — scheitern kommt nicht in Frage."},"simpel":"»Scheitern kommt nicht in Frage (zu viel hängt daran)«.<br><span class='jp'><ruby>失敗<rt>しっぱい</rt></ruby>する<b>わけにはいかない</b></span><br>📖 Buch-Satz: 「<ruby>失敗<rt>しっぱい</rt></ruby>する わけにはいかない」","rule":"V<sub>Grund</sub> + わけにはいかない: aus sozialen/moralischen Gründen unmöglich. V<sub>ない</sub> + わけにはいかない = »muss unbedingt«."},{"l":37,"t":"58 · 〜のみだ","de":"einzig und allein … (schriftlich)","slots":[{"text":"<ruby>迷<rt>まよ</rt></ruby>いは","role":"plain"},{"text":"ない。<ruby>自分<rt>じぶん</rt></ruby>を","role":"plain"},{"text":"<ruby>信<rt>しん</rt></ruby>じて","role":"plain"},{"text":"<ruby>進<rt>すす</rt></ruby>む<b>のみだ</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Kein Zweifel mehr — einzig an sich glauben und weitergehen.«","ex":{"jp":"<ruby>迷<rt>まよ</rt></ruby>いは ない。<ruby>自分<rt>じぶん</rt></ruby>を <ruby>信<rt>しん</rt></ruby>じて <ruby>進<rt>すす</rt></ruby>む<b>のみだ</b>。","de":"Kein Zweifel mehr — einzig an sich glauben und weitergehen."},"simpel":"»Es bleibt einzig: an sich glauben und weitergehen.«<br><span class='jp'><ruby>進<rt>すす</rt></ruby>む<b>のみだ</b></span><br>📖 Buch-Satz: 「<ruby>自分<rt>じぶん</rt></ruby>を <ruby>信<rt>しん</rt></ruby>じて <ruby>進<rt>すす</rt></ruby>むのみだ」","rule":"V<sub>Grund</sub>/N + のみ(だ): schriftlich-gehobenes だけ — »nur/einzig«. あとは〜のみだ = »es bleibt nur noch …«. Auch のみならず (= だけでなく, 63)."},{"l":37,"t":"59 · 〜つもりで","de":"🎭 in der Vorstellung, … zu sein (und so handeln)","slots":[{"text":"スターに","role":"plain"},{"text":"なった<b>つもりで</b>、<ruby>堂々<rt>どうどう</rt></ruby>と","role":"plain"},{"text":"<ruby>発表<rt>はっぴょう</rt></ruby>した。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich präsentierte selbstbewusst — ganz so, als wäre ich ein Star.«","ex":{"jp":"スターに なった<b>つもりで</b>、<ruby>堂々<rt>どうどう</rt></ruby>と <ruby>発表<rt>はっぴょう</rt></ruby>した。","de":"Ich präsentierte selbstbewusst — ganz so, als wäre ich ein Star."},"simpel":"🎭 <b>Rollenspiel im Kopf:</b> Vた/N の + つもりで = »in der Vorstellung, … zu sein — und genau so handeln«.<br><span class=\"jp\">スターに なった<b>つもりで</b>、<ruby>堂々<rt>どうどう</rt></ruby>と <ruby>発表<rt>はっぴょう</rt></ruby>した</span> = »Ich präsentierte selbstbewusst — als wäre ich ein Star.«<br>📖 Buch-Satz: 「スターになったつもりで」","rule":"Vた / N の + つもりで = man handelt <b>so, als ob</b> eine (oft irreale) Annahme zuträfe — »in der Vorstellung, … zu sein«: <ruby>死<rt>し</rt></ruby>んだつもりで (als hätte man nichts zu verlieren).<br>⚠ V-ている + つもり = Selbstbild vs. Realität (»ich bilde mir ein …«, Punkt 120) — andere Bedeutung!"},{"l":38,"t":"60 · 〜から<ruby>見<rt>み</rt></ruby>ると／からすると","de":"von … aus betrachtet / aus Sicht von … (Blickwinkel)","slots":[{"text":"<ruby>外国人<rt>がいこくじん</rt></ruby>の","role":"plain"},{"text":"<ruby>立場<rt>たちば</rt></ruby><b>から見ると</b>、この","role":"plain"},{"text":"<ruby>習慣<rt>しゅうかん</rt></ruby>は","role":"plain"},{"text":"<ruby>不思議<rt>ふしぎ</rt></ruby>だ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Aus Sicht eines Ausländers ist diese Sitte seltsam.«","ex":{"jp":"<ruby>外国人<rt>がいこくじん</rt></ruby>の <ruby>立場<rt>たちば</rt></ruby><b>から見ると</b>、この <ruby>習慣<rt>しゅうかん</rt></ruby>は <ruby>不思議<rt>ふしぎ</rt></ruby>だ。","de":"Aus Sicht eines Ausländers ist diese Sitte seltsam."},"simpel":"»Aus Sicht des Menschen …«.<br><span class='jp'><ruby>人間<rt>にんげん</rt></ruby>の <ruby>立場<rt>たちば</rt></ruby><b>から見ると</b></span><br>📖 Buch-Satz: 「<ruby>人間<rt>にんげん</rt></ruby>の <ruby>立場<rt>たちば</rt></ruby>から<ruby>見<rt>み</rt></ruby>ると」","rule":"N + から見ると／からいうと／からすると: nennt den Blickwinkel oder die Urteilsbasis — »von N aus betrachtet / N zufolge«. からして heißt oft »schon allein an N (erkennt man)«."},{"l":38,"t":"61 · 〜<ruby>一方<rt>いっぽう</rt></ruby>で","de":"andererseits / während zugleich …","slots":[{"text":"<ruby>都会<rt>とかい</rt></ruby>は","role":"plain"},{"text":"<ruby>便利<rt>べんり</rt></ruby>な<b><ruby>一方<rt>いっぽう</rt></ruby>で</b>、<ruby>生活費<rt>せいかつひ</rt></ruby>が","role":"plain"},{"text":"<ruby>高<rt>たか</rt></ruby>い。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Die Stadt ist praktisch, andererseits sind die Lebenshaltungskosten hoch.«","ex":{"jp":"<ruby>都会<rt>とかい</rt></ruby>は <ruby>便利<rt>べんり</rt></ruby>な<b><ruby>一方<rt>いっぽう</rt></ruby>で</b>、<ruby>生活費<rt>せいかつひ</rt></ruby>が <ruby>高<rt>たか</rt></ruby>い。","de":"Die Stadt ist praktisch, andererseits sind die Lebenshaltungskosten hoch."},"simpel":"Zwei Seiten: »während auf der einen Seite …«.<br><span class='jp'>その <b><ruby>一方<rt>いっぽう</rt></ruby>で</b></span><br>📖 Buch-Satz: 「その<ruby>一方<rt>いっぽう</rt></ruby>で」","rule":"einfache Form (な-Adj な, N である) + 一方で: stellt zwei gegensätzliche/parallele Seiten nebeneinander — »einerseits …, andererseits …«. Sachlich, oft schriftlich."},{"l":38,"t":"62 · 〜ことから","de":"🔍 daher / an dem, dass … (der sichtbare Anlass)","slots":[{"text":"オオカミが","role":"plain"},{"text":"<ruby>絶滅<rt>ぜつめつ</rt></ruby>した<b>ことから</b>、シカが","role":"plain"},{"text":"<ruby>増<rt>ふ</rt></ruby>えすぎた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Weil die Wölfe ausgestorben waren, vermehrten sich die Hirsche zu stark.«","ex":{"jp":"オオカミが <ruby>絶滅<rt>ぜつめつ</rt></ruby>した<b>ことから</b>、シカが <ruby>増<rt>ふ</rt></ruby>えすぎた。","de":"Weil die Wölfe ausgestorben waren, vermehrten sich die Hirsche zu stark."},"simpel":"🔍 <b>»Woran erkennt/erklärt sich X? → Daran, dass …«:</b> ことから nennt den <b>sichtbaren Anlass</b> für einen Namen oder Schluss.<br><span class=\"jp\"><ruby>煙<rt>けむり</rt></ruby>が <ruby>出<rt>で</rt></ruby>ている<b>ことから</b>、<ruby>火事<rt>かじ</rt></ruby>だと <ruby>分<rt>わ</rt></ruby>かった</span> = »Am Rauch erkannte man das Feuer.«<br>📖 Buch-Satz: 「<ruby>絶滅<rt>ぜつめつ</rt></ruby>したことから」","rule":"einfache Form (な-Adj な, N である) + ことから = nennt die <b>Tatsache/das Anzeichen</b>, aus dem sich eine Feststellung, ein Name oder ein Schluss ergibt — »daraus, dass … / an dem, dass …«. Sachlich-erklärend (Ursachen, Namensherkünfte)."},{"l":38,"t":"63 · 〜のみならず","de":"nicht nur … (sondern auch)","slots":[{"text":"オオカミは","role":"plain"},{"text":"シカ<b>のみならず</b>、<ruby>小<rt>ちい</rt></ruby>さな","role":"plain"},{"text":"<ruby>動物<rt>どうぶつ</rt></ruby>も","role":"plain"},{"text":"<ruby>襲<rt>おそ</rt></ruby>う。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wölfe fallen nicht nur Hirsche an, sondern auch kleine Tiere.«","ex":{"jp":"オオカミは シカ<b>のみならず</b>、<ruby>小<rt>ちい</rt></ruby>さな <ruby>動物<rt>どうぶつ</rt></ruby>も <ruby>襲<rt>おそ</rt></ruby>う。","de":"Wölfe fallen nicht nur Hirsche an, sondern auch kleine Tiere."},"simpel":"»nicht nur Schaden angerichtet, sondern …«.<br><span class='jp'><ruby>被害<rt>ひがい</rt></ruby>を <ruby>与<rt>あた</rt></ruby>えた<b>のみならず</b></span><br>📖 Buch-Satz: 「<ruby>被害<rt>ひがい</rt></ruby>を<ruby>与<rt>あた</rt></ruby>えたのみならず」","rule":"einfache Form / N + のみならず: schriftlich-formelle Steigerung »nicht nur A, sondern auch B«. Nachsatz oft mit も. = だけでなく, aber gehobener."},{"l":38,"t":"64 · 〜といった","de":"wie zum Beispiel … / solche … wie","slots":[{"text":"<ruby>頭痛<rt>ずつう</rt></ruby>や","role":"plain"},{"text":"<ruby>発熱<rt>はつねつ</rt></ruby><b>といった</b>","role":"plain"},{"text":"<ruby>症状<rt>しょうじょう</rt></ruby>が","role":"plain"},{"text":"<ruby>出<rt>で</rt></ruby>た。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Es traten Symptome wie Kopfschmerz und Fieber auf.«","ex":{"jp":"ネズミやビーバー<b>といった</b> <ruby>小動物<rt>しょうどうぶつ</rt></ruby>が <ruby>増<rt>ふ</rt></ruby>えた。","de":"Kleintiere wie Mäuse und Biber nahmen zu."},"simpel":"Beispiele aufzählen: »Tiere wie Mäuse und Biber«.<br><span class='jp'>ネズミやビーバー<b>といった</b> <ruby>動物<rt>どうぶつ</rt></ruby></span><br>📖 Buch-Satz: 「ネズミやビーバーといった」","rule":"N1やN2 + といった + N(Oberbegriff): nennt zwei, drei Beispiele für eine Kategorie — »… wie N1, N2 (und dergleichen)«. Steht vor dem Oberbegriff."},{"l":38,"t":"65 · 〜にしたがって／につれて","de":"je mehr …, desto … / mit (paralleler Wandel)","slots":[{"text":"シカの","role":"plain"},{"text":"<ruby>数<rt>かず</rt></ruby>が","role":"plain"},{"text":"<ruby>増<rt>ふ</rt></ruby>える<b>にしたがって</b>、<ruby>森<rt>もり</rt></ruby>の","role":"plain"},{"text":"<ruby>草<rt>くさ</rt></ruby>が","role":"plain"},{"text":"<ruby>減<rt>へ</rt></ruby>った。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Je mehr die Hirsche wurden, desto weniger Gras gab es im Wald.«","ex":{"jp":"シカの <ruby>数<rt>かず</rt></ruby>が <ruby>増<rt>ふ</rt></ruby>える<b>にしたがって</b>、<ruby>森<rt>もり</rt></ruby>の <ruby>草<rt>くさ</rt></ruby>が <ruby>減<rt>へ</rt></ruby>った。","de":"Je mehr die Hirsche wurden, desto weniger Gras gab es im Wald."},"simpel":"Zwei Dinge ändern sich parallel: »mit steigender Zahl …«.<br><span class='jp'><ruby>数<rt>かず</rt></ruby>が <ruby>増<rt>ふ</rt></ruby>える<b>にしたがって</b></span><br>📖 Buch-Satz: 「<ruby>数<rt>かず</rt></ruby>が<ruby>増<rt>ふ</rt></ruby>えるにしたがって」","rule":"Grundform / N + にしたがって（につれて）: zwei Veränderungen laufen parallel — »je mehr A, desto B / im Zuge von A«. Allmählich, nicht absichtlich steuerbar."},{"l":38,"t":"66 · 〜<ruby>得<rt>う</rt></ruby>る","de":"kann (durchaus) passieren / ist denkbar — verneint 得ない = unmöglich","slots":[{"text":"それは","role":"plain"},{"text":"<ruby>十分<rt>じゅうぶん</rt></ruby>","role":"plain"},{"text":"<ruby>考<rt>かんが</rt></ruby>え<b><ruby>得<rt>う</rt></ruby>る</b>","role":"plain"},{"text":"<ruby>結果<rt>けっか</rt></ruby>だ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Das ist ein durchaus denkbares Ergebnis.«","ex":{"jp":"<ruby>誰<rt>だれ</rt></ruby>にでも <ruby>起<rt>お</rt></ruby>こり<b><ruby>得<rt>う</rt></ruby>る</b> <ruby>事故<rt>じこ</rt></ruby>だ。","de":"Das ist ein Unfall, der jedem passieren kann."},"simpel":"💡 Du kennst <b>ありえない</b> (»gibt’s nicht / ausgeschlossen«) — das IST genau diese Form!<br>ます-Stamm + <b><ruby>得<rt>う</rt></ruby>る（うる／える）</b> = »kann (durchaus) passieren«.<br><span class=\"jp\"><ruby>誰<rt>だれ</rt></ruby>にでも <ruby>起<rt>お</rt></ruby>こり<b><ruby>得<rt>う</rt></ruby>る</b></span> (kann jedem passieren) ↔ <span class=\"jp\">あり<b><ruby>得<rt>え</rt></ruby>ない</b></span> (unmöglich)<br>📖 Buch-Satz: 「<ruby>回復<rt>かいふく</rt></ruby>させ<ruby>得<rt>う</rt></ruby>る」","rule":"ます-Stamm + 得る（うる／える）: »es ist (theoretisch) möglich, dass V«. Das alltägliche <b>あり得ない</b> (unmöglich) ist genau diese Form, verneint. Schriftlich. Nur Möglichkeit — NICHT erlernte Fähigkeit (dafür die Kann-Form)."},{"l":38,"t":"67 · 〜に<ruby>反<rt>はん</rt></ruby>して","de":"entgegen / im Gegensatz zu (Erwartung)","slots":[{"text":"<ruby>親<rt>おや</rt></ruby>の","role":"plain"},{"text":"<ruby>期待<rt>きたい</rt></ruby><b>に<ruby>反<rt>はん</rt></ruby>して</b>、<ruby>彼<rt>かれ</rt></ruby>は","role":"plain"},{"text":"<ruby>大学<rt>だいがく</rt></ruby>を","role":"plain"},{"text":"やめた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Entgegen den Erwartungen der Eltern brach er das Studium ab.«","ex":{"jp":"<ruby>予想<rt>よそう</rt></ruby><b>に<ruby>反<rt>はん</rt></ruby>して</b>、<ruby>試合<rt>しあい</rt></ruby>は <ruby>簡単<rt>かんたん</rt></ruby>に <ruby>終<rt>お</rt></ruby>わった。","de":"Entgegen den Erwartungen war das Spiel schnell vorbei."},"simpel":"»Entgegen den Erwartungen …«.<br><span class='jp'><ruby>期待<rt>きたい</rt></ruby><b>に<ruby>反<rt>はん</rt></ruby>して</b></span><br>📖 Buch-Satz: 「<ruby>期待<rt>きたい</rt></ruby>に<ruby>反<rt>はん</rt></ruby>して」","rule":"N + に反して／に反し: das Ergebnis läuft dem N (Erwartung, Vorhersage, Regel) zuwider — »entgegen N«. Attributiv: N + に反する + N. Schriftlich."},{"l":38,"t":"68 · 〜に<ruby>関<rt>かん</rt></ruby>して","de":"bezüglich / in Bezug auf …","slots":[{"text":"この","role":"plain"},{"text":"<ruby>問題<rt>もんだい</rt></ruby><b>に<ruby>関<rt>かん</rt></ruby>して</b>、<ruby>意見<rt>いけん</rt></ruby>を","role":"plain"},{"text":"<ruby>聞<rt>き</rt></ruby>かせてください。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Bezüglich dieses Problems sagen Sie mir bitte Ihre Meinung.«","ex":{"jp":"この <ruby>問題<rt>もんだい</rt></ruby><b>に<ruby>関<rt>かん</rt></ruby>して</b>、<ruby>意見<rt>いけん</rt></ruby>を <ruby>聞<rt>き</rt></ruby>かせてください。","de":"Bezüglich dieses Problems sagen Sie mir bitte Ihre Meinung."},"simpel":"Thema nennen: »was das Mitbringen betrifft …«.<br><span class='jp'><ruby>連<rt>つ</rt></ruby>れてくること<b>に<ruby>関<rt>かん</rt></ruby>して</b></span><br>📖 Buch-Satz: 「<ruby>連<rt>つ</rt></ruby>れてくることに<ruby>関<rt>かん</rt></ruby>して」","rule":"N + に関して／に関する: nennt das Thema, um das es geht — »bezüglich N«. Etwas förmlicher als について. Attributiv: N + に関する + N."},{"l":38,"t":"69 · 〜<ruby>反面<rt>はんめん</rt></ruby>","de":"andererseits / auf der Kehrseite jedoch","slots":[{"text":"この","role":"plain"},{"text":"<ruby>薬<rt>くすり</rt></ruby>は","role":"plain"},{"text":"よく","role":"plain"},{"text":"<ruby>効<rt>き</rt></ruby>く<b><ruby>反面<rt>はんめん</rt></ruby></b>、<ruby>副作用<rt>ふくさよう</rt></ruby>も","role":"plain"},{"text":"<ruby>強<rt>つよ</rt></ruby>い。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Dieses Medikament wirkt gut, hat andererseits aber starke Nebenwirkungen.«","ex":{"jp":"この <ruby>薬<rt>くすり</rt></ruby>は よく <ruby>効<rt>き</rt></ruby>く<b><ruby>反面<rt>はんめん</rt></ruby></b>、<ruby>副作用<rt>ふくさよう</rt></ruby>も <ruby>強<rt>つよ</rt></ruby>い。","de":"Dieses Medikament wirkt gut, hat andererseits aber starke Nebenwirkungen."},"simpel":"Zwei Seiten einer Sache: »zwar erhofft, aber …«.<br><span class='jp'><ruby>期待<rt>きたい</rt></ruby>される<b><ruby>反面<rt>はんめん</rt></ruby></b></span><br>📖 Buch-Satz: 「<ruby>期待<rt>きたい</rt></ruby>される<ruby>反面<rt>はんめん</rt></ruby>」","rule":"einfache Form (な-Adj な, N である) + 反面: dieselbe Sache hat zwei gegensätzliche Seiten — »… , andererseits aber …«. Guter Punkt + Schattenseite."},{"l":38,"t":"70 · 〜<ruby>上<rt>じょう</rt></ruby>（は）","de":"📋 N-technisch / auf dem Papier (theoretisch, rechtlich …)","slots":[{"text":"<ruby>経験<rt>けいけん</rt></ruby><b><ruby>上<rt>じょう</rt></ruby></b>、<ruby>雨<rt>あめ</rt></ruby>の","role":"plain"},{"text":"<ruby>日<rt>ひ</rt></ruby>は","role":"plain"},{"text":"<ruby>客<rt>きゃく</rt></ruby>が","role":"plain"},{"text":"<ruby>少<rt>すく</rt></ruby>ない。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Erfahrungsgemäß gibt es an Regentagen wenige Kunden.«","ex":{"jp":"<ruby>理論<rt>りろん</rt></ruby><b><ruby>上<rt>じょう</rt></ruby></b>は <ruby>可能<rt>かのう</rt></ruby>だが、<ruby>実際<rt>じっさい</rt></ruby>は <ruby>難<rt>むずか</rt></ruby>しい。","de":"Theoretisch ist es möglich, in der Praxis aber schwierig."},"simpel":"📋 <b>Wie das deutsche »-technisch / auf dem Papier«:</b> N + <ruby>上<rt>じょう</rt></ruby> = »auf der Ebene von N«.<br><span class=\"jp\"><ruby>理論<rt>りろん</rt></ruby><b><ruby>上<rt>じょう</rt></ruby></b>は</span> theoretisch · <ruby>法律<rt>ほうりつ</rt></ruby><b><ruby>上<rt>じょう</rt></ruby></b> rechtlich · <ruby>計算<rt>けいさん</rt></ruby><b><ruby>上<rt>じょう</rt></ruby></b> rechnerisch — oft im Gegensatz zur Praxis.<br>📖 Buch-Satz: 「<ruby>理論<rt>りろん</rt></ruby><ruby>上<rt>じょう</rt></ruby>は」","rule":"Nomen + 上（<b>じょう</b>, nicht うえ） = »in Hinsicht auf N / N-technisch«: <ruby>理論<rt>りろん</rt></ruby>上 (theoretisch), <ruby>法律<rt>ほうりつ</rt></ruby>上 (rechtlich), <ruby>経験<rt>けいけん</rt></ruby>上 (erfahrungsgemäß). Nennt den Aspekt, unter dem etwas gilt — häufig als Gegensatz zur Realität."},{"l":38,"t":"71 · 〜つつある","de":"ist gerade dabei, zu … (Wandel im Gange)","slots":[{"text":"オオカミの","role":"plain"},{"text":"<ruby>数<rt>かず</rt></ruby>は","role":"plain"},{"text":"<ruby>回復<rt>かいふく</rt></ruby>し<b>つつある</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Die Zahl der Wölfe erholt sich allmählich.«","ex":{"jp":"オオカミの <ruby>数<rt>かず</rt></ruby>は <ruby>回復<rt>かいふく</rt></ruby>し<b>つつある</b>。","de":"Die Zahl der Wölfe erholt sich allmählich."},"simpel":"Prozess läuft: »die Zahl nimmt gerade zu«.<br><span class='jp'><ruby>増加<rt>ぞうか</rt></ruby>し<b>つつある</b></span><br>📖 Buch-Satz: 「<ruby>増加<rt>ぞうか</rt></ruby>しつつある」","rule":"ます-Stamm + つつある: eine Veränderung ist im Gange und schreitet fort — »ist gerade dabei, zu …«. Schriftlich; ≒ ているところ, betont aber die Entwicklung."},{"l":38,"t":"72 · 〜に<ruby>限<rt>かぎ</rt></ruby>らず","de":"nicht nur … / nicht beschränkt auf …","slots":[{"text":"この","role":"plain"},{"text":"<ruby>問題<rt>もんだい</rt></ruby>は","role":"plain"},{"text":"アメリカ<b>に<ruby>限<rt>かぎ</rt></ruby>らず</b>、<ruby>世界中<rt>せかいじゅう</rt></ruby>で","role":"plain"},{"text":"<ruby>起<rt>お</rt></ruby>きている。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Dieses Problem gibt es nicht nur in Amerika, sondern weltweit.«","ex":{"jp":"この <ruby>問題<rt>もんだい</rt></ruby>は アメリカ<b>に<ruby>限<rt>かぎ</rt></ruby>らず</b>、<ruby>世界中<rt>せかいじゅう</rt></ruby>で <ruby>起<rt>お</rt></ruby>きている。","de":"Dieses Problem gibt es nicht nur in Amerika, sondern weltweit."},"simpel":"»Nicht nur in Amerika …«.<br><span class='jp'>アメリカ<b>に<ruby>限<rt>かぎ</rt></ruby>らず</b></span><br>📖 Buch-Satz: 「アメリカに<ruby>限<rt>かぎ</rt></ruby>らず」","rule":"N + に限らず: »nicht nur auf N beschränkt, sondern (breiter)«. Nachsatz nennt oft mit も den weiteren Bereich. Vgl. に限り／に限る (nur, Punkte 3 / 104)."},{"l":39,"t":"73 · お<ruby>見<rt>み</rt></ruby>えになる","de":"(jd.) kommt — Respekt-Keigo für 来る","slots":[{"text":"<ruby>先生<rt>せんせい</rt></ruby>は","role":"plain"},{"text":"もう","role":"plain"},{"text":"<b>お<ruby>見<rt>み</rt></ruby>えに","role":"plain"},{"text":"なっています</b>か。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ist der Lehrer schon da?«","ex":{"jp":"お<ruby>客様<rt>きゃくさま</rt></ruby>が <ruby>受付<rt>うけつけ</rt></ruby>に <b>お<ruby>見<rt>み</rt></ruby>えになりました</b>。","de":"Ein Kunde ist am Empfang eingetroffen."},"simpel":"Höflich über den Gast: »Herr Sasaki ist gekommen.«<br><span class='jp'><ruby>佐々木<rt>ささき</rt></ruby><ruby>様<rt>さま</rt></ruby>が <b>お<ruby>見<rt>み</rt></ruby>えになりました</b></span><br>📖 Buch-Satz: 「<ruby>佐々木<rt>ささき</rt></ruby><ruby>様<rt>さま</rt></ruby>がお<ruby>見<rt>み</rt></ruby>えになりました」","rule":"お見えになる: sehr höfliches Respekt-Keigo für 来る (jemand kommt). Nur über die andere Person, nie über sich selbst. Höflicher als いらっしゃる/お越しになる, typisch im Service."},{"l":39,"t":"74 · お／ご〜<ruby>願<rt>ねが</rt></ruby>えますか","de":"Dürfte ich Sie um … bitten? (sehr höfliche Bitte)","slots":[{"text":"ご","role":"actor"},{"text":"[Nomen]","role":"subj","label":"Handlung"},{"text":"<ruby>願<rt>ねが</rt></ruby>えますか","role":"plain","label":"dürfte ich bitten?"}],"gloss":"sehr höfliche Bitte: »dürfte ich Sie um N bitten?«.","ex":{"jp":"<ruby>内容<rt>ないよう</rt></ruby>を ご<ruby>確認<rt>かくにん</rt></ruby><b><ruby>願<rt>ねが</rt></ruby>えますか</b>。","de":"Könnten Sie den Inhalt bitte bestätigen?"},"simpel":"Höfliche Bitte: »Dürfte ich Sie um Bestätigung bitten?«<br><span class='jp'>ご<ruby>確認<rt>かくにん</rt></ruby><b><ruby>願<rt>ねが</rt></ruby>えますでしょうか</b></span><br>📖 Buch-Satz: 「ご<ruby>確認<rt>かくにん</rt></ruby><ruby>願<rt>ねが</rt></ruby>えますでしょうか」","rule":"お + ます-Stamm / ご + Nomen + 願えますか（でしょうか）: sehr höfliche Bitte — »dürfte ich Sie um … bitten?«. 願える = Potential von 願う (bitten). Mit でしょうか noch weicher."},{"l":39,"t":"75 · お／ご〜<ruby>申<rt>もう</rt></ruby>し<ruby>上<rt>あ</rt></ruby>げる","de":"(demütig) etw. für Sie tun — Bescheiden-Keigo (stärker als お〜する)","slots":[{"text":"ご","role":"actor"},{"text":"[Nomen]","role":"subj","label":"Handlung"},{"text":"<ruby>申<rt>もう</rt></ruby>し<ruby>上<rt>あ</rt></ruby>げる","role":"plain","label":"tue ich demütig"}],"gloss":"sehr demütiges Bescheiden-Keigo: die eigene Handlung für das Gegenüber.","ex":{"jp":"<ruby>心<rt>こころ</rt></ruby>より お<ruby>礼<rt>れい</rt></ruby><b><ruby>申<rt>もう</rt></ruby>し<ruby>上<rt>あ</rt></ruby>げます</b>。","de":"Ich danke Ihnen von Herzen."},"simpel":"Sehr bescheiden: »Ich möchte es Ihnen erklären.«<br><span class='jp'>ご<ruby>説明<rt>せつめい</rt></ruby><b><ruby>申<rt>もう</rt></ruby>し<ruby>上<rt>あ</rt></ruby>げたい</b></span><br>📖 Buch-Satz: 「ご<ruby>説明<rt>せつめい</rt></ruby><ruby>申<rt>もう</rt></ruby>し<ruby>上<rt>あ</rt></ruby>げたい」","rule":"お + ます-Stamm / ご + Nomen + 申し上げる: besonders demütiges Bescheiden-Keigo für die eigene Handlung, die dem Gegenüber gilt. Noch bescheidener als お〜する. Formell (Rede, Brief)."},{"l":39,"t":"76 · 〜ていただければと<ruby>思<rt>おも</rt></ruby>います","de":"Ich wäre froh, wenn Sie … könnten (weiche höfliche Bitte)","slots":[{"text":"[Handlung て-Form]","role":"cond"},{"text":"いただければと<ruby>思<rt>おも</rt></ruby>います","role":"plain","label":"wäre ich dankbar"}],"gloss":"weiche höfliche Bitte: »ich wäre dankbar, wenn Sie … würden«.","ex":{"jp":"<ruby>明日<rt>あした</rt></ruby>までに ご<ruby>返信<rt>へんしん</rt></ruby><b>いただければと<ruby>思<rt>おも</rt></ruby>います</b>。","de":"Ich wäre froh über eine Antwort bis morgen."},"simpel":"Weiche Bitte: »Ich würde mich über Ihre Nachricht freuen.«<br><span class='jp'>ご<ruby>連絡<rt>れんらく</rt></ruby><b>いただければと<ruby>思<rt>おも</rt></ruby>います</b></span><br>📖 Buch-Satz: 「ご<ruby>連絡<rt>れんらく</rt></ruby>いただければと<ruby>思<rt>おも</rt></ruby>います」","rule":"て-Form + いただければと思います (bzw. お／ご〜いただければ〜): sehr weiche, höfliche Bitte — »ich wäre dankbar, wenn Sie … würden«. Wörtlich: »wenn ich es (von Ihnen) bekäme, denke ich (wäre gut)«."},{"l":39,"t":"77 · 〜につきましては","de":"was … betrifft / bezüglich … (sehr formell)","slots":[{"text":"その","role":"plain"},{"text":"<ruby>件<rt>けん</rt></ruby><b>につきましては</b>、<ruby>担当者<rt>たんとうしゃ</rt></ruby>から","role":"plain"},{"text":"<ruby>連絡<rt>れんらく</rt></ruby>します。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Zu dieser Angelegenheit meldet sich der Zuständige.«","ex":{"jp":"<ruby>料金<rt>りょうきん</rt></ruby><b>につきましては</b>、<ruby>別途<rt>べっと</rt></ruby> ご<ruby>案内<rt>あんない</rt></ruby>いたします。","de":"Was die Gebühren betrifft, informieren wir Sie gesondert."},"simpel":"Formell ein Thema aufgreifen: »Was den Terminplan betrifft …«<br><span class='jp'><ruby>日程<rt>にってい</rt></ruby><b>につきましては</b></span><br>📖 Buch-Satz: 「<ruby>日程<rt>にってい</rt></ruby>につきましては」","rule":"N + につきましては: sehr formelle Themen-Markierung — »was N betrifft«. Höfliche Schriftform von については／に関しては. Typisch in Geschäftsmails und Ansagen."},{"l":40,"t":"78 · 〜のなんのって","de":"und wie! / unglaublich (umgangssprachliche Betonung)","slots":[{"text":"あの","role":"plain"},{"text":"<ruby>日<rt>ひ</rt></ruby>は","role":"plain"},{"text":"<ruby>寒<rt>さむ</rt></ruby>い<b>のなんのって</b>、<ruby>手<rt>て</rt></ruby>が","role":"plain"},{"text":"<ruby>凍<rt>こお</rt></ruby>りそうだった。","role":"plain"}],"gloss":"Baue den Beispielsatz: »An dem Tag war es sowas von kalt, mir sind fast die Hände abgefroren.«","ex":{"jp":"<ruby>店<rt>みせ</rt></ruby>が <ruby>混<rt>こ</rt></ruby>んでいる<b>のなんのって</b>、<ruby>席<rt>せき</rt></ruby>が <ruby>全然<rt>ぜんぜん</rt></ruby>なかった。","de":"Der Laden war sowas von voll, es gab überhaupt keine Plätze."},"simpel":"»Die Karte war soooo lang, unglaublich!«<br><span class='jp'><ruby>多<rt>おお</rt></ruby>い<b>のなんのって</b></span><br>📖 Buch-Satz: 「メニューが<ruby>多<rt>おお</rt></ruby>いのなんのって」","rule":"い-Adj / Verb (einfache Form) + のなんのって: sehr umgangssprachliche Übertreibung — »und wie!, es war der Wahnsinn«. Der Sprecher betont emotional ein extremes Ausmaß."},{"l":40,"t":"79 · 〜たて","de":"frisch … / gerade eben … (frisch gemacht)","slots":[{"text":"この","role":"plain"},{"text":"<ruby>料理<rt>りょうり</rt></ruby>は","role":"plain"},{"text":"でき<b>たて</b>です。<ruby>熱<rt>あつ</rt></ruby>いうちに","role":"plain"},{"text":"どうぞ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Das Gericht ist frisch fertig. Bitte, solange es heiß ist.«","ex":{"jp":"<ruby>焼<rt>や</rt></ruby>き<b>たて</b>の パンは おいしい。","de":"Frisch gebackenes Brot schmeckt gut."},"simpel":"»Frisch fertig / ganz frisch gemacht.«<br><span class='jp'>でき<b>たて</b></span><br>📖 Buch-Satz: 「できたて」","rule":"ます-Stamm + たて: etwas ist gerade frisch fertiggestellt und im besten Zustand — できたて (frisch gemacht), <ruby>焼<rt>や</rt></ruby>きたて (frisch gebacken), <ruby>取<rt>と</rt></ruby>りたて (frisch geerntet). Begrenzte Verbmenge."},{"l":40,"t":"80 · 〜ったら／ってば","de":"also wirklich, dieser …! / ich sag doch …! (Vorwurf/Nachdruck)","slots":[{"text":"お<ruby>母<rt>かあ</rt></ruby>さん<b>ったら</b>、また","role":"plain"},{"text":"<ruby>同<rt>おな</rt></ruby>じ","role":"plain"},{"text":"<ruby>話<rt>はなし</rt></ruby>を","role":"plain"},{"text":"している。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Mama, also wirklich, sie erzählt schon wieder dasselbe.«","ex":{"jp":"お<ruby>母<rt>かあ</rt></ruby>さん<b>ったら</b>、また <ruby>同<rt>おな</rt></ruby>じ <ruby>話<rt>はなし</rt></ruby>を している。","de":"Mama, also wirklich, sie erzählt schon wieder dasselbe."},"simpel":"Kopfschütteln über jemanden: »Dieser Kobayashi, also wirklich!«<br><span class='jp'><ruby>小林<rt>こばやし</rt></ruby><ruby>君<rt>くん</rt></ruby><b>ったら</b></span><br>📖 Buch-Satz: 「<ruby>小林<rt>こばやし</rt></ruby><ruby>君<rt>くん</rt></ruby>ったら」","rule":"N + ったら／ってば (gesprochen): (1) leichter Tadel/Staunen über eine Person — »dieser …, also wirklich!«; (2) ってば auch »ich sag doch …!« beim wiederholten Beharren. Sehr umgangssprachlich."},{"l":40,"t":"81 · 〜ようになっている","de":"ist so eingerichtet/gemacht, dass … (System/Regel)","slots":[{"text":"<ruby>時間<rt>じかん</rt></ruby>に","role":"plain"},{"text":"なると","role":"plain"},{"text":"<ruby>電気<rt>でんき</rt></ruby>が","role":"plain"},{"text":"<ruby>消<rt>き</rt></ruby>える<b>ようになっている</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Es ist so eingestellt, dass das Licht zur bestimmten Zeit ausgeht.«","ex":{"jp":"ドアは <ruby>自動<rt>じどう</rt></ruby>で <ruby>閉<rt>し</rt></ruby>まる<b>ようになっている</b>。","de":"Die Tür ist so gebaut, dass sie sich automatisch schließt."},"simpel":"»Es ist so gebaut, dass es (automatisch) wechselt.«<br><span class='jp'><ruby>変<rt>か</rt></ruby>わる<b>ようになっている</b></span><br>📖 Buch-Satz: 「<ruby>変<rt>か</rt></ruby>わるようになっている」","rule":"Grundform / ない-Form + ようになっている: ein Mechanismus, eine Regel oder ein Aufbau ist so gestaltet, dass etwas (von selbst) geschieht — »es ist so eingerichtet, dass …«."},{"l":40,"t":"82 · 〜わけだ","de":"das erklärt, warum … / kein Wunder, dass … (logische Folge)","slots":[{"text":"<ruby>彼<rt>かれ</rt></ruby>は","role":"plain"},{"text":"10<ruby>年<rt>ねん</rt></ruby>","role":"plain"},{"text":"<ruby>日本<rt>にほん</rt></ruby>に","role":"plain"},{"text":"いた。<ruby>日本語<rt>にほんご</rt></ruby>が","role":"plain"},{"text":"<ruby>上手<rt>じょうず</rt></ruby>な<b>わけだ</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Er war zehn Jahre in Japan. Kein Wunder, dass sein Japanisch so gut ist.«","ex":{"jp":"3<ruby>皿<rt>さら</rt></ruby>も <ruby>食<rt>た</rt></ruby>べたのか。もう <ruby>入<rt>はい</rt></ruby>らない<b>わけだ</b>。","de":"Drei Teller hast du gegessen? Kein Wunder, dass nichts mehr reingeht."},"simpel":"Aha-Schluss: »Kein Wunder, dass ich nicht mehr essen konnte.«<br><span class='jp'><ruby>食<rt>た</rt></ruby>べられなかった<b>わけだ</b></span><br>📖 Buch-Satz: 「<ruby>食<rt>た</rt></ruby>べられなかったわけだ」","rule":"einfache Form (な-Adj な, N な/という) + わけだ: zieht aus dem Gesagten einen logischen Schluss — »also deshalb …; das erklärt, dass …; kein Wunder«. Man versteht jetzt den Zusammenhang."},{"l":40,"t":"83 · 〜どころか","de":"weit gefehlt / im Gegenteil (ganz anders als erwartet)","slots":[{"text":"たくさん","role":"plain"},{"text":"<ruby>食<rt>た</rt></ruby>べる<b>どころか</b>、<ruby>一口<rt>ひとくち</rt></ruby>も","role":"plain"},{"text":"<ruby>食<rt>た</rt></ruby>べられなかった。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Von wegen viel essen — ich konnte nicht mal einen Bissen essen.«","ex":{"jp":"たくさん <ruby>食<rt>た</rt></ruby>べる<b>どころか</b>、<ruby>一口<rt>ひとくち</rt></ruby>も <ruby>食<rt>た</rt></ruby>べられなかった。","de":"Von wegen viel essen — ich konnte nicht mal einen Bissen essen."},"simpel":"»Von wegen viel essen — im Gegenteil …«<br><span class='jp'>たくさん <ruby>食<rt>た</rt></ruby>べる<b>どころか</b></span><br>📖 Buch-Satz: 「たくさん<ruby>食<rt>た</rt></ruby>べるどころか」","rule":"einfache Form / N + どころか: verneint eine Erwartung stark und stellt das Gegenteil dagegen — »weit gefehlt, im Gegenteil …«. Nachsatz oft mit も/さえ."},{"l":40,"t":"84 · 〜ようじゃ（ようでは）","de":"wenn es (schon) so ist, dann … (negative Folge)","slots":[{"text":"この","role":"plain"},{"text":"<ruby>値段<rt>ねだん</rt></ruby>で","role":"plain"},{"text":"<ruby>文句<rt>もんく</rt></ruby>を","role":"plain"},{"text":"<ruby>言<rt>い</rt></ruby>う<b>ようじゃ</b>、<ruby>商売<rt>しょうばい</rt></ruby>は","role":"plain"},{"text":"<ruby>難<rt>むずか</rt></ruby>しい。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wenn man schon bei dem Preis meckert, wird das Geschäft schwierig.«","ex":{"jp":"そんなことで あきらめる<b>ようじゃ</b>、<ruby>成功<rt>せいこう</rt></ruby>できないよ。","de":"Wenn du schon deswegen aufgibst, wirst du keinen Erfolg haben."},"simpel":"Kritik + schlechte Folge: »Wenn du nicht mal das weißt, dann …«<br><span class='jp'>そんなことも <ruby>知<rt>し</rt></ruby>らない<b>ようじゃ</b></span><br>📖 Buch-Satz: 「そんなことも<ruby>知<rt>し</rt></ruby>らないようじゃ」","rule":"einfache Form + ようじゃ（ようでは）: nennt eine (schlechte) Lage als Bedingung — »wenn es so steht, dass …, dann (kein Erfolg)«. Nachsatz negativ. ようじゃ ist die saloppe Form von ようでは."},{"l":40,"t":"85 · 〜ぶる","de":"sich … geben / … spielen (posieren, meist negativ)","slots":[{"text":"<ruby>彼<rt>かれ</rt></ruby>は","role":"plain"},{"text":"すぐ","role":"plain"},{"text":"<ruby>偉<rt>えら</rt></ruby><b>ぶる</b>から","role":"plain"},{"text":"<ruby>嫌<rt>きら</rt></ruby>われる。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Er macht sich schnell wichtig, darum mag man ihn nicht.«","ex":{"jp":"<ruby>彼<rt>かれ</rt></ruby>は すぐ <ruby>偉<rt>えら</rt></ruby><b>ぶる</b>から <ruby>嫌<rt>きら</rt></ruby>われる。","de":"Er macht sich schnell wichtig, darum mag man ihn nicht."},"simpel":"»Sich vornehm geben bringt nichts.«<br><span class='jp'><ruby>上品<rt>じょうひん</rt></ruby><b>ぶって</b>も しょうがない</span><br>📖 Buch-Satz: 「<ruby>上品<rt>じょうひん</rt></ruby>ぶってもしょうがない」","rule":"な-Adj-Stamm / Nomen + ぶる: so tun, als sei man …; sich … geben (abwertend) — <ruby>上品<rt>じょうひん</rt></ruby>ぶる (sich vornehm geben), <ruby>偉<rt>えら</rt></ruby>ぶる (sich wichtig machen). Oft mit てもしょうがない (»bringt nichts«)."},{"l":40,"t":"86 · 〜に<ruby>限<rt>かぎ</rt></ruby>って","de":"ausgerechnet … / gerade … (oft ironisch)","slots":[{"text":"うちの","role":"plain"},{"text":"<ruby>子<rt>こ</rt></ruby><b>に<ruby>限<rt>かぎ</rt></ruby>って</b>、うそを","role":"plain"},{"text":"つく","role":"plain"},{"text":"はずがない。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Gerade mein Kind würde niemals lügen.«","ex":{"jp":"<ruby>急<rt>いそ</rt></ruby>いでいる <ruby>時<rt>とき</rt></ruby><b>に<ruby>限<rt>かぎ</rt></ruby>って</b>、バスが <ruby>来<rt>こ</rt></ruby>ない。","de":"Ausgerechnet wenn man es eilig hat, kommt kein Bus."},"simpel":"»Ausgerechnet Anfänger (übertreiben) …«<br><span class='jp'><ruby>初心者<rt>しょしんしゃ</rt></ruby><b>に<ruby>限<rt>かぎ</rt></ruby>って</b></span><br>📖 Buch-Satz: 「<ruby>初心者<rt>しょしんしゃ</rt></ruby>に<ruby>限<rt>かぎ</rt></ruby>って」","rule":"N + に限って: (1) »ausgerechnet N« — gerade in diesem Fall passiert etwas (oft ärgerlich); (2) »gerade N (würde nie) …« — Vertrauen in N, verneinter Nachsatz. Aus dem Kontext klar."},{"l":40,"t":"87 · 〜ことだ","de":"man sollte … / das Beste ist, zu … (Rat)","slots":[{"text":"<ruby>疲<rt>つか</rt></ruby>れた","role":"plain"},{"text":"<ruby>時<rt>とき</rt></ruby>は","role":"plain"},{"text":"<ruby>無理<rt>むり</rt></ruby>を","role":"plain"},{"text":"しない<b>ことだ</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wenn du müde bist, solltest du dich lieber nicht übernehmen.«","ex":{"jp":"<ruby>上手<rt>じょうず</rt></ruby>に なりたければ、<ruby>毎日<rt>まいにち</rt></ruby> <ruby>練習<rt>れんしゅう</rt></ruby>する<b>ことだ</b>。","de":"Wenn du besser werden willst, solltest du jeden Tag üben."},"simpel":"Rat geben: »Am besten isst du einfach weiter.«<br><span class='jp'><ruby>食<rt>た</rt></ruby>べ<ruby>続<rt>つづ</rt></ruby>ける<b>ことだ</b>よ</span><br>📖 Buch-Satz: 「<ruby>食<rt>た</rt></ruby>べ<ruby>続<rt>つづ</rt></ruby>けることだよ」","rule":"Grundform / ない-Form + ことだ: nachdrücklicher Rat/Ermahnung — »du solltest …; das Beste ist, zu …«. Verneint: 〜ないことだ (»tu lieber nicht«)."},{"l":40,"t":"88 · 〜という〜（すべて）","de":"jedes einzelne … / restlos alle … (Wiederholung)","slots":[{"text":"<ruby>窓<rt>まど</rt></ruby><b>という</b><ruby>窓<rt>まど</rt></ruby>を","role":"plain"},{"text":"<ruby>全部<rt>ぜんぶ</rt></ruby>","role":"plain"},{"text":"<ruby>閉<rt>し</rt></ruby>めた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich habe restlos jedes Fenster geschlossen.«","ex":{"jp":"<ruby>窓<rt>まど</rt></ruby><b>という</b><ruby>窓<rt>まど</rt></ruby>を <ruby>全部<rt>ぜんぶ</rt></ruby> <ruby>閉<rt>し</rt></ruby>めた。","de":"Ich habe restlos jedes Fenster geschlossen."},"simpel":"Alles ausnahmslos: »Jedes einzelne All-you-can-eat …«<br><span class='jp'><ruby>食<rt>た</rt></ruby>べ<ruby>放題<rt>ほうだい</rt></ruby><b>という</b><ruby>食<rt>た</rt></ruby>べ<ruby>放題<rt>ほうだい</rt></ruby></span><br>📖 Buch-Satz: 「<ruby>食<rt>た</rt></ruby>べ<ruby>放題<rt>ほうだい</rt></ruby>という<ruby>食<rt>た</rt></ruby>べ<ruby>放題<rt>ほうだい</rt></ruby>」","rule":"N + という + (dasselbe) N: betont Vollständigkeit — »jedes einzelne N, restlos alle N«. Das Nomen wird wiederholt; oft mit 全部/みんな im Nachsatz."},{"l":40,"t":"89 · 〜ところだった","de":"beinahe wäre … (passiert) / fast hätte ich …","slots":[{"text":"あぶなく","role":"plain"},{"text":"<ruby>電車<rt>でんしゃ</rt></ruby>に","role":"plain"},{"text":"<ruby>乗<rt>の</rt></ruby>り<ruby>遅<rt>おく</rt></ruby>れる<b>ところだった</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Fast hätte ich den Zug verpasst.«","ex":{"jp":"あぶなく <ruby>電車<rt>でんしゃ</rt></ruby>に <ruby>乗<rt>の</rt></ruby>り<ruby>遅<rt>おく</rt></ruby>れる<b>ところだった</b>。","de":"Fast hätte ich den Zug verpasst."},"simpel":"Knapp entkommen: »Fast hätte ich Strafe zahlen müssen.«<br><span class='jp'><ruby>罰金<rt>ばっきん</rt></ruby>を <ruby>払<rt>はら</rt></ruby>わされる<b>ところだった</b></span><br>📖 Buch-Satz: 「<ruby>罰金<rt>ばっきん</rt></ruby>を<ruby>払<rt>はら</rt></ruby>わされるところだった」","rule":"Grundform + ところだった: etwas Schlimmes wäre beinahe passiert, ist aber gerade nicht eingetreten — »fast wäre …«. Oft mit あぶなく/もう<ruby>少<rt>すこ</rt></ruby>しで. (Hier zusätzlich lassen-Passiv 払わされる = »zum Zahlen gezwungen werden«.)"},{"l":40,"t":"90 · 〜くらいなら","de":"wenn schon …, dann lieber … / eher als zu …","slots":[{"text":"<ruby>行列<rt>ぎょうれつ</rt></ruby>に","role":"plain"},{"text":"<ruby>並<rt>なら</rt></ruby>ぶ<b>くらいなら</b>、<ruby>食<rt>た</rt></ruby>べない","role":"plain"},{"text":"<ruby>方<rt>ほう</rt></ruby>が","role":"plain"},{"text":"ましだ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Bevor ich mich in die Schlange stelle, esse ich lieber gar nicht.«","ex":{"jp":"<ruby>行列<rt>ぎょうれつ</rt></ruby>に <ruby>並<rt>なら</rt></ruby>ぶ<b>くらいなら</b>、<ruby>食<rt>た</rt></ruby>べない <ruby>方<rt>ほう</rt></ruby>が ましだ。","de":"Bevor ich mich in die Schlange stelle, esse ich lieber gar nicht."},"simpel":"»Bevor ich Strafe zahle, dann lieber …«<br><span class='jp'><ruby>罰金<rt>ばっきん</rt></ruby> <ruby>払<rt>はら</rt></ruby>う<b>くらいなら</b></span><br>📖 Buch-Satz: 「<ruby>罰金<rt>ばっきん</rt></ruby><ruby>払<rt>はら</rt></ruby>うくらいなら」","rule":"Grundform + くらいなら: nennt eine unerwünschte Option A und stellt eine lieber gewählte B dagegen — »wenn (schon) A, dann lieber B«. B ist oft extrem, Nachsatz mit ほうがましだ／方がいい."},{"l":40,"t":"91 · 〜<ruby>方<rt>ほう</rt></ruby>がましだ","de":"da ist … noch besser / das kleinere Übel","slots":[{"text":"まずい","role":"plain"},{"text":"<ruby>店<rt>みせ</rt></ruby>に","role":"plain"},{"text":"<ruby>行<rt>い</rt></ruby>く","role":"plain"},{"text":"くらいなら、<ruby>行<rt>い</rt></ruby>かない<b><ruby>方<rt>ほう</rt></ruby>がましだ</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Bevor ich in ein schlechtes Lokal gehe, gehe ich lieber gar nicht.«","ex":{"jp":"<ruby>何<rt>なに</rt></ruby>も しないより、やってみた<b><ruby>方<rt>ほう</rt></ruby>がましだ</b>。","de":"Als gar nichts zu tun, ist es besser, es zu versuchen."},"simpel":"Kleineres Übel: »Sich anzustrengen ist noch viel besser.«<br><span class='jp'>がんばった<b><ruby>方<rt>ほう</rt></ruby>がずっとましだ</b></span><br>📖 Buch-Satz: 「がんばった<ruby>方<rt>ほう</rt></ruby>がずっとましだ」","rule":"た-Form / ない-Form + 方がましだ: von zwei schlechten Optionen ist diese die weniger schlimme — »das ist (immerhin) noch besser«. ましだ = »besser als nichts«, nicht »gut«. Oft mit ずっと."},{"l":41,"t":"92 · 〜ものがある","de":"da ist wirklich was dran / etwas … an sich (man spürt es)","slots":[{"text":"<ruby>彼<rt>かれ</rt></ruby>の","role":"plain"},{"text":"<ruby>言葉<rt>ことば</rt></ruby>には","role":"plain"},{"text":"<ruby>人<rt>ひと</rt></ruby>を","role":"plain"},{"text":"<ruby>動<rt>うご</rt></ruby>かす<b>ものがある</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Seine Worte haben etwas Bewegendes.«","ex":{"jp":"<ruby>満員<rt>まんいん</rt></ruby><ruby>電車<rt>でんしゃ</rt></ruby>の <ruby>通勤<rt>つうきん</rt></ruby>は つらい<b>ものがある</b>。","de":"Das Pendeln in der überfüllten Bahn hat wirklich etwas Zermürbendes."},"simpel":"😮 <b>»Da ist echt was dran«:</b> man <b>spürt</b> deutlich eine Seite einer <b>Sache</b> (nie direkt einer Person).<br><span class=\"jp\"><ruby>満員<rt>まんいん</rt></ruby><ruby>電車<rt>でんしゃ</rt></ruby>は つらい<b>ものがある</b></span> = »Das Pendeln in der vollen Bahn hat wirklich was Zermürbendes.«<br>📖 Buch-Satz: 「つらいものがある」","rule":"einfache Form (oft い/な-Adjektiv) + ものがある: man spürt eine Eigenschaft/Wirkung nachdrücklich — »da ist wirklich etwas …«. Gefühlte Wertung.<br>⚠ Über <b>Sachen, Werke, Situationen</b> — nicht direkt über eine Person."},{"l":41,"t":"93 · 〜まい","de":"wird wohl nicht … / bestimmt kein … (auch: will nicht …)","slots":[{"text":"<ruby>都会<rt>とかい</rt></ruby>で","role":"plain"},{"text":"<ruby>満員<rt>まんいん</rt></ruby><ruby>電車<rt>でんしゃ</rt></ruby>を","role":"plain"},{"text":"<ruby>知<rt>し</rt></ruby>らない","role":"plain"},{"text":"<ruby>人<rt>ひと</rt></ruby>は","role":"plain"},{"text":"いる<b>まい</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Es wird wohl niemanden in der Stadt geben, der die volle Bahn nicht kennt.«","ex":{"jp":"こんな <ruby>失敗<rt>しっぱい</rt></ruby>は <ruby>二度<rt>にど</rt></ruby>と する<b>まい</b>。","de":"So einen Fehler werde ich nie wieder machen."},"simpel":"»Es wird wohl niemanden geben, der …«<br><span class='jp'>いる<b>まい</b></span><br>📖 Buch-Satz: 「ストレスを<ruby>感<rt>かん</rt></ruby>じない<ruby>人<rt>ひと</rt></ruby>はいるまい」","rule":"Verb + まい (schriftlich/gehoben): (1) negative Vermutung »wird wohl nicht …/gibt es sicher nicht«; (2) negativer Wille »ich werde niemals …«. Anschluss meist Grundform (する→すまい／するまい)."},{"l":41,"t":"94 · 〜につけ","de":"jedes Mal, wenn … / immer wenn (Gefühl kommt auf)","slots":[{"text":"<ruby>満員<rt>まんいん</rt></ruby><ruby>電車<rt>でんしゃ</rt></ruby>に","role":"plain"},{"text":"<ruby>乗<rt>の</rt></ruby>る<b>につけ</b>、<ruby>田舎<rt>いなか</rt></ruby>の","role":"plain"},{"text":"<ruby>生活<rt>せいかつ</rt></ruby>が","role":"plain"},{"text":"<ruby>恋<rt>こい</rt></ruby>しく","role":"plain"},{"text":"なる。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Jedes Mal in der vollen Bahn sehne ich mich nach dem Landleben.«","ex":{"jp":"この <ruby>歌<rt>うた</rt></ruby>を <ruby>聞<rt>き</rt></ruby>く<b>につけ</b>、<ruby>故郷<rt>こきょう</rt></ruby>を <ruby>思<rt>おも</rt></ruby>い<ruby>出<rt>だ</rt></ruby>す。","de":"Immer wenn ich dieses Lied höre, denke ich an meine Heimat."},"simpel":"»Jedes Mal, wenn ich die Fahrgäste sehe …«<br><span class='jp'><ruby>乗客<rt>じょうきゃく</rt></ruby>を <ruby>見<rt>み</rt></ruby>る<b>につけ</b></span><br>📖 Buch-Satz: 「<ruby>乗客<rt>じょうきゃく</rt></ruby>を<ruby>見<rt>み</rt></ruby>るにつけ」","rule":"Grundform + につけ: »immer wenn …, kommt (unwillkürlich) ein Gefühl/Gedanke auf«. Nachsatz nennt ein Gefühl (思い出す, 感じる …). Auch Paar 〜につけ〜につけ (»ob … oder …«)."},{"l":41,"t":"95 · 〜わりに（は）","de":"verhältnismäßig / trotz … (anders als erwartet)","slots":[{"text":"この","role":"plain"},{"text":"<ruby>店<rt>みせ</rt></ruby>は","role":"plain"},{"text":"<ruby>安<rt>やす</rt></ruby>い<b>わりに</b>","role":"plain"},{"text":"おいしい。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Das Lokal ist für den günstigen Preis überraschend gut.«","ex":{"jp":"この <ruby>店<rt>みせ</rt></ruby>は <ruby>安<rt>やす</rt></ruby>い<b>わりに</b> おいしい。","de":"Das Lokal ist für den günstigen Preis überraschend gut."},"simpel":"»Trotz des Gedränges (überraschend ruhig).«<br><span class='jp'><ruby>混<rt>こ</rt></ruby>んでいる<b>わりには</b></span><br>📖 Buch-Satz: 「<ruby>混<rt>こ</rt></ruby>んでいるわりには」","rule":"einfache Form (な-Adj な, N の) + わりに(は): das Ergebnis passt nicht zum Erwartbaren — »gemessen an …, überraschend …«. Neutral, oft positiv-erstaunt."},{"l":41,"t":"96 · 〜か〜ないかのうちに","de":"kaum … , da schon … / in dem Moment, als …","slots":[{"text":"ベルが","role":"plain"},{"text":"<ruby>鳴<rt>な</rt></ruby>る<b>か</b>","role":"plain"},{"text":"<ruby>鳴<rt>な</rt></ruby>らない<b>かのうちに</b>、<ruby>子供<rt>こども</rt></ruby>たちは","role":"plain"},{"text":"<ruby>教室<rt>きょうしつ</rt></ruby>を","role":"plain"},{"text":"<ruby>飛<rt>と</rt></ruby>び<ruby>出<rt>だ</rt></ruby>した。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Kaum hatte es geklingelt, stürmten die Kinder aus dem Klassenzimmer.«","ex":{"jp":"ベルが <ruby>鳴<rt>な</rt></ruby>る<b>か</b> <ruby>鳴<rt>な</rt></ruby>らない<b>かのうちに</b>、<ruby>子供<rt>こども</rt></ruby>たちは <ruby>教室<rt>きょうしつ</rt></ruby>を <ruby>飛<rt>と</rt></ruby>び<ruby>出<rt>だ</rt></ruby>した。","de":"Kaum hatte es geklingelt, stürmten die Kinder aus dem Klassenzimmer."},"simpel":"Sofort danach: »Kaum aufgestanden, schon …«<br><span class='jp'><ruby>立<rt>た</rt></ruby>つか <ruby>立<rt>た</rt></ruby>たないか<b>のうちに</b></span><br>📖 Buch-Satz: 「<ruby>立<rt>た</rt></ruby>つか<ruby>立<rt>た</rt></ruby>たないかのうちに」","rule":"Grundform + か + ない-Form + か + のうちに: zwei Ereignisse fast gleichzeitig — »kaum war A, da schon B«. A ist gerade erst (fast) geschehen, B folgt sofort. Schriftlich-erzählend."},{"l":41,"t":"97 · 〜げ","de":"wirkt … / sieht … aus (sichtbarer Anschein)","slots":[{"text":"<ruby>老人<rt>ろうじん</rt></ruby>は","role":"plain"},{"text":"<ruby>寂<rt>さび</rt></ruby>し<b>げ</b>に","role":"plain"},{"text":"<ruby>窓<rt>まど</rt></ruby>の","role":"plain"},{"text":"<ruby>外<rt>そと</rt></ruby>を","role":"plain"},{"text":"<ruby>見<rt>み</rt></ruby>ていた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Der alte Mann blickte einsam aus dem Fenster.«","ex":{"jp":"<ruby>子供<rt>こども</rt></ruby>たちは <ruby>楽<rt>たの</rt></ruby>し<b>げ</b>に <ruby>遊<rt>あそ</rt></ruby>んでいる。","de":"Die Kinder spielen vergnügt."},"simpel":"»Sie plaudern vergnügt (wirken fröhlich).«<br><span class='jp'><ruby>楽<rt>たの</rt></ruby>し<b>げ</b>に おしゃべりしている</span><br>📖 Buch-Satz: 「<ruby>楽<rt>たの</rt></ruby>しげにおしゃべりしている」","rule":"い-Adj-Stamm (〜い weg) / な-Adj-Stamm + げ: »sieht … aus, wirkt …« — ein von außen sichtbarer Anschein. <ruby>楽<rt>たの</rt></ruby>しげ, <ruby>寂<rt>さび</rt></ruby>しげ, <ruby>不安<rt>ふあん</rt></ruby>げ. Wird wie ein な-Adjektiv benutzt (げな/げに)."},{"l":41,"t":"98 · 〜やら〜やら","de":"teils … teils … / ein Durcheinander aus … und …","slots":[{"text":"<ruby>合格<rt>ごうかく</rt></ruby>して、うれしい<b>やら</b>","role":"plain"},{"text":"ほっとする<b>やら</b>で","role":"plain"},{"text":"<ruby>涙<rt>なみだ</rt></ruby>が","role":"plain"},{"text":"<ruby>出<rt>で</rt></ruby>た。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich habe bestanden — halb Freude, halb Erleichterung, mir kamen die Tränen.«","ex":{"jp":"<ruby>合格<rt>ごうかく</rt></ruby>して、うれしい<b>やら</b> ほっとする<b>やら</b>で <ruby>涙<rt>なみだ</rt></ruby>が <ruby>出<rt>で</rt></ruby>た。","de":"Ich habe bestanden — halb Freude, halb Erleichterung, mir kamen die Tränen."},"simpel":"Gemischte Gefühle: »teils ärgerlich, teils neidisch«.<br><span class='jp'>くやしい<b>やら</b> うらやましい<b>やら</b></span><br>📖 Buch-Satz: 「くやしいやらうらやましいやら」","rule":"A やら B やら: zählt zwei (repräsentative) Dinge/Gefühle auf, die ungeordnet zusammenkommen — »teils A, teils B; was mit A und B alles«. Anschluss: einfache Form/Nomen."},{"l":41,"t":"99 · 〜（た）かと<ruby>思<rt>おも</rt></ruby>うと","de":"kaum … , schon … / kaum dass ich dachte …","slots":[{"text":"<ruby>乗客<rt>じょうきゃく</rt></ruby>が","role":"plain"},{"text":"<ruby>降<rt>お</rt></ruby>りた<b>かと<ruby>思<rt>おも</rt></ruby>うと</b>、<ruby>次<rt>つぎ</rt></ruby>の","role":"plain"},{"text":"<ruby>人<rt>ひと</rt></ruby>が","role":"plain"},{"text":"どっと","role":"plain"},{"text":"<ruby>乗<rt>の</rt></ruby>って","role":"plain"},{"text":"きた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Kaum waren die Fahrgäste ausgestiegen, drängten schon die nächsten hinein.«","ex":{"jp":"<ruby>赤<rt>あか</rt></ruby>ちゃんが <ruby>泣<rt>な</rt></ruby>いた<b>かと<ruby>思<rt>おも</rt></ruby>うと</b>、すぐ <ruby>笑<rt>わら</rt></ruby>い <ruby>出<rt>だ</rt></ruby>した。","de":"Kaum hatte das Baby geweint, lachte es schon wieder."},"simpel":"Sofortiger Wechsel: »Kaum ausgestiegen, schon steigen neue ein.«<br><span class='jp'><ruby>降<rt>お</rt></ruby>りた<b>かと<ruby>思<rt>おも</rt></ruby>うと</b></span><br>📖 Buch-Satz: 「<ruby>乗客<rt>じょうきゃく</rt></ruby>が<ruby>降<rt>お</rt></ruby>りたかと<ruby>思<rt>おも</rt></ruby>うと」","rule":"た-Form + かと思うと（かと思ったら）: kaum ist A geschehen, folgt (überraschend) sofort B — »kaum …, schon …«. B ist oft unerwartet/gegensätzlich. Nicht für eigene, geplante Handlungen."},{"l":42,"t":"100 · 〜にほかならない","de":"nichts anderes als / genau das ist …","slots":[{"text":"<ruby>今<rt>いま</rt></ruby>の","role":"plain"},{"text":"ラーメンは","role":"plain"},{"text":"<ruby>日本<rt>にほん</rt></ruby>で","role":"plain"},{"text":"<ruby>生<rt>う</rt></ruby>まれた","role":"plain"},{"text":"<ruby>料理<rt>りょうり</rt></ruby><b>にほかならない</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Der heutige Ramen ist nichts anderes als ein in Japan entstandenes Gericht.«","ex":{"jp":"<ruby>今<rt>いま</rt></ruby>の ラーメンは <ruby>日本<rt>にほん</rt></ruby>で <ruby>生<rt>う</rt></ruby>まれた <ruby>料理<rt>りょうり</rt></ruby><b>にほかならない</b>。","de":"Der heutige Ramen ist nichts anderes als ein in Japan entstandenes Gericht."},"simpel":"»Ramen ist nichts anderes als japanische Küche.«<br><span class='jp'><ruby>日本<rt>にほん</rt></ruby><ruby>料理<rt>りょうり</rt></ruby><b>にほかならない</b></span><br>📖 Buch-Satz: 「<ruby>日本<rt>にほん</rt></ruby><ruby>料理<rt>りょうり</rt></ruby>にほかならない」","rule":"N + にほかならない: nachdrückliche Gleichsetzung — »es ist genau/nichts anderes als N«. Schriftlich-nachdrücklich, oft in Erklärungen. Grund: 〜からにほかならない (»eben weil …«)."},{"l":42,"t":"101 · 〜にすぎない","de":"nichts weiter als / bloß / nur","slots":[{"text":"<ruby>昔<rt>むかし</rt></ruby>の","role":"plain"},{"text":"ラーメンは","role":"plain"},{"text":"<ruby>空腹<rt>くうふく</rt></ruby>を","role":"plain"},{"text":"<ruby>満<rt>み</rt></ruby>たす","role":"plain"},{"text":"<ruby>食<rt>た</rt></ruby>べ<ruby>物<rt>もの</rt></ruby><b>にすぎなかった</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Früher war Ramen bloß eine Speise, um satt zu werden.«","ex":{"jp":"<ruby>昔<rt>むかし</rt></ruby>の ラーメンは <ruby>空腹<rt>くうふく</rt></ruby>を <ruby>満<rt>み</rt></ruby>たす <ruby>食<rt>た</rt></ruby>べ<ruby>物<rt>もの</rt></ruby><b>にすぎなかった</b>。","de":"Früher war Ramen bloß eine Speise, um satt zu werden."},"simpel":"»Es war bloß etwas, um den Hunger zu stillen.«<br><span class='jp'><ruby>空腹<rt>くうふく</rt></ruby>を <ruby>満<rt>み</rt></ruby>たすもの<b>にすぎなかった</b></span><br>📖 Buch-Satz: 「<ruby>空腹<rt>くうふく</rt></ruby>を<ruby>満<rt>み</rt></ruby>たすものにすぎなかった」","rule":"N / einfache Form + にすぎない: setzt etwas herab — »ist nur/bloß …, nicht mehr«. Oft mit ただの／単なる (bloß). Vergangenheit: にすぎなかった."},{"l":42,"t":"102 · 〜<ruby>上<rt>うえ</rt></ruby>に","de":"obendrein / zusätzlich zu … (noch dazu)","slots":[{"text":"<ruby>道<rt>みち</rt></ruby>に","role":"plain"},{"text":"<ruby>迷<rt>まよ</rt></ruby>った<b><ruby>上<rt>うえ</rt></ruby>に</b>、<ruby>雨<rt>あめ</rt></ruby>まで","role":"plain"},{"text":"<ruby>降<rt>ふ</rt></ruby>って","role":"plain"},{"text":"きた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich habe mich verlaufen und obendrein fing es auch noch an zu regnen.«","ex":{"jp":"この <ruby>店<rt>みせ</rt></ruby>は <ruby>安<rt>やす</rt></ruby>い<b><ruby>上<rt>うえ</rt></ruby>に</b>、おいしい。","de":"Dieses Lokal ist billig und obendrein lecker."},"simpel":"Noch dazu: »Man kann kreativ sein, und obendrein …«<br><span class='jp'><ruby>工夫<rt>くふう</rt></ruby>ができる<b><ruby>上<rt>うえ</rt></ruby>に</b></span><br>📖 Buch-Satz: 「<ruby>工夫<rt>くふう</rt></ruby>ができる<ruby>上<rt>うえ</rt></ruby>に」","rule":"einfache Form (な-Adj な, N の) + 上に: fügt zum Ersten etwas Gleichgerichtetes hinzu — »obendrein, noch dazu«. Beide Teile gleich gewertet (beide gut ODER beide schlecht). Lesung うえ."},{"l":42,"t":"103 · 〜といっても","de":"auch wenn man … sagt / auch wenn es … heißt (in Wahrheit)","slots":[{"text":"ラーメン<b>といっても</b>、<ruby>味<rt>あじ</rt></ruby>は","role":"plain"},{"text":"<ruby>店<rt>みせ</rt></ruby>ごとに","role":"plain"},{"text":"<ruby>全然<rt>ぜんぜん</rt></ruby>","role":"plain"},{"text":"<ruby>違<rt>ちが</rt></ruby>う。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Auch wenn man Ramen sagt, ist der Geschmack je nach Lokal ganz verschieden.«","ex":{"jp":"ラーメン<b>といっても</b>、<ruby>味<rt>あじ</rt></ruby>は <ruby>店<rt>みせ</rt></ruby>ごとに <ruby>全然<rt>ぜんぜん</rt></ruby> <ruby>違<rt>ちが</rt></ruby>う。","de":"Auch wenn man Ramen sagt, ist der Geschmack je nach Lokal ganz verschieden."},"simpel":"Einschränkung: »Auch wenn man Ramen sagt (es gibt viele Arten).«<br><span class='jp'>ラーメン<b>といっても</b></span><br>📖 Buch-Satz: 「ラーメンといっても」","rule":"einfache Form / N + といっても: relativiert einen Begriff — »auch wenn man … sagt, in Wirklichkeit …«. Der Nachsatz korrigiert die naheliegende Erwartung."},{"l":42,"t":"104 · 〜に<ruby>限<rt>かぎ</rt></ruby>る","de":"nichts geht über … / am besten ist …","slots":[{"text":"<ruby>疲<rt>つか</rt></ruby>れた","role":"plain"},{"text":"<ruby>時<rt>とき</rt></ruby>は","role":"plain"},{"text":"<ruby>早<rt>はや</rt></ruby>く","role":"plain"},{"text":"<ruby>寝<rt>ね</rt></ruby>る<b>に<ruby>限<rt>かぎ</rt></ruby>る</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wenn man müde ist, geht man am besten früh schlafen.«","ex":{"jp":"<ruby>夏<rt>なつ</rt></ruby>は <ruby>冷<rt>つめ</rt></ruby>たい ビール<b>に<ruby>限<rt>かぎ</rt></ruby>る</b>。","de":"Im Sommer geht nichts über ein kaltes Bier."},"simpel":"Persönliche Vorliebe: »Bei Ramen geht nichts über Sojasoße.«<br><span class='jp'>ラーメンは しょうゆ<b>に<ruby>限<rt>かぎ</rt></ruby>る</b></span><br>📖 Buch-Satz: 「ラーメンはしょうゆに<ruby>限<rt>かぎ</rt></ruby>る」","rule":"N / Grundform / ない-Form + に限る: nachdrückliche Empfehlung/Vorliebe — »nichts geht über …, am besten …«. Subjektive Wertung des Sprechers."},{"l":42,"t":"105 · 〜だけあって","de":"wie erwartet von … / gerade weil … (verdient)","slots":[{"text":"<ruby>人気<rt>にんき</rt></ruby><ruby>店<rt>てん</rt></ruby><b>だけあって</b>、いつも","role":"plain"},{"text":"<ruby>行列<rt>ぎょうれつ</rt></ruby>が","role":"plain"},{"text":"できている。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wie man es von einem beliebten Lokal erwartet, bildet sich immer eine Schlange.«","ex":{"jp":"<ruby>人気<rt>にんき</rt></ruby><ruby>店<rt>てん</rt></ruby><b>だけあって</b>、いつも <ruby>行列<rt>ぎょうれつ</rt></ruby>が できている。","de":"Wie man es von einem beliebten Lokal erwartet, bildet sich immer eine Schlange."},"simpel":"Verdiente Folge: »Wie man es von einem beliebten Lokal erwartet …«<br><span class='jp'><ruby>人気<rt>にんき</rt></ruby><ruby>店<rt>てん</rt></ruby><b>だけあって</b></span><br>📖 Buch-Satz: 「<ruby>人気<rt>にんき</rt></ruby><ruby>店<rt>てん</rt></ruby>だけあって」","rule":"N / einfache Form + だけあって: das (positive) Ergebnis passt zum Ruf/zur Anstrengung — »wie erwartet von …, gerade weil …«. Anerkennend; das Ergebnis ist verdient."},{"l":42,"t":"106 · 〜にしろ〜にしろ","de":"ob … oder … / sei es … oder …","slots":[{"text":"スープ<b>にしろ</b>","role":"plain"},{"text":"<ruby>具<rt>ぐ</rt></ruby><b>にしろ</b>、この","role":"plain"},{"text":"<ruby>店<rt>みせ</rt></ruby>は","role":"plain"},{"text":"こだわっている。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ob Suppe oder Einlage — dieses Lokal legt auf alles Wert.«","ex":{"jp":"<ruby>行<rt>い</rt></ruby>く<b>にしろ</b> <ruby>行<rt>い</rt></ruby>かない<b>にしろ</b>、<ruby>連絡<rt>れんらく</rt></ruby>は してください。","de":"Ob du gehst oder nicht, gib bitte Bescheid."},"simpel":"Beides gilt: »ob Suppe oder Einlage …«<br><span class='jp'>スープ<b>にしろ</b> <ruby>具<rt>ぐ</rt></ruby><b>にしろ</b></span><br>📖 Buch-Satz: 「スープにしろ<ruby>具<rt>ぐ</rt></ruby>にしろ」","rule":"A にしろ B にしろ（にせよ）: nennt zwei (Gegensatz-)Fälle, für die dasselbe gilt — »ob A oder B, in jedem Fall …«. Einfache Form/Nomen. にせよ ist die etwas förmlichere Variante."},{"l":43,"t":"107 · 〜とか","de":"angeblich … / ich hab gehört, dass … (unsicheres Hörensagen)","slots":[{"text":"<ruby>来月<rt>らいげつ</rt></ruby>","role":"plain"},{"text":"<ruby>新<rt>あたら</rt></ruby>しい","role":"plain"},{"text":"<ruby>靴<rt>くつ</rt></ruby>が","role":"plain"},{"text":"<ruby>発売<rt>はつばい</rt></ruby>される<b>とか</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Nächsten Monat sollen angeblich neue Schuhe rauskommen.«","ex":{"jp":"<ruby>来月<rt>らいげつ</rt></ruby> <ruby>新<rt>あたら</rt></ruby>しい <ruby>靴<rt>くつ</rt></ruby>が <ruby>発売<rt>はつばい</rt></ruby>される<b>とか</b>。","de":"Nächsten Monat sollen angeblich neue Schuhe rauskommen."},"simpel":"Vage Info: »Es soll wohl auf den Markt kommen.«<br><span class='jp'><ruby>発売<rt>はつばい</rt></ruby>される<b>とか</b></span><br>📖 Buch-Satz: 「<ruby>発売<rt>はつばい</rt></ruby>されるとか」","rule":"einfache Form + とか (am Satzende): unsicheres Hörensagen — »angeblich …, ich hab (vage) gehört, dass …«. Weniger sicher als そうだ. Gesprochen."},{"l":43,"t":"108 · 〜に<ruby>沿<rt>そ</rt></ruby>って","de":"entlang … / gemäß … (einer Linie/Vorgabe folgen)","slots":[{"text":"<ruby>会社<rt>かいしゃ</rt></ruby>の","role":"plain"},{"text":"<ruby>方針<rt>ほうしん</rt></ruby><b>に<ruby>沿<rt>そ</rt></ruby>った</b>","role":"plain"},{"text":"<ruby>計画<rt>けいかく</rt></ruby>を","role":"plain"},{"text":"<ruby>立<rt>た</rt></ruby>てる。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wir erstellen einen Plan gemäß der Firmenlinie.«","ex":{"jp":"<ruby>川<rt>かわ</rt></ruby><b>に<ruby>沿<rt>そ</rt></ruby>って</b> <ruby>桜<rt>さくら</rt></ruby>が <ruby>咲<rt>さ</rt></ruby>いている。","de":"Am Fluss entlang blühen Kirschbäume."},"simpel":"Einer Vorgabe folgen: »dem Trend der Branche folgend«.<br><span class='jp'><ruby>業界<rt>ぎょうかい</rt></ruby>の <ruby>流<rt>なが</rt></ruby>れ<b>に<ruby>沿<rt>そ</rt></ruby>って</b></span><br>📖 Buch-Satz: 「<ruby>業界<rt>ぎょうかい</rt></ruby>の<ruby>流<rt>なが</rt></ruby>れに<ruby>沿<rt>そ</rt></ruby>って」","rule":"N + に沿って: (1) räumlich »entlang N« (川に沿って); (2) »gemäß N« — einer Linie, Vorgabe, einem Wunsch/Plan folgen (方針に沿って). Attributiv に沿った."},{"l":43,"t":"109 · 〜にかけては","de":"was … angeht (da ist niemand besser) / im … ist … spitze","slots":[{"text":"<ruby>歩<rt>ある</rt></ruby>きやすさ<b>にかけては</b>、この","role":"plain"},{"text":"<ruby>靴<rt>くつ</rt></ruby>に","role":"plain"},{"text":"<ruby>勝<rt>か</rt></ruby>てる","role":"plain"},{"text":"ものは","role":"plain"},{"text":"ない。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Was den Tragekomfort angeht, kommt an diese Schuhe nichts heran.«","ex":{"jp":"<ruby>足<rt>あし</rt></ruby>の <ruby>速<rt>はや</rt></ruby>さ<b>にかけては</b>、<ruby>誰<rt>だれ</rt></ruby>にも <ruby>負<rt>ま</rt></ruby>けない。","de":"Was Schnelligkeit angeht, ist mir keiner überlegen."},"simpel":"Stärke betonen: »Was Walking-Schuhe angeht …«<br><span class='jp'>ウォーキングシューズ<b>にかけては</b></span><br>📖 Buch-Satz: 「ウォーキングシューズにかけては」","rule":"N + にかけては: hebt ein Gebiet hervor, auf dem jemand herausragend ist — »was N angeht, ist … (unschlagbar)«. Nachsatz immer positiv (Können, Selbstvertrauen)."},{"l":43,"t":"110 · 〜ないことには","de":"ohne zu … (geht gar nichts) / solange nicht …","slots":[{"text":"<ruby>実際<rt>じっさい</rt></ruby>に","role":"plain"},{"text":"<ruby>試<rt>ため</rt></ruby>してみ<b>ないことには</b>、<ruby>良<rt>よ</rt></ruby>さは","role":"plain"},{"text":"<ruby>分<rt>わ</rt></ruby>からない。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ohne es auszuprobieren, kann man die Qualität nicht beurteilen.«","ex":{"jp":"<ruby>実際<rt>じっさい</rt></ruby>に <ruby>試<rt>ため</rt></ruby>してみ<b>ないことには</b>、<ruby>良<rt>よ</rt></ruby>さは <ruby>分<rt>わ</rt></ruby>からない。","de":"Ohne es auszuprobieren, kann man die Qualität nicht beurteilen."},"simpel":"Bedingung fürs Weiterkommen: »Ohne Entwicklung geht es nicht.«<br><span class='jp'><ruby>開発<rt>かいはつ</rt></ruby>し<b>ないことには</b></span><br>📖 Buch-Satz: 「<ruby>開発<rt>かいはつ</rt></ruby>しないことには」","rule":"ない-Form + ことには: »solange nicht A (geschieht), (kann B nicht) …«. Der Nachsatz ist immer verneint/negativ. A ist die unverzichtbare Voraussetzung."},{"l":43,"t":"111 · 〜がち","de":"neigt zu … / oft … (meist unerwünscht)","slots":[{"text":"<ruby>冬<rt>ふゆ</rt></ruby>は","role":"plain"},{"text":"<ruby>運動<rt>うんどう</rt></ruby>が","role":"plain"},{"text":"<ruby>不足<rt>ふそく</rt></ruby>し<b>がち</b>だ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Im Winter bewegt man sich oft zu wenig.«","ex":{"jp":"<ruby>冬<rt>ふゆ</rt></ruby>は <ruby>運動<rt>うんどう</rt></ruby>が <ruby>不足<rt>ふそく</rt></ruby>し<b>がち</b>だ。","de":"Im Winter bewegt man sich oft zu wenig."},"simpel":"Häufige Tendenz: »Man legt oft (zu) viel Wert auf …«<br><span class='jp'><ruby>重視<rt>じゅうし</rt></ruby>し<b>がち</b>です</span><br>📖 Buch-Satz: 「<ruby>歩<rt>ある</rt></ruby>きやすさを<ruby>重視<rt>じゅうし</rt></ruby>しがちです」","rule":"ます-Stamm / N + がち: etwas passiert häufig/leicht, meist unerwünscht — »neigt zu …, oft …«. <ruby>忘<rt>わす</rt></ruby>れがち, <ruby>病気<rt>びょうき</rt></ruby>がち, <ruby>遅<rt>おく</rt></ruby>れがち."},{"l":43,"t":"112 · 〜つつ（も）","de":"obwohl … / während doch … (Widerspruch zum Tun)","slots":[{"text":"<ruby>体<rt>からだ</rt></ruby>に","role":"plain"},{"text":"<ruby>悪<rt>わる</rt></ruby>いと","role":"plain"},{"text":"<ruby>知<rt>し</rt></ruby>り<b>つつも</b>、たばこを","role":"plain"},{"text":"やめられない。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Obwohl ich weiß, dass es ungesund ist, kann ich nicht mit dem Rauchen aufhören.«","ex":{"jp":"<ruby>体<rt>からだ</rt></ruby>に <ruby>悪<rt>わる</rt></ruby>いと <ruby>知<rt>し</rt></ruby>り<b>つつも</b>、たばこを やめられない。","de":"Obwohl ich weiß, dass es ungesund ist, kann ich nicht mit dem Rauchen aufhören."},"simpel":"Widerspruch: »Obwohl ich es (eigentlich) haben will …«<br><span class='jp'>ほしいと <ruby>思<rt>おも</rt></ruby>い<b>つつも</b></span><br>📖 Buch-Satz: 「ほしいと<ruby>思<rt>おも</rt></ruby>いつつも」","rule":"ます-Stamm + つつ（も）: (1) つつ = »während zugleich« (gleichzeitige Handlung, schriftlich); (2) つつも = »obwohl (man doch) …« — man tut B, obwohl man A denkt/weiß."},{"l":43,"t":"113 · 〜としたら","de":"angenommen, … / wenn man mal … (hypothetisch)","slots":[{"text":"<ruby>宝<rt>たから</rt></ruby>くじが","role":"plain"},{"text":"<ruby>当<rt>あ</rt></ruby>たった<b>としたら</b>、<ruby>何<rt>なに</rt></ruby>を","role":"plain"},{"text":"<ruby>買<rt>か</rt></ruby>いますか。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Angenommen, du gewinnst im Lotto — was würdest du kaufen?«","ex":{"jp":"<ruby>宝<rt>たから</rt></ruby>くじが <ruby>当<rt>あ</rt></ruby>たった<b>としたら</b>、<ruby>何<rt>なに</rt></ruby>を <ruby>買<rt>か</rt></ruby>いますか。","de":"Angenommen, du gewinnst im Lotto — was würdest du kaufen?"},"simpel":"Hypothese: »Angenommen, wir machen ein neues Produkt …«<br><span class='jp'><ruby>新商品<rt>しんしょうひん</rt></ruby>を <ruby>作<rt>つく</rt></ruby>る<b>としたら</b></span><br>📖 Buch-Satz: 「<ruby>新商品<rt>しんしょうひん</rt></ruby>を<ruby>作<rt>つく</rt></ruby>るとしたら」","rule":"einfache Form + としたら（とすれば／とすると）: stellt eine Annahme auf — »angenommen …, mal angenommen, wenn …«. Der Nachsatz überlegt die Folge/Wahl. Hypothetisch."},{"l":43,"t":"114 · 〜<ruby>次第<rt>しだい</rt></ruby>で","de":"je nach … / hängt ganz von … ab","slots":[{"text":"<ruby>売<rt>う</rt></ruby>れ<ruby>行<rt>ゆ</rt></ruby>きは","role":"plain"},{"text":"デザイン<b><ruby>次第<rt>しだい</rt></ruby>で</b>","role":"plain"},{"text":"<ruby>大<rt>おお</rt></ruby>きく","role":"plain"},{"text":"<ruby>変<rt>か</rt></ruby>わる。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Der Absatz ändert sich stark je nach Design.«","ex":{"jp":"<ruby>明日<rt>あした</rt></ruby>の <ruby>予定<rt>よてい</rt></ruby>は <ruby>天気<rt>てんき</rt></ruby><b><ruby>次第<rt>しだい</rt></ruby>だ</b>。","de":"Der Plan für morgen hängt vom Wetter ab."},"simpel":"Abhängigkeit: »Je nach Design (verkauft es sich).«<br><span class='jp'>デザイン<b><ruby>次第<rt>しだい</rt></ruby>で</b></span><br>📖 Buch-Satz: 「デザイン<ruby>次第<rt>しだい</rt></ruby>で」","rule":"N + 次第で／次第だ: das Ergebnis hängt ganz von N ab — »je nach N, kommt es auf N an«. 〜次第だ am Satzende: »das hängt von N ab«. (Anders als ます-Stamm + 次第 »sobald«, Punkt 36.)"},{"l":43,"t":"115 · 〜<ruby>一方<rt>いっぽう</rt></ruby>だ","de":"wird immer mehr … / nimmt stetig zu (nur in eine Richtung)","slots":[{"text":"<ruby>都会<rt>とかい</rt></ruby>の","role":"plain"},{"text":"<ruby>人口<rt>じんこう</rt></ruby>は","role":"plain"},{"text":"<ruby>増<rt>ふ</rt></ruby>える<b><ruby>一方<rt>いっぽう</rt></ruby>だ</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Die Bevölkerung der Städte nimmt immer weiter zu.«","ex":{"jp":"<ruby>物価<rt>ぶっか</rt></ruby>は <ruby>上<rt>あ</rt></ruby>がる<b><ruby>一方<rt>いっぽう</rt></ruby>だ</b>。","de":"Die Preise steigen immer weiter."},"simpel":"Einseitige Entwicklung: »Es wird immer nur härter.«<br><span class='jp'><ruby>厳<rt>きび</rt></ruby>しくなる<b><ruby>一方<rt>いっぽう</rt></ruby>です</b></span><br>📖 Buch-Satz: 「<ruby>厳<rt>きび</rt></ruby>しくなる<ruby>一方<rt>いっぽう</rt></ruby>です」","rule":"Grundform + 一方だ: eine Entwicklung geht stetig nur in eine (meist schlechte) Richtung — »wird immer mehr …«. ＋Plus: 〜ばかり (nur/immer nur) drückt Ähnliches aus."},{"l":43,"t":"116 · 〜に<ruby>先立<rt>さきだ</rt></ruby>って","de":"vor … / im Vorfeld von … (als Vorbereitung)","slots":[{"text":"<ruby>新製品<rt>しんせいひん</rt></ruby>の","role":"plain"},{"text":"<ruby>発売<rt>はつばい</rt></ruby><b>に<ruby>先立<rt>さきだ</rt></ruby>って</b>、<ruby>調査<rt>ちょうさ</rt></ruby>を","role":"plain"},{"text":"した。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Im Vorfeld der Produkteinführung führten wir eine Untersuchung durch.«","ex":{"jp":"<ruby>開店<rt>かいてん</rt></ruby><b>に<ruby>先立<rt>さきだ</rt></ruby>って</b>、<ruby>試食会<rt>ししょくかい</rt></ruby>を <ruby>行<rt>おこな</rt></ruby>った。","de":"Vor der Eröffnung veranstalteten wir eine Verkostung."},"simpel":"Vorbereitung davor: »Vor der Entwicklung (untersuchen wir …).«<br><span class='jp'><ruby>開発<rt>かいはつ</rt></ruby><b>に<ruby>先立<rt>さきだ</rt></ruby>って</b></span><br>📖 Buch-Satz: 「<ruby>開発<rt>かいはつ</rt></ruby>に<ruby>先立<rt>さきだ</rt></ruby>って」","rule":"N / Grundform + に先立って（に先立ち）: etwas geschieht als Vorbereitung VOR einem wichtigen Ereignis — »vor …, im Vorfeld von …«. Formell; für bedeutsame Anlässe. Attributiv に先立つ."},{"l":43,"t":"117 · 〜<ruby>上<rt>うえ</rt></ruby>で","de":"nach (erst) … / auf Grundlage von … (dann erst)","slots":[{"text":"<ruby>契約<rt>けいやく</rt></ruby>は","role":"plain"},{"text":"<ruby>内容<rt>ないよう</rt></ruby>を","role":"plain"},{"text":"<ruby>確認<rt>かくにん</rt></ruby>した<b><ruby>上<rt>うえ</rt></ruby>で</b>","role":"plain"},{"text":"サインしてください。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Unterschreiben Sie den Vertrag erst, nachdem Sie den Inhalt geprüft haben.«","ex":{"jp":"よく <ruby>考<rt>かんが</rt></ruby>えた<b><ruby>上<rt>うえ</rt></ruby>で</b>、<ruby>返事<rt>へんじ</rt></ruby>を します。","de":"Ich antworte, nachdem ich es gut überlegt habe."},"simpel":"Erst A, dann B: »Nach einer Marktstudie (entscheiden wir).«<br><span class='jp'><ruby>市場<rt>しじょう</rt></ruby><ruby>調査<rt>ちょうさ</rt></ruby>をした<b><ruby>上<rt>うえ</rt></ruby>で</b></span><br>📖 Buch-Satz: 「<ruby>市場<rt>しじょう</rt></ruby><ruby>調査<rt>ちょうさ</rt></ruby>をした<ruby>上<rt>うえ</rt></ruby>で」","rule":"た-Form / N の + 上で: »nachdem man erst A gemacht hat, (dann) B« — B baut bewusst auf A auf. Formell, für überlegte Schritte. Lesung うえ."},{"l":43,"t":"118 · 〜に<ruby>応<rt>こた</rt></ruby>えて","de":"als Antwort auf … / einem Wunsch/einer Erwartung entsprechend","slots":[{"text":"ファンの","role":"plain"},{"text":"<ruby>期待<rt>きたい</rt></ruby><b>に<ruby>応<rt>こた</rt></ruby>えて</b>、<ruby>選手<rt>せんしゅ</rt></ruby>は","role":"plain"},{"text":"<ruby>全力<rt>ぜんりょく</rt></ruby>を","role":"plain"},{"text":"<ruby>尽<rt>つ</rt></ruby>くした。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Den Erwartungen der Fans entsprechend gab der Spieler sein Bestes.«","ex":{"jp":"ファンの <ruby>期待<rt>きたい</rt></ruby><b>に<ruby>応<rt>こた</rt></ruby>えて</b>、<ruby>選手<rt>せんしゅ</rt></ruby>は <ruby>全力<rt>ぜんりょく</rt></ruby>を <ruby>尽<rt>つ</rt></ruby>くした。","de":"Den Erwartungen der Fans entsprechend gab der Spieler sein Bestes."},"simpel":"Wünsche erfüllen: »Den Stimmen der Berufstätigen entsprechend …«<br><span class='jp'><ruby>社会人<rt>しゃかいじん</rt></ruby>の <ruby>声<rt>こえ</rt></ruby><b>に<ruby>応<rt>こた</rt></ruby>えた</b></span><br>📖 Buch-Satz: 「<ruby>社会人<rt>しゃかいじん</rt></ruby>の<ruby>声<rt>こえ</rt></ruby>にこたえた」","rule":"N + に応えて: eine Erwartung, Bitte oder Nachfrage wird erfüllt — »als Antwort auf N, dem N entsprechend«. Typische N: 期待, 要望, 声, 要求. Attributiv に応えた/に応える."},{"l":44,"t":"119 · 〜ことにする","de":"beschließen zu … / so tun, als ob … (なかったことにする: ungeschehen machen)","slots":[{"text":"<ruby>健康<rt>けんこう</rt></ruby>の","role":"plain"},{"text":"ために、<ruby>毎朝<rt>まいあさ</rt></ruby>","role":"plain"},{"text":"<ruby>走<rt>はし</rt></ruby>る<b>ことにした</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Meiner Gesundheit zuliebe habe ich beschlossen, jeden Morgen zu laufen.«","ex":{"jp":"<ruby>健康<rt>けんこう</rt></ruby>の ために、<ruby>毎朝<rt>まいあさ</rt></ruby> <ruby>走<rt>はし</rt></ruby>る<b>ことにした</b>。","de":"Meiner Gesundheit zuliebe habe ich beschlossen, jeden Morgen zu laufen."},"simpel":"Ungeschehen machen: »Die Beförderung tun wir, als hätte es sie nie gegeben.«<br><span class='jp'>なかった<b>ことにする</b></span><br>📖 Buch-Satz: 「<ruby>昇進<rt>しょうしん</rt></ruby>の<ruby>話<rt>はなし</rt></ruby>はなかったことにする」","rule":"einfache Form + ことにする: eine bewusste Entscheidung — »ich beschließe zu …«. Sonderfall た-Form: 〜たことにする »so tun, als ob (schon) …«; なかったことにする »etwas ungeschehen machen«."},{"l":44,"t":"120 · 〜つもりだった","de":"ich war überzeugt / hatte gemeint (aber in Wahrheit anders)","slots":[{"text":"よく","role":"plain"},{"text":"<ruby>確認<rt>かくにん</rt></ruby>した<b>つもりだった</b>が、ミスが","role":"plain"},{"text":"<ruby>残<rt>のこ</rt></ruby>っていた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich dachte, ich hätte gut geprüft, aber es blieben Fehler.«","ex":{"jp":"よく <ruby>確認<rt>かくにん</rt></ruby>した<b>つもりだった</b>が、ミスが <ruby>残<rt>のこ</rt></ruby>っていた。","de":"Ich dachte, ich hätte gut geprüft, aber es blieben Fehler."},"simpel":"Selbstirrtum: »Ich dachte, ich hätte mich angestrengt (aber …).«<br><span class='jp'>がんばった<b>つもりだった</b></span><br>📖 Buch-Satz: 「がんばったつもりだった」","rule":"た-Form / einfache Form + つもりだった: man war fest überzeugt, etwas getan/so zu sein — doch die Realität war anders. Oft mit Bedauern. Auch 〜ているつもり (»ich bilde mir ein …«)."},{"l":44,"t":"121 · 〜てならない","de":"unerträglich … / ich kann nicht anders, als … zu empfinden","slots":[{"text":"[Gefühl て-Form]","role":"cond"},{"text":"ならない","role":"plain","label":"unerträglich"}],"gloss":"überwältigendes, nicht zurückhaltbares Gefühl: »unerträglich …«.","ex":{"jp":"<ruby>結果<rt>けっか</rt></ruby>が <ruby>気<rt>き</rt></ruby>になっ<b>てならない</b>。","de":"Das Ergebnis lässt mir keine Ruhe."},"simpel":"Überwältigendes Gefühl: »Es war unerträglich schmerzlich.«<br><span class='jp'>つらく<b>てならなかった</b></span><br>📖 Buch-Satz: 「つらくてならなかった」","rule":"い-Adj-くて / な-Adj-で / Verb-て + ならない: ein Gefühl ist so stark, dass man es nicht zurückhalten kann — »unerträglich …, ich kann nicht anders«. Für Gefühle & spontane Empfindungen."},{"l":44,"t":"122 · 〜ものなら","de":"wenn es (überhaupt) möglich wäre, zu … (schwer erfüllbarer Wunsch)","slots":[{"text":"<ruby>会<rt>あ</rt></ruby>える<b>ものなら</b>、もう","role":"plain"},{"text":"<ruby>一度<rt>いちど</rt></ruby>","role":"plain"},{"text":"<ruby>会<rt>あ</rt></ruby>いたい。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wenn ich sie (irgend) treffen könnte, würde ich sie gern wiedersehen.«","ex":{"jp":"<ruby>昔<rt>むかし</rt></ruby>に <ruby>戻<rt>もど</rt></ruby>れる<b>ものなら</b>、<ruby>戻<rt>もど</rt></ruby>りたい。","de":"Wenn ich in die Vergangenheit zurück könnte, würde ich es tun."},"simpel":"Sehnlicher Wunsch: »Wenn ich (es) nur könnte …«<br><span class='jp'>できる<b>ものなら</b></span><br>📖 Buch-Satz: 「できるものなら」","rule":"Kann-Form + ものなら: nennt einen schwer erfüllbaren Wunsch — »wenn es (überhaupt) möglich wäre, zu …«. Nachsatz oft mit derselben Handlung + たい. Meint: eigentlich kaum machbar."},{"l":44,"t":"123 · 〜（よ）うか〜まいか","de":"ob … oder (lieber) nicht … (schwanken)","slots":[{"text":"<ruby>本当<rt>ほんとう</rt></ruby>のことを","role":"plain"},{"text":"<ruby>言<rt>い</rt></ruby>おう<b>か</b>","role":"plain"},{"text":"<ruby>言<rt>い</rt></ruby>う<b>まいか</b>","role":"plain"},{"text":"<ruby>悩<rt>なや</rt></ruby>んだ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich rang mit mir, ob ich die Wahrheit sagen sollte oder nicht.«","ex":{"jp":"パーティーに <ruby>行<rt>い</rt></ruby>こう<b>か</b> <ruby>行<rt>い</rt></ruby>く<b>まいか</b>、<ruby>迷<rt>まよ</rt></ruby>っている。","de":"Ich schwanke, ob ich zur Party gehen soll oder nicht."},"simpel":"Unentschlossen: »ob ich gehen soll oder nicht …«<br><span class='jp'><ruby>行<rt>い</rt></ruby>こう<b>か</b> <ruby>行<rt>い</rt></ruby>く<b>まいか</b></span><br>📖 Buch-Satz: 「<ruby>行<rt>い</rt></ruby>こうか<ruby>行<rt>い</rt></ruby>くまいか」","rule":"Willensform + か + (gleiches Verb) + まいか: der Sprecher schwankt zwischen tun und nicht tun — »ob ich … soll oder lieber nicht«. Nachsatz oft 迷う/悩む (schwanken)."},{"l":44,"t":"124 · 〜<ruby>末<rt>すえ</rt></ruby>（に）","de":"nach langem … schließlich / am Ende von …","slots":[{"text":"さんざん","role":"plain"},{"text":"<ruby>悩<rt>なや</rt></ruby>んだ<b><ruby>末<rt>すえ</rt></ruby></b>、<ruby>会社<rt>かいしゃ</rt></ruby>を","role":"plain"},{"text":"やめる","role":"plain"},{"text":"ことにした。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Nach langem Grübeln entschied ich mich schließlich zu kündigen.«","ex":{"jp":"<ruby>長<rt>なが</rt></ruby>い <ruby>議論<rt>ぎろん</rt></ruby>の<b><ruby>末<rt>すえ</rt></ruby></b>、<ruby>結論<rt>けつろん</rt></ruby>が <ruby>出<rt>で</rt></ruby>た。","de":"Nach langer Diskussion kam schließlich ein Ergebnis."},"simpel":"Endergebnis nach Mühe: »Nach langem Zögern schließlich …«<br><span class='jp'><ruby>迷<rt>まよ</rt></ruby>った<b><ruby>末<rt>すえ</rt></ruby></b></span><br>📖 Buch-Satz: 「<ruby>迷<rt>まよ</rt></ruby>った<ruby>末<rt>すえ</rt></ruby>」","rule":"た-Form / N の + 末（に）: nach einem langen Prozess (Mühe, Überlegung, Streit) kommt schließlich ein Ergebnis — »nach langem …, am Ende«. Betont den langen Weg. Lesung すえ."},{"l":44,"t":"125 · たとえ〜ても","de":"selbst wenn … / egal wie/was …","slots":[{"text":"たとえ","role":"plain"},{"text":"<ruby>雨<rt>あめ</rt></ruby>が","role":"plain"},{"text":"<ruby>降<rt>ふ</rt></ruby>っ<b>ても</b>、<ruby>試合<rt>しあい</rt></ruby>は","role":"plain"},{"text":"<ruby>行<rt>おこな</rt></ruby>う。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Selbst wenn es regnet, findet das Spiel statt.«","ex":{"jp":"たとえ <ruby>雨<rt>あめ</rt></ruby>が <ruby>降<rt>ふ</rt></ruby>っ<b>ても</b>、<ruby>試合<rt>しあい</rt></ruby>は <ruby>行<rt>おこな</rt></ruby>う。","de":"Selbst wenn es regnet, findet das Spiel statt."},"simpel":"Bedingungslos: »Egal welche Umstände es gibt …«<br><span class='jp'>たとえ どんな <ruby>事情<rt>じじょう</rt></ruby>が あっ<b>ても</b></span><br>📖 Buch-Satz: 「たとえどんな<ruby>事情<rt>じじょう</rt></ruby>があっても」","rule":"たとえ + て-Form + も（でも）: »selbst wenn …, egal ob …« — das Ergebnis gilt trotzdem. たとえ am Satzanfang verstärkt das ても. Oft mit どんなに／どんな."},{"l":44,"t":"126 · 〜がたい","de":"schwer zu … / kaum zu … (innerlich unmöglich)","slots":[{"text":"あの","role":"plain"},{"text":"<ruby>日<rt>ひ</rt></ruby>のことは","role":"plain"},{"text":"<ruby>忘<rt>わす</rt></ruby>れ<b>がたい</b>","role":"plain"},{"text":"<ruby>思<rt>おも</rt></ruby>い<ruby>出<rt>で</rt></ruby>だ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Jener Tag ist eine unvergessliche Erinnerung.«","ex":{"jp":"それは <ruby>信<rt>しん</rt></ruby>じ<b>がたい</b> <ruby>話<rt>はなし</rt></ruby>だ。","de":"Das ist eine kaum zu glaubende Geschichte."},"simpel":"Kaum möglich: »schwer zu verzeihen«.<br><span class='jp'><ruby>許<rt>ゆる</rt></ruby>し<b>がたい</b></span><br>📖 Buch-Satz: 「<ruby>許<rt>ゆる</rt></ruby>しがたい」","rule":"ます-Stamm + がたい: etwas ist (gefühlt/innerlich) sehr schwer zu tun — »schwer/kaum zu …«. Für abstrakte Verben: 信じがたい, 理解しがたい, 忘れがたい. Nicht für körperliche Mühe (dafür にくい)."},{"l":44,"t":"127 · 〜もかまわず","de":"ohne sich um … zu kümmern / ungeachtet …","slots":[{"text":"<ruby>彼<rt>かれ</rt></ruby>は","role":"plain"},{"text":"<ruby>服<rt>ふく</rt></ruby>が","role":"plain"},{"text":"<ruby>汚<rt>よご</rt></ruby>れるの<b>もかまわず</b>、<ruby>子供<rt>こども</rt></ruby>を","role":"plain"},{"text":"<ruby>助<rt>たす</rt></ruby>けた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ungeachtet dessen, dass seine Kleidung schmutzig wurde, rettete er das Kind.«","ex":{"jp":"<ruby>彼<rt>かれ</rt></ruby>は <ruby>服<rt>ふく</rt></ruby>が <ruby>汚<rt>よご</rt></ruby>れるの<b>もかまわず</b>、<ruby>子供<rt>こども</rt></ruby>を <ruby>助<rt>たす</rt></ruby>けた。","de":"Ungeachtet dessen, dass seine Kleidung schmutzig wurde, rettete er das Kind."},"simpel":"Rücksichtslos weiter: »ohne sich daran zu stören, dass der Mann sie aufhalten will«.<br><span class='jp'><ruby>止<rt>と</rt></ruby>めるの<b>もかまわず</b></span><br>📖 Buch-Satz: 「<ruby>男<rt>おとこ</rt></ruby>が<ruby>止<rt>と</rt></ruby>めるのもかまわず」","rule":"N / einfache Form + の + もかまわず: man tut etwas, ohne auf N Rücksicht zu nehmen — »ungeachtet …, ohne sich zu kümmern um …«. Oft etwas, worauf man normalerweise achten würde (服, 人目 …)."},{"l":44,"t":"128 · 〜あまり（に）","de":"vor lauter … / aus übergroßer … (extremes Gefühl → Folge)","slots":[{"text":"[übergroßes Gefühl]","role":"subj"},{"text":"のあまり","role":"actor","label":"vor lauter"},{"text":"[Folge]","role":"plain"}],"gloss":"»ein Übermaß an … führt zu (unüblicher) Folge«.","ex":{"jp":"<ruby>驚<rt>おどろ</rt></ruby>き<b>のあまり</b>、<ruby>声<rt>こえ</rt></ruby>も <ruby>出<rt>で</rt></ruby>なかった。","de":"Vor lauter Schreck brachte ich kein Wort heraus."},"simpel":"Übermaß führt zu Folge: »vor lauter Scham …«<br><span class='jp'><ruby>恥<rt>は</rt></ruby>ずかしさ<b>のあまり</b></span><br>📖 Buch-Satz: 「<ruby>恥<rt>は</rt></ruby>ずかしさのあまり」","rule":"N の / einfache Form + あまり(に): ein übergroßes Gefühl/Ausmaß führt zu einer (meist unüblichen) Folge — »vor lauter …, aus übergroßer …«. Oft mit Gefühls-Nomen (<ruby>喜<rt>よろこ</rt></ruby>び, <ruby>驚<rt>おどろ</rt></ruby>き)."},{"l":44,"t":"129 · 〜を<ruby>込<rt>こ</rt></ruby>めて","de":"voller … / mit (ganzem) … (Gefühl hineinlegen)","slots":[{"text":"<ruby>感謝<rt>かんしゃ</rt></ruby>の","role":"plain"},{"text":"<ruby>気持<rt>きも</rt></ruby>ち<b>を<ruby>込<rt>こ</rt></ruby>めて</b>、<ruby>手紙<rt>てがみ</rt></ruby>を","role":"plain"},{"text":"<ruby>書<rt>か</rt></ruby>いた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Voller Dankbarkeit schrieb ich einen Brief.«","ex":{"jp":"<ruby>感謝<rt>かんしゃ</rt></ruby>の <ruby>気持<rt>きも</rt></ruby>ち<b>を<ruby>込<rt>こ</rt></ruby>めて</b>、<ruby>手紙<rt>てがみ</rt></ruby>を <ruby>書<rt>か</rt></ruby>いた。","de":"Voller Dankbarkeit schrieb ich einen Brief."},"simpel":"Gefühl hineinlegen: »mit ganzem Herzen / voller Gefühl«.<br><span class='jp'><ruby>気持<rt>きも</rt></ruby>ち<b>を<ruby>込<rt>こ</rt></ruby>めて</b></span><br>📖 Buch-Satz: 「<ruby>気持<rt>きも</rt></ruby>ちを<ruby>込<rt>こ</rt></ruby>めて」","rule":"N + を込めて: man legt ein Gefühl/eine Haltung ganz in eine Handlung hinein — »voller …, mit …«. Typische N: 心, 愛情, 感謝, 祈り. Attributiv を込めた."},{"l":44,"t":"130 · 〜も〜ば〜も","de":"sowohl … als auch … / mal … , mal … (Aufzählung)","slots":[{"text":"<ruby>人生<rt>じんせい</rt></ruby>には","role":"plain"},{"text":"いい","role":"plain"},{"text":"<ruby>時<rt>とき</rt></ruby><b>も</b>","role":"plain"},{"text":"あれ<b>ば</b>、<ruby>悪<rt>わる</rt></ruby>い","role":"plain"},{"text":"<ruby>時<rt>とき</rt></ruby><b>も</b>","role":"plain"},{"text":"ある。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Im Leben gibt es gute und auch schlechte Zeiten.«","ex":{"jp":"<ruby>人生<rt>じんせい</rt></ruby>には いい <ruby>時<rt>とき</rt></ruby><b>も</b> あれ<b>ば</b>、<ruby>悪<rt>わる</rt></ruby>い <ruby>時<rt>とき</rt></ruby><b>も</b> ある。","de":"Im Leben gibt es gute und auch schlechte Zeiten."},"simpel":"Beides tun: »trägt Gepäck und verkauft auch Tickets«.<br><span class='jp'><ruby>荷物<rt>にもつ</rt></ruby><ruby>運<rt>はこ</rt></ruby>び<b>も</b>すれ<b>ば</b> <ruby>切符<rt>きっぷ</rt></ruby><b>も</b> <ruby>売<rt>う</rt></ruby>る</span><br>📖 Buch-Satz: 「<ruby>荷物<rt>にもつ</rt></ruby><ruby>運<rt>はこ</rt></ruby>びもすれば<ruby>切符<rt>きっぷ</rt></ruby>も<ruby>売<rt>う</rt></ruby>る」","rule":"N1 も + Verb-ば … N2 も + Verb: zählt zwei parallele Eigenschaften/Handlungen auf — »sowohl … als auch; mal … mal …«. Zeigt: die Sache hat mehrere Seiten. Anschluss: ば-Form."},{"l":44,"t":"131 · 〜<ruby>抜<rt>ぬ</rt></ruby>く","de":"bis zum Ende durch-… / vollständig durchhalten","slots":[{"text":"<ruby>最後<rt>さいご</rt></ruby>まで","role":"plain"},{"text":"やり<b><ruby>抜<rt>ぬ</rt></ruby>く</b>","role":"plain"},{"text":"<ruby>覚悟<rt>かくご</rt></ruby>だ。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich bin entschlossen, es bis zum Ende durchzuziehen.«","ex":{"jp":"<ruby>最後<rt>さいご</rt></ruby>まで やり<b><ruby>抜<rt>ぬ</rt></ruby>く</b> <ruby>覚悟<rt>かくご</rt></ruby>だ。","de":"Ich bin entschlossen, es bis zum Ende durchzuziehen."},"simpel":"Durchhalten: »Ich ziehe es bis zum Ende durch!«<br><span class='jp'>やり<b><ruby>抜<rt>ぬ</rt></ruby>く</b>ぞ</span><br>📖 Buch-Satz: 「やり<ruby>抜<rt>ぬ</rt></ruby>くぞ」","rule":"ます-Stamm + 抜く（ぬく）: eine Handlung trotz Mühe bis zum Ende durchführen — »ganz durch-…, bis zuletzt durchhalten«. Betont Willen/Durchhaltevermögen. やり抜く, 考え抜く, 生き抜く."},{"l":45,"t":"132 · 〜（た）ものだ","de":"früher … (Rückblick) / da hat man wirklich … (emotionale Erinnerung)","slots":[{"text":"<ruby>子供<rt>こども</rt></ruby>の","role":"plain"},{"text":"<ruby>頃<rt>ころ</rt></ruby>は","role":"plain"},{"text":"よく","role":"plain"},{"text":"この","role":"plain"},{"text":"<ruby>川<rt>かわ</rt></ruby>で","role":"plain"},{"text":"<ruby>泳<rt>およ</rt></ruby>いだ<b>ものだ</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Als Kind bin ich oft in diesem Fluss geschwommen.«","ex":{"jp":"<ruby>子供<rt>こども</rt></ruby>の <ruby>頃<rt>ころ</rt></ruby>は よく この <ruby>川<rt>かわ</rt></ruby>で <ruby>泳<rt>およ</rt></ruby>いだ<b>ものだ</b>。","de":"Als Kind bin ich oft in diesem Fluss geschwommen."},"simpel":"Nostalgischer Rückblick: »Da hat das ganze Land wahrlich gejubelt.«<br><span class='jp'><ruby>国<rt>くに</rt></ruby>を <ruby>挙<rt>あ</rt></ruby>げて <ruby>喜<rt>よろこ</rt></ruby>んだ<b>ものだ</b></span><br>📖 Buch-Satz: 「<ruby>国<rt>くに</rt></ruby>を<ruby>挙<rt>あ</rt></ruby>げて<ruby>喜<rt>よろこ</rt></ruby>んだものだ」","rule":"た-Form + ものだ: nostalgischer, gefühlvoller Rückblick — »früher … oft/wirklich«. Erinnert an Vergangenes mit Emotion. (国を挙げて = »das ganze Land«.) Vgl. ものだ als »allgemeine Wahrheit« (Punkt 13)."},{"l":45,"t":"133 · 〜をめぐって","de":"rund um … / über … (meist strittiges Thema)","slots":[{"text":"<ruby>新<rt>あたら</rt></ruby>しい","role":"plain"},{"text":"<ruby>法律<rt>ほうりつ</rt></ruby><b>をめぐって</b>、<ruby>激<rt>はげ</rt></ruby>しい","role":"plain"},{"text":"<ruby>議論<rt>ぎろん</rt></ruby>が","role":"plain"},{"text":"<ruby>起<rt>お</rt></ruby>きた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Rund um das neue Gesetz entbrannte eine heftige Debatte.«","ex":{"jp":"<ruby>新<rt>あたら</rt></ruby>しい <ruby>法律<rt>ほうりつ</rt></ruby><b>をめぐって</b>、<ruby>激<rt>はげ</rt></ruby>しい <ruby>議論<rt>ぎろん</rt></ruby>が <ruby>起<rt>お</rt></ruby>きた。","de":"Rund um das neue Gesetz entbrannte eine heftige Debatte."},"simpel":"Streitthema: »Rund um die Austragung (gab es Debatten).«<br><span class='jp'><ruby>開催<rt>かいさい</rt></ruby><b>をめぐって</b></span><br>📖 Buch-Satz: 「<ruby>開催<rt>かいさい</rt></ruby>をめぐって」","rule":"N + をめぐって: nennt das Thema, um das herum (oft kontrovers) diskutiert/gestritten wird — »rund um N, über N«. Nachsatz oft 議論, 対立, 争う. Attributiv をめぐる."},{"l":45,"t":"134 · 〜（という）わけだ","de":"das heißt also … / daraus folgt (logischerweise) …","slots":[{"text":"<ruby>準備<rt>じゅんび</rt></ruby>に","role":"plain"},{"text":"3<ruby>年<rt>ねん</rt></ruby>","role":"plain"},{"text":"かかるなら、<ruby>今<rt>いま</rt></ruby>から","role":"plain"},{"text":"<ruby>始<rt>はじ</rt></ruby>める","role":"plain"},{"text":"<ruby>必要<rt>ひつよう</rt></ruby>が","role":"plain"},{"text":"ある<b>わけだ</b>。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Wenn die Vorbereitung drei Jahre dauert, muss man folglich jetzt anfangen.«","ex":{"jp":"<ruby>費用<rt>ひよう</rt></ruby>が <ruby>増<rt>ふ</rt></ruby>えれば、<ruby>税金<rt>ぜいきん</rt></ruby>も <ruby>上<rt>あ</rt></ruby>がる<b>わけだ</b>。","de":"Wenn die Kosten steigen, steigen folglich auch die Steuern."},"simpel":"Logische Schlussfolgerung: »Also kommt es (zwangsläufig) zu Protesten.«<br><span class='jp'><ruby>抗議<rt>こうぎ</rt></ruby>の <ruby>声<rt>こえ</rt></ruby>が <ruby>上<rt>あ</rt></ruby>がることになる<b>わけだ</b></span><br>📖 Buch-Satz: 「<ruby>抗議<rt>こうぎ</rt></ruby>の<ruby>声<rt>こえ</rt></ruby>が<ruby>上<rt>あ</rt></ruby>がることになるわけだ」","rule":"einfache Form + わけだ: zieht eine logisch zwingende Schlussfolgerung — »das heißt also …, daraus folgt …«. Oft mit ことになる (»es kommt dazu, dass …«). Erklärend/folgernd. (Grundbedeutung: Punkt 82.)"},{"l":45,"t":"135 · 〜にあたって","de":"anlässlich … / bei (einem besonderen Anlass)","slots":[{"text":"<ruby>新<rt>あたら</rt></ruby>しい","role":"plain"},{"text":"<ruby>生活<rt>せいかつ</rt></ruby>を","role":"plain"},{"text":"<ruby>始<rt>はじ</rt></ruby>める<b>にあたって</b>、<ruby>目標<rt>もくひょう</rt></ruby>を","role":"plain"},{"text":"<ruby>立<rt>た</rt></ruby>てた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Anlässlich des neuen Lebensabschnitts setzte ich mir Ziele.«","ex":{"jp":"<ruby>新<rt>あたら</rt></ruby>しい <ruby>生活<rt>せいかつ</rt></ruby>を <ruby>始<rt>はじ</rt></ruby>める<b>にあたって</b>、<ruby>目標<rt>もくひょう</rt></ruby>を <ruby>立<rt>た</rt></ruby>てた。","de":"Anlässlich des neuen Lebensabschnitts setzte ich mir Ziele."},"simpel":"Bei besonderem Anlass: »Anlässlich der Austragung der Olympiade …«<br><span class='jp'><ruby>開催<rt>かいさい</rt></ruby><b>にあたって</b></span><br>📖 Buch-Satz: 「オリンピック<ruby>開催<rt>かいさい</rt></ruby>にあたって」","rule":"N / Grundform + にあたって（にあたり）: bei/vor einem besonderen, bedeutsamen Anlass — »anlässlich …, wenn man … in Angriff nimmt«. Formell, für positive/wichtige Gelegenheiten."},{"l":45,"t":"136 · 〜に<ruby>加<rt>くわ</rt></ruby>えて","de":"zusätzlich zu … / außerdem noch …","slots":[{"text":"<ruby>雨<rt>あめ</rt></ruby><b>に<ruby>加<rt>くわ</rt></ruby>えて</b>、<ruby>風<rt>かぜ</rt></ruby>も","role":"plain"},{"text":"<ruby>強<rt>つよ</rt></ruby>く","role":"plain"},{"text":"なってきた。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Zum Regen kam auch noch starker Wind.«","ex":{"jp":"<ruby>資金<rt>しきん</rt></ruby><b>に<ruby>加<rt>くわ</rt></ruby>えて</b>、<ruby>人手<rt>ひとで</rt></ruby>も <ruby>足<rt>た</rt></ruby>りない。","de":"Zusätzlich zum Geld fehlt es auch an Arbeitskräften."},"simpel":"Etwas hinzufügen: »Zusätzlich zu den Geldmitteln …«<br><span class='jp'><ruby>資金<rt>しきん</rt></ruby><b>に<ruby>加<rt>くわ</rt></ruby>えて</b></span><br>📖 Buch-Satz: 「<ruby>資金<rt>しきん</rt></ruby>に<ruby>加<rt>くわ</rt></ruby>えて」","rule":"N + に加えて: fügt zu einer Sache eine weitere gleichartige hinzu — »zusätzlich zu N, außerdem«. Nachsatz oft mit も. Schriftlich-sachlich."},{"l":45,"t":"137 · 〜としても","de":"selbst wenn (angenommen) … / auch wenn es … wäre","slots":[{"text":"<ruby>予算<rt>よさん</rt></ruby>が","role":"plain"},{"text":"<ruby>用意<rt>ようい</rt></ruby>された<b>としても</b>、<ruby>時間<rt>じかん</rt></ruby>が","role":"plain"},{"text":"<ruby>足<rt>た</rt></ruby>りない。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Selbst wenn das Budget bereitstünde, reicht die Zeit nicht.«","ex":{"jp":"<ruby>予算<rt>よさん</rt></ruby>が <ruby>用意<rt>ようい</rt></ruby>された<b>としても</b>、<ruby>時間<rt>じかん</rt></ruby>が <ruby>足<rt>た</rt></ruby>りない。","de":"Selbst wenn das Budget bereitstünde, reicht die Zeit nicht."},"simpel":"Hypothese + trotzdem: »Selbst wenn es bereitgestellt würde …«<br><span class='jp'><ruby>用意<rt>ようい</rt></ruby>された<b>としても</b></span><br>📖 Buch-Satz: 「<ruby>用意<rt>ようい</rt></ruby>されたとしても」","rule":"einfache Form + としても: nimmt einen Fall (auch hypothetisch) an und sagt, das Ergebnis ändert sich trotzdem nicht — »selbst wenn (angenommen) …«. Kombiniert Annahme (とする) + »auch« (ても)."},{"l":45,"t":"138 · 〜に<ruby>基<rt>もと</rt></ruby>づいて","de":"auf Grundlage von … / gestützt auf … (＋Plus をもとに)","slots":[{"text":"<ruby>事実<rt>じじつ</rt></ruby><b>に<ruby>基<rt>もと</rt></ruby>づいて</b>","role":"plain"},{"text":"<ruby>記事<rt>きじ</rt></ruby>を","role":"plain"},{"text":"<ruby>書<rt>か</rt></ruby>く。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Ich schreibe den Artikel auf Grundlage der Fakten.«","ex":{"jp":"<ruby>事実<rt>じじつ</rt></ruby><b>に<ruby>基<rt>もと</rt></ruby>づいて</b> <ruby>記事<rt>きじ</rt></ruby>を <ruby>書<rt>か</rt></ruby>く。","de":"Ich schreibe den Artikel auf Grundlage der Fakten."},"simpel":"Fundament: »Auf Grundlage der Leitidee …«<br><span class='jp'><ruby>理念<rt>りねん</rt></ruby><b>に<ruby>基<rt>もと</rt></ruby>づいて</b></span><br>📖 Buch-Satz: 「<ruby>理念<rt>りねん</rt></ruby>に<ruby>基<rt>もと</rt></ruby>づいて」","rule":"N + に基づいて: etwas geschieht auf der Grundlage von N (Regel, Prinzip, Daten) — »basierend auf N, gemäß N«. Attributiv に基づく/に基づいた. ＋Plus: 〜をもとに(して) = »ausgehend von N (als Vorlage)«."},{"l":45,"t":"139 · 〜てこそ","de":"🔑 erst dadurch, dass … / nur wenn … (dann wirklich)","slots":[{"text":"<ruby>多<rt>おお</rt></ruby>くの","role":"plain"},{"text":"<ruby>人<rt>ひと</rt></ruby>が","role":"plain"},{"text":"<ruby>賛同<rt>さんどう</rt></ruby>し<b>てこそ</b>、<ruby>計画<rt>けいかく</rt></ruby>は","role":"plain"},{"text":"<ruby>実現<rt>じつげん</rt></ruby>する。","role":"plain"}],"gloss":"Baue den Beispielsatz: »Erst wenn viele zustimmen, wird der Plan Wirklichkeit.«","ex":{"jp":"<ruby>努力<rt>どりょく</rt></ruby>し<b>てこそ</b>、<ruby>成功<rt>せいこう</rt></ruby>できる。","de":"Nur durch Anstrengung kann man Erfolg haben."},"simpel":"🔑 <b>Schlüssel &amp; Schloss — »erst wenn X, dann zählt’s«:</b> て-Form + こそ = nur durch A wird B (wirklich) möglich.<br><span class=\"jp\"><ruby>助<rt>たす</rt></ruby>け<ruby>合<rt>あ</rt></ruby>っ<b>てこそ</b> <ruby>仲間<rt>なかま</rt></ruby>だ</span> = »Erst wenn man sich hilft, ist man wirklich Kameraden.«<br>📖 Buch-Satz: 「<ruby>賛同<rt>さんどう</rt></ruby>してこそ」","rule":"て-Form + こそ = nur/erst durch A wird B (wirklich) möglich oder sinnvoll — »erst dadurch, dass A, (dann) B«. A ist der unverzichtbare Schlüssel. Nachsatz positiv."}];
